window.CHAPTERS = [{"num": 1, "title": "第1章 反光玻璃", "file": "chapters/ch001.mp3", "dur": 371.1, "size_mb": 3.0, "segs": [{"s": 0.0, "e": 2.75, "t": "时间：9 月初 · 高一开学第一周"}, {"s": 2.75, "e": 5.82, "t": "高一开学的第三天，我才注意到那扇窗户。"}, {"s": 5.82, "e": 8.57, "t": "不是教室的窗户——是走廊尽头那扇。"}, {"s": 8.57, "e": 14.55, "t": "611 班的教室在四楼最东边，走廊尽头有一扇大窗，正对着教学楼中间的天井。"}, {"s": 14.55, "e": 16.49, "t": "天井不宽，大概 5 米。"}, {"s": 16.49, "e": 18.1, "t": "对面是 610 班。"}, {"s": 18.1, "e": 24.57, "t": "这件事本来是没什么特别的——两间教室隔着一个天井，走廊窗户对走廊窗户，仅此而已。"}, {"s": 24.57, "e": 29.58, "t": "我第三天早自习站到走廊上背课文的时候，纯粹是因为教室里太闷了。"}, {"s": 29.58, "e": 32.0, "t": "九月初的早上还带着夏天的尾巴。"}, {"s": 32.0, "e": 35.56, "t": "电扇在头顶吱吱呀呀地转，吹出来的风全是热的。"}, {"s": 35.56, "e": 42.83, "t": "语文老师让我们自由朗读《滕王阁序》，我读了大概两遍\"豫章故郡，洪都新府\"，后背就湿了一片。"}, {"s": 42.83, "e": 45.09, "t": "于是我拿着课本站到了走廊上。"}, {"s": 45.09, "e": 46.71, "t": "走廊比教室凉快一点。"}, {"s": 46.71, "e": 50.75, "t": "有风从窗户外面吹进来，虽然也是热的，但至少是活的。"}, {"s": 50.75, "e": 56.25, "t": "我翻到\"落霞与孤鹜齐飞，秋水共长天一色\"那一页，靠在窗台上，开始背。"}, {"s": 56.25, "e": 58.83, "t": "然后我抬起头，看见了对面那个人。"}, {"s": 58.83, "e": 61.1, "t": "610 班的窗户也是开着的。"}, {"s": 61.1, "e": 65.46, "t": "最后一排靠窗的位置坐着一个人——他低着头，正在写什么。"}, {"s": 65.46, "e": 68.05, "t": "从我这个角度，只能看到他的侧脸。"}, {"s": 68.05, "e": 74.35, "t": "光线从窗外照进来，落在他的侧脸上——他的眉毛不浓，鼻梁很直，下唇比上唇厚一点。"}, {"s": 74.35, "e": 76.13, "t": "这些是我后来才看清的。"}, {"s": 76.13, "e": 78.07, "t": "当时我只注意到了一件事。"}, {"s": 78.07, "e": 78.87, "t": "他的眼睛。"}, {"s": 78.87, "e": 83.08, "t": "他抬头了——大概是写完了什么，抬起头活动了一下脖子。"}, {"s": 83.08, "e": 85.66, "t": "就在那一瞬间，我看见了他的眼睛。"}, {"s": 85.66, "e": 86.15, "t": "很亮。"}, {"s": 86.15, "e": 91.0, "t": "不是\"有精神\"的那种亮——是那种你隔着 5 米都能看清的亮。"}, {"s": 91.0, "e": 96.82, "t": "像早上第一节课前、太阳刚升起来、照到对面教学楼的白墙再反射过来的那种光。"}, {"s": 96.82, "e": 98.92, "t": "我盯着他看了大概 3 秒。"}, {"s": 98.92, "e": 100.86, "t": "然后他低下头，继续写了。"}, {"s": 100.86, "e": 102.8, "t": "我也低下头，看我的课本。"}, {"s": 102.8, "e": 109.1, "t": "\"落霞与孤鹜齐飞，秋水共长天一色\"——我盯着这行字看了很久，一个字都没读进去。"}, {"s": 109.1, "e": 110.72, "t": "脑子里全是那双眼睛。"}, {"s": 110.72, "e": 113.79, "t": "我对自己说：你只是没见过长成这样的人。"}, {"s": 113.79, "e": 114.92, "t": "但我知道不是。"}, {"s": 114.92, "e": 118.8, "t": "我那天早上回到教室之后，坐在座位上发了很久的呆。"}, {"s": 118.8, "e": 123.32, "t": "周海——我新认识的同桌，坐我左边——拿胳膊肘捅了我一下。"}, {"s": 123.32, "e": 124.45, "t": "\"你怎么了？\""}, {"s": 124.45, "e": 125.42, "t": "\"没怎么。\""}, {"s": 125.42, "e": 126.56, "t": "\"你脸红了。\""}, {"s": 126.56, "e": 127.36, "t": "\"天热。\""}, {"s": 127.36, "e": 129.3, "t": "他看了我一眼，没继续问。"}, {"s": 129.3, "e": 132.7, "t": "我把课本翻到《滕王阁序》那一页，假装在背。"}, {"s": 132.7, "e": 134.64, "t": "但我的目光一直往窗外飘。"}, {"s": 134.64, "e": 140.62, "t": "从我这个位置——靠窗，倒数第二排——刚好能看见对面 610 班的那扇窗户。"}, {"s": 140.62, "e": 142.23, "t": "他的位置在最后一排。"}, {"s": 142.23, "e": 147.41, "t": "从我这里看过去，隔着天井，隔着反光玻璃，只能看到一个人影的轮廓。"}, {"s": 147.41, "e": 152.58, "t": "但我还是一眼认出了他——他低着头，伏在桌上，右手在动，在写东西。"}, {"s": 152.58, "e": 154.52, "t": "他写字的时候头埋得很低。"}, {"s": 154.52, "e": 159.04, "t": "偶尔他会停下来，用手摸一下后脑勺——就一下，然后继续写。"}, {"s": 159.04, "e": 160.98, "t": "我盯着那个动作看了很久。"}, {"s": 160.98, "e": 162.6, "t": "然后我发现了一件事。"}, {"s": 162.6, "e": 167.61, "t": "我还没记住《滕王阁序》第二段，但我已经记住了他摸后脑勺的节奏。"}, {"s": 167.61, "e": 169.55, "t": "那天的课我基本没听进去。"}, {"s": 169.55, "e": 176.01, "t": "数学课老师在讲集合——我在纸上画了一条线，标了一个点，代表 5 米外的那个位置。"}, {"s": 176.01, "e": 183.77, "t": "语文课继续背《滕王阁序》——我背到\"潦水尽而寒潭清\"的时候，脑子里浮现的是他抬头时那双眼睛的光。"}, {"s": 183.77, "e": 187.65, "t": "吃午饭的时候周海问我：\"你今天怎么魂不守舍的？\""}, {"s": 187.65, "e": 188.46, "t": "\"有吗？\""}, {"s": 188.46, "e": 188.94, "t": "\"有。"}, {"s": 188.94, "e": 191.37, "t": "数学老师叫你两遍你都没听见。\""}, {"s": 191.37, "e": 192.18, "t": "我没说话。"}, {"s": 192.18, "e": 195.41, "t": "下午最后一节自习课，我提前把作业写完了。"}, {"s": 195.41, "e": 198.64, "t": "然后我站起来，走到走廊尽头那扇窗户前面。"}, {"s": 198.64, "e": 202.04, "t": "那个位置——正对着 610 班的走廊窗户。"}, {"s": 202.04, "e": 202.84, "t": "他的窗户。"}, {"s": 202.84, "e": 205.43, "t": "我站在那里，假装在看楼下的操场。"}, {"s": 205.43, "e": 210.6, "t": "操场上有人在跑步，有人在打篮球，远处的围墙外面能看见城市的楼顶。"}, {"s": 210.6, "e": 212.22, "t": "但我什么都没看进去。"}, {"s": 212.22, "e": 219.98, "t": "我侧过头，往 610 班的方向看了一眼——隔着 5 米宽的天井，隔着玻璃的反光，我看见他的背影。"}, {"s": 219.98, "e": 224.02, "t": "他坐在最后一排，坐得很直，右手在写，左手搭在桌沿。"}, {"s": 224.02, "e": 225.15, "t": "他就那么坐着。"}, {"s": 225.15, "e": 226.93, "t": "我站了大概 3 分钟。"}, {"s": 226.93, "e": 228.06, "t": "然后我回去了。"}, {"s": 228.06, "e": 231.61, "t": "回教室的路上，我在心里对自己说：你只是好奇。"}, {"s": 231.61, "e": 233.39, "t": "你只是没见过这样的人。"}, {"s": 233.39, "e": 236.46, "t": "但我记得回座位的时候，心跳快得不正常。"}, {"s": 236.46, "e": 239.37, "t": "晚自习结束后，我背着书包走出教学楼。"}, {"s": 239.37, "e": 242.93, "t": "九月的晚上有了点凉意，路灯把校园照成昏黄色。"}, {"s": 242.93, "e": 247.13, "t": "我往宿舍走的路上，经过食堂门口的时候——看见了个人。"}, {"s": 247.13, "e": 251.33, "t": "他站在食堂门口的灯光下面，背着书包，手里拿着一瓶水。"}, {"s": 251.33, "e": 251.82, "t": "是他。"}, {"s": 251.82, "e": 255.54, "t": "他没看见我——他在看手机，屏幕的光映在他脸上。"}, {"s": 255.54, "e": 258.44, "t": "我从他身后走过去，大概隔了 3 米。"}, {"s": 258.44, "e": 263.46, "t": "走过去的时候我放慢了脚步，不是故意的——是我的脚自己慢下来的。"}, {"s": 263.46, "e": 267.5, "t": "我走过他身边的时候，听见他把瓶盖拧开、喝水的声音。"}, {"s": 267.5, "e": 269.11, "t": "咕咚——很小的一声。"}, {"s": 269.11, "e": 270.41, "t": "然后我走过去了。"}, {"s": 270.41, "e": 271.21, "t": "没有回头。"}, {"s": 271.21, "e": 277.36, "t": "但那个声音——瓶盖拧开的咔的一声，喝水的声音，路灯下他的侧脸——我都记住了。"}, {"s": 277.36, "e": 280.75, "t": "回到宿舍，我爬上床，拿出手机，打开备忘录。"}, {"s": 280.75, "e": 281.72, "t": "打了一行字："}, {"s": 281.72, "e": 284.47, "t": "\"对面 610 班最后一排，靠窗。"}, {"s": 284.47, "e": 285.44, "t": "眼睛很亮。\""}, {"s": 285.44, "e": 288.02, "t": "我看着这行字看了大概 10 秒。"}, {"s": 288.02, "e": 288.99, "t": "然后删掉了。"}, {"s": 288.99, "e": 291.42, "t": "把手机放到枕头底下，闭上眼睛。"}, {"s": 291.42, "e": 299.18, "t": "但眼前全是那个画面——他坐在窗户后面，阳光落在他的侧脸上，他抬起头来，那一瞬间，他的眼睛里有光。"}, {"s": 299.18, "e": 301.44, "t": "我翻了个身，把被子拉过头顶。"}, {"s": 301.44, "e": 301.92, "t": "完了。"}, {"s": 301.92, "e": 302.89, "t": "我在心里说。"}, {"s": 302.89, "e": 303.86, "t": "这才第三天。"}, {"s": 303.86, "e": 307.42, "t": "<!-- summary:start -->"}, {"s": 307.42, "e": 308.55, "t": "本章推进线索："}, {"s": 308.55, "e": 317.28, "t": "- 🔵 埋设全书核心意象\"眼睛里的光\"——博文眼睛\"像早上第一节课前、太阳照到对面教学楼白墙再反射过来的光\""}, {"s": 317.28, "e": 321.64, "t": "- 🔵 埋设反光玻璃意象——隔着天井 5 米的物理距离"}, {"s": 321.64, "e": 325.68, "t": "- 🔵 埋设\"摸后脑勺\"习惯——博文的标志性小动作"}, {"s": 325.68, "e": 335.22, "t": "- 🔵 埋设滕王阁序关联场景——开学早自习背书，与\"落霞与孤鹜齐飞\"形成隐含对比（看到博文的瞬间 = 看到最美的风景）"}, {"s": 335.22, "e": 336.83, "t": "本章关键事件时间戳："}, {"s": 336.83, "e": 341.2, "t": "- 高一开学第三天，早自习：林深第一次透过窗户看见博文"}, {"s": 341.2, "e": 345.24, "t": "- 当天晚自习后：食堂门口第一次近距离（3米）经过"}, {"s": 345.24, "e": 346.37, "t": "本章新埋伏笔："}, {"s": 346.37, "e": 352.51, "t": "- F-反光玻璃：5 米天井，反光玻璃的视觉阻挡——物理距离=情感距离的隐喻"}, {"s": 352.51, "e": 356.72, "t": "- F-摸后脑勺：博文的个人习惯，被林深第一次观察到"}, {"s": 356.72, "e": 357.52, "t": "下章钩子："}, {"s": 357.52, "e": 362.86, "t": "- 林深自己都还没搞清楚的这种\"完了\"的感觉——接下来会怎么发展？"}, {"s": 362.86, "e": 366.09, "t": "<!-- summary:end -->"}, {"s": 366.09, "e": 371.1, "t": "2026-07-19 初始版本：Ch 1 反光玻璃——全书开篇"}]}, {"num": 2, "title": "第2章 越看越耐看", "file": "chapters/ch002.mp3", "dur": 447.7, "size_mb": 3.6, "segs": [{"s": 0.0, "e": 3.2, "t": "时间：9 月中至 11 月初 · 高一上"}, {"s": 3.2, "e": 5.91, "t": "从那天之后，我开始注意那扇窗户了。"}, {"s": 5.91, "e": 8.95, "t": "不是刻意的——至少我对自己是这么说的。"}, {"s": 8.95, "e": 13.58, "t": "我只是发现走廊尽头那个位置通风比较好，站那里背书比较凉快。"}, {"s": 13.58, "e": 14.38, "t": "只是这样。"}, {"s": 14.38, "e": 18.53, "t": "但连续站了一周之后，周海问我：\"你怎么老往那边跑？\""}, {"s": 18.53, "e": 19.65, "t": "\"那边凉快。\""}, {"s": 19.65, "e": 21.25, "t": "\"这边也有窗户啊。\""}, {"s": 21.25, "e": 22.53, "t": "\"这边太阳大。\""}, {"s": 22.53, "e": 27.96, "t": "他看了一眼我站的位置——那个位置刚好被墙挡住一半的阳光——没再问了。"}, {"s": 27.96, "e": 29.08, "t": "但我自己知道。"}, {"s": 29.08, "e": 32.59, "t": "那个角度，刚好能看见 610 班的最后一排。"}, {"s": 32.59, "e": 34.35, "t": "我发现了他的一些规律。"}, {"s": 34.35, "e": 38.35, "t": "每天早上 7 点 15 分左右，他会从后门进教室。"}, {"s": 38.35, "e": 42.66, "t": "不早也不晚——不是最早到的那批，也不是踩点进来的那种。"}, {"s": 42.66, "e": 45.7, "t": "书包单肩背着，右手拎着一个透明的水杯。"}, {"s": 45.7, "e": 50.33, "t": "他坐下来之后，会先把杯子放在桌角，然后从书包里抽出一本书。"}, {"s": 50.33, "e": 56.4, "t": "他翻书的动作很快——不像是在挑今天读什么，像是早就决定好了，直接翻到某一页。"}, {"s": 56.4, "e": 59.76, "t": "他看书的时候头埋得很低，几乎要贴到桌面上。"}, {"s": 59.76, "e": 62.47, "t": "这个姿势我隔着天井都看得清清楚楚。"}, {"s": 62.47, "e": 69.5, "t": "偶尔他会停下来——不是抬头，是停下来，盯着书页的某一行，一动不动，大概 3 到 5 秒。"}, {"s": 69.5, "e": 72.54, "t": "然后他会拿起笔，在那一行下面画一条线。"}, {"s": 72.54, "e": 75.74, "t": "画线的动作很干脆——一笔到头，不带犹豫。"}, {"s": 75.74, "e": 78.77, "t": "我观察了两周，发现他几乎每页都会画线。"}, {"s": 78.77, "e": 84.52, "t": "不是整段整段地画——是偶尔一行，偶尔一行，像在书页上种了一排稀疏的篱笆。"}, {"s": 84.52, "e": 86.28, "t": "我开始好奇他在读什么。"}, {"s": 86.28, "e": 93.31, "t": "但距离太远了——5 米，隔着反光玻璃，我连他桌面上摊的是什么颜色的书都看不清，更别说字。"}, {"s": 93.31, "e": 94.91, "t": "我只能看到他的动作。"}, {"s": 94.91, "e": 97.31, "t": "看到他低头、抬头、画线、翻页。"}, {"s": 97.31, "e": 102.26, "t": "看到他偶尔停下来，用手摸一下后脑勺——和第一天一模一样的动作。"}, {"s": 102.26, "e": 105.77, "t": "我发现自己已经能预判他什么时候会摸后脑勺了。"}, {"s": 105.77, "e": 109.29, "t": "一般是连续看完三页之后，或者写完一大段之后。"}, {"s": 109.29, "e": 115.36, "t": "他会停一两秒，然后抬起右手，用手掌贴住后脑勺，往上摸一下——很短，不到一秒。"}, {"s": 115.36, "e": 118.24, "t": "有时候他摸完之后，会顺便伸一个懒腰。"}, {"s": 118.24, "e": 124.47, "t": "伸懒腰的时候他会往后靠，椅背发出咯吱一声，两只手举过头顶，手指交叉，掌心朝天。"}, {"s": 124.47, "e": 128.62, "t": "那个动作会持续大概三秒，然后他收回来，继续低头看书。"}, {"s": 128.62, "e": 131.66, "t": "第一次看见他伸懒腰的时候，我正在喝水。"}, {"s": 131.66, "e": 132.46, "t": "差点呛到。"}, {"s": 132.46, "e": 137.57, "t": "不是因为他伸懒腰的样子有什么特别的——是因为我发现我竟然在看他。"}, {"s": 137.57, "e": 138.37, "t": "一直在看。"}, {"s": 138.37, "e": 143.0, "t": "从早自习看到第一节课预备铃响，从大课间看到最后一节课下课。"}, {"s": 143.0, "e": 150.99, "t": "我站在走廊上、站在窗户边上、有时候甚至站在教室后门——只要那个角度能看见他，我就会不自觉地往那边看。"}, {"s": 150.99, "e": 153.07, "t": "我说服自己：我只是在发呆。"}, {"s": 153.07, "e": 154.83, "t": "只是刚好面朝那个方向。"}, {"s": 154.83, "e": 155.94, "t": "但我知道不是。"}, {"s": 155.94, "e": 158.82, "t": "因为我发呆的时候，脑子里想的全是他。"}, {"s": 158.82, "e": 162.02, "t": "十月中旬的时候，我记住了他大部分的习惯。"}, {"s": 162.02, "e": 168.09, "t": "他每天中午会去食堂，但不是去一楼的普通窗口——他去二楼，最里面那个面食窗口。"}, {"s": 168.09, "e": 171.12, "t": "每次都是同一碗面，不加辣，加一个煎蛋。"}, {"s": 171.12, "e": 172.88, "t": "这件事我是怎么知道的？"}, {"s": 172.88, "e": 175.6, "t": "因为我开始调整自己去食堂的时间了。"}, {"s": 175.6, "e": 178.15, "t": "不是跟踪他——我在心里这么强调。"}, {"s": 178.15, "e": 180.71, "t": "只是刚好我也想在那个时间去二楼。"}, {"s": 180.71, "e": 181.19, "t": "刚好。"}, {"s": 181.19, "e": 186.46, "t": "有一个周五的中午，我端着餐盘找位子，发现他坐在靠窗的位置，一个人。"}, {"s": 186.46, "e": 189.82, "t": "那张桌子能坐四个人，其他三个位子都是空的。"}, {"s": 189.82, "e": 193.01, "t": "我端着餐盘站在走道中间，犹豫了大概五秒。"}, {"s": 193.01, "e": 194.29, "t": "然后我走了过去。"}, {"s": 194.29, "e": 197.65, "t": "坐到同一张桌子——但是隔了两个位子的对角。"}, {"s": 197.65, "e": 199.08, "t": "他抬头看了我一眼。"}, {"s": 199.08, "e": 200.68, "t": "就一眼——大概一秒。"}, {"s": 200.68, "e": 202.76, "t": "然后他低下头，继续吃面了。"}, {"s": 202.76, "e": 209.95, "t": "那个眼神没有任何表情——不是友好，也不是不友好，就是看了一眼，确认有人坐过来了，然后移开。"}, {"s": 209.95, "e": 212.35, "t": "就像确认今天天气不错一样普通。"}, {"s": 212.35, "e": 213.94, "t": "但我记了一整个下午。"}, {"s": 213.94, "e": 216.82, "t": "他看我的那一眼——他的眼睛确实很亮。"}, {"s": 216.82, "e": 222.89, "t": "在食堂的日光灯下面，那种亮不是阳光反射出来的亮，是他眼睛里本来就有的那种亮。"}, {"s": 222.89, "e": 225.45, "t": "我低头扒饭的时候，心跳得有点快。"}, {"s": 225.45, "e": 226.73, "t": "但我没表现出来。"}, {"s": 226.73, "e": 227.84, "t": "吃完了就走了。"}, {"s": 227.84, "e": 231.84, "t": "走出食堂大门的时候，我对自己说：他只是看了你一眼。"}, {"s": 231.84, "e": 232.8, "t": "你别想太多。"}, {"s": 232.8, "e": 236.95, "t": "但我走出十米之后，还是回头看了一眼食堂二楼那扇窗户。"}, {"s": 236.95, "e": 237.91, "t": "他还在那里。"}, {"s": 237.91, "e": 239.35, "t": "低着头，继续吃面。"}, {"s": 239.35, "e": 241.11, "t": "后来我养成了一个习惯。"}, {"s": 241.11, "e": 246.7, "t": "每天吃完晚饭之后，我不直接回教室——我会绕到教学楼后面，从那条小路走。"}, {"s": 246.7, "e": 249.73, "t": "那条路不是回教室最近的路，甚至有点绕。"}, {"s": 249.73, "e": 256.76, "t": "但那条路经过 610 班教室窗户的背面——从那里，我可以透过窗户的反光，看到里面的人影。"}, {"s": 256.76, "e": 261.24, "t": "有一次我走到那棵梧桐树下面的时候——刚好看见他站在窗边。"}, {"s": 261.24, "e": 262.2, "t": "他没在看书。"}, {"s": 262.2, "e": 265.55, "t": "他站窗户边上，一只手撑在窗沿上，看着窗外。"}, {"s": 265.55, "e": 267.15, "t": "看的方向——是这边。"}, {"s": 267.15, "e": 268.91, "t": "是 611 班的方向。"}, {"s": 268.91, "e": 271.62, "t": "我站在那棵梧桐树下面，脚步停住了。"}, {"s": 271.62, "e": 277.7, "t": "风把树叶吹得沙沙响，秋天的光从他身后的教室里透出来，把他的轮廓勾出一道金边。"}, {"s": 277.7, "e": 279.77, "t": "他站在窗户边上，看着这边。"}, {"s": 279.77, "e": 281.37, "t": "我不知道他在看什么。"}, {"s": 281.37, "e": 286.16, "t": "但那一刻我发现——我在这棵梧桐树下面站了多久，他就站了多久。"}, {"s": 286.16, "e": 288.24, "t": "然后他转过身，走回座位了。"}, {"s": 288.24, "e": 290.64, "t": "我站在树下面，心脏跳得有点快。"}, {"s": 290.64, "e": 292.87, "t": "刚才——他看的，是我这边吗？"}, {"s": 292.87, "e": 294.95, "t": "还是只是碰巧看向这个方向？"}, {"s": 294.95, "e": 295.75, "t": "我不知道。"}, {"s": 295.75, "e": 299.43, "t": "但我发现——从那天起，我走那条路的次数更多了。"}, {"s": 299.43, "e": 302.78, "t": "十月底的某一天，我在走廊上又站了快十分钟。"}, {"s": 302.78, "e": 306.78, "t": "周海从教室里探出头来：\"林深，你最近是不是瘦了？\""}, {"s": 306.78, "e": 307.57, "t": "\"有吗？\""}, {"s": 307.57, "e": 308.05, "t": "\"有。"}, {"s": 308.05, "e": 310.45, "t": "你每天中午不去食堂的二楼吗？\""}, {"s": 310.45, "e": 311.41, "t": "我愣了一下。"}, {"s": 311.41, "e": 313.97, "t": "\"你——怎么知道我中午去二楼？\""}, {"s": 313.97, "e": 317.32, "t": "\"因为你上周说了五次'二楼的面比较好吃'。"}, {"s": 317.32, "e": 320.84, "t": "\"周海靠在门框上，\"你以前不是吃一楼的吗？\""}, {"s": 320.84, "e": 321.63, "t": "我没回答。"}, {"s": 321.63, "e": 322.59, "t": "他也没追问。"}, {"s": 322.59, "e": 329.62, "t": "但他看了一眼我站的位置——那个刚好能看到对面 610 班最后一排的位置——然后笑了一下。"}, {"s": 329.62, "e": 331.7, "t": "那个笑很轻，什么话都没说。"}, {"s": 331.7, "e": 335.06, "t": "但我总觉得他笑的那个意思，我有点不敢细想。"}, {"s": 335.06, "e": 338.73, "t": "晚上躺在床上的时候，我想起下午窗口的那个画面。"}, {"s": 338.73, "e": 340.97, "t": "他站在窗户边，看着这个方向。"}, {"s": 340.97, "e": 344.96, "t": "夕阳的光照在他脸上，他眯了一下眼睛，但没有马上走。"}, {"s": 344.96, "e": 346.56, "t": "他站了大概有七八秒。"}, {"s": 346.56, "e": 347.84, "t": "然后才转身回去。"}, {"s": 347.84, "e": 350.08, "t": "我翻了个身，把脸埋进枕头里。"}, {"s": 350.08, "e": 353.11, "t": "我知道这个动作是什么意思——我在逃避。"}, {"s": 353.11, "e": 353.91, "t": "逃避什么？"}, {"s": 353.91, "e": 356.15, "t": "逃避一个我越来越清楚的念头。"}, {"s": 356.15, "e": 358.38, "t": "我不是\"刚好\"站在那个位置。"}, {"s": 358.38, "e": 360.94, "t": "我不是\"刚好\"在那个时间去食堂。"}, {"s": 360.94, "e": 363.98, "t": "我不是\"刚好\"绕路走教学楼后面那条路。"}, {"s": 363.98, "e": 365.57, "t": "我——我就是想看他。"}, {"s": 365.57, "e": 369.57, "t": "这个念头，我在心里放了大概两周，没敢对自己说出口。"}, {"s": 369.57, "e": 370.53, "t": "但它在那里。"}, {"s": 370.53, "e": 375.48, "t": "像那扇窗户的反光一样——你看不透它，但你知道它后面有什么东西。"}, {"s": 375.48, "e": 376.44, "t": "一直在那里。"}, {"s": 376.44, "e": 379.95, "t": "<!-- summary:start -->"}, {"s": 379.95, "e": 381.07, "t": "本章推进线索："}, {"s": 381.07, "e": 386.66, "t": "- 🔵 深化\"越看越耐看\"——林深从偶然看到变成刻意去看的完整心路历程"}, {"s": 386.66, "e": 393.69, "t": "- 🔵 埋设博文\"习惯\"细节：7:15 进教室、书页画线、摸后脑勺、伸懒腰、二楼面食窗口"}, {"s": 393.69, "e": 399.45, "t": "- 🔵 第一次\"物理接触\"：食堂同一张桌子，博文看了一眼（1秒，无表情）"}, {"s": 399.45, "e": 405.04, "t": "- 🔵 博文站在窗边看向 611 班方向——首个可能的双向信号（模糊）"}, {"s": 405.04, "e": 409.51, "t": "- 🔵 周海察觉——第一次被外人点破\"你站的位置很特别\""}, {"s": 409.51, "e": 411.11, "t": "本章关键事件时间戳："}, {"s": 411.11, "e": 414.15, "t": "- 9月中至11月初：观察习惯逐步形成"}, {"s": 414.15, "e": 418.46, "t": "- 10月中旬某一周五：食堂二楼同一张桌，博文看了一眼"}, {"s": 418.46, "e": 424.21, "t": "- 10月下旬某天：绕路走教学楼后面，看见博文站在窗边看向 611 方向"}, {"s": 424.21, "e": 428.21, "t": "- 10月底：周海第一次点破\"你以前不是吃一楼的\""}, {"s": 428.21, "e": 429.33, "t": "本章新埋伏笔："}, {"s": 429.33, "e": 435.08, "t": "- F-窗口守望：博文站在窗户边看向 611 方向——是否真的在看林深？"}, {"s": 435.08, "e": 435.88, "t": "下章钩子："}, {"s": 435.88, "e": 438.91, "t": "- 一个不经意的对视——然后一切都变了"}, {"s": 438.91, "e": 442.11, "t": "<!-- summary:end -->"}, {"s": 442.11, "e": 447.7, "t": "2026-07-19 初始版本：Ch 2 越看越耐看——观察习惯的固化"}]}, {"num": 3, "title": "第3章 红笔划一道", "file": "chapters/ch003.mp3", "dur": 218.4, "size_mb": 1.7, "segs": [{"s": 0.0, "e": 3.15, "t": "时间：9 月底—11 月 7 日 · 高一上"}, {"s": 3.15, "e": 6.31, "t": "我观察了他大概三个星期之后，发现了一个规律。"}, {"s": 6.31, "e": 7.74, "t": "他每天会做同一件事。"}, {"s": 7.74, "e": 15.05, "t": "下午最后一节自习课——大概 4 点 50 分左右——他会从笔袋里拿出一支红笔，在面前的本子上写几行字。"}, {"s": 15.05, "e": 20.06, "t": "写完之后，他会用红笔在那一页的末尾划一道——一笔，从右到左，不长不短。"}, {"s": 20.06, "e": 22.07, "t": "然后他把本子合上，放回抽屉。"}, {"s": 22.07, "e": 22.93, "t": "每天都这样。"}, {"s": 22.93, "e": 27.09, "t": "我站在走廊上，隔着反光玻璃，看了整整一周才确认自己没看错。"}, {"s": 27.09, "e": 31.67, "t": "那支红笔——不是老师用的那种批改红笔，是那种细头的、写字的红笔。"}, {"s": 31.67, "e": 33.39, "t": "笔帽上有一个小小的夹子。"}, {"s": 33.39, "e": 34.25, "t": "他在写什么？"}, {"s": 34.25, "e": 34.82, "t": "写日记？"}, {"s": 34.82, "e": 35.25, "t": "做题？"}, {"s": 35.25, "e": 35.97, "t": "我不知道。"}, {"s": 35.97, "e": 39.27, "t": "但那个动作——写完，划一道，合上——我记住了。"}, {"s": 39.27, "e": 44.43, "t": "周日下午我在宿舍洗衣服，端着盆往水房走的时候，在楼梯转角听见了一个声音。"}, {"s": 44.43, "e": 45.43, "t": "有人在读什么。"}, {"s": 45.43, "e": 46.29, "t": "我放慢脚步。"}, {"s": 46.29, "e": 47.29, "t": "——不是中文。"}, {"s": 47.29, "e": 47.86, "t": "是英文。"}, {"s": 47.86, "e": 49.58, "t": "声音不高，带着一点尾音。"}, {"s": 49.58, "e": 50.87, "t": "句子不长，像是诗。"}, {"s": 50.87, "e": 52.88, "t": "我站在转角后面，没有走出去。"}, {"s": 52.88, "e": 54.31, "t": "那声音继续读了几行。"}, {"s": 54.31, "e": 57.04, "t": "我听不太懂内容——有几个单词我没学过。"}, {"s": 57.04, "e": 58.76, "t": "但那个声音的节奏我记得。"}, {"s": 58.76, "e": 59.62, "t": "是他的声音。"}, {"s": 59.62, "e": 62.77, "t": "我站在那里，等到声音停下来，才端着盆走出去。"}, {"s": 62.77, "e": 64.06, "t": "楼梯转角没有人了。"}, {"s": 64.06, "e": 69.5, "t": "但我下楼的时候，看见了那个背影——他走在前面，手里拿着一本书，封面是深色的。"}, {"s": 69.5, "e": 70.08, "t": "英文诗。"}, {"s": 70.08, "e": 71.08, "t": "他在读英文诗。"}, {"s": 71.08, "e": 72.94, "t": "第一次对视发生在一个周二。"}, {"s": 72.94, "e": 74.95, "t": "我站在走廊上，假装在看楼下。"}, {"s": 74.95, "e": 77.82, "t": "其实我的目光在玻璃的反光里——他的方向。"}, {"s": 77.82, "e": 78.82, "t": "他刚好抬起头。"}, {"s": 78.82, "e": 80.4, "t": "然后他往窗外看了一眼。"}, {"s": 80.4, "e": 84.84, "t": "就一眼——但那一瞬间，他的目光和我的目光，在反光玻璃上交错了。"}, {"s": 84.84, "e": 85.84, "t": "不到 1 秒。"}, {"s": 85.84, "e": 87.42, "t": "他低下头，继续写字了。"}, {"s": 87.42, "e": 89.14, "t": "我也低下头，假装在看书。"}, {"s": 89.14, "e": 90.28, "t": "心跳快得不像话。"}, {"s": 90.28, "e": 92.86, "t": "但那 1 秒里——我看见他的眼睛了。"}, {"s": 92.86, "e": 95.59, "t": "不是隔着 5 米的轮廓，是真的看见了。"}, {"s": 95.59, "e": 96.02, "t": "很亮。"}, {"s": 96.02, "e": 97.16, "t": "和第一天一样亮。"}, {"s": 97.16, "e": 100.89, "t": "11 月 7 号那一天，我做了一件自己都没想到的事。"}, {"s": 100.89, "e": 103.75, "t": "早自习结束后，我从教学楼出来，往宿舍走。"}, {"s": 103.75, "e": 106.19, "t": "走到宿舍门口的时候——他站在门口。"}, {"s": 106.19, "e": 106.91, "t": "不是等我。"}, {"s": 106.91, "e": 109.2, "t": "他站在门口看手机，大概是在等谁。"}, {"s": 109.2, "e": 112.64, "t": "我从他旁边经过——准备进门的时候，他抬了一下头。"}, {"s": 112.64, "e": 113.93, "t": "然后他看了我一眼。"}, {"s": 113.93, "e": 116.65, "t": "不是\"不小心扫到\"的那种——是对上了。"}, {"s": 116.65, "e": 117.8, "t": "他看着我的眼睛。"}, {"s": 117.8, "e": 118.8, "t": "大概 3 秒。"}, {"s": 118.8, "e": 120.81, "t": "然后他低下头，继续看手机了。"}, {"s": 120.81, "e": 124.82, "t": "我走进宿舍大门，走到走廊尽头，推开自己那间的门，坐下来。"}, {"s": 124.82, "e": 126.83, "t": "然后我才发现——我的手在抖。"}, {"s": 126.83, "e": 130.84, "t": "我把书包放在床上，坐在床沿上，盯着对面墙上的某一块污渍。"}, {"s": 130.84, "e": 132.56, "t": "然后我在心里说了一句话。"}, {"s": 132.56, "e": 134.85, "t": "说出来的时候，整个房间都安静了。"}, {"s": 134.85, "e": 135.86, "t": "\"我喜欢他。\""}, {"s": 135.86, "e": 136.86, "t": "我用手捂住脸。"}, {"s": 136.86, "e": 137.29, "t": "完了。"}, {"s": 137.29, "e": 138.15, "t": "我在心里说。"}, {"s": 138.15, "e": 138.86, "t": "彻底完了。"}, {"s": 138.86, "e": 142.73, "t": "然后，我又在心里说了一遍——第二遍说得比第一遍更确定："}, {"s": 142.73, "e": 143.74, "t": "\"我喜欢他。\""}, {"s": 143.74, "e": 145.31, "t": "那天晚上我没怎么睡着。"}, {"s": 145.31, "e": 147.89, "t": "不是因为紧张——是因为我终于承认了。"}, {"s": 147.89, "e": 151.19, "t": "10 月底的时候，我在楼梯转角听到他读英文诗。"}, {"s": 151.19, "e": 154.77, "t": "11 月 7 号，我在宿舍门口和他对视了 3 秒。"}, {"s": 154.77, "e": 156.63, "t": "然后我对自己说：我喜欢他。"}, {"s": 156.63, "e": 158.35, "t": "从那天开始，一切都变了。"}, {"s": 158.35, "e": 161.51, "t": "<!-- summary:start -->"}, {"s": 161.51, "e": 162.51, "t": "本章推进线索："}, {"s": 162.51, "e": 171.4, "t": "- 🔵 红笔划一道（F-红笔）——博文每天用红笔在本子上写东西后划一道；埋下全书最大伏笔（后于 Ch 27 揭晓为本子记录）"}, {"s": 171.4, "e": 176.84, "t": "- 🔵 楼梯转角英文诗——博文读英文诗（与 Ch 39 博文的文学气质呼应）"}, {"s": 176.84, "e": 180.42, "t": "- 🔵 第一次 1 秒对视——玻璃反光中的目光交会"}, {"s": 180.42, "e": 185.44, "t": "- 🔵 11/7 宿舍门口 3 秒对视 + 林深第一次承认\"我喜欢他\""}, {"s": 185.44, "e": 186.87, "t": "本章关键事件时间戳："}, {"s": 186.87, "e": 189.88, "t": "- 9月底-10月：观察到红笔划一道的习惯"}, {"s": 189.88, "e": 192.6, "t": "- 10月底某周日：楼梯转角听到英文诗"}, {"s": 192.6, "e": 196.19, "t": "- 11月初某周二：第一次 1 秒对视（玻璃反光）"}, {"s": 196.19, "e": 201.2, "t": "- 11/7（周一）：宿舍门口 3 秒对视，林深第一次承认\"我喜欢他\""}, {"s": 201.2, "e": 202.21, "t": "本章新埋伏笔："}, {"s": 202.21, "e": 205.5, "t": "- F-红笔：博文每天划一道——到底在写什么？"}, {"s": 205.5, "e": 207.22, "t": "（于 Ch 27 揭晓）"}, {"s": 207.22, "e": 207.94, "t": "下章钩子："}, {"s": 207.94, "e": 210.23, "t": "- 承认之后——一切都回不去了。"}, {"s": 210.23, "e": 213.1, "t": "<!-- summary:end -->"}, {"s": 213.1, "e": 218.4, "t": "2026-07-19 初始版本：Ch 3 红笔划一道——暗恋起点与伏笔埋设"}]}, {"num": 4, "title": "第4章 走廊上的守望", "file": "chapters/ch004.mp3", "dur": 374.3, "size_mb": 3.0, "segs": [{"s": 0.0, "e": 3.5, "t": "时间：11 月 8 日—16 日 · 高一上"}, {"s": 3.5, "e": 7.01, "t": "11 月 7 号那天晚上，我在宿舍想了一夜。"}, {"s": 7.01, "e": 11.31, "t": "不是刻意想——是闭上眼睛之后，那个画面就一直浮在眼前。"}, {"s": 11.31, "e": 14.49, "t": "宿舍门口，他看着我的那个眼神——3 秒。"}, {"s": 14.49, "e": 20.71, "t": "他一定看见了我的表情，看见了我愣住的样子，看见了我移开目光之前那一瞬间的慌张。"}, {"s": 20.71, "e": 22.94, "t": "我翻了个身，把被子拉到下巴。"}, {"s": 22.94, "e": 24.05, "t": "宿舍里很安静。"}, {"s": 24.05, "e": 26.92, "t": "上铺的周海已经睡着了，呼吸声很均匀。"}, {"s": 26.92, "e": 31.54, "t": "对面床的人不知道在梦里嘟囔了一句什么，翻了个身，又安静了。"}, {"s": 31.54, "e": 33.13, "t": "我睁着眼睛看天花板。"}, {"s": 33.13, "e": 35.2, "t": "那一刻我对自己说：你完了。"}, {"s": 35.2, "e": 37.43, "t": "你知道\"完了\"是什么意思吗？"}, {"s": 37.43, "e": 38.23, "t": "不是害怕。"}, {"s": 38.23, "e": 45.55, "t": "是终于承认了——你每天站在走廊上，不是为了吹风，不是为了背书，不是为了任何你对自己编的理由。"}, {"s": 45.55, "e": 46.83, "t": "你就是为了看他。"}, {"s": 46.83, "e": 49.85, "t": "这个念头说出来之后，反而没那么可怕了。"}, {"s": 49.85, "e": 52.24, "t": "可怕的是——我接下来该怎么办？"}, {"s": 52.24, "e": 55.91, "t": "第二天早上，我站在走廊上的时候，感觉不一样了。"}, {"s": 55.91, "e": 61.48, "t": "以前我站在这里，心里是空的——我就是站着，看着对面，脑子里什么都不想。"}, {"s": 61.48, "e": 63.23, "t": "但现在我心里有东西了。"}, {"s": 63.23, "e": 67.53, "t": "一层薄薄的、透明的、说不清的东西——像窗户上那层反光。"}, {"s": 67.53, "e": 69.92, "t": "我知道它在那里，但我不想戳破。"}, {"s": 69.92, "e": 73.43, "t": "我站在窗边，手里拿着英语课本，假装在背单词。"}, {"s": 73.43, "e": 78.36, "t": "对面 610 班的窗户开着——他坐在最后一排，低着头在写什么。"}, {"s": 78.36, "e": 81.87, "t": "从我这个角度，只能看到他的头顶和肩膀的轮廓。"}, {"s": 81.87, "e": 84.1, "t": "他今天穿了一件深蓝色的外套。"}, {"s": 84.1, "e": 87.28, "t": "不是校服，是那种拉链开到一半的抓绒外套。"}, {"s": 87.28, "e": 89.83, "t": "我之前从来没注意过他穿什么衣服。"}, {"s": 89.83, "e": 91.27, "t": "现在我开始注意了。"}, {"s": 91.27, "e": 93.81, "t": "连续几天，我都在观察同一个细节。"}, {"s": 93.81, "e": 94.61, "t": "他的窗户。"}, {"s": 94.61, "e": 97.96, "t": "高一的教室朝南，上午的阳光会从窗户照进去。"}, {"s": 97.96, "e": 102.41, "t": "610 班那扇窗户——他那扇——有时候开着，有时候关着。"}, {"s": 102.41, "e": 103.85, "t": "我发现了一个规律。"}, {"s": 103.85, "e": 106.72, "t": "早自习的时候，他的窗户通常是关着的。"}, {"s": 106.72, "e": 110.86, "t": "但到了大课间——大概九点半到十点之间——窗户会打开。"}, {"s": 110.86, "e": 111.81, "t": "是他开的吗？"}, {"s": 111.81, "e": 112.77, "t": "我开始留意。"}, {"s": 112.77, "e": 118.82, "t": "有一次我特地在大课间的时候站到走廊上——刚好看见他站起来，伸手把窗户往外推。"}, {"s": 118.82, "e": 121.37, "t": "动作很随意，像顺手做的一件小事。"}, {"s": 121.37, "e": 123.76, "t": "他推完窗户之后没有马上坐回去。"}, {"s": 123.76, "e": 127.26, "t": "他站在窗户前面站了两三秒——朝窗外看了一眼。"}, {"s": 127.26, "e": 129.01, "t": "看的方向——是这栋楼。"}, {"s": 129.01, "e": 130.13, "t": "是我站的位置。"}, {"s": 130.13, "e": 133.31, "t": "我下意识往后退了半步，心脏猛地跳了一下。"}, {"s": 133.31, "e": 137.3, "t": "但他没有停留——他看了一眼，然后低下头，转回去了。"}, {"s": 137.3, "e": 139.05, "t": "我不知道他看到了什么。"}, {"s": 139.05, "e": 142.23, "t": "但我知道——他推开窗户的时候，没有犹豫。"}, {"s": 142.23, "e": 145.1, "t": "之后的一个星期，我开始记录他的窗户。"}, {"s": 145.1, "e": 149.24, "t": "周一：早自习关，大课间开，午休关，下午开，晚自习关。"}, {"s": 149.24, "e": 150.83, "t": "周二：一整天都关着。"}, {"s": 150.83, "e": 153.7, "t": "周三：早自习关，大课间开了一整节课。"}, {"s": 153.7, "e": 154.66, "t": "周四：全开。"}, {"s": 154.66, "e": 155.61, "t": "周五：全开。"}, {"s": 155.61, "e": 157.52, "t": "我不知道为什么记录这些。"}, {"s": 157.52, "e": 159.75, "t": "我也没打算用这些数据做什么。"}, {"s": 159.75, "e": 165.49, "t": "但我就是会注意到——看到那扇窗户开着的时候，心里会有一点点说不清的踏实。"}, {"s": 165.49, "e": 166.28, "t": "好像他在。"}, {"s": 166.28, "e": 168.83, "t": "好像那扇窗户是他给我的一个信号。"}, {"s": 168.83, "e": 172.18, "t": "虽然我知道——他推开窗户，只是因为教室闷。"}, {"s": 172.18, "e": 173.29, "t": "跟我没有关系。"}, {"s": 173.29, "e": 176.8, "t": "但每次看到那扇窗户开着，我还是会多站一会儿。"}, {"s": 176.8, "e": 179.82, "t": "有一天午休，我又绕到教学楼后面那条路。"}, {"s": 179.82, "e": 185.08, "t": "十一月的梧桐树已经秃了大半，落叶在地上铺了厚厚一层，踩上去沙沙响。"}, {"s": 185.08, "e": 188.74, "t": "我从树后面走过的时候，习惯性地抬头看他的窗户。"}, {"s": 188.74, "e": 189.86, "t": "然后我停住了。"}, {"s": 189.86, "e": 191.13, "t": "他站在窗户边上。"}, {"s": 191.13, "e": 199.1, "t": "不是那种\"走过来看看窗外\"的站法——他是靠在窗沿上，一只手撑着窗台，另一只手里拿着一本书，低头在看。"}, {"s": 199.1, "e": 202.92, "t": "阳光从他身后照过来，把他的影子投在走廊的地面上。"}, {"s": 202.92, "e": 208.81, "t": "那个画面很安静——安静到我站在树下看了大概十秒，才想起来自己不该看这么久。"}, {"s": 208.81, "e": 211.2, "t": "就在我准备低头走过去的时候——"}, {"s": 211.2, "e": 212.32, "t": "他抬了一下头。"}, {"s": 212.32, "e": 216.62, "t": "不是刻意的抬头——是看书看久了，活动一下脖子那种抬头。"}, {"s": 216.62, "e": 218.37, "t": "但他的目光落向了这边。"}, {"s": 218.37, "e": 220.28, "t": "落在教学楼后面这条路上。"}, {"s": 220.28, "e": 222.51, "t": "落在我站的那棵梧桐树的方向。"}, {"s": 222.51, "e": 223.78, "t": "我整个人僵住了。"}, {"s": 223.78, "e": 224.42, "t": "他没动。"}, {"s": 224.42, "e": 225.22, "t": "我也没动。"}, {"s": 225.22, "e": 230.31, "t": "隔着大概七八米，隔着十一月的冷空气和满地落叶，他就那么看向这边。"}, {"s": 230.31, "e": 232.38, "t": "然后他低下头，继续看书了。"}, {"s": 232.38, "e": 234.14, "t": "整个过程大概 3 秒。"}, {"s": 234.14, "e": 237.16, "t": "我站在树后面，心跳快得像刚跑完八百米。"}, {"s": 237.16, "e": 238.28, "t": "他看见我了吗？"}, {"s": 238.28, "e": 239.07, "t": "我不知道。"}, {"s": 239.07, "e": 241.78, "t": "但那 3 秒里——我觉得他在看我。"}, {"s": 241.78, "e": 245.13, "t": "回到教室之后，我坐在座位上，盯着桌面发呆。"}, {"s": 245.13, "e": 247.68, "t": "周海从外面进来，手里端着一杯水。"}, {"s": 247.68, "e": 250.7, "t": "他路过我座位的时候停下来，看了我一眼。"}, {"s": 250.7, "e": 252.61, "t": "\"你又去后面那条路了？\""}, {"s": 252.61, "e": 253.57, "t": "\"……嗯。\""}, {"s": 253.57, "e": 254.52, "t": "他不说话了。"}, {"s": 254.52, "e": 256.59, "t": "但他坐下来之前，说了一句："}, {"s": 256.59, "e": 259.62, "t": "\"你最近走那条路的次数是不是有点多？\""}, {"s": 259.62, "e": 260.42, "t": "我没回答。"}, {"s": 260.42, "e": 261.37, "t": "他也等回答。"}, {"s": 261.37, "e": 264.24, "t": "但他说完之后，喝了一口水，补了一句："}, {"s": 264.24, "e": 265.35, "t": "\"我不问了。\""}, {"s": 265.35, "e": 266.47, "t": "他确实没问了。"}, {"s": 266.47, "e": 270.45, "t": "但我心里清楚——他能看出来的事情，别人也能看出来。"}, {"s": 270.45, "e": 272.2, "t": "还好那条路没什么人走。"}, {"s": 272.2, "e": 273.8, "t": "还好那棵梧桐树够大。"}, {"s": 273.8, "e": 276.19, "t": "还好——他没有问我为什么脸红。"}, {"s": 276.19, "e": 277.94, "t": "晚上我在床上想了很久。"}, {"s": 277.94, "e": 281.44, "t": "我想的是：如果他真的看见我了——那又怎么样？"}, {"s": 281.44, "e": 288.93, "t": "他看见一个 611 班的人，每天走教学楼后面的小路，经过他窗户下面的时候抬头看——他会怎么想？"}, {"s": 288.93, "e": 290.36, "t": "我想了十几种可能。"}, {"s": 290.36, "e": 292.91, "t": "最坏的一种是：他根本没注意到我。"}, {"s": 292.91, "e": 296.25, "t": "一切——窗户、抬头、看过来——都只是巧合。"}, {"s": 296.25, "e": 299.6, "t": "最好的一种是：他知道我在看他，但他不介意。"}, {"s": 299.6, "e": 301.67, "t": "我不知道哪一个更接近真相。"}, {"s": 301.67, "e": 305.01, "t": "但那天晚上我入睡之前，脑子里浮出一个念头："}, {"s": 305.01, "e": 307.4, "t": "明天早上，我还要站到走廊上去。"}, {"s": 307.4, "e": 308.52, "t": "不是为了什么。"}, {"s": 308.52, "e": 309.47, "t": "就是习惯了。"}, {"s": 309.47, "e": 312.98, "t": "<!-- summary:start -->"}, {"s": 312.98, "e": 314.09, "t": "本章推进线索："}, {"s": 314.09, "e": 318.71, "t": "- 🔵 林深第一次对自己承认\"完了\"——接受喜欢博文的事实"}, {"s": 318.71, "e": 323.97, "t": "- 🔵 从\"被动观察\"到\"主动记录\"——开始记录博文窗户的开关规律"}, {"s": 323.97, "e": 329.86, "t": "- 🔵 博文的行为模式显现：大课间开窗、站在窗边看书时偶望向 611 方向"}, {"s": 329.86, "e": 336.39, "t": "- 🔵 第一次在\"那条路\"（教学楼后面）被博文\"看见\"——虽然不确定是否真的被看见"}, {"s": 336.39, "e": 341.01, "t": "- 🔵 周海第二次点破（\"你走那条路的次数是不是有点多\"）"}, {"s": 341.01, "e": 342.6, "t": "本章关键事件时间戳："}, {"s": 342.6, "e": 346.27, "t": "- 11/8-11/16：走廊守望成为固定习惯"}, {"s": 346.27, "e": 351.36, "t": "- 某一天午休：梧桐树下，博文站在窗边看书，抬头看向这边——3秒"}, {"s": 351.36, "e": 352.48, "t": "本章新埋伏笔："}, {"s": 352.48, "e": 356.3, "t": "- F-窗户开关：博文窗户的规律是否暗示了什么？"}, {"s": 356.3, "e": 360.92, "t": "- F-那条路：教学楼后面的小路，以后会成为林深的固定路径"}, {"s": 360.92, "e": 361.72, "t": "下章钩子："}, {"s": 361.72, "e": 364.42, "t": "- 如果窗户会说话——它在说什么？"}, {"s": 364.42, "e": 367.61, "t": "<!-- summary:end -->"}, {"s": 367.61, "e": 374.3, "t": "2026-07-19 初始版本：Ch 4 走廊上的守望——观察从无意识进入有意识阶段"}]}, {"num": 5, "title": "第5章 不算巧合", "file": "chapters/ch005.mp3", "dur": 353.0, "size_mb": 2.8, "segs": [{"s": 0.0, "e": 3.62, "t": "时间：11 月 17 日—23 日 · 高一上"}, {"s": 3.62, "e": 5.66, "t": "周三那天，我发现了一件事。"}, {"s": 5.66, "e": 8.65, "t": "他的窗户——从那天之后，再也没有关过。"}, {"s": 8.65, "e": 9.91, "t": "我说的是大课间。"}, {"s": 9.91, "e": 12.9, "t": "以前他偶尔会关，偶尔会开，没什么规律。"}, {"s": 12.9, "e": 16.36, "t": "但从上周开始，每天大课间那扇窗户一定是开的。"}, {"s": 16.36, "e": 19.51, "t": "不是开到最大——是推开大概一巴掌宽的缝。"}, {"s": 19.51, "e": 25.01, "t": "我从走廊上走过去的时候，刚好能透过那一条缝，看到他放在桌角的透明水杯。"}, {"s": 25.01, "e": 27.06, "t": "我开始觉得——这不算巧合。"}, {"s": 27.06, "e": 30.83, "t": "但我对自己说：你只是注意到了别人没注意到的细节。"}, {"s": 30.83, "e": 31.78, "t": "不代表什么。"}, {"s": 31.78, "e": 33.66, "t": "周四下午最后一节自习课。"}, {"s": 33.66, "e": 36.81, "t": "我坐在位置上，手里转着笔，盯着窗外发呆。"}, {"s": 36.81, "e": 39.01, "t": "对面 610 班的窗户开着。"}, {"s": 39.01, "e": 41.69, "t": "他不在座位上——大概是去上厕所了。"}, {"s": 41.69, "e": 46.41, "t": "桌上摊着一本书，风从窗户吹进去，把书页吹得哗啦哗啦翻了几页。"}, {"s": 46.41, "e": 49.08, "t": "然后我看见了一个人走到他座位旁边。"}, {"s": 49.08, "e": 50.65, "t": "是隔壁班的一个男生。"}, {"s": 50.65, "e": 55.53, "t": "那人弯腰看了看他桌上的书，然后伸手拿了起来——像是在翻看什么。"}, {"s": 55.53, "e": 57.73, "t": "就在这时，博文从后门进来了。"}, {"s": 57.73, "e": 61.51, "t": "他看见那个人在翻他的书，没有发火，也没有说什么。"}, {"s": 61.51, "e": 65.6, "t": "他只是走过去，把书从那人手里拿回来，合上，放回桌上。"}, {"s": 65.6, "e": 66.38, "t": "动作很平。"}, {"s": 66.38, "e": 71.26, "t": "但那个拿书的男生愣了一下，然后笑了一下，拍了拍他的肩膀，走了。"}, {"s": 71.26, "e": 73.15, "t": "整个过程不到 15 秒。"}, {"s": 73.15, "e": 77.08, "t": "我坐在窗户这边，隔着 5 米的天井，看得清清楚楚。"}, {"s": 77.08, "e": 79.28, "t": "他拿回书的时候——表情没变。"}, {"s": 79.28, "e": 82.43, "t": "没有生气，没有不耐烦，甚至没有多余的话。"}, {"s": 82.43, "e": 85.1, "t": "就像他只是在做一件理所当然的事情。"}, {"s": 85.1, "e": 86.68, "t": "我觉得那个动作很帅。"}, {"s": 86.68, "e": 88.25, "t": "但我没敢继续想下去。"}, {"s": 88.25, "e": 90.3, "t": "周五早上，我去食堂吃早餐。"}, {"s": 90.3, "e": 92.34, "t": "七点不到，食堂里人还不多。"}, {"s": 92.34, "e": 95.01, "t": "我端着粥找位子的时候——看见了他。"}, {"s": 95.01, "e": 100.99, "t": "他坐在靠墙的位置，面前放着一碗白粥和一碟咸菜，手里拿着一本书，一边吃一边看。"}, {"s": 100.99, "e": 102.57, "t": "他吃东西的速度很慢。"}, {"s": 102.57, "e": 106.34, "t": "舀一勺粥，吹一下，送进嘴里，放下勺子，翻一页书。"}, {"s": 106.34, "e": 109.49, "t": "我端着托盘站在打饭窗口旁边，犹豫了两秒。"}, {"s": 109.49, "e": 112.63, "t": "然后我选了一个离他三张桌子的位置坐下来。"}, {"s": 112.63, "e": 115.62, "t": "不是故意的——至少我是这么告诉自己的。"}, {"s": 115.62, "e": 117.98, "t": "只是因为那个位置靠窗，光线好。"}, {"s": 117.98, "e": 121.13, "t": "我低头喝粥的时候，余光一直往那个方向飘。"}, {"s": 121.13, "e": 121.91, "t": "他没抬头。"}, {"s": 121.91, "e": 122.86, "t": "一直在看书。"}, {"s": 122.86, "e": 125.37, "t": "但有一瞬间——他的动作停了一下。"}, {"s": 125.37, "e": 129.78, "t": "没有抬头，没有转向我——但他在翻页的那一瞬间，停了一下。"}, {"s": 129.78, "e": 130.88, "t": "像在想什么事。"}, {"s": 130.88, "e": 132.3, "t": "然后他继续翻页了。"}, {"s": 132.3, "e": 133.71, "t": "我低头喝了一口粥。"}, {"s": 133.71, "e": 134.18, "t": "甜的。"}, {"s": 134.18, "e": 136.54, "t": "大概是今天食堂的师傅多放了糖。"}, {"s": 136.54, "e": 137.8, "t": "周六没有晚自习。"}, {"s": 137.8, "e": 141.89, "t": "我在宿舍待了一晚上，躺在床上刷手机，什么也没刷进去。"}, {"s": 141.89, "e": 143.78, "t": "脑子里一直转着一个念头。"}, {"s": 143.78, "e": 144.72, "t": "明天是周日。"}, {"s": 144.72, "e": 146.14, "t": "周日晚上有晚自习。"}, {"s": 146.14, "e": 147.4, "t": "他会上晚自习吗？"}, {"s": 147.4, "e": 148.97, "t": "他周末会留在学校吗？"}, {"s": 148.97, "e": 152.12, "t": "他——坐的那个位置，周日晚上能看到他吗？"}, {"s": 152.12, "e": 154.63, "t": "我把手机翻了个面，扣在枕头旁边。"}, {"s": 154.63, "e": 155.89, "t": "我到底在想什么。"}, {"s": 155.89, "e": 158.41, "t": "周日晚上，我提前十分钟到了教室。"}, {"s": 158.41, "e": 163.44, "t": "教室里的灯全亮着，大部分人都到了——周末回家的同学也陆续回来了。"}, {"s": 163.44, "e": 167.06, "t": "空气里有一股从外面带进来的凉意和食堂的饭菜味。"}, {"s": 167.06, "e": 168.95, "t": "我坐下来，拿出物理作业。"}, {"s": 168.95, "e": 170.52, "t": "然后往窗外看了一眼。"}, {"s": 170.52, "e": 172.1, "t": "610 班的灯亮着。"}, {"s": 172.1, "e": 172.57, "t": "他在。"}, {"s": 172.57, "e": 175.08, "t": "坐在最后一排，低着头，在写什么。"}, {"s": 175.08, "e": 177.92, "t": "窗户开着——和上周一样，推开一条缝。"}, {"s": 177.92, "e": 182.16, "t": "我看见他写了一会儿，停下来，拿起桌角的杯子喝了一口水。"}, {"s": 182.16, "e": 184.84, "t": "放下杯子之后——他往窗外看了一眼。"}, {"s": 184.84, "e": 189.87, "t": "不是刻意的——他就是写完了一道题，休息一下目光，往旁边看了一眼。"}, {"s": 189.87, "e": 191.76, "t": "但他看的方向——是这边。"}, {"s": 191.76, "e": 193.33, "t": "是我这扇窗户的方向。"}, {"s": 193.33, "e": 195.22, "t": "然后他低下头，继续写了。"}, {"s": 195.22, "e": 197.42, "t": "我握着笔，手心出了一层薄汗。"}, {"s": 197.42, "e": 198.52, "t": "他的窗户开着。"}, {"s": 198.52, "e": 199.94, "t": "他的杯子放在桌角。"}, {"s": 199.94, "e": 202.3, "t": "他写完题之后，往这边看了一眼。"}, {"s": 202.3, "e": 203.56, "t": "这些都不算巧合。"}, {"s": 203.56, "e": 205.6, "t": "但它们加起来——能算什么？"}, {"s": 205.6, "e": 206.55, "t": "我说不上来。"}, {"s": 206.55, "e": 209.69, "t": "但那天晚上我做物理题的时候，效率特别高。"}, {"s": 209.69, "e": 212.84, "t": "好像有什么东西，在我的胸口轻轻推了一下。"}, {"s": 212.84, "e": 215.67, "t": "下晚自习的时候，我背着书包走出教室。"}, {"s": 215.67, "e": 219.13, "t": "走廊上有好几个人，我侧着身子从人群里穿过去。"}, {"s": 219.13, "e": 221.49, "t": "走到楼梯口的时候——我看见了。"}, {"s": 221.49, "e": 222.59, "t": "他走在我前面。"}, {"s": 222.59, "e": 224.16, "t": "大概隔了五六级台阶。"}, {"s": 224.16, "e": 227.31, "t": "单肩背着书包，手里拿着那本透明封面的书。"}, {"s": 227.31, "e": 229.04, "t": "他走路的步子不快不慢。"}, {"s": 229.04, "e": 231.09, "t": "我跟在后面，隔着那段距离。"}, {"s": 231.09, "e": 232.82, "t": "没有加快，也没有放慢。"}, {"s": 232.82, "e": 238.32, "t": "楼梯间的灯光把他的影子投在墙上——他的头发在灯光下看起来比白天深一些。"}, {"s": 238.32, "e": 240.52, "t": "走到一楼的时候，他往左拐了。"}, {"s": 240.52, "e": 241.47, "t": "宿舍的方向。"}, {"s": 241.47, "e": 242.57, "t": "我也往左拐了。"}, {"s": 242.57, "e": 243.83, "t": "他在前，我在后。"}, {"s": 243.83, "e": 246.5, "t": "路灯把两个人的影子拉向相反的方向。"}, {"s": 246.5, "e": 249.49, "t": "我看见他走到宿舍楼下的时候，停了一下。"}, {"s": 249.49, "e": 253.27, "t": "没回头——他站在那里，把手里的书换到另一只手上。"}, {"s": 253.27, "e": 255.0, "t": "然后他推开门，进去了。"}, {"s": 255.0, "e": 256.73, "t": "我也走到门口，推开门。"}, {"s": 256.73, "e": 262.08, "t": "门还没完全合上——从我前面大概两三米的地方，有一个人正往走廊深处走。"}, {"s": 262.08, "e": 262.55, "t": "是他。"}, {"s": 262.55, "e": 263.33, "t": "他没回头。"}, {"s": 263.33, "e": 266.8, "t": "但我看见他的脚步，比我走进来之前，慢了一些。"}, {"s": 266.8, "e": 267.9, "t": "只是慢了一些。"}, {"s": 267.9, "e": 269.0, "t": "大概慢了两步。"}, {"s": 269.0, "e": 271.51, "t": "然后他拐进走廊尽头，消失在转角。"}, {"s": 271.51, "e": 274.98, "t": "我站在门口，手指搭在门把手上，好一会儿没动。"}, {"s": 274.98, "e": 276.55, "t": "门外是十一月的夜风。"}, {"s": 276.55, "e": 278.75, "t": "门里是走廊尽头那盏昏暗的灯。"}, {"s": 278.75, "e": 280.01, "t": "他走进去的方向。"}, {"s": 280.01, "e": 281.74, "t": "我刚才——不是巧合吧？"}, {"s": 281.74, "e": 285.2, "t": "<!-- summary:start -->"}, {"s": 285.2, "e": 286.3, "t": "本章推进线索："}, {"s": 286.3, "e": 293.54, "t": "- 🔵 博文的行为变化：窗户从\"偶尔开\"变成\"每天大课间必开\"——林深开始注意到这不是随机的"}, {"s": 293.54, "e": 302.5, "t": "- 🔵 小细节积累：有人翻博文的书→他平静地拿回来、食堂翻页时停顿、写完题往 611 方向看一眼、宿舍楼下脚步放慢"}, {"s": 302.5, "e": 309.9, "t": "- 🔵 林深心态转变：从\"这些都是巧合\"到\"这些不算巧合了\"——首次敢于质疑自己的\"巧合解释\""}, {"s": 309.9, "e": 311.47, "t": "本章关键事件时间戳："}, {"s": 311.47, "e": 316.19, "t": "- 周四下午：林深看见博文平静地拿回被人翻的书——心动的细节"}, {"s": 316.19, "e": 319.97, "t": "- 周五早上：食堂偶遇（林深选了三张桌子的距离）"}, {"s": 319.97, "e": 323.9, "t": "- 周日晚上：博文写完题后往 611 方向看了一眼"}, {"s": 323.9, "e": 328.62, "t": "- 周日晚自习后：宿舍楼下，博文放慢了脚步（不确定是否刻意）"}, {"s": 328.62, "e": 329.72, "t": "本章新埋伏笔："}, {"s": 329.72, "e": 335.07, "t": "- F-脚步放慢：宿舍楼门口，博文的脚步变化——是否意识到身后有人？"}, {"s": 335.07, "e": 335.85, "t": "下章钩子："}, {"s": 335.85, "e": 343.72, "t": "- 那些\"不算巧合\"的细节，在某一个瞬间，会变成确定的信号——但不是通过窗户或脚步，而是通过一个表情"}, {"s": 343.72, "e": 346.86, "t": "<!-- summary:end -->"}, {"s": 346.86, "e": 353.0, "t": "2026-07-19 初始版本：Ch 5 不算巧合——博文的反应开始被林深捕捉"}]}, {"num": 6, "title": "第6章 嘴角一动", "file": "chapters/ch006.mp3", "dur": 145.2, "size_mb": 1.2, "segs": [{"s": 0.0, "e": 3.1, "t": "时间：11 月 24 日—26 日 · 高一上"}, {"s": 3.1, "e": 5.52, "t": "11 月 24 号那天发生了一件事。"}, {"s": 5.52, "e": 5.93, "t": "不大。"}, {"s": 5.93, "e": 6.87, "t": "但我记了三天。"}, {"s": 6.87, "e": 8.62, "t": "下午大课间，我站在走廊上。"}, {"s": 8.62, "e": 12.66, "t": "他在对面 610 班的窗户里面——侧着身，正在和同桌说什么。"}, {"s": 12.66, "e": 18.72, "t": "他说话的时候，嘴角动了一下——不是笑，是那种说到一半、因为某个词而微微往上翘了一点的弧度。"}, {"s": 18.72, "e": 19.4, "t": "不到一秒。"}, {"s": 19.4, "e": 20.74, "t": "然后他继续说下去了。"}, {"s": 20.74, "e": 23.3, "t": "我站在走廊上，把那个画面定格在脑子里。"}, {"s": 23.3, "e": 26.67, "t": "回到教室之后，我坐在座位上，在草稿纸上写了一行字："}, {"s": 26.67, "e": 29.09, "t": "\"他今天说话的时候，嘴角动了一下。\""}, {"s": 29.09, "e": 30.84, "t": "写完之后我看着那行字发呆。"}, {"s": 30.84, "e": 32.33, "t": "然后我在下面补了一句："}, {"s": 32.33, "e": 33.54, "t": "\"我是不是完了。\""}, {"s": 33.54, "e": 34.89, "t": "没有主语，没有标点。"}, {"s": 34.89, "e": 36.23, "t": "但我知道我在说什么。"}, {"s": 36.23, "e": 37.58, "t": "11 月 25 号。"}, {"s": 37.58, "e": 40.81, "t": "大课间的时候，我看到他和一个女生站在走廊上说话。"}, {"s": 40.81, "e": 45.8, "t": "不是普通的说话——那个女生站在他对面，手里拿着一本书，好像在问他什么问题。"}, {"s": 45.8, "e": 49.43, "t": "他低头看了一眼那本书，然后说了几句——她笑着点了点头。"}, {"s": 49.43, "e": 50.78, "t": "整个过程大概两分钟。"}, {"s": 50.78, "e": 54.28, "t": "我站在 611 班的走廊转角，隔着天井看到了这一幕。"}, {"s": 54.28, "e": 57.65, "t": "然后我走回教室，坐下来，发现刚才背的单词全都忘了。"}, {"s": 57.65, "e": 58.86, "t": "不是因为那个女生。"}, {"s": 58.86, "e": 62.77, "t": "是因为——他给别人讲题的时候，也会那样侧过头、微微低头吗？"}, {"s": 62.77, "e": 63.17, "t": "会的。"}, {"s": 63.17, "e": 63.84, "t": "他当然会。"}, {"s": 63.84, "e": 66.27, "t": "但我看到的时候，心里还是咯噔了一下。"}, {"s": 66.27, "e": 67.62, "t": "11 月 26 号。"}, {"s": 67.62, "e": 68.16, "t": "降温了。"}, {"s": 68.16, "e": 68.96, "t": "零下十二度。"}, {"s": 68.96, "e": 72.06, "t": "早自习的时候我站在教室门口，呼出的气全是白雾。"}, {"s": 72.06, "e": 74.49, "t": "我往窗外看了一眼——窗户上全是霜雾。"}, {"s": 74.49, "e": 76.91, "t": "反光玻璃变成了毛玻璃，什么都看不见。"}, {"s": 76.91, "e": 80.95, "t": "他的窗户，我的窗户，中间那片天井——全部被白色的霜雾遮住了。"}, {"s": 80.95, "e": 82.84, "t": "我站了一会儿，然后回座位了。"}, {"s": 82.84, "e": 84.05, "t": "那天我没有看到他。"}, {"s": 84.05, "e": 84.99, "t": "一整天都没有。"}, {"s": 84.99, "e": 87.55, "t": "不是因为他不在——是因为什么都看不见。"}, {"s": 87.55, "e": 90.92, "t": "零下十二度的天气，把唯一能看到他的那扇窗户封住了。"}, {"s": 90.92, "e": 95.36, "t": "晚自习的时候，我坐在座位上，看着那片被霜雾封住的玻璃发了一会儿呆。"}, {"s": 95.36, "e": 96.98, "t": "然后我拿起笔，继续做题。"}, {"s": 96.98, "e": 99.27, "t": "但我心里知道——我今天没有看到他。"}, {"s": 99.27, "e": 101.16, "t": "而这件事，比零下十二度还冷。"}, {"s": 101.16, "e": 104.12, "t": "<!-- summary:start -->"}, {"s": 104.12, "e": 105.06, "t": "本章推进线索："}, {"s": 105.06, "e": 111.8, "t": "- 🔵 \"嘴角一动\"——博文说话时嘴角微翘的弧度，被林深捕捉并记住（后于 Ch 12 再次出现确认）"}, {"s": 111.8, "e": 115.43, "t": "- 🔵 \"我读书是为了看他\"——未明写但暗含的自我确认"}, {"s": 115.43, "e": 119.74, "t": "- 🔵 陌生女生出现——11/25 大课间，触发林深心里\"咯噔\""}, {"s": 119.74, "e": 124.59, "t": "- 🔵 11/26 降温零下十二度，反光玻璃结霜——物理上的阻隔意象强化"}, {"s": 124.59, "e": 125.94, "t": "本章关键事件时间戳："}, {"s": 125.94, "e": 127.82, "t": "- 11/24：博文嘴角一动"}, {"s": 127.82, "e": 130.38, "t": "- 11/25 大课间：博文和女生说话"}, {"s": 130.38, "e": 133.21, "t": "- 11/26：霜雾封窗，一整天没看到博文"}, {"s": 133.21, "e": 133.89, "t": "下章钩子："}, {"s": 133.89, "e": 137.93, "t": "- \"我配不上他\"——这个念头从某一天开始，就再也赶不走了。"}, {"s": 137.93, "e": 140.62, "t": "<!-- summary:end -->"}, {"s": 140.62, "e": 145.2, "t": "2026-07-19 初始版本：Ch 6 嘴角一动——捕捉细节的瞬间"}]}, {"num": 7, "title": "第7章 我配不上他", "file": "chapters/ch007.mp3", "dur": 367.0, "size_mb": 2.9, "segs": [{"s": 0.0, "e": 5.46, "t": "时间：11 月 30 日（周日）— 12 月 3 日（周三）· 高一上"}, {"s": 5.46, "e": 6.87, "t": "周日晚上有晚自习。"}, {"s": 6.87, "e": 12.95, "t": "我坐在靠窗的位置上，面前摊着一本数学练习册——已经做了三页，但脑子里全是乱的。"}, {"s": 12.95, "e": 14.98, "t": "对面的 610 班还有灯。"}, {"s": 14.98, "e": 15.76, "t": "他在不在？"}, {"s": 15.76, "e": 19.19, "t": "我把目光往窗户外移了半寸——没敢转过去太多。"}, {"s": 19.19, "e": 22.16, "t": "余光里，610 班最后一排坐着一个人。"}, {"s": 22.16, "e": 23.56, "t": "低着头，在写什么。"}, {"s": 23.56, "e": 24.03, "t": "博文。"}, {"s": 24.03, "e": 25.43, "t": "他周末也不回家吗？"}, {"s": 25.43, "e": 28.09, "t": "我收回目光，深吸一口气，继续做题。"}, {"s": 28.09, "e": 28.87, "t": "\"林深。\""}, {"s": 28.87, "e": 32.92, "t": "第二天大课间，周海从外面跑进来，表情有点神秘兮兮的。"}, {"s": 32.92, "e": 34.17, "t": "\"我打听到了。\""}, {"s": 34.17, "e": 35.26, "t": "\"打听什么？\""}, {"s": 35.26, "e": 36.04, "t": "\"博文。\""}, {"s": 36.04, "e": 37.61, "t": "我手里的笔顿了一下。"}, {"s": 37.61, "e": 41.35, "t": "周海压低了声音：\"我找张尧问的——张尧你记得吧？"}, {"s": 41.35, "e": 45.25, "t": "上次宿舍楼梯口碰见的那个，他说他就住博文家楼下。\""}, {"s": 45.25, "e": 46.34, "t": "\"他怎么说？\""}, {"s": 46.34, "e": 53.52, "t": "\"他说博文初中是一中附的，从初一开始就是年级前五十——不是 top 那种，但一直稳定在上游。"}, {"s": 53.52, "e": 56.33, "t": "数理特别好，尤其物理，班里经常前五。"}, {"s": 56.33, "e": 62.57, "t": "现在是他们班的学习委员，不是学生会主席——张尧说你听错了，是学习委员不是主席。\""}, {"s": 62.57, "e": 65.85, "t": "我心里记下了：学习委员，数理好，一直稳定。"}, {"s": 65.85, "e": 66.78, "t": "\"还有呢？\""}, {"s": 66.78, "e": 73.03, "t": "\"还有——\"周海看了我一眼，\"他说博文的目标是考个重点一本，一本线往上走的那种。"}, {"s": 73.03, "e": 75.68, "t": "不是清北，就是稳扎稳打的好一本。\""}, {"s": 75.68, "e": 79.89, "t": "我不知道为什么——听到这句话的时候，我反而松了一口气。"}, {"s": 79.89, "e": 80.67, "t": "不是清北。"}, {"s": 80.67, "e": 83.48, "t": "那是不是说明我还有一点点追上的可能？"}, {"s": 83.48, "e": 85.66, "t": "然后我又被自己的想法逗笑了。"}, {"s": 85.66, "e": 86.44, "t": "追什么追。"}, {"s": 86.44, "e": 88.01, "t": "我连他的班都还没进。"}, {"s": 88.01, "e": 91.59, "t": "这句话是周三午休的时候，突然从脑子里冒出来的。"}, {"s": 91.59, "e": 93.15, "t": "我们刚考完数学周测。"}, {"s": 93.15, "e": 95.81, "t": "我翻开答题卡看了一眼——78 分。"}, {"s": 95.81, "e": 96.28, "t": "78。"}, {"s": 96.28, "e": 97.99, "t": "班里的平均分是 85。"}, {"s": 97.99, "e": 100.64, "t": "我闭上眼，脑子里浮现出博文的身影。"}, {"s": 100.64, "e": 105.64, "t": "他侧身坐着，拿笔在卷子上勾画——我甚至不用去问就知道他能考多少。"}, {"s": 105.64, "e": 106.26, "t": "130？"}, {"s": 106.26, "e": 106.89, "t": "140？"}, {"s": 106.89, "e": 108.6, "t": "起码比我高 50 分。"}, {"s": 108.6, "e": 110.79, "t": "我趴在桌上，把脸埋进胳膊里。"}, {"s": 110.79, "e": 114.69, "t": "\"脑子满了就不会想他了\"——这句话是我自己发明的。"}, {"s": 114.69, "e": 127.33, "t": "意思是，如果我每天做 6 道数学题、背 20 个单词，累到脑子转不动了，就不会有闲工夫翻来覆去地想他在干什么、他今天有没有往窗外看、他走路的时候为什么从来不回头。"}, {"s": 127.33, "e": 129.98, "t": "但事实证明，脑子满了，心还是空的。"}, {"s": 129.98, "e": 133.1, "t": "我站在走廊上——那个我每天都会站的位置。"}, {"s": 133.1, "e": 134.82, "t": "不是故意的，是走惯了。"}, {"s": 134.82, "e": 136.38, "t": "然后我看见了一件事。"}, {"s": 136.38, "e": 140.28, "t": "610 班的窗户——博文那一扇——从里面被推开了。"}, {"s": 140.28, "e": 140.75, "t": "是他。"}, {"s": 140.75, "e": 144.33, "t": "他站起来，把手伸到窗沿，把窗户往外推开了一点。"}, {"s": 144.33, "e": 149.02, "t": "然后他没有马上坐回去，而是站在窗户边上，抬头往外面看了一眼。"}, {"s": 149.02, "e": 150.11, "t": "往我这个方向。"}, {"s": 150.11, "e": 152.45, "t": "我后退了半步，心猛地跳了一下。"}, {"s": 152.45, "e": 153.23, "t": "——不对。"}, {"s": 153.23, "e": 156.04, "t": "隔着 5 米的天井，他不可能看清我。"}, {"s": 156.04, "e": 157.6, "t": "他只是刚好看向这边。"}, {"s": 157.6, "e": 158.38, "t": "只是刚好。"}, {"s": 158.38, "e": 161.65, "t": "但我还是在他收回目光之前，看到了他的侧脸。"}, {"s": 161.65, "e": 165.56, "t": "阳光落在他的鼻梁上，他眯了一下眼——然后坐回去了。"}, {"s": 165.56, "e": 166.34, "t": "窗户没关。"}, {"s": 166.34, "e": 168.52, "t": "12 月的冷风——他开着窗。"}, {"s": 168.52, "e": 173.2, "t": "我看着那扇敞开的窗户，心里有一个念头，不敢承认，但一直在冒："}, {"s": 173.2, "e": 175.07, "t": "他是不是……也在看这边？"}, {"s": 175.07, "e": 178.51, "t": "我站在教室门口，手里端着水杯，正要转身进去。"}, {"s": 178.51, "e": 179.6, "t": "然后我看见了。"}, {"s": 179.6, "e": 183.03, "t": "对面六楼，610 班的窗户——博文抬起了头。"}, {"s": 183.03, "e": 187.24, "t": "不是一时抬头——他抬起来之后，往窗外看了一下，停住了。"}, {"s": 187.24, "e": 188.65, "t": "他就那么看着这边。"}, {"s": 188.65, "e": 190.05, "t": "看了大概 3 秒。"}, {"s": 190.05, "e": 192.55, "t": "我端着水杯，站在那里，一动不动。"}, {"s": 192.55, "e": 195.2, "t": "不是我故意不动——是我忘了怎么动。"}, {"s": 195.2, "e": 200.2, "t": "我感觉有什么东西在动——不是天井那边的风，是我胸口里的那团东西。"}, {"s": 200.2, "e": 200.82, "t": "它在翻。"}, {"s": 200.82, "e": 202.07, "t": "然后他低下头了。"}, {"s": 202.07, "e": 202.85, "t": "继续看书。"}, {"s": 202.85, "e": 204.57, "t": "像什么都没发生过一样。"}, {"s": 204.57, "e": 205.81, "t": "我做了一个决定。"}, {"s": 205.81, "e": 210.34, "t": "每天 6 道数学题，2 篇英语阅读，睡前背 10 个单词。"}, {"s": 210.34, "e": 213.3, "t": "不是为了考试，是为了能进 610 班。"}, {"s": 213.3, "e": 216.58, "t": "周海听说了之后，歪着头看我：\"你认真的？\""}, {"s": 216.58, "e": 217.52, "t": "\"认真的。\""}, {"s": 217.52, "e": 222.82, "t": "\"下学期分班按成绩——你知不知道 610 班至少要年级前 200？\""}, {"s": 222.82, "e": 223.76, "t": "\"我知道。\""}, {"s": 223.76, "e": 225.16, "t": "\"你现在多少名？\""}, {"s": 225.16, "e": 225.94, "t": "\"不知道。"}, {"s": 225.94, "e": 227.81, "t": "但应该不到前 300。\""}, {"s": 227.81, "e": 228.75, "t": "周海没说话。"}, {"s": 228.75, "e": 230.78, "t": "然后他说：\"那你得拼了。\""}, {"s": 230.78, "e": 232.18, "t": "我说：\"我知道。\""}, {"s": 232.18, "e": 236.71, "t": "那天下午，物理老师发完周测卷子，路过我座位的时候停了一下。"}, {"s": 236.71, "e": 238.89, "t": "\"林深，这次比上次进步了。\""}, {"s": 238.89, "e": 242.64, "t": "我抬头——物理老师没有多说什么，只是点了一下头。"}, {"s": 242.64, "e": 248.41, "t": "旁边化学老师在讲台上也看了我一眼：\"你们班最近几个同学上课精神头不错啊。\""}, {"s": 248.41, "e": 250.28, "t": "他说这句话的时候没看我。"}, {"s": 250.28, "e": 251.69, "t": "但我知道他在说我。"}, {"s": 251.69, "e": 253.4, "t": "被看见的感觉——很暖。"}, {"s": 253.4, "e": 256.84, "t": "晚自习结束我收拾书包的时候，往窗外看了一眼。"}, {"s": 256.84, "e": 259.18, "t": "对面 610 班的灯已经灭了。"}, {"s": 259.18, "e": 262.61, "t": "我背着书包走出教室，走过那条走廊，走下楼梯。"}, {"s": 262.61, "e": 265.11, "t": "走到一楼拐角的时候——我停下了。"}, {"s": 265.11, "e": 270.41, "t": "博文站在宿舍楼门口的灯光下面，单肩背着书包，手里拿着一本书，正在看。"}, {"s": 270.41, "e": 272.44, "t": "他听见脚步声，抬了一下头。"}, {"s": 272.44, "e": 274.63, "t": "看见是我——他好像停了一秒。"}, {"s": 274.63, "e": 276.5, "t": "然后他低头，继续看书了。"}, {"s": 276.5, "e": 280.09, "t": "我走过去，从他身后经过的距离——大概 1 米。"}, {"s": 280.09, "e": 281.65, "t": "我没敢回头看第二眼。"}, {"s": 281.65, "e": 288.51, "t": "但我记住了那个画面：12 月的路灯把他手上的书页照得发白，他的影子斜斜地落在地上，很长。"}, {"s": 288.51, "e": 291.32, "t": "我走进宿舍楼的时候，在心里说了一句："}, {"s": 291.32, "e": 293.19, "t": "我一定要进 610 班。"}, {"s": 293.19, "e": 295.38, "t": "2026-07-19 修复："}, {"s": 295.38, "e": 299.9, "t": "1. 博文定位：学生会主席 → 学习委员（设定圣经已修正）"}, {"s": 299.9, "e": 305.52, "t": "2. 清北目标 → 重点一本目标（配合 2026-07-18 设定更新）"}, {"s": 305.52, "e": 310.67, "t": "3. 数学物理 top → 数理很好，一直稳定（中上水平，非顶尖）"}, {"s": 310.67, "e": 317.85, "t": "4. 林深\"我配不上他\"的压力源：清北差距 → 普通一本差距（78 分 vs 130+ 分）"}, {"s": 317.85, "e": 319.56, "t": "5. 张尧描述保持一致"}, {"s": 319.56, "e": 323.0, "t": "<!-- summary:start -->"}, {"s": 323.0, "e": 324.09, "t": "本章推进线索："}, {"s": 324.09, "e": 333.3, "t": "- POV-LS-配不上：林深第一次感到\"我配不上他\"——以分数差距(78 vs 130+)替代原先的\"清北目标\"差距"}, {"s": 333.3, "e": 339.07, "t": "- F-博文窗户：博文开始主动开窗户，看向对面走廊——全书的第一个双向信号"}, {"s": 339.07, "e": 340.63, "t": "本章关键事件时间戳："}, {"s": 340.63, "e": 344.69, "t": "- 11/30（周日）：周海从张尧处打听到博文的情况"}, {"s": 344.69, "e": 349.52, "t": "- 12/1（周一）：博文第一次主动开窗户 + 站在窗边抬头看"}, {"s": 349.52, "e": 353.74, "t": "- 12/2（周二）：博文抬头对着林深窗户看了 3 秒"}, {"s": 353.74, "e": 358.26, "t": "- 12/3（周三）：林深做出\"每天 6 道数学题\"的决定"}, {"s": 358.26, "e": 359.04, "t": "下章钩子："}, {"s": 359.04, "e": 363.88, "t": "- 林深的分数要多久才能从 78 分涨到进 610 班的水平？"}, {"s": 363.88, "e": 367.0, "t": "<!-- summary:end -->"}]}, {"num": 8, "title": "第8章 分班之誓", "file": "chapters/ch008.mp3", "dur": 347.2, "size_mb": 2.8, "segs": [{"s": 0.0, "e": 3.67, "t": "时间：12 月中旬—次年 1 月 · 高一上期末"}, {"s": 3.67, "e": 7.64, "t": "从 12 月 3 号那天开始，我给自己定了一个规矩。"}, {"s": 7.64, "e": 12.23, "t": "每天 6 道数学大题、2 篇英语阅读、睡前背 10 个单词。"}, {"s": 12.23, "e": 14.68, "t": "不是老师布置的——是我自己加的。"}, {"s": 14.68, "e": 18.19, "t": "周海看见我桌上摊开的练习册，歪着头看了一会儿。"}, {"s": 18.19, "e": 19.26, "t": "\"你认真的？\""}, {"s": 19.26, "e": 20.18, "t": "\"认真的。\""}, {"s": 20.18, "e": 22.63, "t": "\"下学期分班——要前 200。\""}, {"s": 22.63, "e": 23.54, "t": "\"我知道。\""}, {"s": 23.54, "e": 24.77, "t": "\"你现在多少？\""}, {"s": 24.77, "e": 25.53, "t": "\"不知道。"}, {"s": 25.53, "e": 27.21, "t": "应该不到前 300。\""}, {"s": 27.21, "e": 28.44, "t": "他沉默了一会儿。"}, {"s": 28.44, "e": 29.66, "t": "\"那得加把劲。\""}, {"s": 29.66, "e": 31.04, "t": "我说：\"我知道。\""}, {"s": 31.04, "e": 32.87, "t": "那天的对话就这么结束了。"}, {"s": 32.87, "e": 37.76, "t": "但那天晚上我在台灯下面做到第二道数学题的时候，抬头看了一眼窗外。"}, {"s": 37.76, "e": 40.06, "t": "对面 610 班的灯已经灭了。"}, {"s": 40.06, "e": 47.24, "t": "但我脑子里浮现出他坐在最后一排的样子——低头写字，偶尔停下来摸一下后脑勺，偶尔站起来推开窗户。"}, {"s": 47.24, "e": 51.52, "t": "如果我进不了 610 班——下学期我就再也看不到这些了。"}, {"s": 51.52, "e": 52.9, "t": "我低头，继续做题。"}, {"s": 52.9, "e": 55.5, "t": "第三道题的辅助线我画了三遍才画对。"}, {"s": 55.5, "e": 57.79, "t": "那段时间是我高中最拼命的时候。"}, {"s": 57.79, "e": 62.22, "t": "不是那种热血沸腾的拼——就是每天多做一点，每天多熬一会儿。"}, {"s": 62.22, "e": 65.89, "t": "十二月的教室很冷，窗户关紧了风还是从缝里钻进来。"}, {"s": 65.89, "e": 68.65, "t": "我把校服拉链拉到最高，缩着脖子做题。"}, {"s": 68.65, "e": 73.69, "t": "草稿纸用了一张又一张，写到手指发酸的时候就停下来甩两下，然后继续。"}, {"s": 73.69, "e": 76.29, "t": "我没有告诉任何人我为什么要这么拼。"}, {"s": 76.29, "e": 77.82, "t": "但周海大概是猜到了。"}, {"s": 77.82, "e": 81.64, "t": "有一天晚自习结束的时候，他收拾书包，随口说了一句："}, {"s": 81.64, "e": 83.32, "t": "\"你最近不看对面了。\""}, {"s": 83.32, "e": 84.54, "t": "我的手停了一下。"}, {"s": 84.54, "e": 85.62, "t": "\"……是吗？\""}, {"s": 85.62, "e": 88.21, "t": "\"以前你每写两道题就要抬头看一眼。"}, {"s": 88.21, "e": 90.2, "t": "现在你写半节课都不抬头。\""}, {"s": 90.2, "e": 91.58, "t": "我不知道怎么回答。"}, {"s": 91.58, "e": 92.95, "t": "因为他说的是对的。"}, {"s": 92.95, "e": 94.48, "t": "我确实没怎么抬头了。"}, {"s": 94.48, "e": 95.86, "t": "不是因为不想看了。"}, {"s": 95.86, "e": 98.76, "t": "是因为我怕——如果现在看了，就会分心。"}, {"s": 98.76, "e": 100.6, "t": "如果分心了，就考不进去。"}, {"s": 100.6, "e": 103.5, "t": "如果考不进去——下学期就再也看不到了。"}, {"s": 103.5, "e": 104.57, "t": "所以我低着头。"}, {"s": 104.57, "e": 105.8, "t": "一遍一遍地做题。"}, {"s": 105.8, "e": 111.61, "t": "用每一道题的辅助线、每一个公式、每一页草稿纸——来换一个能继续看到他的资格。"}, {"s": 111.61, "e": 114.82, "t": "期末前两周，有一天下午我在楼梯上遇见了他。"}, {"s": 114.82, "e": 120.32, "t": "不是故意的——我从办公室交作业回来，走到三楼拐角的时候，他从上面走下来。"}, {"s": 120.32, "e": 121.85, "t": "大概隔了三四级台阶。"}, {"s": 121.85, "e": 124.29, "t": "我抬头的时候，他刚好走到我面前。"}, {"s": 124.29, "e": 134.84, "t": "那个距离很近——近到我能看见他外套拉链头的反光，近到我能闻到他身上的味道——不是柚子味的那件衣服，是那种干净的、带着一点洗衣粉残留的味道。"}, {"s": 134.84, "e": 135.76, "t": "他看见了我。"}, {"s": 135.76, "e": 137.6, "t": "我的脚步下意识顿了一下。"}, {"s": 137.6, "e": 138.67, "t": "他也顿了一下。"}, {"s": 138.67, "e": 141.11, "t": "然后他侧了一下身子——让我先走。"}, {"s": 141.11, "e": 144.02, "t": "我说了一声\"谢谢\"，声音比我想象中小。"}, {"s": 144.02, "e": 149.06, "t": "他没回答——但我走过他身边的时候，听到他的脚步声在我身后停了一拍。"}, {"s": 149.06, "e": 150.59, "t": "然后才继续往楼下走。"}, {"s": 150.59, "e": 151.51, "t": "我没有回头。"}, {"s": 151.51, "e": 155.64, "t": "但我走到四楼走廊上的时候，靠在墙边站了大概 10 秒。"}, {"s": 155.64, "e": 156.55, "t": "心跳有点快。"}, {"s": 156.55, "e": 163.43, "t": "不是因为碰到他——是因为我发现，即使只是楼梯上擦肩而过的那一瞬间，我都能认得出他的脚步声。"}, {"s": 163.43, "e": 164.96, "t": "这个认知让我有点慌。"}, {"s": 164.96, "e": 167.87, "t": "我加快脚步走回教室，坐下，翻开练习册。"}, {"s": 167.87, "e": 170.31, "t": "做了两道题之后，才慢慢平静下来。"}, {"s": 170.31, "e": 174.29, "t": "期末考最后一天，我写完英语作文的时候，还剩十五分钟。"}, {"s": 174.29, "e": 176.28, "t": "我放下笔，往窗外看了一眼。"}, {"s": 176.28, "e": 179.94, "t": "对面 610 班的窗户开着——但那排座位是空的。"}, {"s": 179.94, "e": 181.47, "t": "他们已经考完交卷了。"}, {"s": 181.47, "e": 185.3, "t": "我看着那扇空荡荡的窗户，心里忽然涌上来一个念头——"}, {"s": 185.3, "e": 188.81, "t": "如果没考好，这就是我最后一次从这个角度看他了。"}, {"s": 188.81, "e": 191.11, "t": "我低下头，把答题卡检查了一遍。"}, {"s": 191.11, "e": 192.94, "t": "交卷的时候，手指是稳的。"}, {"s": 192.94, "e": 195.39, "t": "但走出考场的那一刻，手心全是汗。"}, {"s": 195.39, "e": 197.83, "t": "寒假开始那天，我在宿舍收拾东西。"}, {"s": 197.83, "e": 204.56, "t": "走廊上很多人都在搬行李，有人喊着\"下学期见\"，有人在楼道里拖着行李箱发出咕噜咕噜的声音。"}, {"s": 204.56, "e": 208.53, "t": "我收拾好背包，站在宿舍门口，往教学楼的方向看了一眼。"}, {"s": 208.53, "e": 210.22, "t": "610 班的窗户关着。"}, {"s": 210.22, "e": 212.05, "t": "放假了，整栋楼都是空的。"}, {"s": 212.05, "e": 213.12, "t": "我站了一会儿。"}, {"s": 213.12, "e": 214.5, "t": "然后背上包，走了。"}, {"s": 214.5, "e": 216.94, "t": "走出校门的时候，我回头看了一眼。"}, {"s": 216.94, "e": 218.17, "t": "那扇窗户还关着。"}, {"s": 218.17, "e": 221.99, "t": "但我在心里说了一句话——不是说出来，是在心里说的："}, {"s": 221.99, "e": 224.74, "t": "下学期，我一定要坐在那扇窗户的后面。"}, {"s": 224.74, "e": 225.2, "t": "等着。"}, {"s": 225.2, "e": 227.49, "t": "寒假里的每一天，我都在做卷子。"}, {"s": 227.49, "e": 233.3, "t": "除夕那天晚上，外面在放鞭炮，我妈在客厅看春晚，我坐在书桌前做了一套物理卷子。"}, {"s": 233.3, "e": 234.68, "t": "做完的时候零点了。"}, {"s": 234.68, "e": 238.35, "t": "我放下笔，拿起手机，打开 QQ——他的头像亮着。"}, {"s": 238.35, "e": 238.81, "t": "在线。"}, {"s": 238.81, "e": 241.1, "t": "我盯着那个亮着的头像看了很久。"}, {"s": 241.1, "e": 242.47, "t": "最后发了一条消息："}, {"s": 242.47, "e": 243.54, "t": "\"新年快乐。\""}, {"s": 243.54, "e": 250.42, "t": "发完之后我立刻把手机翻了过去——不知道为什么，发出去的那一瞬间，我突然觉得这条消息好明显。"}, {"s": 250.42, "e": 252.26, "t": "一分钟后，手机震了一下。"}, {"s": 252.26, "e": 253.18, "t": "我拿起来看。"}, {"s": 253.18, "e": 254.25, "t": "他回了两个字："}, {"s": 254.25, "e": 255.32, "t": "\"新年快乐。\""}, {"s": 255.32, "e": 257.3, "t": "没有表情，没有多余的标点。"}, {"s": 257.3, "e": 260.06, "t": "但那两个字——我翻来覆去看了好几遍。"}, {"s": 260.06, "e": 262.66, "t": "然后把手机放到枕头下面，闭上眼睛。"}, {"s": 262.66, "e": 264.34, "t": "那天晚上我做了一个梦。"}, {"s": 264.34, "e": 270.76, "t": "梦见开学那天，我走进 610 班的教室，他坐在倒数第三排靠窗的位置，抬起头来看见我。"}, {"s": 270.76, "e": 271.98, "t": "他嘴角动了一下。"}, {"s": 271.98, "e": 274.27, "t": "然后他说——不，梦里他没说话。"}, {"s": 274.27, "e": 275.65, "t": "他只是看了我一眼。"}, {"s": 275.65, "e": 278.1, "t": "但那个眼神——我记了一整个冬天。"}, {"s": 278.1, "e": 281.46, "t": "<!-- summary:start -->"}, {"s": 281.46, "e": 282.53, "t": "本章推进线索："}, {"s": 282.53, "e": 287.88, "t": "- 🔵 核心事件：林深决定\"分班之誓\"——用拼命学习换进610班的资格"}, {"s": 287.88, "e": 293.54, "t": "- 🔵 从\"看\"到\"不看\"的转变——埋头做题不是因为不想看，是因为怕看不到"}, {"s": 293.54, "e": 298.43, "t": "- 🔵 楼梯偶遇：面对面擦肩而过，林深发现自己认得出博文的脚步声"}, {"s": 298.43, "e": 303.02, "t": "- 🔵 寒假 QQ 首次互动：\"新年快乐\"——全书第一条消息"}, {"s": 303.02, "e": 308.83, "t": "- 🔵 埋设\"倒数第三排靠窗\"的意象（博文高一下新座位，与 Ch 9 呼应）"}, {"s": 308.83, "e": 310.35, "t": "本章关键事件时间戳："}, {"s": 310.35, "e": 312.65, "t": "- 12月中旬：开始封闭式刷题"}, {"s": 312.65, "e": 315.55, "t": "- 期末前某一周：楼梯上面对面擦肩而过"}, {"s": 315.55, "e": 320.29, "t": "- 期末考最后一天：写完英语作文，最后一次从611窗户看610"}, {"s": 320.29, "e": 322.89, "t": "- 寒假开端：QQ\"新年快乐\"互动"}, {"s": 322.89, "e": 325.34, "t": "- 除夕夜：做完一套物理卷子跨年"}, {"s": 325.34, "e": 326.41, "t": "本章新埋伏笔："}, {"s": 326.41, "e": 329.16, "t": "- F-分班结果：林深到底考进了吗？"}, {"s": 329.16, "e": 330.38, "t": "悬念延续到第二幕"}, {"s": 330.38, "e": 331.15, "t": "下章钩子："}, {"s": 331.15, "e": 337.87, "t": "- 开学那天——当我走进610班的教室，看见他坐在那里的时候，我知道这半年的努力没有白费"}, {"s": 337.87, "e": 340.93, "t": "<!-- summary:end -->"}, {"s": 340.93, "e": 347.2, "t": "2026-07-19 初始版本：Ch 8 分班之誓——用半年的拼命换一个靠近的资格"}]}, {"num": 9, "title": "第9章 80 厘米", "file": "chapters/ch009.mp3", "dur": 209.3, "size_mb": 1.7, "segs": [{"s": 0.0, "e": 3.21, "t": "时间：2 月 13 日 · 高一下开学第一天"}, {"s": 3.21, "e": 8.47, "t": "高一下开学那天，我站在 610 班的门口，手里攥着书包带子，手心全是汗。"}, {"s": 8.47, "e": 9.34, "t": "我考进来了。"}, {"s": 9.34, "e": 14.3, "t": "611 班到 610 班——中间隔了半层楼、一个学期、无数道数学题。"}, {"s": 14.3, "e": 15.18, "t": "但我做到了。"}, {"s": 15.18, "e": 17.08, "t": "我站在门口往里面看了一眼。"}, {"s": 17.08, "e": 18.39, "t": "教室里已经有人了。"}, {"s": 18.39, "e": 22.04, "t": "三三两两坐在一起的，低头看手机的，趴在桌上补觉的。"}, {"s": 22.04, "e": 23.21, "t": "然后我看到了他。"}, {"s": 23.21, "e": 26.56, "t": "他坐在倒数第三排靠窗的位置——不是最后一排了。"}, {"s": 26.56, "e": 27.29, "t": "换位置了。"}, {"s": 27.29, "e": 28.02, "t": "但他还在。"}, {"s": 28.02, "e": 29.77, "t": "我深吸了一口气，走进去。"}, {"s": 29.77, "e": 34.15, "t": "选座位的时候，我没有犹豫——我走到他正后方的那一排，坐下来。"}, {"s": 34.15, "e": 36.05, "t": "坐下之后，我才发现一件事。"}, {"s": 36.05, "e": 39.55, "t": "以前我在走廊上看他的时候，隔着一个天井，5 米。"}, {"s": 39.55, "e": 42.33, "t": "现在他坐在我前面——隔了不到 1 米。"}, {"s": 42.33, "e": 43.2, "t": "80 厘米。"}, {"s": 43.2, "e": 44.81, "t": "5 米到 80 厘米。"}, {"s": 44.81, "e": 45.83, "t": "用了一个学期。"}, {"s": 45.83, "e": 48.31, "t": "上午第一节课之前，班主任进来点名。"}, {"s": 48.31, "e": 50.65, "t": "点到他的名字的时候——\"博文。\""}, {"s": 50.65, "e": 51.23, "t": "\"到。\""}, {"s": 51.23, "e": 53.13, "t": "我听到了他答\"到\"的声音。"}, {"s": 53.13, "e": 55.46, "t": "声母 d，韵母 ao——dào。"}, {"s": 55.46, "e": 57.07, "t": "正常的音量，不高不低。"}, {"s": 57.07, "e": 60.72, "t": "但那个字落到我耳朵里的时候，我握笔的手指紧了一下。"}, {"s": 60.72, "e": 63.05, "t": "这是我第一次这么近听到他的声音。"}, {"s": 63.05, "e": 70.06, "t": "不是楼梯转角那种远远的诗句声，不是模糊的轮廓——是他坐在我前面不到 1 米的地方，发出的那个字。"}, {"s": 70.06, "e": 71.81, "t": "我低下头，假装在看课本。"}, {"s": 71.81, "e": 73.27, "t": "中午我去办宿舍入住。"}, {"s": 73.27, "e": 74.15, "t": "宿舍楼四楼。"}, {"s": 74.15, "e": 76.77, "t": "我找到分配表上写的那一间——409。"}, {"s": 76.77, "e": 79.4, "t": "推开门的时候，房间里已经有一个人了。"}, {"s": 79.4, "e": 82.17, "t": "蹲在靠窗的床旁边，正在往柜子里塞东西。"}, {"s": 82.17, "e": 83.63, "t": "他听见门响，转过来。"}, {"s": 83.63, "e": 84.36, "t": "我愣住了。"}, {"s": 84.36, "e": 87.28, "t": "他手里拿着那件没叠好的校服，也停了一下。"}, {"s": 87.28, "e": 88.01, "t": "然后他说："}, {"s": 88.01, "e": 89.18, "t": "\"你也住这间？\""}, {"s": 89.18, "e": 91.08, "t": "我说不出话来，只点了点头。"}, {"s": 91.08, "e": 92.54, "t": "他放下校服，站起来。"}, {"s": 92.54, "e": 93.85, "t": "\"我睡靠窗那边。\""}, {"s": 93.85, "e": 95.31, "t": "\"……那我睡靠门。\""}, {"s": 95.31, "e": 96.48, "t": "对话就这么简单。"}, {"s": 96.48, "e": 99.4, "t": "但我在心里翻来覆去想了一整天——409。"}, {"s": 99.4, "e": 99.98, "t": "同一间。"}, {"s": 99.98, "e": 103.04, "t": "从 5 米外的走廊到 80 厘米的前后桌。"}, {"s": 103.04, "e": 104.65, "t": "从两栋楼到同一间宿舍。"}, {"s": 104.65, "e": 105.53, "t": "这叫什么呢？"}, {"s": 105.53, "e": 107.86, "t": "我想了半天，想不出一个合适的词。"}, {"s": 107.86, "e": 110.49, "t": "但我放行李的时候，嘴角一直在往上翘。"}, {"s": 110.49, "e": 112.97, "t": "晚自习结束后，我收拾好书包站起来。"}, {"s": 112.97, "e": 116.62, "t": "他走到门口的时候停了一下——我以为他忘了什么东西。"}, {"s": 116.62, "e": 118.52, "t": "但他没回头，只是停在那里。"}, {"s": 118.52, "e": 120.85, "t": "等我走到他旁边，他才继续往前走。"}, {"s": 120.85, "e": 123.19, "t": "我们一起走出了教室，走到走廊上。"}, {"s": 123.19, "e": 123.92, "t": "没有说话。"}, {"s": 123.92, "e": 129.46, "t": "但那个距离——不是前后桌的 80 厘米，是并排的、中间隔了大概一个人的距离。"}, {"s": 129.46, "e": 130.48, "t": "我走在他左边。"}, {"s": 130.48, "e": 134.28, "t": "他比我高一点——不，他没我高，但他走路的步子比我长。"}, {"s": 134.28, "e": 137.05, "t": "我稍微加快了一点脚步才能和他保持平行。"}, {"s": 137.05, "e": 139.39, "t": "走到楼梯口的时候，他忽然开口了。"}, {"s": 139.39, "e": 140.7, "t": "\"你叫什么名字？\""}, {"s": 140.7, "e": 141.14, "t": "他问。"}, {"s": 141.14, "e": 143.91, "t": "声音和早上点到的时候一样——不高不低。"}, {"s": 143.91, "e": 147.56, "t": "我走在他旁边，楼梯间的灯光把两个人的影子投在墙上。"}, {"s": 147.56, "e": 148.29, "t": "\"林深。\""}, {"s": 148.29, "e": 149.31, "t": "他点了一下头。"}, {"s": 149.31, "e": 150.04, "t": "\"林深。\""}, {"s": 150.04, "e": 151.06, "t": "他重复了一遍。"}, {"s": 151.06, "e": 152.09, "t": "然后没再说话。"}, {"s": 152.09, "e": 155.15, "t": "但他的脚步，在念完我名字之后，放慢了一点。"}, {"s": 155.15, "e": 157.92, "t": "刚好够我不用加快脚步，也能走在他旁边。"}, {"s": 157.92, "e": 161.13, "t": "<!-- summary:start -->"}, {"s": 161.13, "e": 162.16, "t": "本章推进线索："}, {"s": 162.16, "e": 165.51, "t": "- 🔵 5米→80厘米——距离意象的关键转折点"}, {"s": 165.51, "e": 170.62, "t": "- 🔵 同宿舍揭晓：两人被分到同一间宿舍（解锁所有宿舍场景的物理前提）"}, {"s": 170.62, "e": 175.0, "t": "- 🔵 第一次近距离听到\"到\"——林深第一次仔细听博文的声音"}, {"s": 175.0, "e": 177.92, "t": "- 🔵 博文主动问名字：\"你叫什么名字？"}, {"s": 177.92, "e": 179.38, "t": "\"——第二幕破冰起点"}, {"s": 179.38, "e": 182.59, "t": "- 🔵 博文放慢脚步——潜意识配合林深的步频"}, {"s": 182.59, "e": 184.05, "t": "本章关键事件时间戳："}, {"s": 184.05, "e": 188.43, "t": "- 2/13 上午：林深走进 610 班教室，坐到博文正后方"}, {"s": 188.43, "e": 191.79, "t": "- 2/13 中午：409 宿舍揭晓——同一间"}, {"s": 191.79, "e": 194.56, "t": "- 2/13 晚自习后：博文主动问名字"}, {"s": 194.56, "e": 195.58, "t": "本章新埋伏笔："}, {"s": 195.58, "e": 198.06, "t": "- F-同宿舍：409，靠窗/靠门"}, {"s": 198.06, "e": 198.79, "t": "下章钩子："}, {"s": 198.79, "e": 201.42, "t": "- 同一间宿舍的第一晚——熄灯之后。"}, {"s": 201.42, "e": 204.34, "t": "<!-- summary:end -->"}, {"s": 204.34, "e": 209.3, "t": "2026-07-19 初始版本：Ch 9 80 厘米——分班后的重逢"}]}, {"num": 10, "title": "第10章 借橡皮", "file": "chapters/ch010.mp3", "dur": 353.9, "size_mb": 2.8, "segs": [{"s": 0.0, "e": 5.18, "t": "时间：2 月 13 日晚—2 月 14 日 · 高一下开学第一天"}, {"s": 5.18, "e": 7.13, "t": "开学第一天，我办了入住。"}, {"s": 7.13, "e": 9.72, "t": "宿舍在四楼，走廊尽头倒数第二间。"}, {"s": 9.72, "e": 17.01, "t": "推开门的时候，房间里已经有一个人了——背对着我，蹲在靠窗的那张床旁边，正在往柜子里塞东西。"}, {"s": 17.01, "e": 18.63, "t": "他听见门响，转过来。"}, {"s": 18.63, "e": 20.41, "t": "我和博文同时愣了一下。"}, {"s": 20.41, "e": 24.3, "t": "我愣住的原因很明显——我没想过会和他分到同一间。"}, {"s": 24.3, "e": 26.4, "t": "他愣住的原因——我不知道。"}, {"s": 26.4, "e": 31.75, "t": "但他手里的那件叠到一半的校服停在了半空中，过了大概两秒，他才放下。"}, {"s": 31.75, "e": 33.2, "t": "然后他说了一句话。"}, {"s": 33.2, "e": 34.5, "t": "\"你也住这间？\""}, {"s": 34.5, "e": 35.47, "t": "\"……嗯。\""}, {"s": 35.47, "e": 36.44, "t": "就这么简单。"}, {"s": 36.44, "e": 43.41, "t": "没有多余的寒暄，没有\"好巧啊\"或者\"以后多关照\"——他就点了下头，转过头继续塞柜子了。"}, {"s": 43.41, "e": 48.91, "t": "我站在门口，手里拎着行李箱的拉杆，感觉心脏还没从刚才那一下里缓过来。"}, {"s": 48.91, "e": 50.53, "t": "我选了靠门的那张床。"}, {"s": 50.53, "e": 54.58, "t": "放好行李之后，我坐在床沿上，偷偷看了一眼他的方向。"}, {"s": 54.58, "e": 56.53, "t": "他背对着我，正在铺床单。"}, {"s": 56.53, "e": 60.74, "t": "动作不太熟练——床单的一角塞进去了，另一角又跑出来。"}, {"s": 60.74, "e": 65.92, "t": "他拽了一下，又塞了一次，然后放弃了，把被子往上一盖，眼不见为净。"}, {"s": 65.92, "e": 67.05, "t": "我差点笑出来。"}, {"s": 67.05, "e": 68.84, "t": "原来他铺床单也铺不好。"}, {"s": 68.84, "e": 71.59, "t": "这个发现让我莫名其妙地放松了一点。"}, {"s": 71.59, "e": 73.86, "t": "晚自习结束之后，我回到宿舍。"}, {"s": 73.86, "e": 78.88, "t": "推门进去的时候，他已经在了——坐在床上，手里拿着一本书，在看。"}, {"s": 78.88, "e": 84.71, "t": "我进去的动作很轻——不是故意的，是因为我不知道该用多大声量出现在他面前。"}, {"s": 84.71, "e": 86.98, "t": "我拿了洗漱用品，去水房刷牙。"}, {"s": 86.98, "e": 93.29, "t": "回来的时候，他换了一个姿势——躺下了，书扣在枕头旁边，手机屏幕的光映在他脸上。"}, {"s": 93.29, "e": 95.4, "t": "我轻手轻脚地爬上自己的床。"}, {"s": 95.4, "e": 95.89, "t": "关灯。"}, {"s": 95.89, "e": 99.29, "t": "黑暗中，我听见他的呼吸声——很轻，很均匀。"}, {"s": 99.29, "e": 100.58, "t": "我以为他睡着了。"}, {"s": 100.58, "e": 101.88, "t": "但过了一会儿——"}, {"s": 101.88, "e": 103.34, "t": "\"你叫什么来着？\""}, {"s": 103.34, "e": 105.28, "t": "他的声音从黑暗中传过来。"}, {"s": 105.28, "e": 106.9, "t": "不大，像是随口问的。"}, {"s": 106.9, "e": 107.71, "t": "\"林深。\""}, {"s": 107.71, "e": 108.52, "t": "\"林深。\""}, {"s": 108.52, "e": 109.65, "t": "他重复了一遍。"}, {"s": 109.65, "e": 110.95, "t": "然后安静了几秒。"}, {"s": 110.95, "e": 112.89, "t": "\"森林的林，深浅的深？\""}, {"s": 112.89, "e": 113.54, "t": "\"对。\""}, {"s": 113.54, "e": 114.19, "t": "\"好。\""}, {"s": 114.19, "e": 115.32, "t": "然后就没有了。"}, {"s": 115.32, "e": 117.26, "t": "我躺在黑暗中，睁着眼睛。"}, {"s": 117.26, "e": 118.72, "t": "他记住了我的名字。"}, {"s": 118.72, "e": 123.1, "t": "第二天早自习，我在座位上翻笔袋的时候，发现了一个问题。"}, {"s": 123.1, "e": 124.39, "t": "我的橡皮不见了。"}, {"s": 124.39, "e": 126.82, "t": "我把笔袋翻了个底朝天——没有。"}, {"s": 126.82, "e": 129.57, "t": "又翻了书包的每一个夹层——也没有。"}, {"s": 129.57, "e": 133.46, "t": "昨晚明明放在桌上的，大概是收拾的时候掉在宿舍了。"}, {"s": 133.46, "e": 135.73, "t": "我今天有三节课要写课堂练习。"}, {"s": 135.73, "e": 136.7, "t": "没橡皮不行。"}, {"s": 136.7, "e": 139.29, "t": "我正犹豫要不要回宿舍拿的时候——"}, {"s": 139.29, "e": 141.24, "t": "一块橡皮从旁边推了过来。"}, {"s": 141.24, "e": 142.21, "t": "停在我桌角。"}, {"s": 142.21, "e": 145.77, "t": "白色的，用得只剩一半了，边角被切掉了一小块。"}, {"s": 145.77, "e": 146.58, "t": "我抬起头。"}, {"s": 146.58, "e": 151.76, "t": "博文已经转回去了——他坐在我前面，背对着我，已经在低头写东西了。"}, {"s": 151.76, "e": 154.19, "t": "他什么时候注意到我在找橡皮的？"}, {"s": 154.19, "e": 156.3, "t": "他什么时候把橡皮拿出来的？"}, {"s": 156.3, "e": 157.92, "t": "他——为什么要借我？"}, {"s": 157.92, "e": 160.35, "t": "我把那块橡皮拿起来，握在手心。"}, {"s": 160.35, "e": 164.4, "t": "上面还带着一点温度——大概是他在口袋里放了一早上。"}, {"s": 164.4, "e": 165.21, "t": "\"谢谢。\""}, {"s": 165.21, "e": 165.69, "t": "我说。"}, {"s": 165.69, "e": 166.5, "t": "他没回头。"}, {"s": 166.5, "e": 171.04, "t": "但我看见他握笔的手停了一下——不到一秒——然后继续写了。"}, {"s": 171.04, "e": 173.47, "t": "那天上午我用了那块橡皮好几次。"}, {"s": 173.47, "e": 176.71, "t": "每次用的时候都下意识看一眼前面那个背影。"}, {"s": 176.71, "e": 180.27, "t": "他坐得很直，低头写字的时候肩膀会微微往左偏。"}, {"s": 180.27, "e": 186.43, "t": "他用的笔是黑色的那种，写字的力道不小，我在后面都能听到笔尖落在纸上的沙沙声。"}, {"s": 186.43, "e": 188.04, "t": "中午我把橡皮还给他。"}, {"s": 188.04, "e": 189.5, "t": "\"谢谢，用完了。\""}, {"s": 189.5, "e": 192.26, "t": "他接过去，没看，直接放进了笔袋里。"}, {"s": 192.26, "e": 193.55, "t": "\"以后不用还。\""}, {"s": 193.55, "e": 194.04, "t": "他说。"}, {"s": 194.04, "e": 195.17, "t": "\"……什么？\""}, {"s": 195.17, "e": 197.92, "t": "\"橡皮这种东西——借了就不用还。\""}, {"s": 197.92, "e": 200.35, "t": "他语气很平，像在陈述一个常识。"}, {"s": 200.35, "e": 201.33, "t": "我愣了一下。"}, {"s": 201.33, "e": 203.11, "t": "\"那我要用的时候——\""}, {"s": 203.11, "e": 203.92, "t": "\"来拿。\""}, {"s": 203.92, "e": 205.05, "t": "他依然没回头。"}, {"s": 205.05, "e": 209.59, "t": "但我看见他的耳朵好像红了一点——也可能是走廊的光线问题。"}, {"s": 209.59, "e": 212.83, "t": "我回到座位上，把这句话在脑子里翻了两遍。"}, {"s": 212.83, "e": 213.64, "t": "\"来拿。\""}, {"s": 213.64, "e": 215.09, "t": "他说的是\"来拿\"。"}, {"s": 215.09, "e": 217.04, "t": "意思是——我可以再找他。"}, {"s": 217.04, "e": 219.63, "t": "晚上回到宿舍，他已经在房间里了。"}, {"s": 219.63, "e": 224.33, "t": "坐在床上，正在往脚上套袜子——看样子是刚从水房洗完脚回来。"}, {"s": 224.33, "e": 228.37, "t": "我推门进去的时候，他抬头看了我一眼，然后又低下去。"}, {"s": 228.37, "e": 230.48, "t": "中间的沉默大概持续了几秒。"}, {"s": 230.48, "e": 235.34, "t": "然后他说：\"你今天下午那节英语课——老师叫你回答问题那次。\""}, {"s": 235.34, "e": 236.64, "t": "\"……怎么了？\""}, {"s": 236.64, "e": 238.09, "t": "\"你答得挺好的。\""}, {"s": 238.09, "e": 242.79, "t": "他说完这句话之后，就低头继续穿袜子了，像什么都没说过一样。"}, {"s": 242.79, "e": 245.22, "t": "我站在房间中央，手里拿着水杯。"}, {"s": 245.22, "e": 247.0, "t": "\"你——你注意到了？\""}, {"s": 247.0, "e": 248.78, "t": "他手上的动作停了一下。"}, {"s": 248.78, "e": 250.08, "t": "\"我坐你前面。\""}, {"s": 250.08, "e": 251.21, "t": "\"……所以？\""}, {"s": 251.21, "e": 252.83, "t": "\"所以——听到了。\""}, {"s": 252.83, "e": 254.45, "t": "他的语气还是那么平。"}, {"s": 254.45, "e": 257.37, "t": "但我注意到他说这句话的时候，没抬头。"}, {"s": 257.37, "e": 259.96, "t": "那天晚上我躺在床上，很久没睡着。"}, {"s": 259.96, "e": 264.66, "t": "不是因为第一天住宿舍不习惯——是因为今天发生的事情太多了。"}, {"s": 264.66, "e": 265.95, "t": "分了同一间宿舍。"}, {"s": 265.95, "e": 267.41, "t": "他记住了我的名字。"}, {"s": 267.41, "e": 268.54, "t": "他借了我橡皮。"}, {"s": 268.54, "e": 269.68, "t": "他说\"来拿\"。"}, {"s": 269.68, "e": 271.3, "t": "他说我英语回答得好。"}, {"s": 271.3, "e": 272.92, "t": "这些事每一件都不大。"}, {"s": 272.92, "e": 277.45, "t": "但它们堆在一起——堆在我胸口——变成了一种说不清的重量。"}, {"s": 277.45, "e": 277.94, "t": "不重。"}, {"s": 277.94, "e": 279.07, "t": "但让我睡不着。"}, {"s": 279.07, "e": 281.18, "t": "我翻了个身，面向窗户那边。"}, {"s": 281.18, "e": 285.39, "t": "月光从窗帘的缝隙里透进来，在地上画了一条细细的白线。"}, {"s": 285.39, "e": 286.68, "t": "他的床在不远处。"}, {"s": 286.68, "e": 290.41, "t": "我看不清他的脸——只能看到被子微微起伏的轮廓。"}, {"s": 290.41, "e": 291.54, "t": "他已经睡着了。"}, {"s": 291.54, "e": 292.51, "t": "呼吸很均匀。"}, {"s": 292.51, "e": 297.7, "t": "我听着那个声音——不知道为什么——觉得这个房间好像没那么陌生了。"}, {"s": 297.7, "e": 301.26, "t": "<!-- summary:start -->"}, {"s": 301.26, "e": 302.39, "t": "本章推进线索："}, {"s": 302.39, "e": 307.58, "t": "- 🔵 同宿舍第一夜的细节确认：靠门vs靠窗、铺床单、熄灯后对话"}, {"s": 307.58, "e": 315.03, "t": "- 🔵 \"借橡皮\"——林深第一次主动从博文这里拿到东西，博文的回应\"来拿\"（＝随时可以找我）"}, {"s": 315.03, "e": 320.86, "t": "- 🔵 博文主动评价林深\"英语答得挺好的\"——第一个\"注意你\"的侧面信号"}, {"s": 320.86, "e": 325.23, "t": "- 🔵 耳朵红了一下的细节——暗示博文并非表面那么平静"}, {"s": 325.23, "e": 326.85, "t": "本章关键事件时间戳："}, {"s": 326.85, "e": 330.41, "t": "- 2/13 晚：入住宿舍，熄灯后博文问名字"}, {"s": 330.41, "e": 334.46, "t": "- 2/14（开学第二天）：早自习借橡皮→\"来拿\""}, {"s": 334.46, "e": 337.54, "t": "- 2/14 晚：宿舍博文称赞英语回答"}, {"s": 337.54, "e": 340.62, "t": "本章新埋伏笔：无（均为已有关系的深化）"}, {"s": 340.62, "e": 341.43, "t": "下章钩子："}, {"s": 341.43, "e": 344.51, "t": "- 他说了\"来拿\"——所以我又去找他了"}, {"s": 344.51, "e": 347.75, "t": "<!-- summary:end -->"}, {"s": 347.75, "e": 353.9, "t": "2026-07-19 初始版本：Ch 10 借橡皮——同宿舍第一夜与\"来拿\""}]}, {"num": 11, "title": "第11章 你是以前 611 那个", "file": "chapters/ch011.mp3", "dur": 116.2, "size_mb": 0.9, "segs": [{"s": 0.0, "e": 2.15, "t": "时间：2 月 15 日 · 高一下"}, {"s": 2.15, "e": 2.91, "t": "开学第三天。"}, {"s": 2.91, "e": 5.05, "t": "大课间的时候，我正坐在座位上看书。"}, {"s": 5.05, "e": 7.7, "t": "他转过身来了——不是侧过头，是整个转过来。"}, {"s": 7.7, "e": 8.34, "t": "\"林深。\""}, {"s": 8.34, "e": 9.35, "t": "他叫了我的名字。"}, {"s": 9.35, "e": 11.11, "t": "这是他第一次主动叫我的名字。"}, {"s": 11.11, "e": 13.26, "t": "\"你以前是 611 班的，对吧？\""}, {"s": 13.26, "e": 14.78, "t": "我握着笔的手指紧了一下。"}, {"s": 14.78, "e": 15.54, "t": "\"……对。\""}, {"s": 15.54, "e": 16.29, "t": "他点了点头。"}, {"s": 16.29, "e": 17.18, "t": "\"我见过你。\""}, {"s": 17.18, "e": 17.81, "t": "我愣住了。"}, {"s": 17.81, "e": 19.07, "t": "\"你——什么时候？\""}, {"s": 19.07, "e": 20.59, "t": "\"你以前每天站在走廊上。"}, {"s": 20.59, "e": 21.6, "t": "靠窗那个位置。\""}, {"s": 21.6, "e": 25.01, "t": "他说这句话的语气很平——像在陈述一个他早就知道的事实。"}, {"s": 25.01, "e": 26.78, "t": "我脑子里的某根弦，绷了一下。"}, {"s": 26.78, "e": 27.28, "t": "他知道。"}, {"s": 27.28, "e": 28.54, "t": "他知道我站在走廊上。"}, {"s": 28.54, "e": 29.3, "t": "他一直知道。"}, {"s": 29.3, "e": 33.09, "t": "我从高一开始就站在那个位置看他——而他，从一开始就看到了我。"}, {"s": 33.09, "e": 35.87, "t": "\"你是以前 611 那个，老站走廊上的人。\""}, {"s": 35.87, "e": 36.75, "t": "他又说了一遍。"}, {"s": 36.75, "e": 37.51, "t": "不是疑问句。"}, {"s": 37.51, "e": 38.14, "t": "是陈述句。"}, {"s": 38.14, "e": 41.43, "t": "我坐在座位上，感觉有什么东西在我胸口稳稳地落下来了。"}, {"s": 41.43, "e": 41.93, "t": "他知道。"}, {"s": 41.93, "e": 44.21, "t": "那天晚自习结束的时候，我在收拾书包。"}, {"s": 44.21, "e": 45.6, "t": "他站起来，走到我桌边。"}, {"s": 45.6, "e": 47.49, "t": "\"明天我把那个英语笔记借你。\""}, {"s": 47.49, "e": 48.37, "t": "\"……什么？\""}, {"s": 48.37, "e": 50.27, "t": "\"你英语笔记上次不是没记全吗？"}, {"s": 50.27, "e": 51.15, "t": "我有完整的。\""}, {"s": 51.15, "e": 52.29, "t": "他说完就走了出去。"}, {"s": 52.29, "e": 54.94, "t": "我坐在座位上，手里握着还没拉好的书包拉链。"}, {"s": 54.94, "e": 56.71, "t": "他连我英语笔记没记全都知道。"}, {"s": 56.71, "e": 59.49, "t": "回到宿舍之后，周海——新同桌——看了我一眼。"}, {"s": 59.49, "e": 61.38, "t": "\"你今天看了他几次你知道吗？\""}, {"s": 61.38, "e": 62.39, "t": "\"……不知道。\""}, {"s": 62.39, "e": 63.4, "t": "\"我帮你数了。\""}, {"s": 63.4, "e": 65.05, "t": "他伸出两只手——十根手指。"}, {"s": 65.05, "e": 65.93, "t": "\"15 次。\""}, {"s": 65.93, "e": 66.69, "t": "我不说话了。"}, {"s": 66.69, "e": 68.33, "t": "\"你知道这意味着什么吗？\""}, {"s": 68.33, "e": 69.21, "t": "\"……什么？\""}, {"s": 69.21, "e": 73.0, "t": "\"你一节晚自习能看他 15 次，但你一道物理题都没做出来。\""}, {"s": 73.0, "e": 73.89, "t": "他说的是对的。"}, {"s": 73.89, "e": 75.4, "t": "我确实一道题都没做出来。"}, {"s": 75.4, "e": 77.3, "t": "因为我一直在想他说的那句话——"}, {"s": 77.3, "e": 80.08, "t": "\"你是以前 611 那个，老站走廊上的人。\""}, {"s": 80.08, "e": 80.58, "t": "他知道。"}, {"s": 80.58, "e": 81.72, "t": "他从一开始就知道。"}, {"s": 81.72, "e": 84.5, "t": "<!-- summary:start -->"}, {"s": 84.5, "e": 85.38, "t": "本章推进线索："}, {"s": 85.38, "e": 91.44, "t": "- 🔵 博文第一次主动认出林深：\"你是以前 611 那个，老站走廊上的人\"——双向确认的关键瞬间"}, {"s": 91.44, "e": 94.48, "t": "- 🔵 博文注意到林深英语笔记没记全——观察之细"}, {"s": 94.48, "e": 97.0, "t": "- 🔵 周海再度点破：15 次/节晚自习"}, {"s": 97.0, "e": 98.26, "t": "本章关键事件时间戳："}, {"s": 98.26, "e": 102.43, "t": "- 2/15 大课间：博文主动转过来问\"你是以前 611 班的？\""}, {"s": 102.43, "e": 105.34, "t": "- 2/15 晚自习后：博文主动说要借英语笔记"}, {"s": 105.34, "e": 106.35, "t": "本章新埋伏笔：无"}, {"s": 106.35, "e": 106.98, "t": "下章钩子："}, {"s": 106.98, "e": 108.75, "t": "- 然后我们的手指碰了一下。"}, {"s": 108.75, "e": 111.27, "t": "<!-- summary:end -->"}, {"s": 111.27, "e": 116.2, "t": "2026-07-19 初始版本：Ch 11 你是以前 611 那个——双向确认"}]}, {"num": 12, "title": "第12章 一秒钟", "file": "chapters/ch012.mp3", "dur": 203.8, "size_mb": 1.6, "segs": [{"s": 0.0, "e": 2.51, "t": "时间：2 月 16 日 · 高一下"}, {"s": 2.51, "e": 4.87, "t": "借笔记这件事，我想了两天才敢做。"}, {"s": 4.87, "e": 9.0, "t": "周四晚自习，我坐在他后面，盯着他的后脑勺看了大概十分钟。"}, {"s": 9.0, "e": 13.57, "t": "他在写物理作业——笔尖在纸上发出沙沙的声音，偶尔停下来翻一页。"}, {"s": 13.57, "e": 14.75, "t": "我深吸了一口气。"}, {"s": 14.75, "e": 16.66, "t": "然后我推了一下椅子——吱。"}, {"s": 16.66, "e": 17.7, "t": "他停了一下笔。"}, {"s": 17.7, "e": 21.97, "t": "没回头，但他知道我在叫他——我们之间好像已经有了这种默契。"}, {"s": 21.97, "e": 22.71, "t": "\"博文。\""}, {"s": 22.71, "e": 23.3, "t": "\"嗯？\""}, {"s": 23.3, "e": 25.81, "t": "\"你英语笔记——能借我看一下吗？\""}, {"s": 25.81, "e": 29.79, "t": "他回头看了我一眼，然后从他桌角拿过那个笔记本，递过来。"}, {"s": 29.79, "e": 30.82, "t": "我伸手去接——"}, {"s": 30.82, "e": 32.15, "t": "我们的手指碰到了。"}, {"s": 32.15, "e": 33.18, "t": "大概 1 秒。"}, {"s": 33.18, "e": 34.36, "t": "他的手指是暖的。"}, {"s": 34.36, "e": 37.46, "t": "我接过来，说了声谢谢，然后低头翻开笔记本。"}, {"s": 37.46, "e": 39.52, "t": "但他的温度，还留在我手指上。"}, {"s": 39.52, "e": 42.47, "t": "那个笔记本我在手里翻了大概 30 分钟。"}, {"s": 42.47, "e": 45.71, "t": "不是因为他记得有多好——是因为我在看他的字。"}, {"s": 45.71, "e": 50.58, "t": "他的英文字母写得很整齐——不圆，偏方，每个字母之间的距离都差不多。"}, {"s": 50.58, "e": 55.01, "t": "不像他写中文那样飞起来的样子，写英文的时候他好像会认真一点。"}, {"s": 55.01, "e": 63.12, "t": "我翻到中间的时候，看见了一个小小的涂鸦——在某一页的右下角，他画了一个歪歪扭扭的笑脸，只有眼睛和嘴巴，没有脸。"}, {"s": 63.12, "e": 64.15, "t": "我差点笑出来。"}, {"s": 64.15, "e": 66.8, "t": "然后我合上笔记，深吸一口气，还给他。"}, {"s": 66.8, "e": 67.54, "t": "\"谢谢。\""}, {"s": 67.54, "e": 68.28, "t": "他接过去。"}, {"s": 68.28, "e": 71.96, "t": "然后他又把物理作业本推了过来——打开到最新的一页。"}, {"s": 71.96, "e": 75.8, "t": "\"你看一下这道题的方法——我用的和老师讲的不一样。\""}, {"s": 75.8, "e": 76.54, "t": "我低头看。"}, {"s": 76.54, "e": 79.63, "t": "他确实用了另一种解法——比老师讲的短两步。"}, {"s": 79.63, "e": 83.47, "t": "我抬头想说\"谢谢\"的时候——他正低着头，翻自己的书。"}, {"s": 83.47, "e": 86.71, "t": "从他的校服领口那里，我看到他脖颈上那一截白。"}, {"s": 86.71, "e": 87.74, "t": "只露了一瞬间。"}, {"s": 87.74, "e": 89.07, "t": "然后他抬起头来了。"}, {"s": 89.07, "e": 90.84, "t": "我赶紧把目光移回本子上。"}, {"s": 90.84, "e": 93.2, "t": "晚自习快结束的时候，我收拾书包。"}, {"s": 93.2, "e": 94.82, "t": "他坐在前面，也在收拾。"}, {"s": 94.82, "e": 98.8, "t": "然后他回头了——不是转身，是侧过头，往我这边看了一眼。"}, {"s": 98.8, "e": 100.13, "t": "他的嘴角动了一下。"}, {"s": 100.13, "e": 103.52, "t": "不是说话——是嘴角微微往上翘了一下，不到半秒。"}, {"s": 103.52, "e": 104.7, "t": "然后他转回去了。"}, {"s": 104.7, "e": 106.62, "t": "我握着书包带子，愣在原地。"}, {"s": 106.62, "e": 108.24, "t": "这个嘴角动——我见过。"}, {"s": 108.24, "e": 111.34, "t": "11 月 24 号，隔着天井，5 米之外。"}, {"s": 111.34, "e": 115.91, "t": "现在他坐在我前面 80 厘米的地方，我不用隔着玻璃也能看到了。"}, {"s": 115.91, "e": 116.79, "t": "同一个弧度。"}, {"s": 116.79, "e": 117.53, "t": "同一个人。"}, {"s": 117.53, "e": 122.84, "t": "周海——新的周海，不是高一上同铺的那个——在我回到宿舍之后，看了我一眼。"}, {"s": 122.84, "e": 125.2, "t": "\"你今天看了他多少次你知道吗？\""}, {"s": 125.2, "e": 126.38, "t": "\"……不知道。\""}, {"s": 126.38, "e": 127.41, "t": "\"我帮你数了。"}, {"s": 127.41, "e": 128.3, "t": "15 次。\""}, {"s": 128.3, "e": 129.18, "t": "我愣了一下。"}, {"s": 129.18, "e": 130.51, "t": "\"你数这个干嘛？\""}, {"s": 130.51, "e": 131.25, "t": "\"帮你数。"}, {"s": 131.25, "e": 133.02, "t": "\"他坐在床沿上，翘着腿。"}, {"s": 133.02, "e": 133.9, "t": "\"15 次。"}, {"s": 133.9, "e": 134.93, "t": "一节晚自习。\""}, {"s": 134.93, "e": 135.67, "t": "他顿了顿。"}, {"s": 135.67, "e": 139.21, "t": "\"要不要我帮你定一个标准——每天最多 5 次。\""}, {"s": 139.21, "e": 140.83, "t": "\"……5 次太少了。\""}, {"s": 140.83, "e": 142.31, "t": "\"那就 10 次。\""}, {"s": 142.31, "e": 143.04, "t": "我想了想。"}, {"s": 143.04, "e": 144.22, "t": "\"……7 次。\""}, {"s": 144.22, "e": 144.96, "t": "\"成交。\""}, {"s": 144.96, "e": 149.24, "t": "——那天晚上我躺在床上，把今天发生的事情在脑子里过了一遍。"}, {"s": 149.24, "e": 150.71, "t": "手指碰到他的那一秒。"}, {"s": 150.71, "e": 152.04, "t": "他脖颈上那一截白。"}, {"s": 152.04, "e": 154.1, "t": "他回头时嘴角动了一下的弧度。"}, {"s": 154.1, "e": 157.64, "t": "嘴角动了一下——和 11 月 24 号一模一样。"}, {"s": 157.64, "e": 158.23, "t": "7 次。"}, {"s": 158.23, "e": 159.12, "t": "我闭上眼睛。"}, {"s": 159.12, "e": 161.33, "t": "明天一定要控制在 7 次以内。"}, {"s": 161.33, "e": 163.84, "t": "--- 第二天我看了他 11 次。"}, {"s": 163.84, "e": 167.08, "t": "<!-- summary:start -->"}, {"s": 167.08, "e": 168.11, "t": "本章推进线索："}, {"s": 168.11, "e": 172.68, "t": "- 🔵 手指相碰 1 秒——全书第一次物理接触，博文手指是暖的"}, {"s": 172.68, "e": 176.52, "t": "- 🔵 博文主动分享物理作业的另一种解法——信任信号"}, {"s": 176.52, "e": 183.15, "t": "- 🔵 嘴角动了一下——与 Ch 6 的\"嘴角一动\"形成跨章呼应，确认为博文的标志性微表情"}, {"s": 183.15, "e": 187.14, "t": "- 🔵 周海\"7 次标准\"——外部视角量化林深的注意力"}, {"s": 187.14, "e": 188.61, "t": "本章关键事件时间戳："}, {"s": 188.61, "e": 193.48, "t": "- 2/16 晚自习：借笔记→手指相碰→博文分享物理解法→嘴角一动"}, {"s": 193.48, "e": 194.21, "t": "下章钩子："}, {"s": 194.21, "e": 195.84, "t": "- 他知道我喜欢甜的。"}, {"s": 195.84, "e": 198.79, "t": "<!-- summary:end -->"}, {"s": 198.79, "e": 203.8, "t": "2026-07-19 初始版本：Ch 12 一秒钟——第一次物理接触"}]}, {"num": 13, "title": "第13章 错题本", "file": "chapters/ch013.mp3", "dur": 248.5, "size_mb": 2.0, "segs": [{"s": 0.0, "e": 3.21, "t": "时间：2 月 18 日—20 日 · 高一下"}, {"s": 3.21, "e": 6.28, "t": "借完笔记之后，我以为接下来不会再有什么了。"}, {"s": 6.28, "e": 8.91, "t": "但第三天晚上，我桌子上多了一个本子。"}, {"s": 8.91, "e": 9.64, "t": "不是我的。"}, {"s": 9.64, "e": 16.06, "t": "我坐下来的时候，一眼就看见了——一个牛皮纸封面的笔记本，A5 大小，放在我桌子的正中央。"}, {"s": 16.06, "e": 17.08, "t": "我翻开第一页。"}, {"s": 17.08, "e": 22.34, "t": "字迹飞起来了一样——不是那种整整齐齐的笔记，是写的人自己才看得懂的写法。"}, {"s": 22.34, "e": 27.74, "t": "公式和公式之间穿插着只有缩写和箭头，有些地方用红笔打了圈，旁边写着三个字："}, {"s": 27.74, "e": 28.62, "t": "\"别踩坑。\""}, {"s": 28.62, "e": 29.78, "t": "我往后翻了几页。"}, {"s": 29.78, "e": 36.36, "t": "每一页都是这样的——不是完整的题目解析，是那种\"我当年做错了、你们别走我的老路\"的错题集。"}, {"s": 36.36, "e": 38.4, "t": "不是老师布置的，是他自己的。"}, {"s": 38.4, "e": 41.47, "t": "翻到中间的时候，有一页的页脚多了一行小字："}, {"s": 41.47, "e": 43.07, "t": "\"这题期中考了，记住。"}, {"s": 43.07, "e": 44.39, "t": "回头看后面那道。\""}, {"s": 44.39, "e": 47.89, "t": "我看了一下日期——不是今年的，是他高一的期中考。"}, {"s": 47.89, "e": 49.93, "t": "他把自己的错题本，拿给我了。"}, {"s": 49.93, "e": 52.85, "t": "第二天早上我把本子带去教室，准备还给他。"}, {"s": 52.85, "e": 54.17, "t": "\"博文，这个——\""}, {"s": 54.17, "e": 55.04, "t": "\"看完了？\""}, {"s": 55.04, "e": 56.94, "t": "\"还没——但这是你的——\""}, {"s": 56.94, "e": 57.96, "t": "\"看完再还。\""}, {"s": 57.96, "e": 59.86, "t": "他头也没抬，正在翻英语书。"}, {"s": 59.86, "e": 61.91, "t": "\"里面可能有你看得上的题。\""}, {"s": 61.91, "e": 63.66, "t": "他说完就站起来去接水了。"}, {"s": 63.66, "e": 66.87, "t": "我站在原地，手里拿着那本错题本，好几秒没动。"}, {"s": 66.87, "e": 73.29, "t": "\"里面可能有你看得上的题\"——他不是说\"可能有你不会的题\"，他说的是\"你可能看得上的\"。"}, {"s": 73.29, "e": 75.05, "t": "他用了\"看得上\"这个词。"}, {"s": 75.05, "e": 76.8, "t": "好像他默认我有那个水平。"}, {"s": 76.8, "e": 78.26, "t": "那天中午我没去食堂。"}, {"s": 78.26, "e": 81.47, "t": "我坐在座位上，把他的错题本从头到尾翻了一遍。"}, {"s": 81.47, "e": 84.39, "t": "他的字虽然飞，但每一道题旁边都写了错因。"}, {"s": 84.39, "e": 95.05, "t": "大部分不是\"公式记错了\"或者\"计算失误\"——是很具体的，像\"这题我用了分析法但应该用建系\"\"第二问我跳过了一个隐条件，在这里→画了一条线标出来\"。"}, {"s": 95.05, "e": 98.85, "t": "他用红笔写的不是正确答案，是\"我当时怎么掉坑里的\"。"}, {"s": 98.85, "e": 101.91, "t": "我看完最后一页的时候，有一种很奇怪的感觉。"}, {"s": 101.91, "e": 105.85, "t": "不是\"他好厉害\"——他确实厉害，但这不是我最大的感受。"}, {"s": 105.85, "e": 109.8, "t": "我最大的感受是——他是一个会认真对待自己犯过的错的人。"}, {"s": 109.8, "e": 112.72, "t": "大多数人是把错题抄一遍，记个答案就完了。"}, {"s": 112.72, "e": 113.3, "t": "他不是。"}, {"s": 113.3, "e": 118.85, "t": "他把每一道错题都变成了一个标记——\"这里要注意\"、\"这里我下次不会再错了\"。"}, {"s": 118.85, "e": 121.04, "t": "我把本子合上，手指按在封面上。"}, {"s": 121.04, "e": 124.4, "t": "那一瞬间我忽然觉得——我好像认识他更多了一点。"}, {"s": 124.4, "e": 127.46, "t": "晚自习结束后，我回宿舍的时候，他已经在了。"}, {"s": 127.46, "e": 129.94, "t": "坐在床上，戴着一边耳机，在看手机。"}, {"s": 129.94, "e": 132.43, "t": "我走过去，把那本错题本放在他床角。"}, {"s": 132.43, "e": 133.3, "t": "\"看完了。\""}, {"s": 133.3, "e": 134.18, "t": "他摘下耳机。"}, {"s": 134.18, "e": 135.05, "t": "\"怎么样？\""}, {"s": 135.05, "e": 137.54, "t": "\"——你那个分析法的题，我看懂了。"}, {"s": 137.54, "e": 140.16, "t": "但你画的那个图，我看了三遍才明白。\""}, {"s": 140.16, "e": 143.67, "t": "他嘴角动了一下——不是笑，是那种\"果然\"的表情。"}, {"s": 143.67, "e": 144.98, "t": "\"第一遍看都那样。"}, {"s": 144.98, "e": 146.3, "t": "看多了就习惯了。\""}, {"s": 146.3, "e": 147.9, "t": "\"……你还有多少本？\""}, {"s": 147.9, "e": 148.63, "t": "他想了想。"}, {"s": 148.63, "e": 151.26, "t": "\"数学两本，物理一本半，化学半本。\""}, {"s": 151.26, "e": 151.99, "t": "\"半本？\""}, {"s": 151.99, "e": 153.01, "t": "\"化学刚开。\""}, {"s": 153.01, "e": 153.74, "t": "他顿了顿。"}, {"s": 153.74, "e": 155.5, "t": "\"你想看的话，自己拿。\""}, {"s": 155.5, "e": 161.48, "t": "他说这句话的时候，目光落在手机屏幕上，语气像在说\"冰箱里有吃的你自己拿\"一样随意。"}, {"s": 161.48, "e": 164.11, "t": "我说了一声\"好\"，转身走回自己的床。"}, {"s": 164.11, "e": 168.93, "t": "坐下来的那一刻，我才注意到——我刚才和他说话的时候，没有任何紧张。"}, {"s": 168.93, "e": 170.68, "t": "像和老朋友说话一样自然。"}, {"s": 170.68, "e": 173.16, "t": "这个认知让我坐在床沿上愣了一会儿。"}, {"s": 173.16, "e": 176.23, "t": "周五晚上，我坐在书桌前，也翻出了一个本子。"}, {"s": 176.23, "e": 181.19, "t": "不是新的——是我高一上的数学错题本，零零散散记了十几页，后面就空了。"}, {"s": 181.19, "e": 183.24, "t": "我在第一页空白处写了几行字："}, {"s": 183.24, "e": 185.43, "t": "\"2/18 借了博文的错题本。"}, {"s": 185.43, "e": 189.81, "t": "他写错因的方式：不是写正确答案，是写'我当时怎么掉坑里的'。"}, {"s": 189.81, "e": 191.12, "t": "我以后也这么写。\""}, {"s": 191.12, "e": 193.75, "t": "写完之后我看着这几行字，忽然觉得——"}, {"s": 193.75, "e": 196.08, "t": "这个本子，以后大概会经常翻开了。"}, {"s": 196.08, "e": 199.3, "t": "<!-- summary:start -->"}, {"s": 199.3, "e": 200.32, "t": "本章推进线索："}, {"s": 200.32, "e": 205.28, "t": "- 🔵 博文主动把错题本放到林深桌上——\"看完再还\"——信任的象征物"}, {"s": 205.28, "e": 210.98, "t": "- 🔵 林深通过错题本看到了博文对待错误的态度（写错因而不写答案）——性格侧写"}, {"s": 210.98, "e": 215.94, "t": "- 🔵 两人对话首次出现\"自然感\"——林深发现自己和他说话不再紧张了"}, {"s": 215.94, "e": 221.2, "t": "- 🔵 林深开始模仿博文的错题方法——\"我以后也这么写\"——被影响的开端"}, {"s": 221.2, "e": 222.66, "t": "本章关键事件时间戳："}, {"s": 222.66, "e": 225.43, "t": "- 2/18：博文把错题本放在林深桌上"}, {"s": 225.43, "e": 228.94, "t": "- 2/18 晚自习后：林深还本子，对话自然发生"}, {"s": 228.94, "e": 233.17, "t": "- 2/20（周五晚）：林深翻出自己的错题本，决定改变记法"}, {"s": 233.17, "e": 234.19, "t": "本章新埋伏笔："}, {"s": 234.19, "e": 238.13, "t": "- F-错题本方法：博文的影响开始渗透进林深的学习习惯"}, {"s": 238.13, "e": 238.86, "t": "下章钩子："}, {"s": 238.86, "e": 239.74, "t": "- 他顺路。"}, {"s": 239.74, "e": 240.47, "t": "我也顺路。"}, {"s": 240.47, "e": 243.39, "t": "<!-- summary:end -->"}, {"s": 243.39, "e": 248.5, "t": "2026-07-19 初始版本：Ch 13 错题本——从借笔记到借习惯"}]}, {"num": 14, "title": "第14章 顺路", "file": "chapters/ch014.mp3", "dur": 294.2, "size_mb": 2.4, "segs": [{"s": 0.0, "e": 3.37, "t": "时间：2 月 20 日—21 日 · 高一下"}, {"s": 3.37, "e": 7.5, "t": "周五晚自习结束后，我收拾书包的时候，他在门口站了一下。"}, {"s": 7.5, "e": 10.26, "t": "不是等我——他站在门口，低头看手机。"}, {"s": 10.26, "e": 13.16, "t": "我背上书包走过去的时候，他刚好抬起头。"}, {"s": 13.16, "e": 16.23, "t": "然后他什么也没说，转身往楼梯的方向走了。"}, {"s": 16.23, "e": 20.05, "t": "我跟在后面——不是刻意的，是因为回宿舍就这一条路。"}, {"s": 20.05, "e": 22.81, "t": "走了大概十步之后，我发现他走得不快。"}, {"s": 22.81, "e": 26.63, "t": "不是平时那种步子——是比我正常速度慢一点点的节奏。"}, {"s": 26.63, "e": 29.24, "t": "我本能地放慢了脚步，跟上他的节奏。"}, {"s": 29.24, "e": 33.22, "t": "就这样——他走在前面，我跟在后面，中间隔了大概两米。"}, {"s": 33.22, "e": 34.13, "t": "谁都没说话。"}, {"s": 34.13, "e": 38.42, "t": "走到一楼拐角的时候，他往旁边侧了一下身，让我走到他旁边。"}, {"s": 38.42, "e": 40.1, "t": "\"你明天早上要出去？\""}, {"s": 40.1, "e": 40.56, "t": "他问。"}, {"s": 40.56, "e": 41.63, "t": "\"……什么？\""}, {"s": 41.63, "e": 43.78, "t": "\"我看你周五晚上都在学校。\""}, {"s": 43.78, "e": 46.99, "t": "\"哦——对，我家有点远，周末一般待学校。\""}, {"s": 46.99, "e": 47.91, "t": "他点了点头。"}, {"s": 47.91, "e": 48.83, "t": "\"我也是。\""}, {"s": 48.83, "e": 50.21, "t": "然后他没再说话了。"}, {"s": 50.21, "e": 55.41, "t": "但我们从那栋楼走到宿舍楼的那段路——大概 200 米——是并排走的。"}, {"s": 55.41, "e": 59.08, "t": "路灯把两个人的影子投在地上，一个偏左，一个偏右。"}, {"s": 59.08, "e": 62.15, "t": "到宿舍楼下的时候，他推开门，侧了一下身。"}, {"s": 62.15, "e": 63.98, "t": "等我进去了，他才跟上来。"}, {"s": 63.98, "e": 65.05, "t": "那个动作很小。"}, {"s": 65.05, "e": 66.13, "t": "但我注意到了。"}, {"s": 66.13, "e": 68.42, "t": "第二天下午，我在食堂碰见了他。"}, {"s": 68.42, "e": 74.24, "t": "不是碰见——是我正在排队，他从另一边走过来，看了一眼队伍，然后站到了我后面。"}, {"s": 74.24, "e": 75.77, "t": "\"你也这个点吃饭？\""}, {"s": 75.77, "e": 76.23, "t": "他问。"}, {"s": 76.23, "e": 76.99, "t": "\"……对。"}, {"s": 76.99, "e": 77.76, "t": "你也是？\""}, {"s": 77.76, "e": 78.22, "t": "\"嗯。"}, {"s": 78.22, "e": 80.06, "t": "中午吃太早了，下午饿。\""}, {"s": 80.06, "e": 82.05, "t": "我们之间隔了一个人的距离。"}, {"s": 82.05, "e": 84.8, "t": "队伍往前挪了一点，他也往前挪了一点。"}, {"s": 84.8, "e": 92.15, "t": "中间还是隔了一个人的距离——但感觉和昨天走路的那个距离一样，不远不近，像一个已经被人量过的尺寸。"}, {"s": 92.15, "e": 94.44, "t": "打到饭之后，我端着盘子找位子。"}, {"s": 94.44, "e": 95.52, "t": "他跟在我后面。"}, {"s": 95.52, "e": 98.12, "t": "我坐下来的时候——他坐到了我对面。"}, {"s": 98.12, "e": 102.56, "t": "不是刻意选的位置——食堂的桌子，对面是空着的，他就坐下了。"}, {"s": 102.56, "e": 106.84, "t": "但我抬头的时候，看见他把餐盘放下，拆开筷子，低头开始吃。"}, {"s": 106.84, "e": 109.6, "t": "从头到尾没有问我\"我可以坐这里吗\"。"}, {"s": 109.6, "e": 110.82, "t": "他就直接坐下了。"}, {"s": 110.82, "e": 112.81, "t": "好像这件事已经不需要问了。"}, {"s": 112.81, "e": 114.8, "t": "我低头吃饭，吃得比平时快。"}, {"s": 114.8, "e": 119.85, "t": "不是因为饿——是因为我不知道和他在一张桌子上吃饭的时候应该说什么。"}, {"s": 119.85, "e": 121.54, "t": "但他好像没有这个困扰。"}, {"s": 121.54, "e": 125.06, "t": "他吃得很自然，偶尔夹一筷子菜，偶尔看一眼手机。"}, {"s": 125.06, "e": 129.19, "t": "吃到一半的时候，他把碗里的煎蛋夹起来，放到了我盘子里。"}, {"s": 129.19, "e": 129.96, "t": "我愣住了。"}, {"s": 129.96, "e": 130.72, "t": "\"你——\""}, {"s": 130.72, "e": 132.25, "t": "\"我不喜欢吃煎蛋。\""}, {"s": 132.25, "e": 133.17, "t": "他头也没抬。"}, {"s": 133.17, "e": 134.55, "t": "\"那你为什么打？\""}, {"s": 134.55, "e": 135.77, "t": "\"食堂阿姨给的。"}, {"s": 135.77, "e": 137.15, "t": "她说'不要煎蛋啊？"}, {"s": 137.15, "e": 138.53, "t": "'我说'要吧'。\""}, {"s": 138.53, "e": 140.21, "t": "\"……那你可以不拿。\""}, {"s": 140.21, "e": 141.28, "t": "\"已经打了。\""}, {"s": 141.28, "e": 142.05, "t": "他顿了顿。"}, {"s": 142.05, "e": 143.58, "t": "\"你帮我吃了就行。\""}, {"s": 143.58, "e": 148.94, "t": "我看着盘子里那个金黄色的煎蛋，蛋白的边缘煎得有点焦，是他盘子里过来的。"}, {"s": 148.94, "e": 150.93, "t": "我用筷子夹起来，咬了一口。"}, {"s": 150.93, "e": 152.46, "t": "和普通煎蛋一个味道。"}, {"s": 152.46, "e": 155.21, "t": "但不知道为什么——我觉得它挺好吃的。"}, {"s": 155.21, "e": 157.51, "t": "吃完饭后我们沿着操场走了半圈。"}, {"s": 157.51, "e": 160.88, "t": "不是散步——是回宿舍的路刚好从操场边上经过。"}, {"s": 160.88, "e": 165.77, "t": "走到操场中间那段的时候，路边有一盏路灯在闪，一亮一灭，一亮一灭。"}, {"s": 165.77, "e": 168.07, "t": "光落在他的侧脸上，忽明忽暗的。"}, {"s": 168.07, "e": 170.67, "t": "走到看台附近的时候，他忽然开口了。"}, {"s": 170.67, "e": 173.27, "t": "\"你昨天那本错题本——你看完了？\""}, {"s": 173.27, "e": 174.19, "t": "\"看完了。\""}, {"s": 174.19, "e": 175.42, "t": "\"有不懂的吗？\""}, {"s": 175.42, "e": 178.79, "t": "\"有一道——你画图的那题，第三问我没太懂。\""}, {"s": 178.79, "e": 179.7, "t": "他点了点头。"}, {"s": 179.7, "e": 181.39, "t": "\"晚上回去讲给你听。\""}, {"s": 181.39, "e": 184.3, "t": "他说\"晚上回去\"——他说的是\"回去\"。"}, {"s": 184.3, "e": 187.2, "t": "好像那个房间，已经默认是我们的房间了。"}, {"s": 187.2, "e": 190.42, "t": "晚上他到宿舍之后，第一件事就是坐到书桌前。"}, {"s": 190.42, "e": 191.95, "t": "\"把你那题拿出来。\""}, {"s": 191.95, "e": 194.86, "t": "他从抽屉里抽出一张草稿纸，把笔帽咬开。"}, {"s": 194.86, "e": 197.92, "t": "我坐到他旁边——隔了大概一个拳头的距离。"}, {"s": 197.92, "e": 199.3, "t": "他开始在纸上画图。"}, {"s": 199.3, "e": 203.58, "t": "画到第三步的时候，他的手指点在某一条辅助线上——停住了。"}, {"s": 203.58, "e": 205.88, "t": "\"这里——我当时也卡了很久。\""}, {"s": 205.88, "e": 208.63, "t": "他的手指按在纸上，指甲修剪得很干净。"}, {"s": 208.63, "e": 211.54, "t": "拇指按着纸面，食指沿着那条线划了一下。"}, {"s": 211.54, "e": 214.3, "t": "\"你从这个角连过去——能看到什么？\""}, {"s": 214.3, "e": 216.29, "t": "我盯着那张图看了大概五秒。"}, {"s": 216.29, "e": 218.12, "t": "\"……一个直角三角形？\""}, {"s": 218.12, "e": 218.58, "t": "\"对。"}, {"s": 218.58, "e": 222.41, "t": "\"他没有抬头，但声音里带着一点\"对了\"的那种轻快。"}, {"s": 222.41, "e": 223.33, "t": "\"然后呢？\""}, {"s": 223.33, "e": 224.86, "t": "\"然后——用勾股？\""}, {"s": 224.86, "e": 225.47, "t": "\"对。\""}, {"s": 225.47, "e": 228.99, "t": "他放下笔，往后靠了一点，让我自己把剩下的写完。"}, {"s": 228.99, "e": 232.21, "t": "我写完最后一个等号的时候，答案确实是对的。"}, {"s": 232.21, "e": 232.97, "t": "\"懂了？\""}, {"s": 232.97, "e": 233.74, "t": "\"懂了。\""}, {"s": 233.74, "e": 235.73, "t": "他点了下头，把笔帽盖回去。"}, {"s": 235.73, "e": 238.02, "t": "然后把那张草稿纸对折，递给我。"}, {"s": 238.02, "e": 238.64, "t": "\"留着。"}, {"s": 238.64, "e": 240.32, "t": "下次再看就不会忘了。\""}, {"s": 240.32, "e": 241.08, "t": "我接过来。"}, {"s": 241.08, "e": 243.07, "t": "那张纸还带着他手指的温度。"}, {"s": 243.07, "e": 246.44, "t": "<!-- summary:start -->"}, {"s": 246.44, "e": 247.51, "t": "本章推进线索："}, {"s": 247.51, "e": 251.8, "t": "- 🔵 第一次\"并排走\"——晚自习后回宿舍，自然变成并排"}, {"s": 251.8, "e": 257.0, "t": "- 🔵 第一次\"一起吃饭\"——食堂，博文主动坐到对面，把煎蛋夹给林深"}, {"s": 257.0, "e": 262.36, "t": "- 🔵 第一次\"面对面讲题\"——宿舍书桌前，隔一个拳头，共用一张草稿纸"}, {"s": 262.36, "e": 266.8, "t": "- 🔵 煎蛋细节——博文说\"帮我吃了就行\"——开始分享食物"}, {"s": 266.8, "e": 272.46, "t": "- 🔵 \"回去\"——博文说\"晚上回去讲给你听\"，已默认宿舍是\"我们一起的\""}, {"s": 272.46, "e": 273.99, "t": "本章关键事件时间戳："}, {"s": 273.99, "e": 277.21, "t": "- 2/20 晚自习后：第一次并排走回宿舍"}, {"s": 277.21, "e": 280.73, "t": "- 2/21 下午：第一次一起在食堂吃饭+煎蛋"}, {"s": 280.73, "e": 283.64, "t": "- 2/21 晚：宿舍书桌前面对面讲题"}, {"s": 283.64, "e": 284.4, "t": "下章钩子："}, {"s": 284.4, "e": 286.24, "t": "- 他开始记我的口味了。"}, {"s": 286.24, "e": 289.3, "t": "<!-- summary:end -->"}, {"s": 289.3, "e": 294.2, "t": "2026-07-19 初始版本：Ch 14 顺路——从同行到同席"}]}, {"num": 15, "title": "第15章 甜的", "file": "chapters/ch015.mp3", "dur": 175.1, "size_mb": 1.4, "segs": [{"s": 0.0, "e": 2.4, "t": "时间：2 月 22 日 · 高一下"}, {"s": 2.4, "e": 3.11, "t": "换座位了。"}, {"s": 3.11, "e": 6.65, "t": "按成绩排的——我 187 名，坐第 12 行附近。"}, {"s": 6.65, "e": 9.48, "t": "离他的距离从 80 厘米变成了 4 米。"}, {"s": 9.48, "e": 14.99, "t": "我到新座位坐下的时候，看了一眼他的方向——他坐在第 6 行靠窗，没有回头看我。"}, {"s": 14.99, "e": 17.96, "t": "但早自习开始之前，一杯豆浆出现在我的桌角。"}, {"s": 17.96, "e": 18.39, "t": "温的。"}, {"s": 18.39, "e": 21.92, "t": "我抬起头——他已经坐回自己的位置了，低着头在翻书。"}, {"s": 21.92, "e": 24.19, "t": "我握着那杯豆浆，手心被烫得发热。"}, {"s": 24.19, "e": 25.46, "t": "他记得我喜欢甜的。"}, {"s": 25.46, "e": 28.85, "t": "中午在食堂，吃完饭后我和他碰见了生物老师张老师。"}, {"s": 28.85, "e": 31.12, "t": "张老师认识他——他是生物课代表。"}, {"s": 31.12, "e": 33.52, "t": "看见我们走在一起，张老师笑了一下。"}, {"s": 33.52, "e": 35.64, "t": "\"博文，这次生物考得不错啊。\""}, {"s": 35.64, "e": 36.35, "t": "\"还行。\""}, {"s": 36.35, "e": 37.91, "t": "\"97 分还不叫不错？"}, {"s": 37.91, "e": 39.32, "t": "你打算多少才算好？\""}, {"s": 39.32, "e": 40.17, "t": "\"100。\""}, {"s": 40.17, "e": 43.28, "t": "张老师笑了——不是被顶撞的那种笑，是欣赏的。"}, {"s": 43.28, "e": 45.12, "t": "我也在旁边跟着松了一口气。"}, {"s": 45.12, "e": 50.63, "t": "他和老师说话的方式——不卑不亢，没有讨好，没有紧张——让我觉得他就是这样的人。"}, {"s": 50.63, "e": 53.18, "t": "他不需要在任何人面前变成另一种样子。"}, {"s": 53.18, "e": 55.3, "t": "张老师走了之后，他转过来看我。"}, {"s": 55.3, "e": 56.72, "t": "\"你这次生物多少？\""}, {"s": 56.72, "e": 57.71, "t": "\"……82。\""}, {"s": 57.71, "e": 59.69, "t": "\"那下周一中午，来我座位。\""}, {"s": 59.69, "e": 60.54, "t": "\"干什么？\""}, {"s": 60.54, "e": 61.24, "t": "\"教你。\""}, {"s": 61.24, "e": 62.23, "t": "他说完就走了。"}, {"s": 62.23, "e": 63.79, "t": "我站在原地，愣了一下。"}, {"s": 63.79, "e": 66.9, "t": "他说的不是\"帮你看看\"——他说的是\"教你\"。"}, {"s": 66.9, "e": 69.59, "t": "下午历史课结束的时候，我正在收拾课本。"}, {"s": 69.59, "e": 70.29, "t": "他走过来。"}, {"s": 70.29, "e": 71.43, "t": "\"明天一起走。\""}, {"s": 71.43, "e": 72.42, "t": "\"……去哪？\""}, {"s": 72.42, "e": 74.11, "t": "\"我今天要去生物实验室。"}, {"s": 74.11, "e": 75.1, "t": "你跟我一起。\""}, {"s": 75.1, "e": 76.94, "t": "他说完没等我回答，就走了。"}, {"s": 76.94, "e": 79.35, "t": "我坐在座位上，看着他走出去的背影。"}, {"s": 79.35, "e": 81.75, "t": "明天一起走——他没有问我愿不愿意。"}, {"s": 81.75, "e": 83.31, "t": "但我知道他为什么不问。"}, {"s": 83.31, "e": 85.15, "t": "因为我已经开始期待明天了。"}, {"s": 85.15, "e": 89.95, "t": "晚自习的时候，周海坐在我旁边，看了一眼我桌上那杯已经喝完的空豆浆杯。"}, {"s": 89.95, "e": 90.8, "t": "\"他买的？\""}, {"s": 90.8, "e": 91.65, "t": "\"……嗯。\""}, {"s": 91.65, "e": 92.64, "t": "\"每天都买？\""}, {"s": 92.64, "e": 93.63, "t": "\"不是每天。\""}, {"s": 93.63, "e": 95.05, "t": "\"那今天是第几次？\""}, {"s": 95.05, "e": 95.89, "t": "我想了一下。"}, {"s": 95.89, "e": 97.03, "t": "\"……第二次。\""}, {"s": 97.03, "e": 98.16, "t": "周海沉默了一下。"}, {"s": 98.16, "e": 98.87, "t": "\"林深。\""}, {"s": 98.87, "e": 99.43, "t": "\"嗯？\""}, {"s": 99.43, "e": 101.98, "t": "\"你有没有想过——他可能也喜欢你？\""}, {"s": 101.98, "e": 104.1, "t": "我握着那个空杯子的手指停住了。"}, {"s": 104.1, "e": 105.37, "t": "\"……他不可能。\""}, {"s": 105.37, "e": 106.22, "t": "\"为什么？\""}, {"s": 106.22, "e": 107.07, "t": "\"因为——\""}, {"s": 107.07, "e": 107.78, "t": "我停住了。"}, {"s": 107.78, "e": 108.48, "t": "因为什么？"}, {"s": 108.48, "e": 109.61, "t": "因为我配不上他？"}, {"s": 109.61, "e": 111.45, "t": "因为他那么亮而我那么普通？"}, {"s": 111.45, "e": 113.29, "t": "因为我不知道他喜欢我什么？"}, {"s": 113.29, "e": 114.14, "t": "我说不出来。"}, {"s": 114.14, "e": 115.98, "t": "周海看了我一眼，没有再问。"}, {"s": 115.98, "e": 117.68, "t": "但他走之前，说了一句话："}, {"s": 117.68, "e": 118.95, "t": "\"你等他主动找你。"}, {"s": 118.95, "e": 120.36, "t": "比你主动找他有用。\""}, {"s": 120.36, "e": 122.77, "t": "那天晚上，我躺在床上，看着天花板。"}, {"s": 122.77, "e": 125.6, "t": "等他主动找我——他今天已经主动了两次了。"}, {"s": 125.6, "e": 126.02, "t": "豆浆。"}, {"s": 126.02, "e": 126.73, "t": "教我生物。"}, {"s": 126.73, "e": 127.58, "t": "明天一起走。"}, {"s": 127.58, "e": 128.85, "t": "——这算不算主动？"}, {"s": 128.85, "e": 129.56, "t": "我不知道。"}, {"s": 129.56, "e": 131.54, "t": "但那个空豆浆杯，我一直没扔。"}, {"s": 131.54, "e": 133.52, "t": "放在书桌的角落里，放了三天。"}, {"s": 133.52, "e": 136.63, "t": "<!-- summary:start -->"}, {"s": 136.63, "e": 137.62, "t": "本章推进线索："}, {"s": 137.62, "e": 140.87, "t": "- 🔵 豆浆出现——博文记住了林深\"喜欢甜的\""}, {"s": 140.87, "e": 144.55, "t": "- 🔵 不卑不亢——博文与生物老师对话的人格侧面展示"}, {"s": 144.55, "e": 149.22, "t": "- 🔵 \"教你生物\" + \"明天一起走\"——博文的主动程度明显提升"}, {"s": 149.22, "e": 151.62, "t": "- 🔵 周海点破\"他可能也喜欢你\""}, {"s": 151.62, "e": 153.74, "t": "- 🔵 空豆浆杯放三天不舍得扔"}, {"s": 153.74, "e": 155.16, "t": "本章关键事件时间戳："}, {"s": 155.16, "e": 157.7, "t": "- 2/22 早自习：豆浆出现在桌角"}, {"s": 157.7, "e": 161.1, "t": "- 2/22 午饭后：碰见生物老师，\"不卑不亢\""}, {"s": 161.1, "e": 163.5, "t": "- 2/22 下午：\"明天一起走\""}, {"s": 163.5, "e": 164.21, "t": "下章钩子："}, {"s": 164.21, "e": 167.46, "t": "- 他说要教我生物，然后我看到了他眼睛里的光。"}, {"s": 167.46, "e": 170.29, "t": "<!-- summary:end -->"}, {"s": 170.29, "e": 175.1, "t": "2026-07-19 初始版本：Ch 15 甜的——甜豆浆与不卑不亢"}]}, {"num": 16, "title": "第16章 搭档", "file": "chapters/ch016.mp3", "dur": 247.9, "size_mb": 2.0, "segs": [{"s": 0.0, "e": 3.5, "t": "时间：2 月 23 日—25 日 · 高一下"}, {"s": 3.5, "e": 7.79, "t": "换座位之后，我和他的距离从 80 厘米变成了 4 米。"}, {"s": 7.79, "e": 9.06, "t": "但有些事情没变。"}, {"s": 9.06, "e": 12.88, "t": "每天早上我走到教室的时候，我桌上会放着一杯豆浆。"}, {"s": 12.88, "e": 18.45, "t": "第一次发现的时候，我还以为是别人放错了——塑料杯，封着盖子，还是温的。"}, {"s": 18.45, "e": 21.31, "t": "我拿起来看了看，杯子上没有任何标记。"}, {"s": 21.31, "e": 23.22, "t": "我回头看了一眼他的位置。"}, {"s": 23.22, "e": 25.76, "t": "他坐在第 6 行靠窗，已经在了。"}, {"s": 25.76, "e": 29.1, "t": "低着头在看书，桌角放着一杯一模一样的豆浆。"}, {"s": 29.1, "e": 31.64, "t": "我握着那杯豆浆，手心被烫得发热。"}, {"s": 31.64, "e": 32.92, "t": "他什么时候买的？"}, {"s": 32.92, "e": 34.51, "t": "他怎麼知道我喝甜的？"}, {"s": 34.51, "e": 36.1, "t": "他为什么要多买一杯？"}, {"s": 36.1, "e": 43.73, "t": "我想问他，但又不知道怎么开口——总不能拿着豆浆走过去说\"你是不是给我买的\"，万一他说\"不是\"呢？"}, {"s": 43.73, "e": 49.77, "t": "但我坐下来的时候，他刚好回过头来看了一眼——扫过我桌上的杯子，然后收回去了。"}, {"s": 49.77, "e": 50.41, "t": "就一眼。"}, {"s": 50.41, "e": 52.79, "t": "但那个眼神的意思是：你拿到了。"}, {"s": 52.79, "e": 54.22, "t": "后来我观察了一下。"}, {"s": 54.22, "e": 58.2, "t": "他每天早上大概 7 点 10 分到教室，先去食堂。"}, {"s": 58.2, "e": 62.17, "t": "回来的时候左手一杯豆浆，右手一杯豆浆——都是甜的。"}, {"s": 62.17, "e": 65.67, "t": "他把自己那杯放桌角，然后把另一杯放在我桌上。"}, {"s": 65.67, "e": 67.74, "t": "整个过程从不超过 3 秒。"}, {"s": 67.74, "e": 70.12, "t": "动作熟练得好像已经做了一百次。"}, {"s": 70.12, "e": 72.03, "t": "第三天早上我终于开口了。"}, {"s": 72.03, "e": 72.83, "t": "\"博文。\""}, {"s": 72.83, "e": 73.46, "t": "\"嗯？\""}, {"s": 73.46, "e": 75.05, "t": "\"豆浆——你买的？\""}, {"s": 75.05, "e": 76.01, "t": "他头也没抬。"}, {"s": 76.01, "e": 76.8, "t": "\"顺手。\""}, {"s": 76.8, "e": 79.19, "t": "\"……怎么会顺手就多买一杯？\""}, {"s": 79.19, "e": 80.78, "t": "他翻书的手停了一下。"}, {"s": 80.78, "e": 83.16, "t": "然后他说：\"因为知道你要喝。\""}, {"s": 83.16, "e": 85.55, "t": "语气平得像在说\"今天是周二\"。"}, {"s": 85.55, "e": 88.25, "t": "我握著那杯豆浆，一句话都说不出来。"}, {"s": 88.25, "e": 89.36, "t": "他知道我要喝。"}, {"s": 89.36, "e": 90.0, "t": "他买了。"}, {"s": 90.0, "e": 90.8, "t": "每天都买。"}, {"s": 90.8, "e": 92.86, "t": "周海大概是第一个注意到的。"}, {"s": 92.86, "e": 99.06, "t": "周五早上，他看着我桌上的豆浆，又看了一眼博文桌上的豆浆，然后把目光移到我脸上。"}, {"s": 99.06, "e": 100.02, "t": "\"他买的？\""}, {"s": 100.02, "e": 100.97, "t": "\"……嗯。\""}, {"s": 100.97, "e": 101.77, "t": "\"每天？\""}, {"s": 101.77, "e": 102.72, "t": "\"……嗯。\""}, {"s": 102.72, "e": 104.15, "t": "周海沉默了一会儿。"}, {"s": 104.15, "e": 107.02, "t": "然后他说：\"你们俩现在是什么组合？\""}, {"s": 107.02, "e": 108.45, "t": "\"什么什么组合？\""}, {"s": 108.45, "e": 111.47, "t": "\"就是——你们是不是已经是固定搭档了？"}, {"s": 111.47, "e": 115.44, "t": "早上一起来，中午一起吃饭，晚自习回宿舍也一起走。\""}, {"s": 115.44, "e": 119.9, "t": "我愣了一下，想说\"没有\"——但仔细一想，好像确实是这样。"}, {"s": 119.9, "e": 121.33, "t": "每天早上他带豆浆。"}, {"s": 121.33, "e": 126.57, "t": "中午有时候一起吃食堂，有时候不吃，但下午 4 点半他会在座位等我。"}, {"s": 126.57, "e": 132.78, "t": "晚自习结束后我们会一起走回宿舍——不用约，收拾书包站起来，他在门口，我跟上去。"}, {"s": 132.78, "e": 133.89, "t": "没有人约定过。"}, {"s": 133.89, "e": 135.32, "t": "但就是变成了这样。"}, {"s": 135.32, "e": 136.43, "t": "\"——不知道。"}, {"s": 136.43, "e": 137.07, "t": "\"我说。"}, {"s": 137.07, "e": 139.14, "t": "周海看了我一眼，没再问了。"}, {"s": 139.14, "e": 142.32, "t": "但他笑了一下——那种\"你心里有数\"的笑。"}, {"s": 142.32, "e": 143.59, "t": "周六下午没有课。"}, {"s": 143.59, "e": 147.56, "t": "我在宿舍看书，他坐在对面床，盘着腿，戴着一只耳机。"}, {"s": 147.56, "e": 148.68, "t": "房间里很安静。"}, {"s": 148.68, "e": 153.29, "t": "窗外的阳光在地板上画了一块斜斜的亮斑，灰尘在光柱里慢慢飘。"}, {"s": 153.29, "e": 156.31, "t": "我翻了一页书的时候，听见他换了一首歌。"}, {"s": 156.31, "e": 158.54, "t": "然后他把另一只耳机递了过来。"}, {"s": 158.54, "e": 159.33, "t": "\"听吗？\""}, {"s": 159.33, "e": 160.13, "t": "我接过来。"}, {"s": 160.13, "e": 162.03, "t": "耳机线上还带着他的温度。"}, {"s": 162.03, "e": 164.58, "t": "我坐到床沿上，把耳机塞进耳朵里。"}, {"s": 164.58, "e": 165.69, "t": "是一首英文歌。"}, {"s": 165.69, "e": 169.35, "t": "吉他前奏，男声很轻，唱到副歌的时候鼓点才进来。"}, {"s": 169.35, "e": 173.64, "t": "我听不太懂歌词，但旋律让那个下午的光线变得更慢了一些。"}, {"s": 173.64, "e": 174.6, "t": "他也没说话。"}, {"s": 174.6, "e": 180.48, "t": "我们就这样面对面坐着——隔了大概一米——各自看着自己的手机，共享同一首歌。"}, {"s": 180.48, "e": 181.43, "t": "耳机线不长。"}, {"s": 181.43, "e": 184.93, "t": "所以我们之间的距离，被那根白色的线固定住了。"}, {"s": 184.93, "e": 185.57, "t": "不算近。"}, {"s": 185.57, "e": 186.52, "t": "但也不算远。"}, {"s": 186.52, "e": 189.86, "t": "晚上我想了很久一个问题——我们这样算什么。"}, {"s": 189.86, "e": 190.34, "t": "朋友？"}, {"s": 190.34, "e": 191.45, "t": "比朋友近一点？"}, {"s": 191.45, "e": 192.56, "t": "还是我想多了？"}, {"s": 192.56, "e": 193.68, "t": "我找不到答案。"}, {"s": 193.68, "e": 198.61, "t": "但第二天早上我看见桌上那杯热豆浆的时候——我想，算了，不找了。"}, {"s": 198.61, "e": 199.56, "t": "管它算什么。"}, {"s": 199.56, "e": 201.63, "t": "反正每天早上都有一杯甜的。"}, {"s": 201.63, "e": 202.58, "t": "这样就够了。"}, {"s": 202.58, "e": 206.08, "t": "<!-- summary:start -->"}, {"s": 206.08, "e": 207.19, "t": "本章推进线索："}, {"s": 207.19, "e": 213.55, "t": "- 🔵 博文每天早上带一杯豆浆放在林深桌上——从偶发到固定，\"知道你喝\"确认偏移"}, {"s": 213.55, "e": 218.16, "t": "- 🔵 周海点破\"固定搭档\"——外部视角确认两人的关系状态"}, {"s": 218.16, "e": 223.73, "t": "- 🔵 宿舍共享耳机：耳机线固定了距离——物理距离约1米，情感距离≈0"}, {"s": 223.73, "e": 228.18, "t": "- 🔵 林深放弃定义关系：\"管它算什么\"，接受当下的状态"}, {"s": 228.18, "e": 229.77, "t": "本章关键事件时间戳："}, {"s": 229.77, "e": 232.63, "t": "- 2/23-2/25：豆浆每天出现"}, {"s": 232.63, "e": 236.13, "t": "- 2/25（周六下午）：宿舍里共享耳机听歌"}, {"s": 236.13, "e": 236.93, "t": "下章钩子："}, {"s": 236.93, "e": 239.47, "t": "- 然后他回过头，对我笑了一下。"}, {"s": 239.47, "e": 242.65, "t": "<!-- summary:end -->"}, {"s": 242.65, "e": 247.9, "t": "2026-07-19 初始版本：Ch 16 搭档——固定组合的形成"}]}, {"num": 17, "title": "第17章 80 厘米的亮", "file": "chapters/ch017.mp3", "dur": 134.6, "size_mb": 1.1, "segs": [{"s": 0.0, "e": 2.34, "t": "时间：2 月 26 日 · 高一下"}, {"s": 2.34, "e": 3.85, "t": "周一中午我去他座位了。"}, {"s": 3.85, "e": 9.9, "t": "他已经把桌子收拾好了——书推到左上角，笔记本翻开到空白页，桌面上清出了一块属于我的位置。"}, {"s": 9.9, "e": 12.79, "t": "他让我坐在他旁边，然后他拿起笔，开始画图。"}, {"s": 12.79, "e": 15.26, "t": "两个圆——一个大一个小——画在一起。"}, {"s": 15.26, "e": 16.36, "t": "光反应，暗反应。"}, {"s": 16.36, "e": 19.39, "t": "他一边画一边讲，从类囊体薄膜讲到卡尔文循环。"}, {"s": 19.39, "e": 21.86, "t": "我坐在他旁边，距离大概 80 厘米。"}, {"s": 21.86, "e": 25.16, "t": "他低头画图的时候，会先画一个圈，然后在圈里标字。"}, {"s": 25.16, "e": 28.46, "t": "标完之后他会抬起头看我一眼——确认我听懂了没有。"}, {"s": 28.46, "e": 31.76, "t": "然后他抬头的那一瞬间——我看见了他眼睛里的东西。"}, {"s": 31.76, "e": 32.45, "t": "不是瞳孔。"}, {"s": 32.45, "e": 33.13, "t": "不是睫毛。"}, {"s": 33.13, "e": 38.63, "t": "是光——从窗户外面照进来的阳光，落在他的眼睛里面，让他的整个虹膜看起来像在发光。"}, {"s": 38.63, "e": 40.01, "t": "不是亮的——是亮的。"}, {"s": 40.01, "e": 43.58, "t": "80 厘米的距离，我甚至能看见那团光里反射出来的我。"}, {"s": 43.58, "e": 44.13, "t": "我的脸。"}, {"s": 44.13, "e": 44.96, "t": "在他眼睛里。"}, {"s": 44.96, "e": 47.43, "t": "我低下头，假装在看那个光合作用的图。"}, {"s": 47.43, "e": 50.73, "t": "但我记住了那个画面——他的眼睛里有光，光里有我。"}, {"s": 50.73, "e": 51.56, "t": "下午历史课。"}, {"s": 51.56, "e": 57.61, "t": "上课到一半的时候，我走神了——我在草稿纸上画了一个圆圈，然后在里面标了\"光反应\"三个字。"}, {"s": 57.61, "e": 59.12, "t": "然后我听到了一声轻响。"}, {"s": 59.12, "e": 60.49, "t": "我抬头——他回头了。"}, {"s": 60.49, "e": 63.66, "t": "不是侧头——是整个人往右转了一下，看了我一眼。"}, {"s": 63.66, "e": 68.19, "t": "然后他笑了一下——不是嘴角动，是真的笑——眼睛底下那一块皱了一下。"}, {"s": 68.19, "e": 69.57, "t": "不到 1 厘米的皱。"}, {"s": 69.57, "e": 70.67, "t": "然后他转回去了。"}, {"s": 70.67, "e": 74.79, "t": "我捏着笔，在草稿纸上的\"光反应\"旁边画了一个歪歪扭扭的箭头。"}, {"s": 74.79, "e": 75.76, "t": "指向他的方向。"}, {"s": 75.76, "e": 77.54, "t": "晚自习的时候，周海凑过来。"}, {"s": 77.54, "e": 79.61, "t": "\"他今天历史课回头对你笑了。\""}, {"s": 79.61, "e": 80.43, "t": "\"……嗯。\""}, {"s": 80.43, "e": 82.22, "t": "\"你知道这意味着什么吗？\""}, {"s": 82.22, "e": 83.18, "t": "\"……什么？\""}, {"s": 83.18, "e": 84.14, "t": "\"他在看你。\""}, {"s": 84.14, "e": 84.69, "t": "周海说。"}, {"s": 84.69, "e": 87.17, "t": "\"上课的时候不看黑板——回头看你。\""}, {"s": 87.17, "e": 87.85, "t": "我没回答。"}, {"s": 87.85, "e": 88.54, "t": "但我知道。"}, {"s": 88.54, "e": 90.47, "t": "我看见了——他眼睛底下的皱。"}, {"s": 90.47, "e": 92.8, "t": "不是 5 米外的玻璃反光里看到的。"}, {"s": 92.8, "e": 95.83, "t": "是 80 厘米外、能看清他每一根睫毛的距离。"}, {"s": 95.83, "e": 97.34, "t": "他回头看我，然后笑了。"}, {"s": 97.34, "e": 100.37, "t": "<!-- summary:start -->"}, {"s": 100.37, "e": 101.33, "t": "本章推进线索："}, {"s": 101.33, "e": 105.59, "t": "- 🔵 80 厘米的亮——林深第一次在博文眼睛里看到自己的倒影"}, {"s": 105.59, "e": 109.16, "t": "- 🔵 博文教光合作用——光反应/暗反应图的经典场景"}, {"s": 109.16, "e": 113.7, "t": "- 🔵 眼睛底下皱了一下（1 厘米的皱）——博文的标志表情首次出现"}, {"s": 113.7, "e": 115.35, "t": "- 🔵 周海\"他在看你\""}, {"s": 115.35, "e": 116.73, "t": "本章关键事件时间戳："}, {"s": 116.73, "e": 120.44, "t": "- 2/26 中午：博文教光合作用，林深看到眼睛里的光"}, {"s": 120.44, "e": 123.05, "t": "- 2/26 历史课：博文回头笑了一下"}, {"s": 123.05, "e": 123.74, "t": "下章钩子："}, {"s": 123.74, "e": 125.8, "t": "- 高二开学，他带了两个水瓶。"}, {"s": 125.8, "e": 128.55, "t": "<!-- summary:end -->"}, {"s": 128.55, "e": 134.6, "t": "2026-07-19 初始版本：Ch 17 80 厘米的亮——眼睛里的光与 1 厘米的皱"}]}, {"num": 18, "title": "第18章 三十厘米", "file": "chapters/ch018.mp3", "dur": 217.6, "size_mb": 1.7, "segs": [{"s": 0.0, "e": 3.2, "t": "时间：2 月 27 日—28 日 · 高一下"}, {"s": 3.2, "e": 4.37, "t": "我发现了一件事。"}, {"s": 4.37, "e": 9.17, "t": "不知道从什么时候开始——我和他之间的距离，已经不需要我刻意去量了。"}, {"s": 9.17, "e": 18.92, "t": "以前我算得很清楚：隔着天井的时候是 5 米，坐在他后面的时候是 80 厘米，换座位之后变成 4 米，绕操场散步的时候大概 50 厘米。"}, {"s": 18.92, "e": 28.09, "t": "但现在我在宿舍里，坐在他床上，背靠着墙，他坐在我旁边，把我做错的物理卷子摊在两个人中间——我们的肩膀之间大概隔了 30 厘米。"}, {"s": 28.09, "e": 29.26, "t": "不是刻意拉近的。"}, {"s": 29.26, "e": 30.86, "t": "是自然而然变成这样的。"}, {"s": 30.86, "e": 31.88, "t": "起因是这样的。"}, {"s": 31.88, "e": 35.95, "t": "周日晚上的物理作业有一道大题，我做了三遍都跟答案对不上。"}, {"s": 35.95, "e": 40.75, "t": "我坐在书桌前咬着笔帽盯着草稿纸，盯了快十分钟，还是一点头绪都没有。"}, {"s": 40.75, "e": 41.48, "t": "\"哪题？\""}, {"s": 41.48, "e": 42.94, "t": "他的声音从背后传来。"}, {"s": 42.94, "e": 47.45, "t": "我回头——他坐在床上，手里拿着一本书，大概是看我坐那儿太久了。"}, {"s": 47.45, "e": 48.47, "t": "\"最后一道。\""}, {"s": 48.47, "e": 50.36, "t": "他放下书，站起来，走过来。"}, {"s": 50.36, "e": 53.56, "t": "他没有坐回自己的书桌——他直接坐到了我旁边。"}, {"s": 53.56, "e": 54.15, "t": "我的床。"}, {"s": 54.15, "e": 55.02, "t": "他坐下来了。"}, {"s": 55.02, "e": 57.2, "t": "我往旁边挪了一点，给他腾位置。"}, {"s": 57.2, "e": 62.73, "t": "他坐下来的时候，床垫往下陷了一点——他往我这边偏了一下，肩膀碰到了我的肩膀。"}, {"s": 62.73, "e": 63.46, "t": "\"这题？\""}, {"s": 63.46, "e": 65.35, "t": "他把卷子拿起来，低头看题。"}, {"s": 65.35, "e": 69.14, "t": "好像碰到我的肩膀这件事，在他那里没有任何值得注意的。"}, {"s": 69.14, "e": 70.45, "t": "但我僵了大概两秒。"}, {"s": 70.45, "e": 72.63, "t": "然后我才想起回答：\"……对。\""}, {"s": 72.63, "e": 74.09, "t": "他开始在草稿上演算。"}, {"s": 74.09, "e": 78.16, "t": "写的步骤不多，每一步之间停一下，像是在确认思路没有跑偏。"}, {"s": 78.16, "e": 80.64, "t": "他的手指按在纸面上，指节微微发白。"}, {"s": 80.64, "e": 82.82, "t": "写到第三步的时候，他停了一下。"}, {"s": 82.82, "e": 83.84, "t": "\"你卡在哪？\""}, {"s": 83.84, "e": 84.86, "t": "\"——第二问。"}, {"s": 84.86, "e": 87.91, "t": "我算出 h 但到不了 \\Delta t。\""}, {"s": 87.91, "e": 89.81, "t": "\"你 h 用的什么公式？\""}, {"s": 89.81, "e": 91.99, "t": "\"自由落体——h=½gt²。\""}, {"s": 91.99, "e": 94.9, "t": "\"那到了 \\Delta t 要换什么？\""}, {"s": 94.9, "e": 95.92, "t": "\"……能量？\""}, {"s": 95.92, "e": 96.5, "t": "\"对。\""}, {"s": 96.5, "e": 100.58, "t": "他侧过脸来看我——那个距离近到我甚至能看清他睫毛的弧度。"}, {"s": 100.58, "e": 103.05, "t": "然后他又转回去了，在纸上补了两行。"}, {"s": 103.05, "e": 105.09, "t": "\"用能量守恒大思路就顺了。\""}, {"s": 105.09, "e": 107.85, "t": "他放下笔，往后靠了一点，把空间让给我。"}, {"s": 107.85, "e": 112.22, "t": "我低头看那张纸——他的字写得很清楚，每一步都在旁边标了根据。"}, {"s": 112.22, "e": 114.26, "t": "最后一行是答案，画了一个圈。"}, {"s": 114.26, "e": 116.88, "t": "我拿起笔，顺着他的思路重新写了一遍。"}, {"s": 116.88, "e": 118.19, "t": "这次一次就对了。\""}, {"s": 118.19, "e": 118.77, "t": "懂了？\""}, {"s": 118.77, "e": 119.5, "t": "\"懂了。\""}, {"s": 119.5, "e": 120.95, "t": "他点了点头，站起来。"}, {"s": 120.95, "e": 124.59, "t": "从他坐到我旁边到站起来——整个过程大概 7 分钟。"}, {"s": 124.59, "e": 127.79, "t": "但我记住了那 7 分钟里他肩膀贴着我的触感。"}, {"s": 127.79, "e": 129.98, "t": "第二天中午，我在走廊上碰见他。"}, {"s": 129.98, "e": 132.6, "t": "他从办公室出来，手里抱着一摞作业本。"}, {"s": 132.6, "e": 134.49, "t": "看见我的时候，他停了一下。"}, {"s": 134.49, "e": 137.98, "t": "\"你昨天那道题——类似的还有一道，我放你桌上了。"}, {"s": 137.98, "e": 139.15, "t": "你下午做一下。\""}, {"s": 139.15, "e": 140.02, "t": "\"……好。\""}, {"s": 140.02, "e": 141.62, "t": "他走了两步，又停下来。"}, {"s": 141.62, "e": 142.93, "t": "\"做完不用给我看。"}, {"s": 142.93, "e": 144.53, "t": "你自己知道对错就行。\""}, {"s": 144.53, "e": 145.99, "t": "他说完就往前走远了。"}, {"s": 145.99, "e": 148.03, "t": "我站在走廊上，看着他的背影。"}, {"s": 148.03, "e": 151.52, "t": "他放了一题在我桌上——不是老师布置的，是他找的。"}, {"s": 151.52, "e": 152.25, "t": "特意找的。"}, {"s": 152.25, "e": 156.9, "t": "晚自习的时候，我做完了他留的那道题，在答案旁边画了一个小小的勾。"}, {"s": 156.9, "e": 158.21, "t": "其实他不在我旁边。"}, {"s": 158.21, "e": 166.37, "t": "但我画那个勾的时候，脑子里想的是昨天晚上他坐在我旁边讲题的样子——他低头画图，手指点在某一条线上，他说\"这里\"。"}, {"s": 166.37, "e": 168.69, "t": "我低头看卷子上自己写出来的答案。"}, {"s": 168.69, "e": 171.75, "t": "30 厘米的距离，好像比我想象中更近一些。"}, {"s": 171.75, "e": 174.95, "t": "<!-- summary:start -->"}, {"s": 174.95, "e": 175.97, "t": "本章推进线索："}, {"s": 175.97, "e": 181.21, "t": "- 🔵 物理边界首次实质跨越：博文主动坐到林深床上（同坐一床），肩膀相碰"}, {"s": 181.21, "e": 186.45, "t": "- 🔵 博文主动为林深找同类题目——\"做完不用给我看\"（信任他的判断力）"}, {"s": 186.45, "e": 190.67, "t": "- 🔵 距离从厘米级变成\"不需要量了\"——物理距离的自然化"}, {"s": 190.67, "e": 195.48, "t": "- 🔵 林深从\"刻意注意距离\"到\"习惯了这个距离\"——心理防线消融"}, {"s": 195.48, "e": 196.93, "t": "本章关键事件时间戳："}, {"s": 196.93, "e": 201.15, "t": "- 2/27 晚：宿舍，博文坐林深床上讲物理——肩膀碰肩膀"}, {"s": 201.15, "e": 204.5, "t": "- 2/28：博文额外放了一道同类题在林深桌上"}, {"s": 204.5, "e": 205.66, "t": "本章新埋伏笔：无"}, {"s": 205.66, "e": 206.39, "t": "下章钩子："}, {"s": 206.39, "e": 207.99, "t": "- 快到选科的时候了。"}, {"s": 207.99, "e": 209.45, "t": "我想知道他会选什么。"}, {"s": 209.45, "e": 212.36, "t": "<!-- summary:end -->"}, {"s": 212.36, "e": 217.6, "t": "2026-07-19 初始版本：Ch 18 三十厘米——身体边界自然消融"}]}, {"num": 19, "title": "第19章 小深", "file": "chapters/ch019.mp3", "dur": 208.2, "size_mb": 1.7, "segs": [{"s": 0.0, "e": 2.0, "t": "时间：3 月下旬 · 高一下"}, {"s": 2.0, "e": 3.99, "t": "选科的通知是三月中旬下来的。"}, {"s": 3.99, "e": 6.7, "t": "一张表，每人一份，要在周五之前交上去。"}, {"s": 6.7, "e": 10.4, "t": "\"物理、化学、生物\"——我在那三个格子前面站了很久。"}, {"s": 10.4, "e": 11.12, "t": "不是犹豫。"}, {"s": 11.12, "e": 11.97, "t": "是太确定了。"}, {"s": 11.97, "e": 13.11, "t": "确定得有点心虚。"}, {"s": 13.11, "e": 16.96, "t": "因为我知道他会选什么——他上学期说过他喜欢物理和生物。"}, {"s": 16.96, "e": 19.67, "t": "所以\"物化生\"对我来说根本不需要考虑。"}, {"s": 19.67, "e": 20.81, "t": "不是因为我喜欢。"}, {"s": 20.81, "e": 21.8, "t": "是因为他要选。"}, {"s": 21.8, "e": 24.94, "t": "交表之前的那天晚上，我在宿舍对着那张纸发呆。"}, {"s": 24.94, "e": 30.07, "t": "他洗完澡进来，头发还是湿的，用毛巾搭在头上擦了两下，看了一眼我手里的表。"}, {"s": 30.07, "e": 31.07, "t": "\"你还没交？\""}, {"s": 31.07, "e": 32.06, "t": "\"……在想。\""}, {"s": 32.06, "e": 34.06, "t": "他坐下来，把毛巾挂到椅背上。"}, {"s": 34.06, "e": 35.2, "t": "\"你想选什么？\""}, {"s": 35.2, "e": 36.05, "t": "\"不知道。\""}, {"s": 36.05, "e": 37.05, "t": "这句话是假的。"}, {"s": 37.05, "e": 38.62, "t": "我知道——我早就知道。"}, {"s": 38.62, "e": 41.18, "t": "我只是不想让他觉得我是因为他才选的。"}, {"s": 41.18, "e": 42.32, "t": "但他看了我一眼。"}, {"s": 42.32, "e": 46.6, "t": "然后他说了一句话——语气很随意，像在说一件没什么大不了的事："}, {"s": 46.6, "e": 47.74, "t": "\"我选物化生。\""}, {"s": 47.74, "e": 49.45, "t": "我握着笔的手指紧了一下。"}, {"s": 49.45, "e": 50.3, "t": "\"……哦。\""}, {"s": 50.3, "e": 51.02, "t": "\"你呢？\""}, {"s": 51.02, "e": 52.16, "t": "我低头看那张表。"}, {"s": 52.16, "e": 56.43, "t": "然后我在\"物理\"\"化学\"\"生物\"三个格子前面，各打了一个勾。"}, {"s": 56.43, "e": 57.57, "t": "\"我也选这个。\""}, {"s": 57.57, "e": 61.42, "t": "他看了一眼我的表，没有说\"你也选这个啊\"或者\"好巧\"。"}, {"s": 61.42, "e": 62.56, "t": "他只是点了点头。"}, {"s": 62.56, "e": 66.12, "t": "然后把他的表也拿了出来——三个勾，和我的一模一样。"}, {"s": 66.12, "e": 67.55, "t": "\"以后课表一样了。\""}, {"s": 67.55, "e": 67.97, "t": "他说。"}, {"s": 67.97, "e": 69.11, "t": "语气还是那么平。"}, {"s": 69.11, "e": 72.25, "t": "但我注意到——他说完之后，嘴角往上翘了一点。"}, {"s": 72.25, "e": 75.53, "t": "选科表交上去之后，班主任在班会上念了统计结果。"}, {"s": 75.53, "e": 77.24, "t": "\"物化生——27 人。\""}, {"s": 77.24, "e": 81.09, "t": "我坐在座位上，听到这个数字的时候，心里悄悄松了一口气。"}, {"s": 81.09, "e": 83.94, "t": "全班 45 个人，选了物化生的是大多数。"}, {"s": 83.94, "e": 86.07, "t": "我和他都在那 27 个人里面。"}, {"s": 86.07, "e": 88.21, "t": "下个学期——我们还在同一个班。"}, {"s": 88.21, "e": 91.77, "t": "不，不止——同一个教室、同一张课表、同一间实验室。"}, {"s": 91.77, "e": 92.63, "t": "同一个方向。"}, {"s": 92.63, "e": 94.77, "t": "这个认知让我在座位上坐了很久。"}, {"s": 94.77, "e": 96.76, "t": "周海在旁边看了一眼我的表情。"}, {"s": 96.76, "e": 98.33, "t": "\"你怎么笑得那么傻？\""}, {"s": 98.33, "e": 99.18, "t": "\"我没有。\""}, {"s": 99.18, "e": 102.18, "t": "\"你脸上写着：'我和他选了同一个组合'。\""}, {"s": 102.18, "e": 103.32, "t": "我把脸转到窗外。"}, {"s": 103.32, "e": 106.74, "t": "窗外的阳光很亮——三月底的春天，风已经有了暖意。"}, {"s": 106.74, "e": 107.59, "t": "我确实在笑。"}, {"s": 107.59, "e": 108.87, "t": "但我没让周海看见。"}, {"s": 108.87, "e": 110.01, "t": "周五晚上，宿舍。"}, {"s": 110.01, "e": 111.15, "t": "我坐在床上看书。"}, {"s": 111.15, "e": 113.01, "t": "他从外面进来，顺手关上门。"}, {"s": 113.01, "e": 114.29, "t": "然后他叫了我一声。"}, {"s": 114.29, "e": 115.0, "t": "\"小深。\""}, {"s": 115.0, "e": 115.71, "t": "我抬起头。"}, {"s": 115.71, "e": 117.14, "t": "\"……你叫我什么？\""}, {"s": 117.14, "e": 117.71, "t": "\"小深。"}, {"s": 117.71, "e": 119.7, "t": "\"他又说了一遍，语气很自然。"}, {"s": 119.7, "e": 120.56, "t": "\"怎么了？\""}, {"s": 120.56, "e": 121.84, "t": "\"没——没怎么。\""}, {"s": 121.84, "e": 123.55, "t": "我低下头，假装继续看书。"}, {"s": 123.55, "e": 126.54, "t": "但我的手指捏着书页的边缘，捏出了一道印子。"}, {"s": 126.54, "e": 127.68, "t": "他叫我\"小深\"。"}, {"s": 127.68, "e": 129.39, "t": "不是林深——是\"小深\"。"}, {"s": 129.39, "e": 131.25, "t": "这个世界上只有他这么叫我。"}, {"s": 131.25, "e": 131.96, "t": "\"小深。\""}, {"s": 131.96, "e": 134.24, "t": "熄灯之后，他在黑暗里又叫了一声。"}, {"s": 134.24, "e": 134.81, "t": "\"嗯？\""}, {"s": 134.81, "e": 136.52, "t": "\"你为什么会选物化生？\""}, {"s": 136.52, "e": 138.66, "t": "黑暗中，他的声音比平时轻一些。"}, {"s": 138.66, "e": 139.8, "t": "我沉默了一会儿。"}, {"s": 139.8, "e": 141.94, "t": "\"因为——我想跟你同一个班。\""}, {"s": 141.94, "e": 144.36, "t": "这句话说出口之后，我立刻就后悔了。"}, {"s": 144.36, "e": 145.07, "t": "太直白了。"}, {"s": 145.07, "e": 145.5, "t": "太——"}, {"s": 145.5, "e": 147.49, "t": "但黑暗里传来一个很轻的声音。"}, {"s": 147.49, "e": 148.49, "t": "像是笑了一下。"}, {"s": 148.49, "e": 150.06, "t": "然后他说：\"我知道。\""}, {"s": 150.06, "e": 151.77, "t": "那两个字——很轻，很短。"}, {"s": 151.77, "e": 153.34, "t": "但让我一整夜都没睡着。"}, {"s": 153.34, "e": 156.47, "t": "<!-- summary:start -->"}, {"s": 156.47, "e": 157.47, "t": "本章推进线索："}, {"s": 157.47, "e": 163.17, "t": "- 🔵 选科分流：两人一致选物化生——未来两年同课表、同教室、同实验室的物理保证"}, {"s": 163.17, "e": 168.3, "t": "- 🔵 专属称呼 \"小深\"——博文首次叫出这个只有他用的名字，且叫了两遍"}, {"s": 168.3, "e": 172.15, "t": "- 🔵 林深第一次在对话中直说\"因为我想跟你同一个班\""}, {"s": 172.15, "e": 176.28, "t": "- 🔵 博文回答\"我知道\"——首次正面承认他一直在意这件事"}, {"s": 176.28, "e": 177.7, "t": "本章关键事件时间戳："}, {"s": 177.7, "e": 179.41, "t": "- 3月中旬：选科表下发"}, {"s": 179.41, "e": 182.41, "t": "- 某天晚上：宿舍里博文先说\"我选物化生\""}, {"s": 182.41, "e": 186.54, "t": "- 交表后：班主任公布选科结果（物化生27人，两人都在内）"}, {"s": 186.54, "e": 188.82, "t": "- 周五晚：博文第一次叫\"小深\""}, {"s": 188.82, "e": 192.81, "t": "- 熄灯后：林深说\"因为想跟你同班\"，博文回答\"我知道\""}, {"s": 192.81, "e": 193.81, "t": "本章新埋伏笔："}, {"s": 193.81, "e": 197.23, "t": "- F-小深：专属称呼，以后在整个故事中固定使用"}, {"s": 197.23, "e": 197.94, "t": "下章钩子："}, {"s": 197.94, "e": 200.36, "t": "- 高二开学那天，他带了两个水瓶。"}, {"s": 200.36, "e": 203.21, "t": "<!-- summary:end -->"}, {"s": 203.21, "e": 208.2, "t": "2026-07-19 初始版本：Ch 19 小深——选科分流与专属称呼"}]}, {"num": 20, "title": "第20章 开学", "file": "chapters/ch020.mp3", "dur": 70.4, "size_mb": 0.6, "segs": [{"s": 0.0, "e": 2.52, "t": "时间：9 月 8 日 · 高二上开学第一天"}, {"s": 2.52, "e": 5.16, "t": "高二开学那天，我走进教室的时候，他已经在了。"}, {"s": 5.16, "e": 7.92, "t": "他坐在倒数第三排靠窗——和上学期差不多的位置。"}, {"s": 7.92, "e": 11.39, "t": "我习惯性地往他后面走——然后发现自己已经不需要坐他后面了。"}, {"s": 11.39, "e": 14.39, "t": "我们选了同一个组合，同一间教室，连桌子都是同一排。"}, {"s": 14.39, "e": 15.95, "t": "我走到他旁边的位置坐下来。"}, {"s": 15.95, "e": 17.27, "t": "他把一瓶水推到我桌上。"}, {"s": 17.27, "e": 17.99, "t": "\"给你的。\""}, {"s": 17.99, "e": 19.19, "t": "\"……你自己带的？\""}, {"s": 19.19, "e": 19.55, "t": "\"嗯。"}, {"s": 19.55, "e": 20.27, "t": "带了两瓶。\""}, {"s": 20.27, "e": 23.63, "t": "我拿起那瓶水——瓶身是凉的，应该是他早上从宿舍带出来的。"}, {"s": 23.63, "e": 25.43, "t": "他桌角放着另一瓶，一模一样的。"}, {"s": 25.43, "e": 27.1, "t": "从高一下开始，他给我带豆浆。"}, {"s": 27.1, "e": 28.9, "t": "高二上开学第一天，他给我带水。"}, {"s": 28.9, "e": 31.06, "t": "我拧开盖子喝了一口——普通的凉白开。"}, {"s": 31.06, "e": 32.62, "t": "但我觉得它比任何饮料都甜。"}, {"s": 32.62, "e": 35.02, "t": "那天下午，他路过我座位的时候，停了一下。"}, {"s": 35.02, "e": 36.82, "t": "\"以后每天下午 4 点半——\""}, {"s": 36.82, "e": 37.42, "t": "他顿了顿。"}, {"s": 37.42, "e": 38.38, "t": "\"——你来找我。"}, {"s": 38.38, "e": 39.94, "t": "我把我的物理笔记给你看。\""}, {"s": 39.94, "e": 40.66, "t": "我抬头看他。"}, {"s": 40.66, "e": 41.26, "t": "\"每天？\""}, {"s": 41.26, "e": 41.86, "t": "\"每天。\""}, {"s": 41.86, "e": 44.73, "t": "他说的不是\"有空的时候\"或者\"你有问题的时候\"。"}, {"s": 44.73, "e": 45.81, "t": "他说的是\"每天\"。"}, {"s": 45.81, "e": 48.45, "t": "<!-- summary:start -->"}, {"s": 48.45, "e": 49.29, "t": "本章推进线索："}, {"s": 49.29, "e": 52.89, "t": "- 🔵 高二开学——博文带两瓶水，\"带了两瓶\"（升级版豆浆）"}, {"s": 52.89, "e": 57.21, "t": "- 🔵 \"每天下午 4 点半\"——固定讲题时间的开端（指向 Ch 27）"}, {"s": 57.21, "e": 58.41, "t": "本章关键事件时间戳："}, {"s": 58.41, "e": 61.41, "t": "- 9/8 高二开学：博文带水、约定每天 4:30"}, {"s": 61.41, "e": 62.0, "t": "下章钩子："}, {"s": 62.0, "e": 64.04, "t": "- 老师说：两人一组，自己找搭档。"}, {"s": 64.04, "e": 66.44, "t": "<!-- summary:end -->"}, {"s": 66.44, "e": 70.4, "t": "2026-07-19 初始版本：Ch 20 开学——高二开学第一天"}]}, {"num": 21, "title": "第21章 同一组", "file": "chapters/ch021.mp3", "dur": 198.9, "size_mb": 1.6, "segs": [{"s": 0.0, "e": 2.14, "t": "时间：9 月中旬 · 高二上"}, {"s": 2.14, "e": 5.5, "t": "高二开学的第二周，生物课上，老师说了一句话："}, {"s": 5.5, "e": 7.33, "t": "\"下节课实验，两人一组。"}, {"s": 7.33, "e": 8.4, "t": "自己找搭档。\""}, {"s": 8.4, "e": 11.46, "t": "教室里安静了一秒，然后开始嗡嗡地响起来。"}, {"s": 11.46, "e": 12.83, "t": "我坐在座位上没动。"}, {"s": 12.83, "e": 16.5, "t": "不是因为我不想找人——是因为我还没想好怎么开口。"}, {"s": 16.5, "e": 18.79, "t": "然后我听见前面的椅子响了一声。"}, {"s": 18.79, "e": 19.71, "t": "他站了起来。"}, {"s": 19.71, "e": 20.62, "t": "走到我桌边。"}, {"s": 20.62, "e": 21.23, "t": "\"走。\""}, {"s": 21.23, "e": 22.3, "t": "\"……去哪？\""}, {"s": 22.3, "e": 23.07, "t": "\"实验室。"}, {"s": 23.07, "e": 24.29, "t": "趁他们还在分。\""}, {"s": 24.29, "e": 29.64, "t": "他站在我桌旁，手插在校服口袋里，表情很平常——像\"去食堂\"一样的语气。"}, {"s": 29.64, "e": 31.47, "t": "我以为他会等我说\"好\"。"}, {"s": 31.47, "e": 32.23, "t": "但他没等。"}, {"s": 32.23, "e": 34.37, "t": "他说完之后就转身往门口走了。"}, {"s": 34.37, "e": 35.75, "t": "我背上书包跟上去。"}, {"s": 35.75, "e": 40.33, "t": "走到门口的时候，我听见后面有人喊了一句：\"博文你们一组啊？\""}, {"s": 40.33, "e": 41.09, "t": "他没回头。"}, {"s": 41.09, "e": 42.47, "t": "\"对，我们一组。\""}, {"s": 42.47, "e": 44.15, "t": "实验室在实验楼的二楼。"}, {"s": 44.15, "e": 47.97, "t": "宽大的台面，每个台子上摆着一个显微镜和一盒载玻片。"}, {"s": 47.97, "e": 49.65, "t": "我们选了靠窗的那一组。"}, {"s": 49.65, "e": 53.62, "t": "他把实验服穿上——白色的，有点大，袖口往上卷了两圈。"}, {"s": 53.62, "e": 58.51, "t": "我低头穿上自己的实验服，余光看见他在扣扣子，从下往上，动作不快。"}, {"s": 58.51, "e": 60.8, "t": "今天的实验是观察洋葱表皮细胞。"}, {"s": 60.8, "e": 63.24, "t": "老师讲完步骤之后，我低头切洋葱。"}, {"s": 63.24, "e": 65.23, "t": "切了两刀，眼睛就开始发酸。"}, {"s": 65.23, "e": 67.83, "t": "我又切了一刀——眼泪直接流下来了。"}, {"s": 67.83, "e": 68.9, "t": "不是因为感动。"}, {"s": 68.9, "e": 69.81, "t": "是因为洋葱。"}, {"s": 69.81, "e": 73.79, "t": "我用手背擦了一下眼睛，但手上也沾了洋葱汁，越擦越辣。"}, {"s": 73.79, "e": 74.7, "t": "\"我来切。\""}, {"s": 74.7, "e": 76.38, "t": "他把刀从我手里拿过去。"}, {"s": 76.38, "e": 77.91, "t": "\"你负责看显微镜。\""}, {"s": 77.91, "e": 79.29, "t": "他低下头，开始切。"}, {"s": 79.29, "e": 83.41, "t": "动作比我利索——手稳，刀口整齐，剥下来的表皮薄得透光。"}, {"s": 83.41, "e": 86.92, "t": "我站在旁边，用另一只干净的手背又擦了一下眼泪。"}, {"s": 86.92, "e": 88.6, "t": "他没抬头，但说了一句："}, {"s": 88.6, "e": 89.98, "t": "\"纸在台子左边。\""}, {"s": 89.98, "e": 92.42, "t": "我转过头——左边确实有一盒纸巾。"}, {"s": 92.42, "e": 94.1, "t": "他连这个都提前看好了。"}, {"s": 94.1, "e": 98.23, "t": "制片的时候，他负责把标本放到载玻片上，我负责调显微镜。"}, {"s": 98.23, "e": 101.28, "t": "他放好之后往旁边让了一步，把位置让给我。"}, {"s": 101.28, "e": 102.35, "t": "我弯腰，对焦。"}, {"s": 102.35, "e": 109.99, "t": "视野从模糊慢慢变得清晰——细胞壁、细胞核、液泡，一格一格整整齐齐地排列着，在光线下呈现出淡淡的紫色。"}, {"s": 109.99, "e": 110.91, "t": "\"看到了。\""}, {"s": 110.91, "e": 114.12, "t": "他凑过来——肩膀贴着我的肩膀，低头看目镜。"}, {"s": 114.12, "e": 119.92, "t": "他把一只手搭在桌沿，另一只手扶着显微镜的底座——那个姿势像是在保护那个画面。"}, {"s": 119.92, "e": 120.68, "t": "\"很清楚。"}, {"s": 120.68, "e": 121.3, "t": "\"他说。"}, {"s": 121.3, "e": 123.28, "t": "他说话的热气碰到我的耳朵。"}, {"s": 123.28, "e": 125.42, "t": "我假装没注意到，继续调焦距。"}, {"s": 125.42, "e": 130.0, "t": "但那份洋葱表皮细胞的玻片标本——我调了三分多钟才调到最清晰。"}, {"s": 130.0, "e": 131.38, "t": "不是因为我没调好。"}, {"s": 131.38, "e": 133.97, "t": "是因为我不想让他那么快把肩膀移开。"}, {"s": 133.97, "e": 135.96, "t": "下课后，我把实验报告写完。"}, {"s": 135.96, "e": 141.0, "t": "他在旁边收拾器材，把用过的载玻片放到回收盒里，把显微镜的镜头盖好。"}, {"s": 141.0, "e": 142.07, "t": "\"你写完了？\""}, {"s": 142.07, "e": 143.75, "t": "\"快了——就差结论。\""}, {"s": 143.75, "e": 145.28, "t": "\"那我在门口等你。\""}, {"s": 145.28, "e": 147.72, "t": "他说完就拎着书包站到走廊上去了。"}, {"s": 147.72, "e": 150.93, "t": "我低头写最后一句话的时候，笔尖动得特别快。"}, {"s": 150.93, "e": 152.15, "t": "不是因为赶时间。"}, {"s": 152.15, "e": 158.11, "t": "是因为他在门口等我——这句写在实验报告结论栏里的不是答案，但我在心里写了一遍。"}, {"s": 158.11, "e": 161.47, "t": "<!-- summary:start -->"}, {"s": 161.47, "e": 162.54, "t": "本章推进线索："}, {"s": 162.54, "e": 167.58, "t": "- 🔵 同选物化生的首次实验室场景——博文主动来叫\"走，我们一组\""}, {"s": 167.58, "e": 172.47, "t": "- 🔵 \"对，我们一组\"——博文第一次对外公开确认两人的搭档关系"}, {"s": 172.47, "e": 177.05, "t": "- 🔵 博文替林深切洋葱，提前看了纸巾位置——细致入微的照顾"}, {"s": 177.05, "e": 181.79, "t": "- 🔵 共同观察显微镜，肩膀相贴——实验课成了新的亲密场景类型"}, {"s": 181.79, "e": 183.32, "t": "本章关键事件时间戳："}, {"s": 183.32, "e": 186.68, "t": "- 9月中旬某节生物课：第一次两人一组做实验"}, {"s": 186.68, "e": 187.9, "t": "本章新埋伏笔：无"}, {"s": 187.9, "e": 188.66, "t": "下章钩子："}, {"s": 188.66, "e": 190.65, "t": "- 他好像知道我喜欢什么。"}, {"s": 190.65, "e": 193.71, "t": "<!-- summary:end -->"}, {"s": 193.71, "e": 198.9, "t": "2026-07-19 初始版本：Ch 21 同一组——实验室首度合作"}]}, {"num": 22, "title": "第22章 酸奶", "file": "chapters/ch022.mp3", "dur": 175.7, "size_mb": 1.4, "segs": [{"s": 0.0, "e": 3.1, "t": "时间：9 月 19 日—21 日 · 高二上"}, {"s": 3.1, "e": 6.06, "t": "他第一次给我带酸奶，是在九月的第三个周末。"}, {"s": 6.06, "e": 11.41, "t": "那天下午他从外面回来，手里拎着一个塑料袋，袋子上印着学校小卖部的 logo。"}, {"s": 11.41, "e": 12.82, "t": "他把袋子放在我桌上。"}, {"s": 12.82, "e": 13.67, "t": "\"给你的。\""}, {"s": 13.67, "e": 15.78, "t": "我打开袋子——里面是一瓶酸奶。"}, {"s": 15.78, "e": 19.44, "t": "不是那种小杯的，是瓶装的，盖子拧开里面还有一层锡纸。"}, {"s": 19.44, "e": 21.13, "t": "\"……你专门出去买的？\""}, {"s": 21.13, "e": 21.84, "t": "\"顺路。\""}, {"s": 21.84, "e": 23.81, "t": "他坐下来，拧开水杯喝了一口。"}, {"s": 23.81, "e": 25.78, "t": "\"上次你不是说想喝酸奶吗？\""}, {"s": 25.78, "e": 27.62, "t": "我愣了一下——我确实说过。"}, {"s": 27.62, "e": 33.25, "t": "大概是一周前，在食堂排队的时候，我看见冰柜里的酸奶，随口说了一句\"好久没喝了\"。"}, {"s": 33.25, "e": 34.52, "t": "我就说了那么一次。"}, {"s": 34.52, "e": 35.22, "t": "他记住了。"}, {"s": 35.22, "e": 37.06, "t": "那瓶酸奶我喝了一整个晚上。"}, {"s": 37.06, "e": 39.03, "t": "不是喝不完——是舍不得喝快。"}, {"s": 39.03, "e": 41.85, "t": "每次拧开盖子喝一小口，再拧紧，放在桌角。"}, {"s": 41.85, "e": 43.96, "t": "到晚上熄灯的时候，还有小半瓶。"}, {"s": 43.96, "e": 46.36, "t": "我把它放在床头的小架子上，躺下来。"}, {"s": 46.36, "e": 48.89, "t": "黑暗中，我听见他的声音从对面传过来。"}, {"s": 48.89, "e": 50.02, "t": "\"你还没喝完？\""}, {"s": 50.02, "e": 51.01, "t": "\"……快了。\""}, {"s": 51.01, "e": 53.82, "t": "\"一瓶酸奶喝三个小时——你是品酒师吗？\""}, {"s": 53.82, "e": 59.04, "t": "他的语气里有一种我没听过的调子——不是平时那种平，是带着一点尾音的往上翘。"}, {"s": 59.04, "e": 59.6, "t": "像在笑。"}, {"s": 59.6, "e": 61.15, "t": "我盯着黑暗中的天花板。"}, {"s": 61.15, "e": 62.42, "t": "\"因为是你买的。\""}, {"s": 62.42, "e": 62.84, "t": "我说。"}, {"s": 62.84, "e": 64.53, "t": "然后对面安静了大概三秒。"}, {"s": 64.53, "e": 66.64, "t": "然后他说：\"那我以后多买点。\""}, {"s": 66.64, "e": 68.05, "t": "声音比刚才轻了一点。"}, {"s": 68.05, "e": 71.01, "t": "但在这间漆黑的宿舍里，每一个字都特别清楚。"}, {"s": 71.01, "e": 73.13, "t": "第二天早上，我桌上又多了一瓶。"}, {"s": 73.13, "e": 75.24, "t": "和昨天一样的牌子，一样的口味。"}, {"s": 75.24, "e": 81.16, "t": "我拿起来的时候，瓶身上还带着冷藏柜里拿出来不久的那种凉意——他大概是一大早就去买了。"}, {"s": 81.16, "e": 82.43, "t": "我走到他座位旁边。"}, {"s": 82.43, "e": 83.69, "t": "\"你今天又买了？\""}, {"s": 83.69, "e": 84.54, "t": "他头也没抬。"}, {"s": 84.54, "e": 86.09, "t": "\"不是说了多买点吗。\""}, {"s": 86.09, "e": 88.77, "t": "他说完就翻了一页书，没给我回话的机会。"}, {"s": 88.77, "e": 91.44, "t": "我站在他旁边，手里握着那瓶冰凉的酸奶。"}, {"s": 91.44, "e": 93.84, "t": "\"多买点\"——他说的是\"多买点\"。"}, {"s": 93.84, "e": 95.11, "t": "不是\"再买一次\"。"}, {"s": 95.11, "e": 96.09, "t": "是\"多买点\"。"}, {"s": 96.09, "e": 97.22, "t": "那瓶酸奶我没喝。"}, {"s": 97.22, "e": 102.01, "t": "不是不想喝——是我把它放进了书包里，带回了宿舍，放在了床头的架子上。"}, {"s": 102.01, "e": 103.84, "t": "和昨晚那瓶的空瓶放在一起。"}, {"s": 103.84, "e": 105.25, "t": "两个瓶子，并排站着。"}, {"s": 105.25, "e": 107.79, "t": "我看着它们站了一会儿，然后躺到床上。"}, {"s": 107.79, "e": 110.46, "t": "窗外的风吹进来，把窗帘吹得轻轻鼓起来。"}, {"s": 110.46, "e": 113.14, "t": "宿舍里只有我一个人，他在教室还没回来。"}, {"s": 113.14, "e": 114.97, "t": "我侧过头，看着那两瓶酸奶。"}, {"s": 114.97, "e": 116.66, "t": "一瓶喝完了，一瓶还没开。"}, {"s": 116.66, "e": 117.51, "t": "但我都没扔。"}, {"s": 117.51, "e": 120.47, "t": "因为这是我第一次收到不只是\"顺手\"的东西。"}, {"s": 120.47, "e": 121.6, "t": "他走了很远的路。"}, {"s": 121.6, "e": 122.86, "t": "他记得我说过的话。"}, {"s": 122.86, "e": 125.12, "t": "他把\"多买点\"当作一个承诺来说。"}, {"s": 125.12, "e": 128.22, "t": "我闭上眼睛，在只有一个人的宿舍里，笑了一下。"}, {"s": 128.22, "e": 131.32, "t": "<!-- summary:start -->"}, {"s": 131.32, "e": 132.3, "t": "本章推进线索："}, {"s": 132.3, "e": 137.09, "t": "- 🔵 酸奶意象首次出现——博文记得林深一周前随口说的\"好久没喝了\""}, {"s": 137.09, "e": 140.9, "t": "- 🔵 \"那我以后多买点\"——博文第一次做出持续性承诺"}, {"s": 140.9, "e": 143.29, "t": "- 🔵 林深收藏酸奶瓶——不舍得扔"}, {"s": 143.29, "e": 147.1, "t": "- 🔵 为 Ch 24 \"别扭的酸奶\"标题提供剧情基础"}, {"s": 147.1, "e": 148.51, "t": "本章关键事件时间戳："}, {"s": 148.51, "e": 151.32, "t": "- 9/19 周六下午：博文带酸奶回宿舍"}, {"s": 151.32, "e": 154.0, "t": "- 9/20 周日早上：桌上又多了一瓶"}, {"s": 154.0, "e": 157.24, "t": "- 9/20 晚：林深把两瓶并排放在床头架子上"}, {"s": 157.24, "e": 158.23, "t": "本章新埋伏笔："}, {"s": 158.23, "e": 163.44, "t": "- F-酸奶：将成为两人之间的一个\"信号\"物件（用于 Ch 24 及以后）"}, {"s": 163.44, "e": 164.15, "t": "下章钩子："}, {"s": 164.15, "e": 167.53, "t": "- 张尧说：\"博文上周三看了我一眼，不太高兴。\""}, {"s": 167.53, "e": 170.35, "t": "<!-- summary:end -->"}, {"s": 170.35, "e": 175.7, "t": "2026-07-19 初始版本：Ch 22 酸奶——记住你随口说过的每一句话"}]}, {"num": 23, "title": "第23章 吃醋", "file": "chapters/ch023.mp3", "dur": 156.0, "size_mb": 1.2, "segs": [{"s": 0.0, "e": 2.41, "t": "时间：9 月 22 日 · 高二上"}, {"s": 2.41, "e": 4.97, "t": "张尧来找我的时候，我正在座位上做题。"}, {"s": 4.97, "e": 5.68, "t": "\"林深。\""}, {"s": 5.68, "e": 6.39, "t": "我抬起头。"}, {"s": 6.39, "e": 10.08, "t": "张尧——博文的邻居，也是他的初中同学——站在我桌边。"}, {"s": 10.08, "e": 12.49, "t": "\"你知道博文上周三看了我一眼吗？\""}, {"s": 12.49, "e": 13.77, "t": "\"……什么意思？\""}, {"s": 13.77, "e": 16.89, "t": "\"上周三中午你在走廊上跟我说话——他看见了。"}, {"s": 16.89, "e": 19.87, "t": "后来我去找他，他看了我一眼——不太高兴。\""}, {"s": 19.87, "e": 21.43, "t": "我握着笔的手停了一下。"}, {"s": 21.43, "e": 22.85, "t": "\"……你看错了吧。\""}, {"s": 22.85, "e": 23.56, "t": "\"没看错。"}, {"s": 23.56, "e": 24.7, "t": "我认识他十年了。"}, {"s": 24.7, "e": 26.83, "t": "他不高兴的时候就是那个表情。\""}, {"s": 26.83, "e": 31.65, "t": "张尧走了之后，我坐在座位上，盯着面前的题看了半天，一个字都没看进去。"}, {"s": 31.65, "e": 33.64, "t": "中午在食堂，我和他坐在一起。"}, {"s": 33.64, "e": 34.92, "t": "他今天不怎么说话。"}, {"s": 34.92, "e": 39.46, "t": "不是完全不说——是那种表面看起来正常、但筷子按得比平时重的安静。"}, {"s": 39.46, "e": 44.71, "t": "他把碗里的饭夹起来，放下，夹起来，放下——好像吃饭只是一件他在完成的任务。"}, {"s": 44.71, "e": 46.56, "t": "我吃完了，他碗里还剩大半。"}, {"s": 46.56, "e": 47.55, "t": "\"你吃饱了？\""}, {"s": 47.55, "e": 48.12, "t": "\"嗯。\""}, {"s": 48.12, "e": 48.97, "t": "他放下筷子。"}, {"s": 48.97, "e": 52.52, "t": "我看着他那个样子，心里有一个念头——但我不敢确认。"}, {"s": 52.52, "e": 54.37, "t": "下午在楼梯口，他叫住了我。"}, {"s": 54.37, "e": 56.49, "t": "\"你今天上午和张尧说什么了？\""}, {"s": 56.49, "e": 58.48, "t": "他的语气很平——和平时一样。"}, {"s": 58.48, "e": 61.46, "t": "但我注意到他握着楼梯扶手的手指，指节发白。"}, {"s": 61.46, "e": 64.16, "t": "\"没说什么——他过来跟我说了几句话。\""}, {"s": 64.16, "e": 65.01, "t": "\"什么话？\""}, {"s": 65.01, "e": 68.28, "t": "\"……他说——你上周三看了他一眼，不太高兴。\""}, {"s": 68.28, "e": 68.99, "t": "他没回答。"}, {"s": 68.99, "e": 69.98, "t": "沉默了一会儿。"}, {"s": 69.98, "e": 72.39, "t": "\"以后——不要和张尧讨论数学题。\""}, {"s": 72.39, "e": 74.38, "t": "\"……我没有和他讨论数学题。"}, {"s": 74.38, "e": 75.52, "t": "就说了几句话。\""}, {"s": 75.52, "e": 76.65, "t": "\"那也别说了。\""}, {"s": 76.65, "e": 78.07, "t": "他转身往上走了两步。"}, {"s": 78.07, "e": 78.92, "t": "然后停下来。"}, {"s": 78.92, "e": 80.63, "t": "\"你要问物理题，找我。\""}, {"s": 80.63, "e": 81.62, "t": "他说完就走了。"}, {"s": 81.62, "e": 84.6, "t": "我站在楼梯上，看着他的背影消失在三楼转角。"}, {"s": 84.6, "e": 86.59, "t": "他要说的是——你要找，找我。"}, {"s": 86.59, "e": 88.72, "t": "周海在晚自习的时候听了这件事。"}, {"s": 88.72, "e": 89.71, "t": "\"他吃醋了。\""}, {"s": 89.71, "e": 90.85, "t": "\"……不可能。\""}, {"s": 90.85, "e": 91.84, "t": "\"怎么不可能？"}, {"s": 91.84, "e": 94.82, "t": "他不让你和别人说话——这不叫吃醋叫什么？\""}, {"s": 94.82, "e": 95.53, "t": "我看着他。"}, {"s": 95.53, "e": 96.52, "t": "\"他喜欢你。\""}, {"s": 96.52, "e": 97.09, "t": "周海说。"}, {"s": 97.09, "e": 98.23, "t": "我不敢接这句话。"}, {"s": 98.23, "e": 101.21, "t": "但那天晚上我回到宿舍的时候，他已经躺下了。"}, {"s": 101.21, "e": 106.03, "t": "我推门进去，他没动——但我看见他放在被子上面的手指，微微收紧了一下。"}, {"s": 106.03, "e": 106.74, "t": "他在装睡。"}, {"s": 106.74, "e": 107.45, "t": "我没戳穿。"}, {"s": 107.45, "e": 109.87, "t": "但我躺下之后，在黑暗里说了一句话。"}, {"s": 109.87, "e": 112.14, "t": "\"我以后不和他们讨论数学题了。\""}, {"s": 112.14, "e": 112.99, "t": "安静了很久。"}, {"s": 112.99, "e": 114.41, "t": "久到我以为他睡着了。"}, {"s": 114.41, "e": 116.68, "t": "然后黑暗里传来一声很轻的\"嗯\"。"}, {"s": 116.68, "e": 118.1, "t": "像从被子里闷出来的。"}, {"s": 118.1, "e": 121.22, "t": "<!-- summary:start -->"}, {"s": 121.22, "e": 122.22, "t": "本章推进线索："}, {"s": 122.22, "e": 126.05, "t": "- 🔵 张尧触发吃醋：博文看到林深和张尧说话后表情变化"}, {"s": 126.05, "e": 128.32, "t": "- 🔵 食堂博文不说话、筷子按重"}, {"s": 128.32, "e": 132.15, "t": "- 🔵 \"以后不要和张尧讨论数学题\"——博文式吃醋表达"}, {"s": 132.15, "e": 134.14, "t": "- 🔵 周海点破\"他喜欢你\""}, {"s": 134.14, "e": 138.54, "t": "- 🔵 林深主动说\"以后不和他们讨论数学题了\"，博文回应\"嗯\""}, {"s": 138.54, "e": 139.96, "t": "本章关键事件时间戳："}, {"s": 139.96, "e": 144.64, "t": "- 9/22：张尧来报信→食堂沉默→楼梯口对峙→周海点破→宿舍回应"}, {"s": 144.64, "e": 145.35, "t": "下章钩子："}, {"s": 145.35, "e": 148.62, "t": "- 他给我起了一个外号——但这外号只有他能叫。"}, {"s": 148.62, "e": 151.46, "t": "<!-- summary:end -->"}, {"s": 151.46, "e": 156.0, "t": "2026-07-19 初始版本：Ch 23 吃醋——博文的不高兴"}]}, {"num": 24, "title": "第24章 别扭", "file": "chapters/ch024.mp3", "dur": 59.2, "size_mb": 0.5, "segs": [{"s": 0.0, "e": 1.85, "t": "时间：9 月 23 日 · 高二上"}, {"s": 1.85, "e": 3.81, "t": "吃醋那件事的第二天，我做了一件蠢事。"}, {"s": 3.81, "e": 6.64, "t": "下午自习课，我走到他桌边，想打破那个还有点僵的气氛。"}, {"s": 6.64, "e": 7.18, "t": "\"博文。\""}, {"s": 7.18, "e": 7.73, "t": "他抬起头。"}, {"s": 7.73, "e": 8.81, "t": "\"我能叫你小博吗？\""}, {"s": 8.81, "e": 10.01, "t": "他看了我大概 3 秒。"}, {"s": 10.01, "e": 10.56, "t": "\"不能。\""}, {"s": 10.56, "e": 11.43, "t": "\"……为什么？\""}, {"s": 11.43, "e": 12.3, "t": "他合上手里的书。"}, {"s": 12.3, "e": 13.71, "t": "\"因为'博文'是'博文'。"}, {"s": 13.71, "e": 14.91, "t": "'小博'是'小博'。\""}, {"s": 14.91, "e": 16.0, "t": "\"……有什么区别？\""}, {"s": 16.0, "e": 16.54, "t": "他想了想。"}, {"s": 16.54, "e": 17.85, "t": "\"'博文'只有你能叫。\""}, {"s": 17.85, "e": 19.26, "t": "他说完就低下头继续看书了。"}, {"s": 19.26, "e": 21.66, "t": "我站在他桌边，手里拿着本来要问他的物理卷子。"}, {"s": 21.66, "e": 23.18, "t": "他说——\"博文\"只有我能叫。"}, {"s": 23.18, "e": 24.59, "t": "下午，他桌上多了一瓶酸奶。"}, {"s": 24.59, "e": 27.21, "t": "我坐下来的时候，他把它推过来——没看我，没说话。"}, {"s": 27.21, "e": 29.71, "t": "我拿起来看了一眼——是我上次说好喝的那个牌子。"}, {"s": 29.71, "e": 30.58, "t": "我打开喝了一口。"}, {"s": 30.58, "e": 31.01, "t": "别扭的。"}, {"s": 31.01, "e": 31.34, "t": "甜的。"}, {"s": 31.34, "e": 32.32, "t": "两个味道混在一起。"}, {"s": 32.32, "e": 34.93, "t": "就像我和他现在这样——不说话，但他给我买了酸奶。"}, {"s": 34.93, "e": 37.33, "t": "<!-- summary:start -->"}, {"s": 37.33, "e": 38.09, "t": "本章推进线索："}, {"s": 38.09, "e": 41.14, "t": "- 🔵 \"小博\"被拒——\"博文只有你能叫\"（专属感宣言）"}, {"s": 41.14, "e": 44.73, "t": "- 🔵 酸奶出现——呼应 Ch 22 的酸奶意象，冷战中的和解信号"}, {"s": 44.73, "e": 47.01, "t": "- 🔵 \"别扭的，甜的\"——双重情绪的表达"}, {"s": 47.01, "e": 48.1, "t": "本章关键事件时间戳："}, {"s": 48.1, "e": 51.58, "t": "- 9/23：尝试起外号被拒→博文说\"博文只有你能叫\"→酸奶和解"}, {"s": 51.58, "e": 52.13, "t": "下章钩子："}, {"s": 52.13, "e": 53.11, "t": "- 然后我发烧了。"}, {"s": 53.11, "e": 55.28, "t": "<!-- summary:end -->"}, {"s": 55.28, "e": 59.2, "t": "2026-07-19 初始版本：Ch 24 别扭——起外号被拒与酸奶和解"}]}, {"num": 25, "title": "第25章 发烧", "file": "chapters/ch025.mp3", "dur": 186.2, "size_mb": 1.5, "segs": [{"s": 0.0, "e": 2.51, "t": "时间：10 月 5 日 · 高二上"}, {"s": 2.51, "e": 5.17, "t": "国庆假期回来之后，我就开始不舒服了。"}, {"s": 5.17, "e": 7.98, "t": "早上起来的时候嗓子干得像砂纸，头也沉。"}, {"s": 7.98, "e": 12.56, "t": "我摸了一下额头——没发烧，但那种\"快要发烧了\"的感觉已经来了。"}, {"s": 12.56, "e": 13.89, "t": "我没有告诉任何人。"}, {"s": 13.89, "e": 15.52, "t": "第一节课我撑着听完了。"}, {"s": 15.52, "e": 18.32, "t": "第二节开始之前，我趴在桌上，想缓一下。"}, {"s": 18.32, "e": 20.84, "t": "再抬头的时候——桌角多了一杯热水。"}, {"s": 20.84, "e": 23.2, "t": "我转过头——他坐回自己的座位了。"}, {"s": 23.2, "e": 25.71, "t": "但他桌上放着一盒退烧药，还没拆封。"}, {"s": 25.71, "e": 26.9, "t": "他什么时候买的？"}, {"s": 26.9, "e": 27.93, "t": "什么时候放的？"}, {"s": 27.93, "e": 28.67, "t": "我不知道。"}, {"s": 28.67, "e": 32.07, "t": "但那杯热水冒着白气，在十月的冷空气里特别显眼。"}, {"s": 32.07, "e": 33.99, "t": "我握起来喝了一口——烫的。"}, {"s": 33.99, "e": 35.76, "t": "中午的时候，体温上来了。"}, {"s": 35.76, "e": 38.42, "t": "我趴在桌上，头埋在胳膊里，浑身发冷。"}, {"s": 38.42, "e": 42.71, "t": "教室里有人在说话，有人在笑——那些声音像隔了一层水传过来。"}, {"s": 42.71, "e": 45.22, "t": "然后我感觉到一只手贴上了我的额头。"}, {"s": 45.22, "e": 45.66, "t": "凉的。"}, {"s": 45.66, "e": 50.24, "t": "我睁开眼——他站在我旁边，手背贴着我的额头，眉头微微皱了一下。"}, {"s": 50.24, "e": 51.28, "t": "\"你发烧了。\""}, {"s": 51.28, "e": 52.17, "t": "\"……嗯。\""}, {"s": 52.17, "e": 53.2, "t": "\"吃药了吗？\""}, {"s": 53.2, "e": 53.94, "t": "\"吃了。\""}, {"s": 53.94, "e": 54.97, "t": "\"那回宿舍。\""}, {"s": 54.97, "e": 56.89, "t": "我站起来的时候，腿有点软。"}, {"s": 56.89, "e": 62.36, "t": "他伸手扶了我一下——手掌贴着我的手臂，隔着校服的袖子，我感觉到他手的温度。"}, {"s": 62.36, "e": 62.95, "t": "凉凉的。"}, {"s": 62.95, "e": 63.54, "t": "很舒服。"}, {"s": 63.54, "e": 65.76, "t": "他把我送到宿舍门口，没有进去。"}, {"s": 65.76, "e": 66.5, "t": "\"你躺着。"}, {"s": 66.5, "e": 67.53, "t": "我去医务室。\""}, {"s": 67.53, "e": 70.05, "t": "我说\"不用\"——但他已经转身走了。"}, {"s": 70.05, "e": 72.26, "t": "我躺在床上，也不知道过了多久。"}, {"s": 72.26, "e": 75.37, "t": "头很重，身体发冷，被子被我裹了一圈又一圈。"}, {"s": 75.37, "e": 76.25, "t": "然后门开了。"}, {"s": 76.25, "e": 76.99, "t": "他回来了。"}, {"s": 76.99, "e": 81.28, "t": "手里拎着一个塑料袋——里面装着药、酒精棉、还有一个保温杯。"}, {"s": 81.28, "e": 86.01, "t": "他坐到床沿上——我睡下铺——把保温杯拧开，倒了一杯热水放在床头。"}, {"s": 86.01, "e": 88.08, "t": "然后他拆开酒精棉，抽出一片。"}, {"s": 88.08, "e": 88.96, "t": "\"手给我。\""}, {"s": 88.96, "e": 89.7, "t": "我伸出手。"}, {"s": 89.7, "e": 92.8, "t": "他握住我的手腕，用酒精棉擦了一下我的手心。"}, {"s": 92.8, "e": 93.25, "t": "凉的。"}, {"s": 93.25, "e": 96.65, "t": "他的拇指按在我手腕内侧——那个位置，脉搏在跳。"}, {"s": 96.65, "e": 99.6, "t": "他的拇指停在那里，大概过了两三秒才松开。"}, {"s": 99.6, "e": 101.67, "t": "然后他把那杯热水放到我手里。"}, {"s": 101.67, "e": 102.41, "t": "\"喝完。\""}, {"s": 102.41, "e": 103.0, "t": "我喝了。"}, {"s": 103.0, "e": 105.07, "t": "他又拆了一包退烧药放在桌上。"}, {"s": 105.07, "e": 107.14, "t": "\"晚上如果又烧了，吃这个。\""}, {"s": 107.14, "e": 108.62, "t": "我说了一声\"谢谢\"。"}, {"s": 108.62, "e": 109.36, "t": "他没回答。"}, {"s": 109.36, "e": 114.82, "t": "但他站起来之前，把挂在床头的校服外套拿了下来——团成一团，垫在我枕头上面。"}, {"s": 114.82, "e": 116.45, "t": "\"这样高一点，舒服。\""}, {"s": 116.45, "e": 117.48, "t": "那是他的校服。"}, {"s": 117.48, "e": 120.0, "t": "我枕着他的校服，在被子里闭着眼睛。"}, {"s": 120.0, "e": 124.28, "t": "他的外套有一股洗衣液的味道——不是柚子味的那件，是另一件。"}, {"s": 124.28, "e": 125.76, "t": "但我记住了那个味道。"}, {"s": 125.76, "e": 126.94, "t": "第二天我退烧了。"}, {"s": 126.94, "e": 129.75, "t": "早上去教室的时候，我桌上放着一杯豆浆。"}, {"s": 129.75, "e": 130.19, "t": "温的。"}, {"s": 130.19, "e": 133.15, "t": "我坐下来，看了一眼他的方向——他在看书。"}, {"s": 133.15, "e": 135.66, "t": "但桌角放着一个已经拆开的退烧药盒。"}, {"s": 135.66, "e": 137.29, "t": "和我床头那盒一模一样。"}, {"s": 137.29, "e": 138.76, "t": "他给自己也买了一盒。"}, {"s": 138.76, "e": 141.28, "t": "大概是——怕被我传染，不能照顾我。"}, {"s": 141.28, "e": 144.53, "t": "<!-- summary:start -->"}, {"s": 144.53, "e": 145.56, "t": "本章推进线索："}, {"s": 145.56, "e": 150.14, "t": "- 🔵 林深发烧——博文全程照顾（热水+药+酒精棉+校服枕头）"}, {"s": 150.14, "e": 153.69, "t": "- 🔵 博文用酒精棉擦手心、把脉——身体接触升级"}, {"s": 153.69, "e": 156.94, "t": "- 🔵 校服枕头——柚子味洗衣液的另一个侧面"}, {"s": 156.94, "e": 160.49, "t": "- 🔵 博文给自己也买退烧药（怕被传染、怕倒下）"}, {"s": 160.49, "e": 161.96, "t": "本章关键事件时间戳："}, {"s": 161.96, "e": 164.48, "t": "- 10/5 上午：热水出现在桌角"}, {"s": 164.48, "e": 168.17, "t": "- 10/5 中午：博文摸额头→送宿舍→医务室拿药"}, {"s": 168.17, "e": 171.27, "t": "- 10/5 下午：校服枕头+酒精棉擦手心"}, {"s": 171.27, "e": 173.93, "t": "- 10/6 早上：退烧，豆浆在桌上"}, {"s": 173.93, "e": 174.67, "t": "下章钩子："}, {"s": 174.67, "e": 178.66, "t": "- 每天下午 4 点半，他会拿出一个封面有颜色的本子。"}, {"s": 178.66, "e": 181.62, "t": "<!-- summary:end -->"}, {"s": 181.62, "e": 186.2, "t": "2026-07-19 初始版本：Ch 25 发烧——博文式照顾"}]}, {"num": 26, "title": "第26章 同一层楼", "file": "chapters/ch026.mp3", "dur": 224.6, "size_mb": 1.8, "segs": [{"s": 0.0, "e": 2.67, "t": "时间：10 月底 · 高二上，月考"}, {"s": 2.67, "e": 4.87, "t": "月考的考场是按上次排名排的。"}, {"s": 4.87, "e": 9.57, "t": "我拿着准考证在教学楼前面看了一眼——我在三楼，302 考场。"}, {"s": 9.57, "e": 10.36, "t": "\"你呢？\""}, {"s": 10.36, "e": 12.4, "t": "我把准考证递给旁边的人看。"}, {"s": 12.4, "e": 13.18, "t": "\"303。"}, {"s": 13.18, "e": 13.81, "t": "\"他说。"}, {"s": 13.81, "e": 14.44, "t": "303。"}, {"s": 14.44, "e": 16.01, "t": "就在 302 隔壁。"}, {"s": 16.01, "e": 17.26, "t": "中间隔了一道墙。"}, {"s": 17.26, "e": 23.23, "t": "但我走到三楼的时候，发现 302 和 303 之间隔的不是墙——是一扇窗户。"}, {"s": 23.23, "e": 25.74, "t": "走廊尽头有一扇大窗，正对着天井。"}, {"s": 25.74, "e": 29.82, "t": "和我高一上站的那扇窗户在同一层楼，只是换了一个方向。"}, {"s": 29.82, "e": 32.65, "t": "我站在那扇窗户前面，往对面看了一眼。"}, {"s": 32.65, "e": 34.06, "t": "对面是一间空教室。"}, {"s": 34.06, "e": 39.55, "t": "但我知道——从高一上开始，我和他之间的距离，已经从那扇窗户走到了这里。"}, {"s": 39.55, "e": 40.34, "t": "同一层楼。"}, {"s": 40.34, "e": 40.81, "t": "隔壁。"}, {"s": 40.81, "e": 41.91, "t": "第一场考语文。"}, {"s": 41.91, "e": 46.77, "t": "我坐在靠窗的位置，写完作文之后还剩一点时间，我往窗外看了一眼。"}, {"s": 46.77, "e": 49.6, "t": "隔壁考场的窗户开着——但我看不到他。"}, {"s": 49.6, "e": 53.52, "t": "可我知道他就在那扇窗户后面，大概隔着一道墙的距离。"}, {"s": 53.52, "e": 57.13, "t": "和我同时在做同一张卷子，和我同时在抬头看窗外。"}, {"s": 57.13, "e": 59.8, "t": "这个认知让我的作文结尾多写了三行。"}, {"s": 59.8, "e": 61.84, "t": "不为什么——就是突然想写。"}, {"s": 61.84, "e": 64.51, "t": "第二场考数学的时候，发生了一件事。"}, {"s": 64.51, "e": 68.27, "t": "我的 2B 铅笔在涂第三道选择题的时候——断了。"}, {"s": 68.27, "e": 70.16, "t": "笔芯断在里面，转不动了。"}, {"s": 70.16, "e": 72.67, "t": "我翻了一下笔袋——备用笔芯没带。"}, {"s": 72.67, "e": 75.81, "t": "夹层里只有一支签字笔和一管快用完的胶带。"}, {"s": 75.81, "e": 76.91, "t": "还有半块橡皮。"}, {"s": 76.91, "e": 81.77, "t": "是开学初他借给我的那块——后来他说不用还，我就一直放在笔袋里。"}, {"s": 81.77, "e": 84.13, "t": "我盯着那半块橡皮看了大概两秒。"}, {"s": 84.13, "e": 85.23, "t": "然后我举手了。"}, {"s": 85.23, "e": 88.21, "t": "\"老师——我能借一下隔壁桌的铅笔吗？\""}, {"s": 88.21, "e": 92.13, "t": "监考老师看了我一眼，点了点头，陪我到隔壁考场门口。"}, {"s": 92.13, "e": 95.27, "t": "老师敲了一下门，里面的监考老师探出头来。"}, {"s": 95.27, "e": 96.53, "t": "\"他铅笔断了。\""}, {"s": 96.53, "e": 100.92, "t": "303 的监考老师往教室里看了一眼——\"谁有多的铅笔？\""}, {"s": 100.92, "e": 102.65, "t": "然后我听见了一个声音："}, {"s": 102.65, "e": 103.59, "t": "\"我这有。\""}, {"s": 103.59, "e": 104.06, "t": "是他。"}, {"s": 104.06, "e": 108.14, "t": "他站起来，走到门口，把一支削好的 2B 铅笔递给我。"}, {"s": 108.14, "e": 109.4, "t": "没多问，没多说。"}, {"s": 109.4, "e": 110.34, "t": "就递过来了。"}, {"s": 110.34, "e": 115.67, "t": "我接住的时候，他的手指碰到我的手指——凉的，和他平时的手温不太一样。"}, {"s": 115.67, "e": 117.4, "t": "大概是因为考场的空调。"}, {"s": 117.4, "e": 118.19, "t": "\"谢谢。\""}, {"s": 118.19, "e": 118.66, "t": "我说。"}, {"s": 118.66, "e": 119.6, "t": "他点了下头。"}, {"s": 119.6, "e": 121.01, "t": "然后转身回座位了。"}, {"s": 121.01, "e": 125.41, "t": "我回到自己的考场，坐下来，用那支铅笔画完了剩下的答题卡。"}, {"s": 125.41, "e": 128.7, "t": "最后一笔涂完的时候，我把那支铅笔放在桌角。"}, {"s": 128.7, "e": 131.37, "t": "等我做完卷子，抬头看了一眼窗外——"}, {"s": 131.37, "e": 134.98, "t": "502 考场和 303 考场之间，隔了一道墙。"}, {"s": 134.98, "e": 138.12, "t": "但他的手，刚刚从这个考场借到了那个考场。"}, {"s": 138.12, "e": 140.32, "t": "考完最后一科，我在楼下等他。"}, {"s": 140.32, "e": 142.83, "t": "他走出来的时候，手里拎着文具袋。"}, {"s": 142.83, "e": 143.61, "t": "\"笔——\""}, {"s": 143.61, "e": 144.4, "t": "\"你留着。"}, {"s": 144.4, "e": 145.65, "t": "下次别再断了。\""}, {"s": 145.65, "e": 148.32, "t": "他说完就往前走了一步，走到我旁边。"}, {"s": 148.32, "e": 149.58, "t": "\"考得怎么样？\""}, {"s": 149.58, "e": 150.2, "t": "\"还行。"}, {"s": 150.2, "e": 152.4, "t": "数学最后一道大题没做出来。\""}, {"s": 152.4, "e": 153.19, "t": "\"哪题？\""}, {"s": 153.19, "e": 154.28, "t": "\"函数那道。\""}, {"s": 154.28, "e": 155.23, "t": "他点了下头。"}, {"s": 155.23, "e": 156.95, "t": "\"那题我也想了挺久。\""}, {"s": 156.95, "e": 161.98, "t": "他说\"我也想了挺久\"——不是\"那题不难\"或者\"你应该能写出来\"。"}, {"s": 161.98, "e": 163.7, "t": "他说的是一起想了很久。"}, {"s": 163.7, "e": 165.9, "t": "好像那场考试我们是一起考的。"}, {"s": 165.9, "e": 170.45, "t": "虽然隔了一道墙，但在同一层楼，同一时间，为同一道题在转笔。"}, {"s": 170.45, "e": 173.75, "t": "我走在他旁边，十一月的风从走廊那头吹过来。"}, {"s": 173.75, "e": 177.83, "t": "他刚考完试，校服没拉拉链，风把他的衣摆吹起来了一下。"}, {"s": 177.83, "e": 180.03, "t": "距离下一次月考，还有一个月。"}, {"s": 180.03, "e": 182.69, "t": "但下次——我们不只会在同一层楼了。"}, {"s": 182.69, "e": 186.15, "t": "<!-- summary:start -->"}, {"s": 186.15, "e": 187.25, "t": "本章推进线索："}, {"s": 187.25, "e": 191.64, "t": "- 🔵 同一考场楼层——\"同一层楼，隔壁\"的距离意象推进"}, {"s": 191.64, "e": 195.25, "t": "- 🔵 博文借铅笔给林深——跨越考场传递的小物"}, {"s": 195.25, "e": 200.27, "t": "- 🔵 博文说\"我也想了挺久\"——同频的暗示（连难题都是同一道）"}, {"s": 200.27, "e": 201.84, "t": "本章关键事件时间戳："}, {"s": 201.84, "e": 205.61, "t": "- 10月底月考：林深302考场，博文303考场"}, {"s": 205.61, "e": 209.06, "t": "- 数学科：铅笔断了，博文经监考老师转交铅笔"}, {"s": 209.06, "e": 210.32, "t": "本章新埋伏笔：无"}, {"s": 210.32, "e": 211.1, "t": "下章钩子："}, {"s": 211.1, "e": 216.12, "t": "- 每天下午 4 点半，他会拿出一个深蓝色的本子，写 1 分钟。"}, {"s": 216.12, "e": 219.26, "t": "<!-- summary:end -->"}, {"s": 219.26, "e": 224.6, "t": "2026-07-19 初始版本：Ch 26 同一层楼——月考考场隔壁"}]}, {"num": 27, "title": "第27章 封面有颜色的本子", "file": "chapters/ch027.mp3", "dur": 300.8, "size_mb": 2.4, "segs": [{"s": 0.0, "e": 3.26, "t": "时间：10 月 7 日—20 日 · 高二上"}, {"s": 3.26, "e": 6.66, "t": "下午 4 点 25 分，我站起来，往他座位走。"}, {"s": 6.66, "e": 12.58, "t": "不是约好的——是两周前的一个下午，他路过我座位的时候说了一句\"你物理作业写完没？"}, {"s": 12.58, "e": 13.47, "t": "拿来我看\"。"}, {"s": 13.47, "e": 18.36, "t": "从那之后，每天下午 4 点半，我会拿着一周攒下来的物理题去他那里。"}, {"s": 18.36, "e": 19.98, "t": "他坐在倒数第三排靠窗。"}, {"s": 19.98, "e": 25.02, "t": "我走过去的时候，他正在把桌上的东西往旁边推——腾出一个放卷子的位置。"}, {"s": 25.02, "e": 26.65, "t": "我坐下来，把卷子摊开。"}, {"s": 26.65, "e": 28.57, "t": "他低头看了大概 30 秒。"}, {"s": 28.57, "e": 31.53, "t": "\"第三题思路对了，但第二步用错了公式。\""}, {"s": 31.53, "e": 34.64, "t": "他拿起笔，在草稿纸上写了一个公式，推过来。"}, {"s": 34.64, "e": 37.16, "t": "我看了一眼——确实是我记混的那个。"}, {"s": 37.16, "e": 40.41, "t": "\"这个地方用这个，上面那道题你就能接上了。\""}, {"s": 40.41, "e": 43.08, "t": "\"……你只看了一眼就知道我卡在哪？\""}, {"s": 43.08, "e": 45.59, "t": "\"因为你每次都在同一个地方卡住。\""}, {"s": 45.59, "e": 48.85, "t": "他说完就低下头，在自己的本子上写了一行什么。"}, {"s": 48.85, "e": 51.81, "t": "我没看清他在写什么——他用手臂挡了一下。"}, {"s": 51.81, "e": 53.74, "t": "但我注意到他用的那个本子。"}, {"s": 53.74, "e": 57.58, "t": "封面上有一点颜色——深蓝色，好像还有一个小树的图案。"}, {"s": 57.58, "e": 58.32, "t": "我没多想。"}, {"s": 58.32, "e": 59.51, "t": "他把本子合上了。"}, {"s": 59.51, "e": 62.47, "t": "\"今天先把这三道改完，明天再讲后面的。\""}, {"s": 62.47, "e": 63.8, "t": "一周后，我又去了。"}, {"s": 63.8, "e": 65.58, "t": "同样的时间，同样的位置。"}, {"s": 65.58, "e": 68.98, "t": "他已经把桌子腾好了，桌上放着一杯水——给我的。"}, {"s": 68.98, "e": 71.8, "t": "我坐下来之后，他讲了大概 20 分钟。"}, {"s": 71.8, "e": 76.68, "t": "然后他停下来，从抽屉里拿出那个深蓝色的本子，翻开，低头写了一分钟。"}, {"s": 76.68, "e": 79.34, "t": "我坐在他右边，距离不到 30 厘米。"}, {"s": 79.34, "e": 84.82, "t": "他写字的时候，我习惯性地往那个方向看了一眼——不是刻意偷看，是余光扫到的。"}, {"s": 84.82, "e": 86.15, "t": "但我什么也没看清。"}, {"s": 86.15, "e": 88.67, "t": "他把本子侧了一下，挡住了我的视线。"}, {"s": 88.67, "e": 90.15, "t": "然后合上，放回抽屉。"}, {"s": 90.15, "e": 90.89, "t": "\"讲完了。"}, {"s": 90.89, "e": 92.96, "t": "你回去把第五题做出来就行。\""}, {"s": 92.96, "e": 93.85, "t": "我点了点头。"}, {"s": 93.85, "e": 97.11, "t": "但我走出他座位的时候，回头看了一眼他的抽屉。"}, {"s": 97.11, "e": 99.92, "t": "那个深蓝色的本子，合着，露出一截书脊。"}, {"s": 99.92, "e": 101.4, "t": "他到底每天在写什么？"}, {"s": 101.4, "e": 103.47, "t": "真相是在第三个星期三揭开的。"}, {"s": 103.47, "e": 106.88, "t": "那天下午 4 点半，我到的时候，他不在座位上。"}, {"s": 106.88, "e": 108.21, "t": "我就站在他桌边等。"}, {"s": 108.21, "e": 113.24, "t": "他的桌面收拾得很干净——卷子叠成一沓，笔袋放在右上角，水杯放在左边。"}, {"s": 113.24, "e": 116.35, "t": "那个深蓝色的本子——放在桌面上，没有合上。"}, {"s": 116.35, "e": 118.43, "t": "我不确定他是不是故意留下的。"}, {"s": 118.43, "e": 120.65, "t": "但我就站在那里，低头看了一眼。"}, {"s": 120.65, "e": 121.98, "t": "那一页上的字很少。"}, {"s": 121.98, "e": 122.42, "t": "一行。"}, {"s": 122.42, "e": 127.16, "t": "蓝黑色的墨水，字迹很整齐，和平时草稿纸上那种飞起来的样子不一样。"}, {"s": 127.16, "e": 128.05, "t": "那行字写着："}, {"s": 128.05, "e": 130.12, "t": "\"小深今天问了一道物理题。\""}, {"s": 130.12, "e": 132.34, "t": "我盯着那行字看了大概 5 秒。"}, {"s": 132.34, "e": 137.08, "t": "不是因为我没看懂——是因为我看懂了，但我的大脑拒绝处理它的意思。"}, {"s": 137.08, "e": 143.29, "t": "他每天下午 4 点半拿出这个本子写一分钟——写的不是物理笔记，不是日记——写的是我。"}, {"s": 143.29, "e": 146.4, "t": "\"小深今天问了一道物理题\"——他在记录我。"}, {"s": 146.4, "e": 147.0, "t": "每一天。"}, {"s": 147.0, "e": 150.7, "t": "我站在他座位旁边，手指搭在桌沿上，不知道该看哪里。"}, {"s": 150.7, "e": 152.77, "t": "这时候他从教室门口走进来了。"}, {"s": 152.77, "e": 156.77, "t": "他看见我站在他桌边，又看见那个本子——他脚步顿了一下。"}, {"s": 156.77, "e": 159.73, "t": "然后他走过来，把本子合上，放进了抽屉里。"}, {"s": 159.73, "e": 160.47, "t": "动作很轻。"}, {"s": 160.47, "e": 161.95, "t": "安静持续了大概三秒。"}, {"s": 161.95, "e": 162.69, "t": "\"你——\""}, {"s": 162.69, "e": 163.87, "t": "\"……看见了。\""}, {"s": 163.87, "e": 164.91, "t": "他看了我一眼。"}, {"s": 164.91, "e": 166.24, "t": "然后他说了一句话。"}, {"s": 166.24, "e": 168.9, "t": "\"你知道我是从什么时候开始写的吗？\""}, {"s": 168.9, "e": 170.24, "t": "\"……什么时候？\""}, {"s": 170.24, "e": 171.42, "t": "他沉默了一会儿。"}, {"s": 171.42, "e": 172.16, "t": "\"高一上。"}, {"s": 172.16, "e": 173.64, "t": "12 月 7 号。\""}, {"s": 173.64, "e": 175.57, "t": "我握着卷子的手指紧了一下。"}, {"s": 175.57, "e": 181.04, "t": "\"第一页写的是：'今天 611 班那个站在走廊上的人——他今天看了我很久。"}, {"s": 181.04, "e": 182.52, "t": "他的眼睛里有光。'\""}, {"s": 182.52, "e": 184.6, "t": "他说这句话的时候，语气很平。"}, {"s": 184.6, "e": 187.11, "t": "像是在念一条已经背了几百遍的定理。"}, {"s": 187.11, "e": 190.07, "t": "我站在他面前，感觉整个世界都安静了两秒。"}, {"s": 190.07, "e": 190.66, "t": "高一上。"}, {"s": 190.66, "e": 192.0, "t": "12 月 7 号。"}, {"s": 192.0, "e": 195.85, "t": "那时候我在走廊上看着他——我以为他从来没有注意到我。"}, {"s": 195.85, "e": 197.18, "t": "但他不仅注意到了。"}, {"s": 197.18, "e": 198.07, "t": "他记下来了。"}, {"s": 198.07, "e": 199.84, "t": "他把那一天写进了本子里。"}, {"s": 199.84, "e": 201.47, "t": "从那天开始，记了一年。"}, {"s": 201.47, "e": 203.1, "t": "那天晚上我没有回教室。"}, {"s": 203.1, "e": 207.39, "t": "我一个人走到了 611 班的走廊——我高一上站的那个位置。"}, {"s": 207.39, "e": 208.43, "t": "那扇窗户还在。"}, {"s": 208.43, "e": 210.8, "t": "玻璃上的反光在路灯下映出我的脸。"}, {"s": 210.8, "e": 215.53, "t": "我站在那里，看着对面 610 班的最后一排——他高一上坐的位置。"}, {"s": 215.53, "e": 216.13, "t": "空着的。"}, {"s": 216.13, "e": 217.61, "t": "但他已经不在那里了。"}, {"s": 217.61, "e": 219.83, "t": "我站在那扇窗户前面，忽然笑了。"}, {"s": 219.83, "e": 221.6, "t": "不是苦笑——是真的笑了。"}, {"s": 221.6, "e": 223.08, "t": "因为我发现了一件事。"}, {"s": 223.08, "e": 227.38, "t": "我们高一上每天早上隔着那个天井互相看——他看我，我也看他。"}, {"s": 227.38, "e": 229.0, "t": "谁都不知道对方也在看。"}, {"s": 229.0, "e": 231.37, "t": "但他在本子的第一页写下了那一天。"}, {"s": 231.37, "e": 233.59, "t": "而我在心里，记下了每一个瞬间。"}, {"s": 233.59, "e": 234.63, "t": "那扇窗户还在。"}, {"s": 234.63, "e": 235.67, "t": "玻璃还在反光。"}, {"s": 235.67, "e": 238.33, "t": "但我和他之间——已经不需要隔着它了。"}, {"s": 238.33, "e": 241.59, "t": "<!-- summary:start -->"}, {"s": 241.59, "e": 242.62, "t": "本章推进线索："}, {"s": 242.62, "e": 249.73, "t": "- 🔵 🔑 全书核心反转：博文从高一上 12/7 开始记录\"今天 611 班那个站在走廊上的人\""}, {"s": 249.73, "e": 252.99, "t": "- 🔵 深蓝+小树图案的本子首次揭晓内部内容"}, {"s": 252.99, "e": 257.28, "t": "- 🔵 \"小深今天问了一道物理题\"——林深看到的第一行记录"}, {"s": 257.28, "e": 262.46, "t": "- 🔵 双向暗恋起点正式确认：2024/12/7，两人同时开始互相注视"}, {"s": 262.46, "e": 270.31, "t": "- 🔵 林深回到 611 走廊，站在高一上的位置看对面空座位——\"玻璃还在反光，但我们已经不需要隔着他了\""}, {"s": 270.31, "e": 271.79, "t": "本章关键事件时间戳："}, {"s": 271.79, "e": 275.49, "t": "- 10/7（周三）：首次下午 4:30 物理讲题"}, {"s": 275.49, "e": 280.52, "t": "- 10/14（周三）：博文拿出本子写 1 分钟，林深注意到但不看清"}, {"s": 280.52, "e": 286.14, "t": "- 10/20（周一）：本子未合，林深看到\"小深今天问了一道物理题\"——揭晓"}, {"s": 286.14, "e": 288.66, "t": "本章新埋伏笔：无（这是一个回收章）"}, {"s": 288.66, "e": 289.4, "t": "下章钩子："}, {"s": 289.4, "e": 290.88, "t": "- 他知道我在看他。"}, {"s": 290.88, "e": 292.21, "t": "他从一开始就知道。"}, {"s": 292.21, "e": 295.17, "t": "<!-- summary:end -->"}, {"s": 295.17, "e": 300.8, "t": "2026-07-19 初始版本：Ch 27 封面有颜色的本子——双向暗恋揭晓"}]}, {"num": 28, "title": "第28章 烦躁", "file": "chapters/ch028.mp3", "dur": 100.6, "size_mb": 0.8, "segs": [{"s": 0.0, "e": 2.23, "t": "时间：12 月 4 日 · 高二上"}, {"s": 2.23, "e": 5.12, "t": "12 月 4 号那天，我也不知道自己怎么了。"}, {"s": 5.12, "e": 6.82, "t": "早上起来的时候就感觉不对。"}, {"s": 6.82, "e": 9.31, "t": "不是哪里痛，不是哪里不舒服——就是闷。"}, {"s": 9.31, "e": 11.41, "t": "像有一团东西堵在胸口，不上不下。"}, {"s": 11.41, "e": 13.51, "t": "早自习我坐在座位上了，但没看书。"}, {"s": 13.51, "e": 18.62, "t": "我盯着英语课本的第一页，盯着那篇课文的第一行——看了十分钟，一个字都没读进去。"}, {"s": 18.62, "e": 20.59, "t": "下午 4 点半我没有去他那里。"}, {"s": 20.59, "e": 21.38, "t": "不是不想去。"}, {"s": 21.38, "e": 23.74, "t": "是觉得自己今天去了也说不出什么好话。"}, {"s": 23.74, "e": 27.67, "t": "我怕我一开口，就会把那团堵在胸口的东西吐出来——吐在他面前。"}, {"s": 27.67, "e": 29.25, "t": "我不想让他看见那样的我。"}, {"s": 29.25, "e": 31.74, "t": "但 4 点 45 的时候，他走过来了。"}, {"s": 31.74, "e": 32.92, "t": "在我桌边站了一下。"}, {"s": 32.92, "e": 33.97, "t": "\"你今天没来。\""}, {"s": 33.97, "e": 34.76, "t": "\"……嗯。\""}, {"s": 34.76, "e": 35.54, "t": "\"为什么？\""}, {"s": 35.54, "e": 36.33, "t": "\"不想去。\""}, {"s": 36.33, "e": 37.25, "t": "他沉默了几秒。"}, {"s": 37.25, "e": 39.48, "t": "然后他拉出我旁边的椅子，坐了下来。"}, {"s": 39.48, "e": 40.27, "t": "\"那我来。\""}, {"s": 40.27, "e": 43.41, "t": "他把物理卷子放在我桌上——不是我的，是他自己的。"}, {"s": 43.41, "e": 45.25, "t": "\"最后一道大题我不确定答案。"}, {"s": 45.25, "e": 45.91, "t": "你看看。\""}, {"s": 45.91, "e": 46.96, "t": "我低头看那道题。"}, {"s": 46.96, "e": 48.14, "t": "他不需要我不确定。"}, {"s": 48.14, "e": 49.05, "t": "他哪道题都会。"}, {"s": 49.05, "e": 50.1, "t": "但他坐在这里了。"}, {"s": 50.1, "e": 51.81, "t": "我拿起笔，看了一眼那道题。"}, {"s": 51.81, "e": 54.3, "t": "然后我开口说了一句话——不是关于题的。"}, {"s": 54.3, "e": 55.61, "t": "\"我今天心情不好。\""}, {"s": 55.61, "e": 56.53, "t": "\"看出来了。\""}, {"s": 56.53, "e": 57.45, "t": "\"那你还来？\""}, {"s": 57.45, "e": 58.1, "t": "他想了想。"}, {"s": 58.1, "e": 61.25, "t": "\"心情不好的时候，有人在旁边——会好得快一点。\""}, {"s": 61.25, "e": 63.88, "t": "他说的不是\"我陪你\"，不是\"你怎么了\"。"}, {"s": 63.88, "e": 67.15, "t": "他说的是\"会好得快一点\"——像一个经过验证的事实。"}, {"s": 67.15, "e": 71.61, "t": "我低头看着他那道我明明知道答案的大题，忽然觉得胸口那团东西松了一点。"}, {"s": 71.61, "e": 74.5, "t": "<!-- summary:start -->"}, {"s": 74.5, "e": 75.42, "t": "本章推进线索："}, {"s": 75.42, "e": 77.91, "t": "- 🔵 林深莫名烦躁的一天——不想见人"}, {"s": 77.91, "e": 81.98, "t": "- 🔵 博文主动过来\"那我来\"——不追问、不劝说、只是坐在旁边"}, {"s": 81.98, "e": 85.52, "t": "- 🔵 \"心情不好的时候，有人在旁边——会好得快一点\""}, {"s": 85.52, "e": 86.83, "t": "本章关键事件时间戳："}, {"s": 86.83, "e": 90.24, "t": "- 12/4：林深没去 4:30 讲题，博文主动过来"}, {"s": 90.24, "e": 90.89, "t": "下章钩子："}, {"s": 90.89, "e": 91.68, "t": "- 期末了。"}, {"s": 91.68, "e": 93.78, "t": "寒假要来了——20 公里的距离。"}, {"s": 93.78, "e": 96.4, "t": "<!-- summary:end -->"}, {"s": 96.4, "e": 100.6, "t": "2026-07-19 初始版本：Ch 28 烦躁——不说破的理解"}]}, {"num": 29, "title": "第29章 寒假", "file": "chapters/ch029.mp3", "dur": 139.2, "size_mb": 1.1, "segs": [{"s": 0.0, "e": 2.59, "t": "时间：1 月 10 日 · 高二上期末"}, {"s": 2.59, "e": 5.18, "t": "期末成绩出来那天，我排在 132 名。"}, {"s": 5.18, "e": 5.72, "t": "不算差。"}, {"s": 5.72, "e": 7.63, "t": "比期中的 187 名进步了。"}, {"s": 7.63, "e": 10.08, "t": "但离他还差着一大截——他 64 名。"}, {"s": 10.08, "e": 13.89, "t": "我盯着那个数字看了一会儿，然后把成绩单折好，放进口袋里。"}, {"s": 13.89, "e": 16.07, "t": "走出公告栏的时候，他在外面等我。"}, {"s": 16.07, "e": 16.75, "t": "\"多少？\""}, {"s": 16.75, "e": 17.57, "t": "\"132。\""}, {"s": 17.57, "e": 18.39, "t": "他点了点头。"}, {"s": 18.39, "e": 20.43, "t": "\"你比期中进步了 55 名。\""}, {"s": 20.43, "e": 21.52, "t": "\"……你算了？\""}, {"s": 21.52, "e": 23.15, "t": "\"每期的排名我都看了。\""}, {"s": 23.15, "e": 24.65, "t": "他说完就往前走了一步。"}, {"s": 24.65, "e": 25.33, "t": "\"走吧。\""}, {"s": 25.33, "e": 27.51, "t": "寒假开始那天，我们一起走出校门。"}, {"s": 27.51, "e": 29.42, "t": "他的家和我的家在相反的方向。"}, {"s": 29.42, "e": 32.42, "t": "他在城东，我在城西——隔着大概 20 公里。"}, {"s": 32.42, "e": 34.73, "t": "走出校门之后，他往左走，我往右走。"}, {"s": 34.73, "e": 36.77, "t": "走了大概十步，我回头看了一眼。"}, {"s": 36.77, "e": 37.59, "t": "他也在回头。"}, {"s": 37.59, "e": 38.68, "t": "我们对视了一秒。"}, {"s": 38.68, "e": 42.09, "t": "然后他笑了一下——嘴角往上翘了一下，然后转回去了。"}, {"s": 42.09, "e": 43.04, "t": "我也转回去了。"}, {"s": 43.04, "e": 43.86, "t": "20 公里。"}, {"s": 43.86, "e": 44.4, "t": "不算远。"}, {"s": 44.4, "e": 47.13, "t": "但在这个没有住校的寒假里——它就是很远。"}, {"s": 47.13, "e": 49.58, "t": "寒假第三天晚上，我给他发了一条微信。"}, {"s": 49.58, "e": 50.26, "t": "\"睡了？\""}, {"s": 50.26, "e": 51.62, "t": "过了一分半，他回了。"}, {"s": 51.62, "e": 52.17, "t": "\"没。\""}, {"s": 52.17, "e": 52.98, "t": "\"在干嘛？\""}, {"s": 52.98, "e": 53.66, "t": "\"看书。\""}, {"s": 53.66, "e": 55.16, "t": "过了一会儿他回了一条："}, {"s": 55.16, "e": 55.84, "t": "\"你呢？\""}, {"s": 55.84, "e": 56.52, "t": "\"发呆。\""}, {"s": 56.52, "e": 57.48, "t": "然后就没有了。"}, {"s": 57.48, "e": 60.34, "t": "但那个绿色的对话框，我翻来覆去看了好几遍。"}, {"s": 60.34, "e": 61.7, "t": "\"没\"——\"你呢？\""}, {"s": 61.7, "e": 62.25, "t": "四个字。"}, {"s": 62.25, "e": 64.02, "t": "但我抱着手机看了好一会儿。"}, {"s": 64.02, "e": 64.83, "t": "寒假第七天。"}, {"s": 64.83, "e": 65.51, "t": "\"睡了？\""}, {"s": 65.51, "e": 66.19, "t": "\"睡吧。\""}, {"s": 66.19, "e": 66.88, "t": "\"晚安。\""}, {"s": 66.88, "e": 67.56, "t": "\"晚安。\""}, {"s": 67.56, "e": 68.51, "t": "寒假第十五天。"}, {"s": 68.51, "e": 69.19, "t": "\"睡了？\""}, {"s": 69.19, "e": 70.01, "t": "\"刚洗完。\""}, {"s": 70.01, "e": 70.83, "t": "\"我也是。\""}, {"s": 70.83, "e": 73.14, "t": "然后他发了一张照片——窗外的月亮。"}, {"s": 73.14, "e": 74.09, "t": "不大，但很亮。"}, {"s": 74.09, "e": 77.09, "t": "我回了一张——我的窗户外面，也是同一个月亮。"}, {"s": 77.09, "e": 77.91, "t": "20 公里。"}, {"s": 77.91, "e": 79.0, "t": "但月亮是同一轮。"}, {"s": 79.0, "e": 80.22, "t": "寒假最后一个晚上。"}, {"s": 80.22, "e": 81.31, "t": "\"明天开学了。\""}, {"s": 81.31, "e": 81.86, "t": "\"嗯。\""}, {"s": 81.86, "e": 82.95, "t": "\"东西收好了？\""}, {"s": 82.95, "e": 83.77, "t": "\"收好了。\""}, {"s": 83.77, "e": 84.58, "t": "\"明天见。\""}, {"s": 84.58, "e": 86.49, "t": "我盯着那三个字看了好一会儿。"}, {"s": 86.49, "e": 87.03, "t": "明天见。"}, {"s": 87.03, "e": 88.8, "t": "整个寒假，最像样的一句话。"}, {"s": 88.8, "e": 89.76, "t": "我回了一个字："}, {"s": 89.76, "e": 90.3, "t": "\"好。\""}, {"s": 90.3, "e": 92.62, "t": "然后把手机放在枕头旁边，闭上眼睛。"}, {"s": 92.62, "e": 96.02, "t": "明天见——这三个字比我整个寒假的任何一条消息都重。"}, {"s": 96.02, "e": 99.02, "t": "<!-- summary:start -->"}, {"s": 99.02, "e": 99.97, "t": "本章推进线索："}, {"s": 99.97, "e": 102.7, "t": "- 🔵 132 名，比期中进步 55 名"}, {"s": 102.7, "e": 105.15, "t": "- 🔵 博文一直在关注林深的排名变化"}, {"s": 105.15, "e": 108.69, "t": "- 🔵 寒假 20 公里距离——QQ/微信聊天的片段"}, {"s": 108.69, "e": 109.78, "t": "- 🔵 \"睡了？"}, {"s": 109.78, "e": 110.46, "t": "\"\"睡吧。"}, {"s": 110.46, "e": 112.1, "t": "\"——简洁但有温度的对话"}, {"s": 112.1, "e": 114.96, "t": "- 🔵 同一轮月亮——20 公里的共情意象"}, {"s": 114.96, "e": 118.22, "t": "- 🔵 \"明天见\"——寒假结束、新学期开始的信号"}, {"s": 118.22, "e": 119.59, "t": "本章关键事件时间戳："}, {"s": 119.59, "e": 122.31, "t": "- 1/10：期末考试出成绩，132 名"}, {"s": 122.31, "e": 124.63, "t": "- 寒假第一天：走出校门，各自回头"}, {"s": 124.63, "e": 126.53, "t": "- 寒假期间：微信碎片化聊天"}, {"s": 126.53, "e": 128.44, "t": "- 寒假最后一晚：\"明天见\""}, {"s": 128.44, "e": 129.12, "t": "下章钩子："}, {"s": 129.12, "e": 131.85, "t": "- 高二下开学那天，他带我去了一个地方。"}, {"s": 131.85, "e": 134.57, "t": "<!-- summary:end -->"}, {"s": 134.57, "e": 139.2, "t": "2026-07-19 初始版本：Ch 29 寒假——20 公里的距离"}]}, {"num": 30, "title": "第30章 天台", "file": "chapters/ch030.mp3", "dur": 239.2, "size_mb": 1.9, "segs": [{"s": 0.0, "e": 3.49, "t": "时间：2 月 10 日 · 高二下学期开学第一天"}, {"s": 3.49, "e": 5.81, "t": "开学那天下午，他走到我座位边上。"}, {"s": 5.81, "e": 6.68, "t": "\"跟我来。\""}, {"s": 6.68, "e": 7.41, "t": "\"去哪？\""}, {"s": 7.41, "e": 8.14, "t": "他没回答。"}, {"s": 8.14, "e": 12.79, "t": "但他站在我桌边等了我一下——那个姿势的意思是\"你来了就知道了\"。"}, {"s": 12.79, "e": 14.1, "t": "我站起来，跟他走。"}, {"s": 14.1, "e": 16.42, "t": "他带我从教学楼的侧楼梯上了六楼。"}, {"s": 16.42, "e": 19.04, "t": "六楼上面有一扇铁门——平时是锁着的。"}, {"s": 19.04, "e": 21.8, "t": "他从口袋里掏出一把钥匙，打开了那扇门。"}, {"s": 21.8, "e": 23.11, "t": "\"你哪来的钥匙？\""}, {"s": 23.11, "e": 23.98, "t": "\"学生会的。"}, {"s": 23.98, "e": 25.0, "t": "天台归我管。\""}, {"s": 25.0, "e": 27.32, "t": "他推开门，侧过身，等我先走出去。"}, {"s": 27.32, "e": 29.36, "t": "我走出去的那一瞬间——天台。"}, {"s": 29.36, "e": 30.81, "t": "整片天空就在我面前。"}, {"s": 30.81, "e": 32.26, "t": "那天下午的阳光很好。"}, {"s": 32.26, "e": 36.04, "t": "二月的风还是凉的，但阳光落在身上，把凉意晒成了暖的。"}, {"s": 36.04, "e": 40.54, "t": "天台的水泥地面被照成浅灰色，远处城市的天际线在空气里清清楚楚。"}, {"s": 40.54, "e": 42.14, "t": "他走过来，站到我旁边。"}, {"s": 42.14, "e": 43.45, "t": "两只手搭在围栏上。"}, {"s": 43.45, "e": 44.47, "t": "安静了一会儿。"}, {"s": 44.47, "e": 45.2, "t": "\"小深。\""}, {"s": 45.2, "e": 45.78, "t": "\"嗯？\""}, {"s": 45.78, "e": 48.39, "t": "\"你知道这个天台对我来说是什么吗？\""}, {"s": 48.39, "e": 49.41, "t": "\"……什么？\""}, {"s": 49.41, "e": 50.43, "t": "他沉默了很久。"}, {"s": 50.43, "e": 52.17, "t": "久到我以为他不会回答了。"}, {"s": 52.17, "e": 55.37, "t": "然后他说：\"是我决定不再一个人待着的地方。\""}, {"s": 55.37, "e": 56.38, "t": "我转过头看他。"}, {"s": 56.38, "e": 57.26, "t": "他没有看我。"}, {"s": 57.26, "e": 61.62, "t": "他低着头，看着围栏上的一道划痕——不知道是哪个学生留下来的。"}, {"s": 61.62, "e": 64.09, "t": "\"我高一上的时候——坐在最后一排。"}, {"s": 64.09, "e": 68.45, "t": "每天早上我抬头，都能看见 611 班的走廊上有个人站在那。\""}, {"s": 68.45, "e": 69.75, "t": "他说的那个人是我。"}, {"s": 69.75, "e": 71.21, "t": "\"我看了你一年半。\""}, {"s": 71.21, "e": 71.64, "t": "他说。"}, {"s": 71.64, "e": 73.53, "t": "\"我在窗户边上看了你一年。"}, {"s": 73.53, "e": 79.06, "t": "我不知道你的名字，不知道你在哪个班，不知道你早上站在走廊上是在背书还是发呆。"}, {"s": 79.06, "e": 80.94, "t": "但我每次抬头——你都在。\""}, {"s": 80.94, "e": 84.29, "t": "风从城市那边吹过来，把他校服的衣摆吹动了一下。"}, {"s": 84.29, "e": 85.89, "t": "他把手从围栏上放下来。"}, {"s": 85.89, "e": 88.94, "t": "\"2 月 13 号——你进 610 班了。"}, {"s": 88.94, "e": 90.1, "t": "你坐到我后面。\""}, {"s": 90.1, "e": 90.83, "t": "他顿了顿。"}, {"s": 90.83, "e": 93.15, "t": "\"那天我回家在本子上写了一行字。"}, {"s": 93.15, "e": 94.75, "t": "'他进 610 班了。"}, {"s": 94.75, "e": 96.06, "t": "原来他叫林深。'\""}, {"s": 96.06, "e": 99.25, "t": "我站在他旁边，手指握着围栏的边缘，握得发白。"}, {"s": 99.25, "e": 101.29, "t": "\"我高一上就想离你近一点。\""}, {"s": 101.29, "e": 103.91, "t": "他说这话的时候，声音比刚才低了一些。"}, {"s": 103.91, "e": 105.94, "t": "\"但我不知道该怎么靠近你。\""}, {"s": 105.94, "e": 107.54, "t": "然后他转过身来面对我。"}, {"s": 107.54, "e": 110.3, "t": "阳光落在他的侧脸上——他的眼睛里有光。"}, {"s": 110.3, "e": 114.66, "t": "那种像早上第一节课前、太阳照到对面教学楼白墙再反射过来的光。"}, {"s": 114.66, "e": 116.11, "t": "\"我想和你在一起。\""}, {"s": 116.11, "e": 116.55, "t": "他说。"}, {"s": 116.55, "e": 117.13, "t": "四个字。"}, {"s": 117.13, "e": 120.47, "t": "没有铺垫，没有修饰，没有\"如果\"或者\"可能\"。"}, {"s": 120.47, "e": 121.49, "t": "就是这四个字。"}, {"s": 121.49, "e": 122.51, "t": "\"我喜欢你。\""}, {"s": 122.51, "e": 123.52, "t": "他又说了一遍。"}, {"s": 123.52, "e": 127.3, "t": "声音比第一遍稍微小一点——但每一笔每一画都清清楚楚。"}, {"s": 127.3, "e": 129.92, "t": "我站在天台上，二月的风从耳边吹过去。"}, {"s": 129.92, "e": 133.26, "t": "我以前想过——如果他真的说出来了，我会怎么样。"}, {"s": 133.26, "e": 135.59, "t": "我想过我会紧张、会脸红、会结巴。"}, {"s": 135.59, "e": 138.2, "t": "但真正发生的时候，我什么感觉都没有。"}, {"s": 138.2, "e": 139.65, "t": "不——不是没有感觉。"}, {"s": 139.65, "e": 144.45, "t": "是感觉太多了，多到我的大脑选择关闭了一部分功能，只留下了一个念头。"}, {"s": 144.45, "e": 145.47, "t": "我听见自己说："}, {"s": 145.47, "e": 146.63, "t": "\"我也喜欢你。\""}, {"s": 146.63, "e": 150.41, "t": "然后我看见他嘴角动了一下——眼睛底下那一块皱了一下。"}, {"s": 150.41, "e": 151.43, "t": "1 厘米的皱。"}, {"s": 151.43, "e": 152.59, "t": "然后他问了一句："}, {"s": 152.59, "e": 154.33, "t": "\"你愿意做我男朋友吗。\""}, {"s": 154.33, "e": 159.27, "t": "不是疑问句的语气——是那种他已经知道答案、但还是想听我说出来的语气。"}, {"s": 159.27, "e": 159.85, "t": "我说：\""}, {"s": 159.85, "e": 160.44, "t": "愿意。\""}, {"s": 160.44, "e": 161.02, "t": "他笑了。"}, {"s": 161.02, "e": 163.63, "t": "不是嘴角动一下的那种——是真的笑了。"}, {"s": 163.63, "e": 166.68, "t": "眼睛弯了一下，嘴角往上，整张脸都亮了一瞬。"}, {"s": 166.68, "e": 169.15, "t": "然后他转回去，重新看向远处的城市。"}, {"s": 169.15, "e": 170.9, "t": "我也转回去，站在他旁边。"}, {"s": 170.9, "e": 174.1, "t": "天台的围栏有一点冰，但阳光照到的地方是暖的。"}, {"s": 174.1, "e": 176.28, "t": "我们并排站着，谁都没有再说话。"}, {"s": 176.28, "e": 179.76, "t": "远处的天际线在下午的阳光里被染成一层淡淡的橘色。"}, {"s": 179.76, "e": 181.22, "t": "和我想象中一模一样。"}, {"s": 181.22, "e": 184.41, "t": "<!-- summary:start -->"}, {"s": 184.41, "e": 185.43, "t": "本章推进线索："}, {"s": 185.43, "e": 187.76, "t": "- 🔵 全书情感高潮——天台表白"}, {"s": 187.76, "e": 192.26, "t": "- 🔵 \"我高一上就想离你近一点\"——博文首次完整袒露心路历程"}, {"s": 192.26, "e": 198.22, "t": "- 🔵 \"我喜欢你\" / \"我也喜欢你\" / \"愿意\"——全书简短但最重的三组对话"}, {"s": 198.22, "e": 202.72, "t": "- 🔵 1 厘米的皱首次在确认关系场景中出现（博文标志性表情）"}, {"s": 202.72, "e": 209.7, "t": "- 🔵 橘色光——天台意象弧开端（Ch 30 橘色 → Ch 34 白色 → Ch 40 淡橘）"}, {"s": 209.7, "e": 214.2, "t": "- 🔵 距离意象里程碑：5米→80厘米→30厘米→\"在你旁边\""}, {"s": 214.2, "e": 215.66, "t": "本章关键事件时间戳："}, {"s": 215.66, "e": 219.15, "t": "- 2/10 高二下学期开学第一天下午：天台表白"}, {"s": 219.15, "e": 220.89, "t": "- 博文用学生会钥匙开门"}, {"s": 220.89, "e": 224.38, "t": "- 整章时长：约 15 分钟，对话不到 10 句"}, {"s": 224.38, "e": 225.39, "t": "本章新埋伏笔："}, {"s": 225.39, "e": 228.88, "t": "- F-橘色光：表白日的颜色，后续将成为贯穿意象"}, {"s": 228.88, "e": 229.61, "t": "下章钩子："}, {"s": 229.61, "e": 231.79, "t": "- 在一起的第一天——然后呢？"}, {"s": 231.79, "e": 234.7, "t": "<!-- summary:end -->"}, {"s": 234.7, "e": 239.2, "t": "2026-07-19 初始版本：Ch 30 天台——全书表白章"}]}, {"num": 31, "title": "第31章 第一天", "file": "chapters/ch031.mp3", "dur": 172.8, "size_mb": 1.4, "segs": [{"s": 0.0, "e": 3.46, "t": "时间：2 月 11 日 · 高二下，在一起第一天"}, {"s": 3.46, "e": 6.34, "t": "在一起之后的第一天，和前一天没什么区别。"}, {"s": 6.34, "e": 8.5, "t": "早上 6 点 40，闹钟响了。"}, {"s": 8.5, "e": 13.11, "t": "我坐起来，看见他已经在穿校服了——背对着我，把拉链从下往上拉好。"}, {"s": 13.11, "e": 13.84, "t": "\"起了？\""}, {"s": 13.84, "e": 14.56, "t": "\"起了。\""}, {"s": 14.56, "e": 15.71, "t": "对话和以前一样。"}, {"s": 15.71, "e": 16.72, "t": "但感觉不一样。"}, {"s": 16.72, "e": 19.74, "t": "早自习的时候，我坐在座位上，低头看英语书。"}, {"s": 19.74, "e": 21.91, "t": "但看了十分钟，一行都没读进去。"}, {"s": 21.91, "e": 24.79, "t": "因为我一直在想——现在我和他是什么关系？"}, {"s": 24.79, "e": 26.52, "t": "想了十分钟，没想出答案。"}, {"s": 26.52, "e": 29.83, "t": "准确地说——是想出了答案，但不知道该怎么执行。"}, {"s": 29.83, "e": 34.88, "t": "如果我现在走过去跟他说话，应该是用\"男朋友\"的语气还是\"朋友\"的语气？"}, {"s": 34.88, "e": 37.76, "t": "如果我用\"男朋友\"的语气，他会怎么反应？"}, {"s": 37.76, "e": 39.92, "t": "如果我什么也不做，他会怎么想？"}, {"s": 39.92, "e": 42.95, "t": "我盯着英语书上的单词，脑子里全是这些问题。"}, {"s": 42.95, "e": 44.82, "t": "然后一张纸条被推到我桌上。"}, {"s": 44.82, "e": 45.4, "t": "我打开。"}, {"s": 45.4, "e": 45.97, "t": "他的字："}, {"s": 45.97, "e": 46.69, "t": "\"别想了。"}, {"s": 46.69, "e": 47.56, "t": "好好背书。\""}, {"s": 47.56, "e": 49.87, "t": "我抬头——他坐在前面，低头看书。"}, {"s": 49.87, "e": 51.88, "t": "但他后脑勺好像长了眼睛一样。"}, {"s": 51.88, "e": 54.19, "t": "我低下头，把那四个字又读了一遍。"}, {"s": 54.19, "e": 56.5, "t": "\"别想了\"——他怎么知道我在想？"}, {"s": 56.5, "e": 58.8, "t": "中午去食堂的时候，他在门口等我。"}, {"s": 58.8, "e": 60.96, "t": "我走过去的时候，他看了我一眼。"}, {"s": 60.96, "e": 66.44, "t": "然后他伸手——不是牵我的手——是把我的书包带子从我肩膀上拿下来，拎到他手里。"}, {"s": 66.44, "e": 67.88, "t": "\"你书包好像很重。\""}, {"s": 67.88, "e": 68.89, "t": "\"……还好。\""}, {"s": 68.89, "e": 69.9, "t": "他没再说别的。"}, {"s": 69.9, "e": 71.92, "t": "就帮我拎着书包，走进食堂了。"}, {"s": 71.92, "e": 76.82, "t": "我跟在后面，看着他把我的书包挂到椅背上，然后坐到我旁边——不是对面。"}, {"s": 76.82, "e": 77.97, "t": "他平时坐对面的。"}, {"s": 77.97, "e": 78.83, "t": "今天坐旁边。"}, {"s": 78.83, "e": 79.7, "t": "下午换座位。"}, {"s": 79.7, "e": 82.72, "t": "按上学期期末的成绩排的——我 132 名。"}, {"s": 82.72, "e": 84.17, "t": "不算差，但也不算好。"}, {"s": 84.17, "e": 87.19, "t": "换了之后我数了一下——我离他隔了 5 行。"}, {"s": 87.19, "e": 88.35, "t": "比之前远了一点。"}, {"s": 88.35, "e": 91.37, "t": "我坐在新位置上，盯着前面的距离看了一会儿。"}, {"s": 91.37, "e": 93.25, "t": "然后一张纸又被推到我桌上。"}, {"s": 93.25, "e": 93.82, "t": "我打开："}, {"s": 93.82, "e": 95.55, "t": "\"你每天都来问我物理题。"}, {"s": 95.55, "e": 96.56, "t": "比距离重要。\""}, {"s": 96.56, "e": 98.87, "t": "我握着那张纸，在座位上坐了三秒。"}, {"s": 98.87, "e": 100.74, "t": "然后我站起来，走到他桌边。"}, {"s": 100.74, "e": 102.04, "t": "\"第四题怎么做？\""}, {"s": 102.04, "e": 103.33, "t": "他抬头看了我一眼。"}, {"s": 103.33, "e": 107.37, "t": "那个眼神——不是\"你这就来了\"——是\"我就知道你会来\"。"}, {"s": 107.37, "e": 108.52, "t": "然后他拿起了笔。"}, {"s": 108.52, "e": 110.11, "t": "晚上回宿舍，熄灯之后。"}, {"s": 110.11, "e": 110.83, "t": "\"小深。\""}, {"s": 110.83, "e": 111.4, "t": "\"嗯？\""}, {"s": 111.4, "e": 113.71, "t": "\"你今天一共问了我七道物理题。\""}, {"s": 113.71, "e": 114.72, "t": "\"……有吗？\""}, {"s": 114.72, "e": 115.15, "t": "\"有。"}, {"s": 115.15, "e": 117.46, "t": "上午两道，中午一道，下午四道。\""}, {"s": 117.46, "e": 118.47, "t": "我沉默了一下。"}, {"s": 118.47, "e": 119.33, "t": "\"你数了？\""}, {"s": 119.33, "e": 121.35, "t": "\"你每次走过来，我都数了。\""}, {"s": 121.35, "e": 122.21, "t": "安静了几秒。"}, {"s": 122.21, "e": 123.08, "t": "\"太多了？\""}, {"s": 123.08, "e": 123.8, "t": "\"不是。\""}, {"s": 123.8, "e": 124.66, "t": "他顿了一下。"}, {"s": 124.66, "e": 126.97, "t": "\"就是——让你多跑几趟也没关系。"}, {"s": 126.97, "e": 127.98, "t": "反正我都在。\""}, {"s": 127.98, "e": 129.85, "t": "黑暗里，我把被子拉过头顶。"}, {"s": 129.85, "e": 130.86, "t": "然后笑了一下。"}, {"s": 130.86, "e": 134.03, "t": "<!-- summary:start -->"}, {"s": 134.03, "e": 135.04, "t": "本章推进线索："}, {"s": 135.04, "e": 139.36, "t": "- 🔵 在一起第一天的\"日常化\"过渡——从身份变化到行为变化"}, {"s": 139.36, "e": 143.4, "t": "- 🔵 博文拎书包、坐旁边——行动上的偏移（比语言更快）"}, {"s": 143.4, "e": 146.14, "t": "- 🔵 便利贴\"你每天都来问我物理题。"}, {"s": 146.14, "e": 147.0, "t": "比距离重要。"}, {"s": 147.0, "e": 149.02, "t": "\"——回应了换座位的距离变化"}, {"s": 149.02, "e": 153.78, "t": "- 🔵 博文数了林深一天问了几道物理题，\"你每次走过来，我都数了\""}, {"s": 153.78, "e": 155.22, "t": "本章关键事件时间戳："}, {"s": 155.22, "e": 157.09, "t": "- 2/11：在一起第一天"}, {"s": 157.09, "e": 158.68, "t": "- 博文拎书包、坐旁边"}, {"s": 158.68, "e": 160.98, "t": "- 换座位后距离变远，便利贴回应"}, {"s": 160.98, "e": 162.57, "t": "- 熄灯后数物理题次数"}, {"s": 162.57, "e": 163.29, "t": "下章钩子："}, {"s": 163.29, "e": 164.73, "t": "- 他好像有话要说。"}, {"s": 164.73, "e": 167.61, "t": "<!-- summary:end -->"}, {"s": 167.61, "e": 172.8, "t": "2026-07-19 初始版本：Ch 31 第一天——在一起之后的第一天"}]}, {"num": 32, "title": "第32章 第三次推迟", "file": "chapters/ch032.mp3", "dur": 428.2, "size_mb": 3.4, "segs": [{"s": 0.0, "e": 2.82, "t": "时间：3 月初 · 在一起两周后"}, {"s": 2.82, "e": 4.05, "t": "在一起两周了。"}, {"s": 4.05, "e": 6.52, "t": "两周——说长不长，说短不短。"}, {"s": 6.52, "e": 25.74, "t": "短到我还是会在路过 610 班门口时下意识放慢脚步，长到我已经开始习惯每天下午 4 点半去他座位这件事——习惯了推椅子时那一声\"吱\"，习惯了他低头讲题时后颈那一截白，习惯了他偶尔回头看我一眼时眼底那一条 1 厘米的皱。"}, {"s": 25.74, "e": 27.85, "t": "但有一件事我还是不习惯。"}, {"s": 27.85, "e": 29.97, "t": "不习惯他欲言又止的样子。"}, {"s": 29.97, "e": 32.79, "t": "今天是周四，下午最后一节自习课。"}, {"s": 32.79, "e": 35.96, "t": "教室里只剩翻书声和窗外远处的广播声。"}, {"s": 35.96, "e": 43.54, "t": "博文坐在我前面两排的位置——上周换座位，他往前挪了一排，我在原地没动，距离变成了四行。"}, {"s": 43.54, "e": 47.95, "t": "不算远，但也不像之前那样一抬头就能看见他的后脑勺。"}, {"s": 47.95, "e": 49.54, "t": "我低头做物理卷子。"}, {"s": 49.54, "e": 55.35, "t": "做完最后一道大题，抬头的时候，看见他正侧着身，手搭在桌沿，看着我。"}, {"s": 55.35, "e": 57.47, "t": "那个眼神——我说不上来。"}, {"s": 57.47, "e": 59.76, "t": "不是平时那种\"你又做完了？"}, {"s": 59.76, "e": 64.17, "t": "拿来我看\"的眼神，也不是吃醋时那种压着脾气的眼神。"}, {"s": 64.17, "e": 69.1, "t": "它更软，像有什么话在嘴里含了很久，含到快化了，又咽回去。"}, {"s": 69.1, "e": 71.57, "t": "他看见我抬头，嘴角动了一下。"}, {"s": 71.57, "e": 72.81, "t": "然后转回去了。"}, {"s": 72.81, "e": 79.15, "t": "放学后我去他座位拿笔记本——他上周说好借我的电磁学笔记，一直放在他桌角。"}, {"s": 79.15, "e": 80.74, "t": "\"博文，笔记——\""}, {"s": 80.74, "e": 81.27, "t": "\"嗯。"}, {"s": 81.27, "e": 83.91, "t": "\"他递过来，指尖碰到我的手指。"}, {"s": 83.91, "e": 84.44, "t": "一秒。"}, {"s": 84.44, "e": 85.85, "t": "然后就收回去了。"}, {"s": 85.85, "e": 89.55, "t": "他低头收拾书包，动作比平时慢，像在等什么。"}, {"s": 89.55, "e": 90.26, "t": "我没走。"}, {"s": 90.26, "e": 92.37, "t": "过了大概十秒，他抬起头。"}, {"s": 92.37, "e": 93.26, "t": "\"林深。\""}, {"s": 93.26, "e": 93.96, "t": "\"嗯？\""}, {"s": 93.96, "e": 96.08, "t": "\"我其实……\"他停住了。"}, {"s": 96.08, "e": 97.31, "t": "喉结动了一下。"}, {"s": 97.31, "e": 102.07, "t": "然后他笑了笑，那个笑很轻，像怕惊动什么似的，\"算了。\""}, {"s": 102.07, "e": 103.3, "t": "\"算了什么？\""}, {"s": 103.3, "e": 105.24, "t": "\"算了，等高考完吧。\""}, {"s": 105.24, "e": 106.12, "t": "又是这句。"}, {"s": 106.12, "e": 107.18, "t": "我没有追问。"}, {"s": 107.18, "e": 108.95, "t": "不是不想，是我不敢。"}, {"s": 108.95, "e": 113.0, "t": "我怕我一追问，就会听到什么我还没准备好听的话。"}, {"s": 113.0, "e": 118.11, "t": "也怕我一追问，他就真的说了——说出来之后，我们还回得去吗？"}, {"s": 118.11, "e": 120.58, "t": "所以我也笑了笑，说：\"好。\""}, {"s": 120.58, "e": 122.52, "t": "他看了我大概 5 秒。"}, {"s": 122.52, "e": 124.99, "t": "然后站起来，拎着书包往外走。"}, {"s": 124.99, "e": 128.51, "t": "走到门口时停了一下，没回头，只说了一句："}, {"s": 128.51, "e": 131.33, "t": "\"明天下午 4 点半，老地方。\""}, {"s": 131.33, "e": 132.04, "t": "\"好。\""}, {"s": 132.04, "e": 135.56, "t": "周海从后门进来，看见我的样子，叹了口气。"}, {"s": 135.56, "e": 136.8, "t": "\"他又说了？\""}, {"s": 136.8, "e": 137.86, "t": "\"又说了。\""}, {"s": 137.86, "e": 139.27, "t": "\"第三次了吧？\""}, {"s": 139.27, "e": 139.97, "t": "\"嗯。\""}, {"s": 139.97, "e": 141.73, "t": "\"你就不想问清楚？\""}, {"s": 141.73, "e": 142.62, "t": "\"我怕。\""}, {"s": 142.62, "e": 143.67, "t": "\"怕什么？\""}, {"s": 143.67, "e": 147.2, "t": "\"怕他说了之后，我发现不是我想的那样。\""}, {"s": 147.2, "e": 148.79, "t": "周海沉默了一会儿。"}, {"s": 148.79, "e": 152.84, "t": "\"你有没有想过——他说的可能就是你想的那样。\""}, {"s": 152.84, "e": 153.72, "t": "\"想过。\""}, {"s": 153.72, "e": 155.13, "t": "\"那不就结了。\""}, {"s": 155.13, "e": 156.37, "t": "\"那是他说的。"}, {"s": 156.37, "e": 157.42, "t": "不是我猜的。"}, {"s": 157.42, "e": 158.31, "t": "不一样。\""}, {"s": 158.31, "e": 159.54, "t": "周海不说话了。"}, {"s": 159.54, "e": 162.54, "t": "他拍了拍我的肩膀，走回自己的座位。"}, {"s": 162.54, "e": 163.24, "t": "不一样。"}, {"s": 163.24, "e": 166.77, "t": "我也说不上来哪里不一样，但它就是不一样。"}, {"s": 166.77, "e": 169.06, "t": "我猜的——我猜了两年多了。"}, {"s": 169.06, "e": 175.93, "t": "从高一上那个窗户开始，我就一直在猜他每一个动作、每一个眼神、每一句话的潜台词。"}, {"s": 175.93, "e": 179.46, "t": "猜对了那就是我运气好，猜错了我也习惯了。"}, {"s": 179.46, "e": 181.05, "t": "但如果是他说的——"}, {"s": 181.05, "e": 182.1, "t": "那就是真的。"}, {"s": 182.1, "e": 185.63, "t": "而\"真的\"这两个字，比我想象中要重得多。"}, {"s": 185.63, "e": 187.57, "t": "走廊尽头有个人靠着墙。"}, {"s": 187.57, "e": 189.86, "t": "我走近了才看清——是博文。"}, {"s": 189.86, "e": 194.09, "t": "他也刚回来，校服外套搭在肩上，手里拿着一个杯子。"}, {"s": 194.09, "e": 195.85, "t": "看见我，他站直了身。"}, {"s": 195.85, "e": 197.09, "t": "\"你还没睡？\""}, {"s": 197.09, "e": 197.97, "t": "\"刚洗完。"}, {"s": 197.97, "e": 198.67, "t": "\"他说。"}, {"s": 198.67, "e": 201.5, "t": "然后顿了顿，把手里的杯子递过来。"}, {"s": 201.5, "e": 203.26, "t": "我接过来——是热的。"}, {"s": 203.26, "e": 205.73, "t": "打开盖子，豆浆的甜味散出来。"}, {"s": 205.73, "e": 207.67, "t": "\"你下午没怎么喝东西。"}, {"s": 207.67, "e": 208.37, "t": "\"他说。"}, {"s": 208.37, "e": 215.95, "t": "我愣了一下——下午我确实没喝水，第三节课就开始口干，但我自己都没在意，他竟然注意到了。"}, {"s": 215.95, "e": 216.83, "t": "\"谢谢。\""}, {"s": 216.83, "e": 217.54, "t": "\"嗯。\""}, {"s": 217.54, "e": 218.24, "t": "他没走。"}, {"s": 218.24, "e": 219.12, "t": "我也没走。"}, {"s": 219.12, "e": 225.29, "t": "我们就这么站在走廊尽头，路灯的光从窗户外面照进来，把他的影子拉得很长。"}, {"s": 225.29, "e": 229.7, "t": "夜晚的操场空荡荡的，远处宿舍楼的灯一盏一盏灭下去。"}, {"s": 229.7, "e": 233.76, "t": "我握着那杯豆浆，手指被烫得发麻，但我不想放下。"}, {"s": 233.76, "e": 234.64, "t": "\"林深。\""}, {"s": 234.64, "e": 235.34, "t": "\"嗯？\""}, {"s": 235.34, "e": 236.58, "t": "他侧过头看我。"}, {"s": 236.58, "e": 239.22, "t": "那个距离——不到 30 厘米。"}, {"s": 239.22, "e": 243.8, "t": "我能看见他眼睛里的光，能看见他睫毛的影子投在眼睑上。"}, {"s": 243.8, "e": 245.74, "t": "他张了张嘴，又闭上了。"}, {"s": 245.74, "e": 246.98, "t": "我看见他在咽。"}, {"s": 246.98, "e": 251.74, "t": "不是咽口水的那种咽——是把什么话硬生生压回去的那种咽。"}, {"s": 251.74, "e": 254.56, "t": "他垂在身侧的手握成了拳，又松开。"}, {"s": 254.56, "e": 255.79, "t": "——他在犹豫。"}, {"s": 255.79, "e": 257.91, "t": "博文是一个很少犹豫的人。"}, {"s": 257.91, "e": 264.43, "t": "他不管做什么都是干脆的——拿主意干脆，做题干脆，连吃醋都是直接把话说出来。"}, {"s": 264.43, "e": 267.6, "t": "可每次到了我面前，他就会变得不像他。"}, {"s": 267.6, "e": 269.37, "t": "\"你到底想说什么？\""}, {"s": 269.37, "e": 275.89, "t": "他看我的眼神变了——不是那种\"我在想\"的眼神，而是那种\"我在决定\"的眼神。"}, {"s": 275.89, "e": 277.48, "t": "过了大概 3 秒。"}, {"s": 277.48, "e": 279.77, "t": "他抬起手，握住了我的手腕。"}, {"s": 279.77, "e": 284.0, "t": "那只手是暖的——和那天借笔记时碰到的手指一样暖。"}, {"s": 284.0, "e": 288.23, "t": "他的拇指按在我的脉搏上，用力了一下，然后松开了。"}, {"s": 288.23, "e": 288.93, "t": "\"算了。"}, {"s": 288.93, "e": 291.58, "t": "\"他说，声音低下去，\"我怕。\""}, {"s": 291.58, "e": 293.16, "t": "这回轮到我愣住了。"}, {"s": 293.16, "e": 294.4, "t": "\"你怕什么？\""}, {"s": 294.4, "e": 295.28, "t": "他没回答。"}, {"s": 295.28, "e": 297.75, "t": "只是转过身，往宿舍走了两步。"}, {"s": 297.75, "e": 298.98, "t": "然后停了下来。"}, {"s": 298.98, "e": 301.63, "t": "\"我怕说出来之后……你不信。\""}, {"s": 301.63, "e": 303.74, "t": "他说这句话的时候没回头。"}, {"s": 303.74, "e": 306.56, "t": "声音比平时小，小到我差点没听清。"}, {"s": 306.56, "e": 307.97, "t": "但走廊太安静了。"}, {"s": 307.97, "e": 311.67, "t": "安静到每一个字都像钉子一样，钉进我耳朵里。"}, {"s": 311.67, "e": 312.56, "t": "\"我信。\""}, {"s": 312.56, "e": 313.79, "t": "我听见自己说。"}, {"s": 313.79, "e": 315.2, "t": "他肩膀动了一下。"}, {"s": 315.2, "e": 317.32, "t": "然后他走进宿舍门了。甜。"}, {"s": 317.32, "e": 318.73, "t": "和上次的一样甜。"}, {"s": 318.73, "e": 320.31, "t": "他记得我喜欢甜的。"}, {"s": 320.31, "e": 323.84, "t": "我一直站在走廊尽头，直到杯子凉了才回去。"}, {"s": 323.84, "e": 326.66, "t": "推门进宿舍的时候，他已经躺下了。"}, {"s": 326.66, "e": 329.83, "t": "我看不见他的脸——他把被角拉过头顶。"}, {"s": 329.83, "e": 332.12, "t": "我轻手轻脚地爬上自己的床。"}, {"s": 332.12, "e": 332.65, "t": "躺下。"}, {"s": 332.65, "e": 333.36, "t": "关了灯。"}, {"s": 333.36, "e": 337.41, "t": "黑暗中，我能听见他的呼吸——不匀，像还没睡着。"}, {"s": 337.41, "e": 338.29, "t": "\"博文。\""}, {"s": 338.29, "e": 339.18, "t": "没有回应。"}, {"s": 339.18, "e": 340.59, "t": "\"我说的是真的。"}, {"s": 340.59, "e": 341.47, "t": "我信你。\""}, {"s": 341.47, "e": 342.52, "t": "安静了很久。"}, {"s": 342.52, "e": 344.64, "t": "久到我以为他已经睡着了。"}, {"s": 344.64, "e": 347.81, "t": "然后——黑暗中传来一声很轻的\"嗯\"。"}, {"s": 347.81, "e": 349.58, "t": "像从被子里闷出来的。"}, {"s": 349.58, "e": 350.81, "t": "我把眼睛闭上。"}, {"s": 350.81, "e": 353.98, "t": "天花板上的月光很淡，淡到几乎看不见。"}, {"s": 353.98, "e": 361.56, "t": "但我脑子里全是走廊尽头他回过头看我的那个表情——那个咽回去的动作，那只握紧又松开的手。"}, {"s": 361.56, "e": 362.27, "t": "他在怕。"}, {"s": 362.27, "e": 363.33, "t": "怕我不信他。"}, {"s": 363.33, "e": 367.2, "t": "不是怕我不喜欢他——是怕我不相信他是认真的。"}, {"s": 367.2, "e": 371.26, "t": "这个认知在我胸口盘了很久，盘到整颗心都是满的。"}, {"s": 371.26, "e": 373.02, "t": "我喜欢他眼睛里的光。"}, {"s": 373.02, "e": 378.49, "t": "但那一刻我发现——我更喜欢他害怕的时候，还是选择走向我的样子。"}, {"s": 378.49, "e": 382.37, "t": "<!-- summary:start -->"}, {"s": 382.37, "e": 383.6, "t": "本章推进线索："}, {"s": 383.6, "e": 389.24, "t": "- POV-BW-推迟：博文第三次推迟\"算了，等高考完\"——保留"}, {"s": 389.24, "e": 398.23, "t": "- POV-BW-不安全感：博文用行动表达不安(握紧手/咽回去/闭上眼睛)，不再直说前任细节——修复版"}, {"s": 398.23, "e": 404.58, "t": "- POV-LS-信：林深说\"我信你\"——第一次在行动层面回应博文的不安"}, {"s": 404.58, "e": 405.81, "t": "本章新埋伏笔："}, {"s": 405.81, "e": 407.75, "t": "- 博文到底想说什么？"}, {"s": 407.75, "e": 410.22, "t": "——悬念继续维持到高考后揭晓"}, {"s": 410.22, "e": 411.98, "t": "本章关键事件时间戳："}, {"s": 411.98, "e": 418.68, "t": "- 3月初·在一起两周后：自习课欲言又止 → 晚自习后走廊豆浆 → 宿舍回应"}, {"s": 418.68, "e": 419.56, "t": "下章钩子："}, {"s": 419.56, "e": 424.67, "t": "- 他说\"我怕说出来之后你不信\"——那他要说的到底是什么？"}, {"s": 424.67, "e": 428.2, "t": "<!-- summary:end -->"}]}, {"num": 33, "title": "第33章 日常", "file": "chapters/ch033.mp3", "dur": 164.6, "size_mb": 1.3, "segs": [{"s": 0.0, "e": 2.75, "t": "时间：3 月中旬—4 月初 · 高二下"}, {"s": 2.75, "e": 6.07, "t": "在一起之后，生活并没有发生什么惊天动地的变化。"}, {"s": 6.07, "e": 11.71, "t": "没有每天写情书，没有每天说\"我喜欢你\"，没有那种偶像剧里突然多出来的浪漫桥段。"}, {"s": 11.71, "e": 18.79, "t": "我们还是每天 6 点 40 起床，他先洗好，然后敲一下我的床沿——\"起了\"——然后我们一起去教室。"}, {"s": 18.79, "e": 20.67, "t": "早自习他在前面，我在后面。"}, {"s": 20.67, "e": 27.17, "t": "上课的时候各上各的，偶尔传一张纸条，上面写着\"中午吃什么\"或者\"物理作业第四题答案不对\"。"}, {"s": 27.17, "e": 29.63, "t": "中午有时候一起吃饭，有时候不一起。"}, {"s": 29.63, "e": 36.13, "t": "不一起的时候他会在桌上留一张便利贴——\"帮我去小卖部带一瓶水\"或者\"食堂今天有糖醋排骨\"。"}, {"s": 36.13, "e": 38.01, "t": "晚自习结束后一起走回宿舍。"}, {"s": 38.01, "e": 44.8, "t": "路不长，200 米，够说一天里最重要的几句话——\"明天英语听写你背了吗\"、\"没\"、\"我也没\"。"}, {"s": 44.8, "e": 49.71, "t": "然后回到宿舍，各洗各的，躺在床上，隔着黑暗说几句有的没的，然后睡着。"}, {"s": 49.71, "e": 50.72, "t": "第二天，一样。"}, {"s": 50.72, "e": 52.17, "t": "没有哪一天是特殊的。"}, {"s": 52.17, "e": 53.9, "t": "但每一天都变得不一样了。"}, {"s": 53.9, "e": 55.49, "t": "有一天晚上，熄灯之后。"}, {"s": 55.49, "e": 56.22, "t": "\"小深。\""}, {"s": 56.22, "e": 56.79, "t": "\"嗯？\""}, {"s": 56.79, "e": 61.13, "t": "\"你今天下午那节化学课——老师讲的那个方程式，你听懂了没？\""}, {"s": 61.13, "e": 62.0, "t": "\"听懂了。\""}, {"s": 62.0, "e": 64.02, "t": "\"那你明天早上给我讲一遍。\""}, {"s": 64.02, "e": 65.9, "t": "\"……你上课不是也在吗？\""}, {"s": 65.9, "e": 66.76, "t": "\"走神了。\""}, {"s": 66.76, "e": 67.63, "t": "我笑了一下。"}, {"s": 67.63, "e": 68.21, "t": "\"好。\""}, {"s": 68.21, "e": 69.66, "t": "黑暗中安静了一会儿。"}, {"s": 69.66, "e": 70.38, "t": "\"博文。\""}, {"s": 70.38, "e": 70.96, "t": "\"嗯？\""}, {"s": 70.96, "e": 73.41, "t": "\"你现在走神都这么理直气壮的吗？\""}, {"s": 73.41, "e": 74.42, "t": "他沉默了两秒。"}, {"s": 74.42, "e": 75.44, "t": "\"跟你学的。\""}, {"s": 75.44, "e": 78.04, "t": "有一个周六下午，宿舍只有我们两个人。"}, {"s": 78.04, "e": 79.63, "t": "他在看书，我在写作业。"}, {"s": 79.63, "e": 84.11, "t": "窗外是四月初的阳光——不烈，暖的，照在桌面上，把白纸照得发亮。"}, {"s": 84.11, "e": 86.85, "t": "我写完最后一道题，放下笔，靠在椅背上。"}, {"s": 86.85, "e": 88.59, "t": "他坐在对面，翻了一页书。"}, {"s": 88.59, "e": 89.45, "t": "\"写完了？\""}, {"s": 89.45, "e": 90.32, "t": "\"写完了。\""}, {"s": 90.32, "e": 91.48, "t": "\"那出去走走？\""}, {"s": 91.48, "e": 92.2, "t": "\"去哪？\""}, {"s": 92.2, "e": 92.92, "t": "\"不知道。"}, {"s": 92.92, "e": 93.79, "t": "随便走走。\""}, {"s": 93.79, "e": 96.1, "t": "我们就在校园里走了大概四十分钟。"}, {"s": 96.1, "e": 101.16, "t": "没有目的地，从教学楼走到操场，从操场走到实验楼后面那条种满梧桐树的路。"}, {"s": 101.16, "e": 104.63, "t": "四月的梧桐已经长出了新叶，嫩绿色，在风里轻轻晃。"}, {"s": 104.63, "e": 107.81, "t": "走到那棵最大的梧桐树下面的时候，我停了一下。"}, {"s": 107.81, "e": 108.67, "t": "\"怎么了？\""}, {"s": 108.67, "e": 109.54, "t": "\"没什么。\""}, {"s": 109.54, "e": 114.31, "t": "我只是想起来——高一上的时候，我站在这里，偷偷看他窗户的那个秋天。"}, {"s": 114.31, "e": 115.47, "t": "现在已经春天了。"}, {"s": 115.47, "e": 116.91, "t": "他没问我为什么停下。"}, {"s": 116.91, "e": 118.93, "t": "但他走到我旁边，也停下来了。"}, {"s": 118.93, "e": 121.25, "t": "我们就在那棵梧桐树下站了一会儿。"}, {"s": 121.25, "e": 124.14, "t": "风吹过来的时候，他的肩膀碰到了我的肩膀。"}, {"s": 124.14, "e": 125.58, "t": "然后他说：\"走吧。\""}, {"s": 125.58, "e": 127.03, "t": "我们就继续往前走了。"}, {"s": 127.03, "e": 130.21, "t": "<!-- summary:start -->"}, {"s": 130.21, "e": 131.22, "t": "本章推进线索："}, {"s": 131.22, "e": 135.12, "t": "- 🔵 在一起之后的\"日常化\"——从戏剧性到平淡的过渡"}, {"s": 135.12, "e": 138.3, "t": "- 🔵 对话自然化：熄灯后的闲聊、讲题的约定"}, {"s": 138.3, "e": 143.93, "t": "- 🔵 梧桐树下的呼应——与 Ch 2/Ch 4 的\"那条路\"形成空间上的对照"}, {"s": 143.93, "e": 145.38, "t": "本章关键事件时间戳："}, {"s": 145.38, "e": 148.7, "t": "- 3月中至4月初：在一起后的日常，没有大事件"}, {"s": 148.7, "e": 152.17, "t": "- 周六下午：校园散步，经过实验楼后面那条梧桐路"}, {"s": 152.17, "e": 153.33, "t": "本章新埋伏笔：无"}, {"s": 153.33, "e": 154.05, "t": "下章钩子："}, {"s": 154.05, "e": 156.51, "t": "- 天台上的光，从橘色变成了白色。"}, {"s": 156.51, "e": 159.4, "t": "<!-- summary:end -->"}, {"s": 159.4, "e": 164.6, "t": "2026-07-19 初始版本：Ch 33 日常——在一起之后的平凡日子"}]}, {"num": 34, "title": "第34章 白色光", "file": "chapters/ch034.mp3", "dur": 339.8, "size_mb": 2.7, "segs": [{"s": 0.0, "e": 4.11, "t": "时间：4 月 15 日—5 月 10 日 · 高二下"}, {"s": 4.11, "e": 7.43, "t": "在一起一个半月之后，他带我上了第二次天台。"}, {"s": 7.43, "e": 9.17, "t": "这一次和第一次不一样。"}, {"s": 9.17, "e": 12.81, "t": "第一次是二月的下午，阳光把整片天台染成橘色的。"}, {"s": 12.81, "e": 13.76, "t": "今天是四月。"}, {"s": 13.76, "e": 18.34, "t": "午后的太阳很高，从天顶直直地照下来——没有橘色，没有暖调。"}, {"s": 18.34, "e": 21.03, "t": "光是白色的，把天台的地面照得发亮。"}, {"s": 21.03, "e": 23.09, "t": "他用钥匙打开铁门，走出去。"}, {"s": 23.09, "e": 24.98, "t": "我跟着他，走到天台中央。"}, {"s": 24.98, "e": 33.36, "t": "他把天台的地面切成了一半亮、一半暗——从围栏到中间有一条笔直的分界线，亮的那边是阳光，暗的那边是楼的影子。"}, {"s": 33.36, "e": 35.42, "t": "他站在亮的那边，面对着我。"}, {"s": 35.42, "e": 38.27, "t": "\"你以后每天下午 4 点半来天台。\""}, {"s": 38.27, "e": 38.74, "t": "他说。"}, {"s": 38.74, "e": 40.0, "t": "\"……为什么？\""}, {"s": 40.0, "e": 41.27, "t": "\"因为天台安静。"}, {"s": 41.27, "e": 42.22, "t": "适合讲题。\""}, {"s": 42.22, "e": 43.64, "t": "\"在教室也能讲。\""}, {"s": 43.64, "e": 44.75, "t": "\"教室太吵。\""}, {"s": 44.75, "e": 45.54, "t": "他顿了顿。"}, {"s": 45.54, "e": 47.91, "t": "\"而且——天台只有我能上来。\""}, {"s": 47.91, "e": 50.12, "t": "后半句他说得比前半句轻一点。"}, {"s": 50.12, "e": 51.39, "t": "但我听得很清楚。"}, {"s": 51.39, "e": 52.34, "t": "\"……好。\""}, {"s": 52.34, "e": 55.18, "t": "他点了点头，然后往围栏那边走了一步。"}, {"s": 55.18, "e": 56.13, "t": "\"还有——\""}, {"s": 56.13, "e": 56.77, "t": "\"嗯？\""}, {"s": 56.77, "e": 59.14, "t": "\"高考完，我带你去一个地方。\""}, {"s": 59.14, "e": 60.24, "t": "\"什么地方？\""}, {"s": 60.24, "e": 61.98, "t": "\"到时候你就知道了。\""}, {"s": 61.98, "e": 62.93, "t": "他没有看我。"}, {"s": 62.93, "e": 66.41, "t": "他站在白色光里，微微眯着眼，看着远处的城市。"}, {"s": 66.41, "e": 67.99, "t": "我在影子这边看着他。"}, {"s": 67.99, "e": 68.94, "t": "\"很远吗？\""}, {"s": 68.94, "e": 69.73, "t": "\"不远。\""}, {"s": 69.73, "e": 70.84, "t": "\"要走很久？\""}, {"s": 70.84, "e": 71.63, "t": "\"不会。\""}, {"s": 71.63, "e": 72.58, "t": "他侧过头来。"}, {"s": 72.58, "e": 74.0, "t": "\"你跟着我就行。\""}, {"s": 74.0, "e": 76.69, "t": "第二天下午 4 点半，我上了天台。"}, {"s": 76.69, "e": 77.64, "t": "他已经在了。"}, {"s": 77.64, "e": 85.07, "t": "我走到他旁边的时候，注意到一个细节——从这个角度看过去，刚好能看见 611 班走廊的那扇窗户。"}, {"s": 85.07, "e": 85.86, "t": "反光玻璃。"}, {"s": 85.86, "e": 86.65, "t": "快两年了。"}, {"s": 86.65, "e": 88.07, "t": "那扇窗户还在那里。"}, {"s": 88.07, "e": 90.44, "t": "高一上的时候，我站在那里看他。"}, {"s": 90.44, "e": 95.35, "t": "现在我和他站在同一个天台上，看着他高一上坐着的那间教室的窗户。"}, {"s": 95.35, "e": 97.56, "t": "从那里到这里——走了快两年。"}, {"s": 97.56, "e": 98.83, "t": "\"你在看什么？\""}, {"s": 98.83, "e": 100.41, "t": "他的声音从旁边传来。"}, {"s": 100.41, "e": 101.67, "t": "\"看那扇窗户。\""}, {"s": 101.67, "e": 103.88, "t": "我指了指 611 班的走廊。"}, {"s": 103.88, "e": 110.68, "t": "他看了一眼，然后说：\"我高一上的时候，每天晚上从 610 班的窗户看你从走廊走过去。\""}, {"s": 110.68, "e": 111.79, "t": "我转过头看他。"}, {"s": 111.79, "e": 112.58, "t": "\"你——\""}, {"s": 112.58, "e": 114.16, "t": "\"你走路的步子很快。"}, {"s": 114.16, "e": 115.27, "t": "像有什么急事。"}, {"s": 115.27, "e": 120.33, "t": "但走到走廊中间的时候会慢下来——大概是走到我窗户正对着的位置。\""}, {"s": 120.33, "e": 122.23, "t": "他说这话的时候语气很平。"}, {"s": 122.23, "e": 124.76, "t": "\"我每天都在等你走到那个位置。\""}, {"s": 124.76, "e": 126.97, "t": "风把他前额的头发吹乱了一点。"}, {"s": 126.97, "e": 128.24, "t": "他伸手理了一下。"}, {"s": 128.24, "e": 131.24, "t": "\"然后你走过去之后，我就继续写题了。\""}, {"s": 131.24, "e": 134.72, "t": "我站在天台的光里，四月午后的风从耳边吹过去。"}, {"s": 134.72, "e": 138.36, "t": "高一上每天晚上——我以为我是一个人在走廊上走。"}, {"s": 138.36, "e": 140.41, "t": "但他每天都在窗户后面看着。"}, {"s": 140.41, "e": 143.41, "t": "第四次上天台的那天，天气已经有点热了。"}, {"s": 143.41, "e": 145.63, "t": "我走上去的时候，他已经到了。"}, {"s": 145.63, "e": 148.63, "t": "靠在围栏上，手里拎着一瓶水——给我的。"}, {"s": 148.63, "e": 150.85, "t": "我接过来，拧开盖子喝了一口。"}, {"s": 150.85, "e": 154.17, "t": "我选了对面的座位——他们那一桌在靠窗位置。"}, {"s": 154.17, "e": 159.86, "t": "教学楼后面的梧桐树已经绿了，阳光通过树叶洒下来，在桌面上亮一块、暗一块。"}, {"s": 159.86, "e": 160.65, "t": "\"小深。\""}, {"s": 160.65, "e": 161.28, "t": "\"嗯？\""}, {"s": 161.28, "e": 163.02, "t": "他走过来，站到我面前。"}, {"s": 163.02, "e": 164.29, "t": "近——比平时近。"}, {"s": 164.29, "e": 169.35, "t": "近到我甚至能看见他锁骨上方有一颗很小的痣——我之前从来没注意过。"}, {"s": 169.35, "e": 170.14, "t": "他低下头。"}, {"s": 170.14, "e": 171.24, "t": "然后他吻了我。"}, {"s": 171.24, "e": 172.67, "t": "很短——大概两秒。"}, {"s": 172.67, "e": 176.62, "t": "他的嘴唇碰到我的嘴唇，凉的，带着一点薄荷糖的味道。"}, {"s": 176.62, "e": 177.73, "t": "然后他退开了。"}, {"s": 177.73, "e": 179.15, "t": "站在那里，看着我。"}, {"s": 179.15, "e": 181.84, "t": "脸上没有表情——但他的耳尖是红的。"}, {"s": 181.84, "e": 182.94, "t": "\"你生气吗？\""}, {"s": 182.94, "e": 183.42, "t": "他问。"}, {"s": 183.42, "e": 184.37, "t": "我愣了一下。"}, {"s": 184.37, "e": 185.63, "t": "\"……不生气。\""}, {"s": 185.63, "e": 189.43, "t": "然后他笑了——嘴角往上，眼睛底下那一块皱了一下。"}, {"s": 189.43, "e": 190.53, "t": "1 厘米的皱。"}, {"s": 190.53, "e": 194.01, "t": "我看着他那个皱——忽然在那一刻知道了一件事："}, {"s": 194.01, "e": 196.23, "t": "我这辈子，想一直看到这个皱。"}, {"s": 196.23, "e": 198.76, "t": "那天晚上，我在走廊上碰见了周海。"}, {"s": 198.76, "e": 204.77, "t": "他很久没主动跟我说话了——不是疏远，是高三大家各忙各的，碰面的机会本来就少。"}, {"s": 204.77, "e": 206.82, "t": "但那天他在走廊上拦住了我。"}, {"s": 206.82, "e": 207.61, "t": "\"林深。\""}, {"s": 207.61, "e": 208.24, "t": "\"嗯？\""}, {"s": 208.24, "e": 209.98, "t": "\"你每天看博文几次？\""}, {"s": 209.98, "e": 211.56, "t": "我没想到他会问这个。"}, {"s": 211.56, "e": 212.67, "t": "\"……干嘛？\""}, {"s": 212.67, "e": 214.25, "t": "\"我帮你算了一下。\""}, {"s": 214.25, "e": 218.68, "t": "他从口袋里掏出一张皱巴巴的纸——上面用铅笔画了几个正字。"}, {"s": 218.68, "e": 221.05, "t": "\"你今天看了他大概 24 次。"}, {"s": 221.05, "e": 224.37, "t": "午休最密集——13 分钟里抬头 8 次。\""}, {"s": 224.37, "e": 225.16, "t": "我愣住了。"}, {"s": 225.16, "e": 227.06, "t": "\"你——你数这个干嘛？\""}, {"s": 227.06, "e": 229.27, "t": "\"因为我想让你知道一件事。\""}, {"s": 229.27, "e": 230.7, "t": "他把那张纸翻过来。"}, {"s": 230.7, "e": 234.65, "t": "背面的左上角也画了几个正字——笔迹和前面的不一样。"}, {"s": 234.65, "e": 236.55, "t": "更用力一些，字压得更深。"}, {"s": 236.55, "e": 238.29, "t": "\"这是他看你的次数。\""}, {"s": 238.29, "e": 239.08, "t": "他顿了顿。"}, {"s": 239.08, "e": 242.87, "t": "\"上周末晚自习后我找他聊天，闲聊的时候说起来了。"}, {"s": 242.87, "e": 250.94, "t": "他说他每天晚上回教室拿东西的时候，会在 610 班窗户那里站一会儿——看你从 611 班走廊走过去。\""}, {"s": 250.94, "e": 253.62, "t": "\"他说——高一上到现在，习惯了。\""}, {"s": 253.62, "e": 255.84, "t": "我把那张纸从周海手里接过来。"}, {"s": 255.84, "e": 260.11, "t": "那张纸上，他看我的次数，比我看他的次数——多一行正字。"}, {"s": 260.11, "e": 262.95, "t": "晚上我在宿舍里，把那行正字数了一遍。"}, {"s": 262.95, "e": 266.91, "t": "然后我把它折好，放进了那个深蓝色本子的最后一页里。"}, {"s": 266.91, "e": 269.28, "t": "并排，和他写的最后一页在一起。"}, {"s": 269.28, "e": 271.97, "t": "高一上到现在——他看我，我也看他。"}, {"s": 271.97, "e": 273.23, "t": "不只是窗户那边。"}, {"s": 273.23, "e": 274.34, "t": "不只是天台上。"}, {"s": 274.34, "e": 276.39, "t": "是每一个他没说出口的时刻。"}, {"s": 276.39, "e": 279.87, "t": "<!-- summary:start -->"}, {"s": 279.87, "e": 280.98, "t": "本章推进线索："}, {"s": 280.98, "e": 288.25, "t": "- 🔵 第二次天台：白色光（与 Ch 30 橘色光形成对比），博文说\"高考完带你去一个地方\""}, {"s": 288.25, "e": 294.58, "t": "- 🔵 4/16 反光玻璃呼应——\"从他看我的窗户，走到他站的天台，用了快两年\""}, {"s": 294.58, "e": 299.01, "t": "- 🔵 第 6 次接吻——博文吻 2 秒，问\"你生气吗\""}, {"s": 299.01, "e": 303.43, "t": "- 🔵 1 厘米的皱→林深决定\"这辈子要一直看到这个皱\""}, {"s": 303.43, "e": 308.81, "t": "- 🔵 周海揭示：博文每晚从 610 班窗户看 611 走廊上的林深"}, {"s": 308.81, "e": 310.39, "t": "本章关键事件时间戳："}, {"s": 310.39, "e": 312.92, "t": "- 4/15：第二次天台，白色光"}, {"s": 312.92, "e": 317.66, "t": "- 4/16：林深注意到反光玻璃，博文揭示每晚都在窗户后面看"}, {"s": 317.66, "e": 319.88, "t": "- 5/10：第 6 次接吻"}, {"s": 319.88, "e": 320.98, "t": "本章新埋伏笔："}, {"s": 320.98, "e": 327.78, "t": "- F-高考后的地方：博文说要带林深去一个地方（指向 Ch 39 的 611 班走廊）"}, {"s": 327.78, "e": 328.57, "t": "下章钩子："}, {"s": 328.57, "e": 329.36, "t": "- 暑假。"}, {"s": 329.36, "e": 329.84, "t": "高三。"}, {"s": 329.84, "e": 330.31, "t": "高考。"}, {"s": 330.31, "e": 333.48, "t": "<!-- summary:end -->"}, {"s": 333.48, "e": 339.8, "t": "2026-07-19 初始版本：Ch 34 白色光——第二次天台与第 6 次接吻"}]}, {"num": 35, "title": "第35章 暑假", "file": "chapters/ch035.mp3", "dur": 168.8, "size_mb": 1.4, "segs": [{"s": 0.0, "e": 3.09, "t": "时间：7 月—8 月 · 高二升高三的夏天"}, {"s": 3.09, "e": 4.26, "t": "暑假我没有回家。"}, {"s": 4.26, "e": 8.23, "t": "我跟家里说要补课——其实学校确实有补课，但不是天天有。"}, {"s": 8.23, "e": 11.02, "t": "大多数时候，我一个人待在宿舍里做卷子。"}, {"s": 11.02, "e": 12.05, "t": "他也留下来了。"}, {"s": 12.05, "e": 15.87, "t": "他回家的时间比我更短——回去住了十天，然后就回来了。"}, {"s": 15.87, "e": 20.42, "t": "他回来那天下午，我正趴在桌上做英语阅读，听到门锁咔嗒响了一声。"}, {"s": 20.42, "e": 22.62, "t": "他推门进来，手里拎着一个袋子。"}, {"s": 22.62, "e": 23.95, "t": "\"你怎么回来了？\""}, {"s": 23.95, "e": 24.68, "t": "\"补课。\""}, {"s": 24.68, "e": 26.59, "t": "\"补课不是下周才开始吗？\""}, {"s": 26.59, "e": 29.38, "t": "他把袋子放到桌上，从里面掏出一瓶酸奶。"}, {"s": 29.38, "e": 30.85, "t": "\"提前回来不行吗。\""}, {"s": 30.85, "e": 32.32, "t": "他把酸奶放到我桌上。"}, {"s": 32.32, "e": 32.76, "t": "冰的。"}, {"s": 32.76, "e": 35.99, "t": "外面三十七度的天，他把酸奶从家里带到了学校。"}, {"s": 35.99, "e": 37.46, "t": "那个暑假过得格外慢。"}, {"s": 37.46, "e": 43.93, "t": "每天早上我们一起去教室——整栋教学楼只有高三的楼层有人，走廊安静得能听见电扇转动的声音。"}, {"s": 43.93, "e": 47.31, "t": "我们把桌子并到一起，面对面坐着，各做各的卷子。"}, {"s": 47.31, "e": 49.36, "t": "做到累了，就抬头看一眼对方。"}, {"s": 49.36, "e": 51.42, "t": "有时候他先抬头，有时候我先。"}, {"s": 51.42, "e": 54.21, "t": "如果目光碰上了，他就说：\"休息一下。\""}, {"s": 54.21, "e": 58.03, "t": "然后我们趴在同一张桌子上，面对面，不说话，闭着眼睛。"}, {"s": 58.03, "e": 59.5, "t": "电扇在头顶嗡嗡地转。"}, {"s": 59.5, "e": 61.56, "t": "夏天的热气从窗户外面涌进来。"}, {"s": 61.56, "e": 67.73, "t": "但那个画面——他闭着眼睛，睫毛垂下来，呼吸平稳——我觉得比任何一道我做对的题都重要。"}, {"s": 67.73, "e": 69.64, "t": "有一天傍晚，太阳快落山了。"}, {"s": 69.64, "e": 72.13, "t": "我们从教室出来，沿着操场走了几圈。"}, {"s": 72.13, "e": 77.42, "t": "操场上没什么人，夕阳把整片天空染成一层一层的橘色——从深到浅，从近到远。"}, {"s": 77.42, "e": 79.77, "t": "走到第三圈的时候，他忽然开口了。"}, {"s": 79.77, "e": 80.51, "t": "\"小深。\""}, {"s": 80.51, "e": 81.09, "t": "\"嗯？\""}, {"s": 81.09, "e": 82.56, "t": "\"你想考哪个大学？\""}, {"s": 82.56, "e": 83.74, "t": "我脚步慢了一下。"}, {"s": 83.74, "e": 84.77, "t": "\"还没想好。\""}, {"s": 84.77, "e": 85.5, "t": "这是假话。"}, {"s": 85.5, "e": 87.26, "t": "我想过——我想过很多次。"}, {"s": 87.26, "e": 91.23, "t": "但我每次想到这个问题，都会先想到一个前提：他要考哪所。"}, {"s": 91.23, "e": 91.97, "t": "\"你呢？\""}, {"s": 91.97, "e": 93.14, "t": "\"我在看江大。\""}, {"s": 93.14, "e": 94.17, "t": "——江城大学。"}, {"s": 94.17, "e": 95.34, "t": "省内的重点一本。"}, {"s": 95.34, "e": 96.37, "t": "物理系还不错。"}, {"s": 96.37, "e": 97.25, "t": "\"物理系？\""}, {"s": 97.25, "e": 97.84, "t": "\"嗯。\""}, {"s": 97.84, "e": 98.58, "t": "他顿了顿。"}, {"s": 98.58, "e": 100.19, "t": "\"你也考虑一下江大。\""}, {"s": 100.19, "e": 105.33, "t": "他说这句话的时候，目光落在远处的地平线上，夕阳把他的脸照成温暖的橘色。"}, {"s": 105.33, "e": 107.54, "t": "\"你计科或者什么，江大都有。\""}, {"s": 107.54, "e": 108.27, "t": "我没说话。"}, {"s": 108.27, "e": 112.83, "t": "但那天晚上，我回到宿舍之后，打开了手机，查了一晚上的江城大学。"}, {"s": 112.83, "e": 113.71, "t": "录取分数线。"}, {"s": 113.71, "e": 114.44, "t": "专业设置。"}, {"s": 114.44, "e": 115.18, "t": "校区位置。"}, {"s": 115.18, "e": 117.68, "t": "然后我关掉手机，在黑暗里躺了很久。"}, {"s": 117.68, "e": 119.29, "t": "他在对面床上翻了个身。"}, {"s": 119.29, "e": 120.17, "t": "\"还没睡？\""}, {"s": 120.17, "e": 121.2, "t": "\"……快了。\""}, {"s": 121.2, "e": 122.08, "t": "我闭上眼睛。"}, {"s": 122.08, "e": 122.52, "t": "江大。"}, {"s": 122.52, "e": 122.96, "t": "他在。"}, {"s": 122.96, "e": 123.55, "t": "我也在。"}, {"s": 123.55, "e": 126.78, "t": "<!-- summary:start -->"}, {"s": 126.78, "e": 127.81, "t": "本章推进线索："}, {"s": 127.81, "e": 130.75, "t": "- 🔵 暑假留校，两人一起度过的安静时光"}, {"s": 130.75, "e": 136.48, "t": "- 🔵 \"提前回来不行吗\"——博文提前返校的潜台词（不是因为补课，是因为林深）"}, {"s": 136.48, "e": 140.59, "t": "- 🔵 江大首次被提及——博文主动说\"你也考虑一下江大\""}, {"s": 140.59, "e": 144.71, "t": "- 🔵 林深当晚查江大信息——为 Ch 39 的录取铺垫"}, {"s": 144.71, "e": 146.18, "t": "本章关键事件时间戳："}, {"s": 146.18, "e": 148.38, "t": "- 7月初-8月：暑假留校复习"}, {"s": 148.38, "e": 152.05, "t": "- 8月某日傍晚：操场散步，博文说\"考虑一下江大\""}, {"s": 152.05, "e": 153.08, "t": "本章新埋伏笔："}, {"s": 153.08, "e": 157.05, "t": "- F-江大：博文的目标大学，也是林深后来选择的同一所"}, {"s": 157.05, "e": 157.78, "t": "下章钩子："}, {"s": 157.78, "e": 160.87, "t": "- 高三第一天，我在公告栏上看见了金色标。"}, {"s": 160.87, "e": 163.81, "t": "<!-- summary:end -->"}, {"s": 163.81, "e": 168.8, "t": "2026-07-19 初始版本：Ch 35 暑假——高二升高三的夏天"}]}, {"num": 36, "title": "第36章 金色标", "file": "chapters/ch036.mp3", "dur": 242.3, "size_mb": 1.9, "segs": [{"s": 0.0, "e": 3.09, "t": "时间：9 月 1 日（周一）· 高三第一天"}, {"s": 3.09, "e": 3.54, "t": "高三。"}, {"s": 3.54, "e": 7.51, "t": "这两个字写在黑板上、贴在走廊墙上、印在每个人的表情里。"}, {"s": 7.51, "e": 15.17, "t": "开学第一天，整个年级弥漫着一种说不清的紧张感——像所有人都在同一时刻意识到了一个事实：该来的，终于来了。"}, {"s": 15.17, "e": 17.97, "t": "我站在教学楼门口的告示牌前，看分班表。"}, {"s": 17.97, "e": 22.98, "t": "不用找——我的名字在第 12 行，理科（物化生）组合，高三 3 班。"}, {"s": 22.98, "e": 25.63, "t": "博文在同一个班，名单上隔了 7 行。"}, {"s": 25.63, "e": 30.93, "t": "理科班的人数少了很多——选文科的人走了一大批，留下来的都是选了物化生的。"}, {"s": 30.93, "e": 37.12, "t": "课程表发下来的时候我扫了一眼——物理、化学、生物几乎每天都有，数学排在一三五大早上。"}, {"s": 37.12, "e": 38.0, "t": "同一间教室。"}, {"s": 38.0, "e": 38.89, "t": "同一张课表。"}, {"s": 38.89, "e": 39.77, "t": "同一个方向。"}, {"s": 39.77, "e": 40.51, "t": "\"林深。\""}, {"s": 40.51, "e": 44.78, "t": "午休的时候，周海从教室门口探进头来，\"你猜你这次排多少？\""}, {"s": 44.78, "e": 45.81, "t": "\"什么排名？\""}, {"s": 45.81, "e": 47.28, "t": "\"期末分班考的总榜。"}, {"s": 47.28, "e": 49.2, "t": "贴出来了，在年级公告栏。\""}, {"s": 49.2, "e": 49.93, "t": "我走过去。"}, {"s": 49.93, "e": 52.58, "t": "公告栏前面围了好几个人，我挤进去——"}, {"s": 52.58, "e": 53.32, "t": "白纸黑字。"}, {"s": 53.32, "e": 55.82, "t": "第一名到第三百名，按分数排下来的。"}, {"s": 55.82, "e": 57.15, "t": "我在第 89 行。"}, {"s": 57.15, "e": 57.89, "t": "89 名。"}, {"s": 57.89, "e": 59.65, "t": "我盯着那个数字看了三遍。"}, {"s": 59.65, "e": 64.96, "t": "第一遍是\"看错了\"，第二遍是\"真的是我\"，第三遍是——心跳突然快了起来。"}, {"s": 64.96, "e": 67.31, "t": "高一上我连前 300 都进不去。"}, {"s": 67.31, "e": 68.93, "t": "高一下我挤进 200。"}, {"s": 68.93, "e": 70.55, "t": "高二上我冲到 132。"}, {"s": 70.55, "e": 71.44, "t": "现在 89。"}, {"s": 71.44, "e": 72.32, "t": "\"前一百了！"}, {"s": 72.32, "e": 74.83, "t": "\"周海在我旁边喊了一声，\"看见没？"}, {"s": 74.83, "e": 75.56, "t": "金色标！\""}, {"s": 75.56, "e": 81.16, "t": "他指的是公告栏上的标记——前 100 名的名字前面，贴了一个小小的金色圆标。"}, {"s": 81.16, "e": 82.93, "t": "不多，就在最前面那一列。"}, {"s": 82.93, "e": 84.55, "t": "我的名字前面也有一个。"}, {"s": 84.55, "e": 87.49, "t": "我伸出手指碰了一下那个标——贴得挺牢的。"}, {"s": 87.49, "e": 90.29, "t": "回到教室的时候，博文已经坐在座位上了。"}, {"s": 90.29, "e": 93.53, "t": "他在看书，听见我的脚步声没抬头，但问了一句："}, {"s": 93.53, "e": 94.71, "t": "\"看见排名了？\""}, {"s": 94.71, "e": 95.59, "t": "\"看见了。\""}, {"s": 95.59, "e": 96.33, "t": "\"多少？\""}, {"s": 96.33, "e": 97.07, "t": "\"89。\""}, {"s": 97.07, "e": 98.54, "t": "他翻书的手停了一下。"}, {"s": 98.54, "e": 99.87, "t": "然后抬起头来看我。"}, {"s": 99.87, "e": 102.08, "t": "那个眼神——我不知道怎么形容。"}, {"s": 102.08, "e": 106.05, "t": "不是\"意料之中\"的平淡，也不是\"你太棒了\"的那种激动。"}, {"s": 106.05, "e": 108.26, "t": "他看了我大概 3 秒，然后说："}, {"s": 108.26, "e": 111.21, "t": "\"你按这个速度——12 月能进 50。\""}, {"s": 111.21, "e": 114.45, "t": "他说这句话的时候语气很平，像在陈述一个事实。"}, {"s": 114.45, "e": 119.01, "t": "但我注意到他的嘴角往上翘了一下——不到 1 厘米，但我看见了。"}, {"s": 119.01, "e": 121.96, "t": "我低下头，假装在找书，不让他看见我在笑。"}, {"s": 121.96, "e": 124.17, "t": "\"89 名，你那是什么表情？\""}, {"s": 124.17, "e": 127.7, "t": "下午最后一节自习课，周海坐到我旁边，歪着头看我。"}, {"s": 127.7, "e": 129.03, "t": "\"什么什么表情？\""}, {"s": 129.03, "e": 131.24, "t": "\"一副'好像还不够'的表情。\""}, {"s": 131.24, "e": 132.42, "t": "\"我没说不够。\""}, {"s": 132.42, "e": 134.04, "t": "\"你脸上写了：不够。\""}, {"s": 134.04, "e": 134.92, "t": "我不说话了。"}, {"s": 134.92, "e": 136.1, "t": "周海说的是对的。"}, {"s": 136.1, "e": 141.26, "t": "89 名，年级前 100，金色标——这些东西放一年前我会高兴到跳起来。"}, {"s": 141.26, "e": 144.94, "t": "但现在坐在这个教室里，我知道 89 名意味着什么。"}, {"s": 144.94, "e": 146.85, "t": "意味着我可以够到一本线了。"}, {"s": 146.85, "e": 147.59, "t": "但还不够。"}, {"s": 147.59, "e": 150.98, "t": "因为博文在 47 名——比我高 42 个名次。"}, {"s": 150.98, "e": 152.45, "t": "我到现在还追不上他。"}, {"s": 152.45, "e": 153.78, "t": "我把头埋进胳膊里。"}, {"s": 153.78, "e": 154.36, "t": "\"行了。"}, {"s": 154.36, "e": 159.37, "t": "\"周海的声音从旁边飘过来，\"你从 300+ 追到 89，用了一年半。"}, {"s": 159.37, "e": 162.32, "t": "剩下的 42 个名次——你还有一整年。\""}, {"s": 162.32, "e": 163.06, "t": "我没回答。"}, {"s": 163.06, "e": 164.68, "t": "但我在心里说了一句话："}, {"s": 164.68, "e": 165.26, "t": "一整年。"}, {"s": 165.26, "e": 165.71, "t": "够了。"}, {"s": 165.71, "e": 167.47, "t": "晚自习结束，我收拾书包。"}, {"s": 167.47, "e": 170.27, "t": "一盒牛奶被放在我的桌角上——不是我的。"}, {"s": 170.27, "e": 172.48, "t": "我抬头——博文已经走到门口了。"}, {"s": 172.48, "e": 174.54, "t": "他没回头，只往后扬了一下手。"}, {"s": 174.54, "e": 178.23, "t": "我拿起那盒牛奶，看到上面贴了一张便利贴，是他的字："}, {"s": 178.23, "e": 179.7, "t": "> 前 100 了。"}, {"s": 179.7, "e": 180.14, "t": "继续。"}, {"s": 180.14, "e": 182.5, "t": "三个字加一个句号——不是感叹号。"}, {"s": 182.5, "e": 185.15, "t": "是他一贯的风格，不多写一个多余的字。"}, {"s": 185.15, "e": 187.8, "t": "我把便利贴撕下来，折好，放进笔袋里。"}, {"s": 187.8, "e": 188.98, "t": "然后把牛奶喝完。"}, {"s": 188.98, "e": 189.42, "t": "甜的。"}, {"s": 189.42, "e": 192.66, "t": "<!-- summary:start -->"}, {"s": 192.66, "e": 193.69, "t": "本章推进线索："}, {"s": 193.69, "e": 202.53, "t": "- POV-LS-进步弧：林深从 300+ → 132 → 89 名，金色标前 100，验证\"我配不上他\"的弧线正在逆转"}, {"s": 202.53, "e": 206.65, "t": "- POV-BW-回应：博文用便利贴（\"前 100 了。"}, {"s": 206.65, "e": 207.1, "t": "继续。"}, {"s": 207.1, "e": 210.19, "t": "\"）+ 牛奶回应林深的进步——行动多于语言"}, {"s": 210.19, "e": 211.66, "t": "本章关键事件时间戳："}, {"s": 211.66, "e": 217.26, "t": "- 9/1 高三第一天：分班公布 → 排名 89 → 金色标 → 便利贴牛奶"}, {"s": 217.26, "e": 218.0, "t": "下章钩子："}, {"s": 218.0, "e": 221.68, "t": "- 42 个名次的差距，高三这一年，林深能追上吗？"}, {"s": 221.68, "e": 224.62, "t": "<!-- summary:end -->"}, {"s": 224.62, "e": 226.69, "t": "2026-07-19 修复："}, {"s": 226.69, "e": 231.25, "t": "1. 89 名 = 前 100（重点一本线），不再是\"清北线\""}, {"s": 231.25, "e": 235.38, "t": "2. 金色标 = 前 100 名标记，不再是\"清北线标\""}, {"s": 235.38, "e": 239.35, "t": "3. 博文排名 47 名（中上水平），不再暗示清北档次"}, {"s": 239.35, "e": 242.3, "t": "4. 林深\"一本线\"目标替代\"清北\"目标"}]}, {"num": 37, "title": "第37章 最后一年", "file": "chapters/ch037.mp3", "dur": 320.8, "size_mb": 2.6, "segs": [{"s": 0.0, "e": 2.82, "t": "时间：9 月—次年 5 月 · 高三"}, {"s": 2.82, "e": 4.69, "t": "高三的日子过得既快又慢。"}, {"s": 4.69, "e": 10.32, "t": "快的是每天——早自习、第一节课、第二节课、午休、下午课、晚自习、回宿舍。"}, {"s": 10.32, "e": 13.45, "t": "像一个循环，还没反应过来，一周就过去了。"}, {"s": 13.45, "e": 16.89, "t": "慢的是整个人——你总觉得六月八号永远不会来。"}, {"s": 16.89, "e": 22.52, "t": "黑板上的倒计时一天一天地减，但当你盯着那个数字的时候，它好像根本没在动。"}, {"s": 22.52, "e": 24.4, "t": "博文和我坐在同一间教室。"}, {"s": 24.4, "e": 27.37, "t": "但高三之后，我们说话的时间反而变少了。"}, {"s": 27.37, "e": 30.03, "t": "不是因为关系变了——是因为太累了。"}, {"s": 30.03, "e": 32.85, "t": "每天早上我到教室的时候，他已经在了。"}, {"s": 32.85, "e": 34.88, "t": "桌上一杯豆浆，和以前一样。"}, {"s": 34.88, "e": 41.29, "t": "他有时候抬头看我一眼，有时候不抬——不是不想看，是连抬头的力气都想省下来留给做题。"}, {"s": 41.29, "e": 42.07, "t": "我也一样。"}, {"s": 42.07, "e": 44.11, "t": "我们之间最常说的话变成了："}, {"s": 44.11, "e": 45.52, "t": "\"这题你做了吗？\""}, {"s": 45.52, "e": 46.3, "t": "\"做了。\""}, {"s": 46.3, "e": 47.39, "t": "\"答案多少？\""}, {"s": 47.39, "e": 48.17, "t": "\"我选C。"}, {"s": 48.17, "e": 48.8, "t": "你呢？\""}, {"s": 48.8, "e": 49.9, "t": "\"我也选C。\""}, {"s": 49.9, "e": 51.3, "t": "然后继续低头做题。"}, {"s": 51.3, "e": 53.02, "t": "十月中旬有一次模拟考。"}, {"s": 53.02, "e": 58.03, "t": "成绩出来那天，我在公告栏上找了很久才找到自己的名字——73 名。"}, {"s": 58.03, "e": 59.12, "t": "比上次进步了。"}, {"s": 59.12, "e": 62.1, "t": "但我往上看的时候，看见他在 41 名。"}, {"s": 62.1, "e": 62.56, "t": "41。"}, {"s": 62.56, "e": 64.29, "t": "中间隔着 32 个人。"}, {"s": 64.29, "e": 71.01, "t": "那天晚自习我没有去找他——我一个人坐在座位上，把错题本翻出来，把那套卷子重新做了一遍。"}, {"s": 71.01, "e": 74.14, "t": "做到一半的时候，一张便利贴被推到我桌上。"}, {"s": 74.14, "e": 74.76, "t": "他的字："}, {"s": 74.76, "e": 75.7, "t": "\"73 了。"}, {"s": 75.7, "e": 76.33, "t": "继续。\""}, {"s": 76.33, "e": 79.14, "t": "我抬头——他坐在前面几排，没有回头。"}, {"s": 79.14, "e": 81.65, "t": "我低下头，把那三个字又看了一遍。"}, {"s": 81.65, "e": 83.37, "t": "然后拿起笔，继续做题。"}, {"s": 83.37, "e": 86.5, "t": "冬天的时候，晚自习结束后天已经完全黑了。"}, {"s": 86.5, "e": 89.62, "t": "我们走在回宿舍的路上，呼出的气变成白雾。"}, {"s": 89.62, "e": 95.25, "t": "那段时间我的数学遇到了瓶颈——不管怎么做，分数就是卡在 110 上不去。"}, {"s": 95.25, "e": 99.63, "t": "有一天晚上我趴在桌上，盯着面前那张卷子，一个字都不想写。"}, {"s": 99.63, "e": 101.67, "t": "他走过来，在我旁边坐下了。"}, {"s": 101.67, "e": 102.76, "t": "\"哪题不会？\""}, {"s": 102.76, "e": 104.48, "t": "\"不是不会——是烦。\""}, {"s": 104.48, "e": 105.26, "t": "他没说话。"}, {"s": 105.26, "e": 107.77, "t": "坐了一会儿，然后站起来，走出去。"}, {"s": 107.77, "e": 110.74, "t": "过了一会儿他回来了，手里拿着两杯热水。"}, {"s": 110.74, "e": 113.24, "t": "他把一杯放到我面前，然后坐下来。"}, {"s": 113.24, "e": 114.49, "t": "\"那就不做了。\""}, {"s": 114.49, "e": 115.59, "t": "\"……什么？\""}, {"s": 115.59, "e": 116.68, "t": "\"今天不做了。"}, {"s": 116.68, "e": 117.47, "t": "明天再做。"}, {"s": 117.47, "e": 118.4, "t": "又不会跑。\""}, {"s": 118.4, "e": 119.19, "t": "我看着他。"}, {"s": 119.19, "e": 123.25, "t": "他没有说\"你再坚持一下\"或者\"这道题不难你再想想\"。"}, {"s": 123.25, "e": 125.13, "t": "他说的是\"今天不做了\"。"}, {"s": 125.13, "e": 127.63, "t": "我握着那杯热水，手指被烫得发麻。"}, {"s": 127.63, "e": 129.04, "t": "然后我合上了卷子。"}, {"s": 129.04, "e": 132.79, "t": "那是高三上学期我唯一一次在晚自习结束前合上卷子。"}, {"s": 132.79, "e": 134.51, "t": "但那一晚，我睡得很好。"}, {"s": 134.51, "e": 136.39, "t": "三月份的时候有一次体检。"}, {"s": 136.39, "e": 141.08, "t": "量身高体重的时候，我站上去，发现我长高了一点——173 了。"}, {"s": 141.08, "e": 142.96, "t": "高一的时候我才 170。"}, {"s": 142.96, "e": 144.68, "t": "他站在旁边等我的数据。"}, {"s": 144.68, "e": 145.46, "t": "\"多少？\""}, {"s": 145.46, "e": 146.24, "t": "\"173。"}, {"s": 146.24, "e": 146.87, "t": "你呢？\""}, {"s": 146.87, "e": 147.81, "t": "\"168。\""}, {"s": 147.81, "e": 149.84, "t": "我说：\"你是不是也长了？\""}, {"s": 149.84, "e": 150.31, "t": "\"没。"}, {"s": 150.31, "e": 151.88, "t": "我还是高一那个数。\""}, {"s": 151.88, "e": 154.38, "t": "我说：\"那你以后要抬头看我了。\""}, {"s": 154.38, "e": 155.47, "t": "他看了我一眼。"}, {"s": 155.47, "e": 162.2, "t": "那个眼神——不是\"你完了\"也不是\"你等着\"——是那种\"你尽管说，我有的是办法\"的眼神。"}, {"s": 162.2, "e": 163.92, "t": "然后他说：\"那又怎样。"}, {"s": 163.92, "e": 165.48, "t": "我低头看你也能看。\""}, {"s": 165.48, "e": 166.73, "t": "旁边的人没听懂。"}, {"s": 166.73, "e": 167.67, "t": "但我听懂了。"}, {"s": 167.67, "e": 170.8, "t": "五月份的时候，教室里的气氛变得越来越紧。"}, {"s": 170.8, "e": 175.96, "t": "有人开始失眠，有人在课间趴在桌上就能睡着，有人吃着吃着饭突然哭了。"}, {"s": 175.96, "e": 179.72, "t": "我看着那个人被同学围着安慰，心里也跟着紧了一下。"}, {"s": 179.72, "e": 181.75, "t": "博文顺着我的目光看了一眼。"}, {"s": 181.75, "e": 183.63, "t": "然后他低下头，继续吃饭。"}, {"s": 183.63, "e": 185.19, "t": "\"你晚上睡得好吗？\""}, {"s": 185.19, "e": 185.66, "t": "他问。"}, {"s": 185.66, "e": 186.44, "t": "\"还行。\""}, {"s": 186.44, "e": 187.22, "t": "\"真的？\""}, {"s": 187.22, "e": 188.79, "t": "\"……有时候会醒。\""}, {"s": 188.79, "e": 190.98, "t": "他夹了一筷子菜，放到我碗里。"}, {"s": 190.98, "e": 192.86, "t": "\"考不上江大也没关系。\""}, {"s": 192.86, "e": 193.32, "t": "他说。"}, {"s": 193.32, "e": 195.2, "t": "我握着筷子的手停了一下。"}, {"s": 195.2, "e": 196.3, "t": "\"你说什么？\""}, {"s": 196.3, "e": 198.49, "t": "\"我说——考不上也没关系。\""}, {"s": 198.49, "e": 200.99, "t": "他嚼了一口饭，咽下去，才继续说。"}, {"s": 200.99, "e": 202.71, "t": "\"江大不是唯一的选择。"}, {"s": 202.71, "e": 204.12, "t": "你努力过了就行。\""}, {"s": 204.12, "e": 204.9, "t": "我看着他。"}, {"s": 204.9, "e": 205.84, "t": "他没有看我。"}, {"s": 205.84, "e": 210.22, "t": "但他说这句话的时候，筷子上夹着的那块肉，放到了我的碗里。"}, {"s": 210.22, "e": 212.72, "t": "那天晚上，我睡得比前几天都安稳。"}, {"s": 212.72, "e": 216.94, "t": "倒计时变成 30 天的时候，学校给高三放了一下午的假。"}, {"s": 216.94, "e": 218.19, "t": "大部分人回家了。"}, {"s": 218.19, "e": 220.23, "t": "我没回——我在教室做卷子。"}, {"s": 220.23, "e": 222.26, "t": "做到一半的时候，他走进来。"}, {"s": 222.26, "e": 223.51, "t": "手里拎着两瓶水。"}, {"s": 223.51, "e": 224.92, "t": "\"你怎么回来了？\""}, {"s": 224.92, "e": 226.48, "t": "\"你不是也没走吗。\""}, {"s": 226.48, "e": 230.08, "t": "他把一瓶水放在我桌上，然后坐到他自己的位置上。"}, {"s": 230.08, "e": 231.8, "t": "教室里只有我们两个人。"}, {"s": 231.8, "e": 236.02, "t": "电扇在转，窗外的风吹进来，把桌上的试卷吹得微微掀起来。"}, {"s": 236.02, "e": 237.59, "t": "他坐下来之后没做题。"}, {"s": 237.59, "e": 244.31, "t": "他拿了一本书出来——不是课本，是那本封面上有深蓝色和小树的、他已经很久没拿出来的本子。"}, {"s": 244.31, "e": 247.6, "t": "我看见他翻开最后一页，拿起笔，写了几行字。"}, {"s": 247.6, "e": 248.54, "t": "然后合上了。"}, {"s": 248.54, "e": 249.79, "t": "我问他写什么了。"}, {"s": 249.79, "e": 250.57, "t": "他没回答。"}, {"s": 250.57, "e": 254.95, "t": "但后来——很久以后——我翻到那一页的时候，看见了那行字："}, {"s": 254.95, "e": 258.39, "t": "\"2026/5/8 距离高考还有 30 天。"}, {"s": 258.39, "e": 259.49, "t": "小深还在做题。"}, {"s": 259.49, "e": 260.27, "t": "我也还在。"}, {"s": 260.27, "e": 261.52, "t": "我们都会好的。\""}, {"s": 261.52, "e": 264.96, "t": "<!-- summary:start -->"}, {"s": 264.96, "e": 266.06, "t": "本章推进线索："}, {"s": 266.06, "e": 268.87, "t": "- 🔵 高三全年的学习压力与情感支撑"}, {"s": 268.87, "e": 272.63, "t": "- 🔵 便利贴呼应 Ch 36 ——\"73 了。"}, {"s": 272.63, "e": 273.09, "t": "继续。"}, {"s": 273.09, "e": 274.66, "t": "\"——博文持续的关注"}, {"s": 274.66, "e": 280.45, "t": "- 🔵 \"考不上江大也没关系\"——博文第一次说\"不是唯一选择\"，为林深减压"}, {"s": 280.45, "e": 283.57, "t": "- 🔵 深蓝本子再次出现（博文偷偷记录）"}, {"s": 283.57, "e": 287.8, "t": "- 🔵 \"我们都会好的\"——全书最后一条来自本子的伏笔"}, {"s": 287.8, "e": 289.36, "t": "本章关键事件时间戳："}, {"s": 289.36, "e": 292.49, "t": "- 10月中旬：模拟考73名，博文便利贴"}, {"s": 292.49, "e": 296.24, "t": "- 11月冬夜：数学瓶颈夜，博文说\"今天不做了\""}, {"s": 296.24, "e": 298.75, "t": "- 3月体检：身高173/168"}, {"s": 298.75, "e": 302.97, "t": "- 5月8日：倒计时30天，博文写本子\"我们都会好的\""}, {"s": 302.97, "e": 304.06, "t": "本章新埋伏笔："}, {"s": 304.06, "e": 307.51, "t": "- F-本子最后一页：博文在高三期间继续记录"}, {"s": 307.51, "e": 308.29, "t": "下章钩子："}, {"s": 308.29, "e": 311.73, "t": "- 考完最后一科的时候，他站在考场门口等我。"}, {"s": 311.73, "e": 314.86, "t": "<!-- summary:end -->"}, {"s": 314.86, "e": 320.8, "t": "2026-07-19 初始版本：Ch 37 最后一年——高三全年的陪伴与压力"}]}, {"num": 38, "title": "第38章 围墙外的城市", "file": "chapters/ch038.mp3", "dur": 188.8, "size_mb": 1.5, "segs": [{"s": 0.0, "e": 2.76, "t": "时间：6 月 6 日—8 日 · 高考"}, {"s": 2.76, "e": 5.95, "t": "高考前夜，我坐在宿舍床上，面前摊着五套卷子。"}, {"s": 5.95, "e": 9.0, "t": "不是临时抱佛脚——是把做过的卷子再过一遍。"}, {"s": 9.0, "e": 12.34, "t": "对一下答案，确认自己不会在同一个地方再错一次。"}, {"s": 12.34, "e": 14.23, "t": "他坐在对面床，也在看卷子。"}, {"s": 14.23, "e": 15.83, "t": "房间里只有翻纸的声音。"}, {"s": 15.83, "e": 18.01, "t": "过了一阵子，他抬头看了我一眼。"}, {"s": 18.01, "e": 19.17, "t": "\"看得进去吗？\""}, {"s": 19.17, "e": 20.48, "t": "\"……看不进去。\""}, {"s": 20.48, "e": 21.49, "t": "\"那别看了。\""}, {"s": 21.49, "e": 24.4, "t": "他站起来，把我手里的卷子抽走，放到桌上。"}, {"s": 24.4, "e": 25.42, "t": "\"出去走走。\""}, {"s": 25.42, "e": 28.03, "t": "我们走到操场，坐在跑道旁边的长椅上。"}, {"s": 28.03, "e": 31.37, "t": "六月的晚上不冷不热，风带着白天晒过的草地气味。"}, {"s": 31.37, "e": 32.97, "t": "围墙外面的城市亮着灯。"}, {"s": 32.97, "e": 39.36, "t": "远处高楼的轮廓在天际线上连成一片，近处是居民楼的窗户，一格一格的，有的亮着灯，有的没有。"}, {"s": 39.36, "e": 42.7, "t": "他坐在我旁边，两只手搭在膝盖上，看着围墙外面。"}, {"s": 42.7, "e": 43.86, "t": "\"明天就考了。\""}, {"s": 43.86, "e": 44.44, "t": "\"嗯。\""}, {"s": 44.44, "e": 45.31, "t": "\"紧张吗？\""}, {"s": 45.31, "e": 46.18, "t": "\"有一点。\""}, {"s": 46.18, "e": 47.05, "t": "他点了点头。"}, {"s": 47.05, "e": 48.22, "t": "\"我也有一点。\""}, {"s": 48.22, "e": 49.52, "t": "然后他就不说话了。"}, {"s": 49.52, "e": 51.99, "t": "我们坐在那里，看着围墙外面的城市。"}, {"s": 51.99, "e": 53.59, "t": "围墙不高——两米左右。"}, {"s": 53.59, "e": 57.37, "t": "上面爬着一些不知名的藤蔓植物，风一吹，叶子轻轻晃动。"}, {"s": 57.37, "e": 59.54, "t": "高一的时候，我站在走廊上看他。"}, {"s": 59.54, "e": 62.01, "t": "高二的时候，我们坐在天台上看城市。"}, {"s": 62.01, "e": 65.06, "t": "现在高三了，我们坐在操场上看围墙外面的灯。"}, {"s": 65.06, "e": 66.81, "t": "位置在变，旁边的人没变。"}, {"s": 66.81, "e": 67.53, "t": "\"小深。\""}, {"s": 67.53, "e": 68.11, "t": "\"嗯？\""}, {"s": 68.11, "e": 70.15, "t": "\"你还记得天台上的颜色吗？\""}, {"s": 70.15, "e": 71.02, "t": "\"橘色的。\""}, {"s": 71.02, "e": 71.45, "t": "\"嗯。"}, {"s": 71.45, "e": 72.47, "t": "\"他点了点头。"}, {"s": 72.47, "e": 75.08, "t": "\"橘色是 2 月 11 日的颜色。\""}, {"s": 75.08, "e": 79.15, "t": "2 月 11 日——那是表白之后、我们正式在一起的日子。"}, {"s": 79.15, "e": 79.73, "t": "他记得。"}, {"s": 79.73, "e": 81.33, "t": "他把那天的颜色记住了。"}, {"s": 81.33, "e": 83.8, "t": "\"考完之后——我带你去一个地方。\""}, {"s": 83.8, "e": 85.11, "t": "\"上次你说过了。\""}, {"s": 85.11, "e": 85.83, "t": "\"我知道。"}, {"s": 85.83, "e": 87.43, "t": "再说一次，怕你忘了。\""}, {"s": 87.43, "e": 88.3, "t": "\"我没忘。\""}, {"s": 88.3, "e": 89.61, "t": "他又安静了一会儿。"}, {"s": 89.61, "e": 91.2, "t": "然后他说：\"那就好。\""}, {"s": 91.2, "e": 91.64, "t": "语文。"}, {"s": 91.64, "e": 92.08, "t": "数学。"}, {"s": 92.08, "e": 94.25, "t": "考完数学出来的时候，太阳正烈。"}, {"s": 94.25, "e": 95.71, "t": "我站在考场楼下等他。"}, {"s": 95.71, "e": 100.06, "t": "他从楼梯上走下来——看见我的时候，脚步没停，但嘴角动了一下。"}, {"s": 100.06, "e": 100.94, "t": "\"怎么样？\""}, {"s": 100.94, "e": 102.82, "t": "\"语文 130 应该稳的。"}, {"s": 102.82, "e": 105.15, "t": "数学——最后一道大题写了一半。\""}, {"s": 105.15, "e": 106.31, "t": "\"我也差不多。\""}, {"s": 106.31, "e": 109.65, "t": "和我们一起备考的每一天一样——\"我也差不多\"。"}, {"s": 109.65, "e": 112.12, "t": "站在同一片太阳下，往同一个方向走。"}, {"s": 112.12, "e": 112.55, "t": "理综。"}, {"s": 112.55, "e": 112.99, "t": "英语。"}, {"s": 112.99, "e": 115.6, "t": "考完英语的那个下午，我从考场走出来。"}, {"s": 115.6, "e": 120.54, "t": "阳光还是和昨天一样烈，但比昨天轻了一些——因为我知道这是最后一科了。"}, {"s": 120.54, "e": 121.56, "t": "他在门口等我。"}, {"s": 121.56, "e": 123.59, "t": "站在教学楼前面那棵樟树下面。"}, {"s": 123.59, "e": 124.9, "t": "手插在校服口袋里。"}, {"s": 124.9, "e": 126.93, "t": "看见我出来了，他站直了身子。"}, {"s": 126.93, "e": 128.24, "t": "所有科目都考完了。"}, {"s": 128.24, "e": 130.85, "t": "十二年的书，两天的卷子，全部结束了。"}, {"s": 130.85, "e": 132.45, "t": "他看着我，我也看着他。"}, {"s": 132.45, "e": 133.47, "t": "\"你跟我来。\""}, {"s": 133.47, "e": 133.9, "t": "他说。"}, {"s": 133.9, "e": 136.23, "t": "然后他转身，往教学楼的方向走了。"}, {"s": 136.23, "e": 136.95, "t": "我跟上去。"}, {"s": 136.95, "e": 137.82, "t": "没有问去哪。"}, {"s": 137.82, "e": 140.58, "t": "因为我知道——他一定会带我去那个地方。"}, {"s": 140.58, "e": 143.78, "t": "<!-- summary:start -->"}, {"s": 143.78, "e": 144.8, "t": "本章推进线索："}, {"s": 144.8, "e": 147.7, "t": "- 🔵 高考前夜：操场长椅，围墙外的城市"}, {"s": 147.7, "e": 153.8, "t": "- 🔵 \"橘色是 2 月 11 日的颜色\"——与 Ch 30/Ch 31 的意象呼应"}, {"s": 153.8, "e": 159.75, "t": "- 🔵 博文说\"考完之后我带你去一个地方\"（指向 Ch 39 的 611 班走廊）"}, {"s": 159.75, "e": 163.09, "t": "- 🔵 高考结束：最后一科考完，博文在樟树下等"}, {"s": 163.09, "e": 166.14, "t": "- 🔵 \"你跟我来\"——衔接到 Ch 39"}, {"s": 166.14, "e": 167.6, "t": "本章关键事件时间戳："}, {"s": 167.6, "e": 170.36, "t": "- 6/6 晚：操场长椅，围墙外的城市"}, {"s": 170.36, "e": 173.99, "t": "- 6/7：语文 130，数学最后一道大题写了一半"}, {"s": 173.99, "e": 177.33, "t": "- 6/8 下午 5 点：考完，博文在校门口等"}, {"s": 177.33, "e": 178.05, "t": "下章钩子："}, {"s": 178.05, "e": 181.25, "t": "- 他带我去了那个地方——611 班的走廊。"}, {"s": 181.25, "e": 184.15, "t": "<!-- summary:end -->"}, {"s": 184.15, "e": 188.8, "t": "2026-07-19 初始版本：Ch 38 围墙外的城市——高考"}]}, {"num": 39, "title": "第39章 本子", "file": "chapters/ch039.mp3", "dur": 503.4, "size_mb": 4.0, "segs": [{"s": 0.0, "e": 5.4, "t": "时间：6 月 30 日（周一）— 7 月 2 日（周三）· 高考后"}, {"s": 5.4, "e": 8.51, "t": "查录取的那天，我在电脑前坐了一个上午。"}, {"s": 8.51, "e": 13.09, "t": "屏幕上的网页刷新了一遍又一遍，每一次都显示\"系统繁忙\"。"}, {"s": 13.09, "e": 16.2, "t": "我一边刷新一边想——如果没录上怎么办？"}, {"s": 16.2, "e": 18.66, "t": "如果因为一分之差滑档了怎么办？"}, {"s": 18.66, "e": 19.97, "t": "然后页面出来了。"}, {"s": 19.97, "e": 22.42, "t": "江城大学 · 计算机科学与技术"}, {"s": 22.42, "e": 22.91, "t": "一本。"}, {"s": 22.91, "e": 23.73, "t": "第一志愿。"}, {"s": 23.73, "e": 26.35, "t": "我盯着那行字看了大概 10 秒。"}, {"s": 26.35, "e": 30.93, "t": "然后我站起来，走进客厅，倒了一杯水，喝完了，才拿出手机。"}, {"s": 30.93, "e": 31.91, "t": "手指有点抖。"}, {"s": 31.91, "e": 33.39, "t": "我拨了博文的号码。"}, {"s": 33.39, "e": 34.69, "t": "响了两声就接了。"}, {"s": 34.69, "e": 35.35, "t": "\"喂？\""}, {"s": 35.35, "e": 36.99, "t": "——他的声音有点紧。"}, {"s": 36.99, "e": 37.97, "t": "\"查了吗？\""}, {"s": 37.97, "e": 38.79, "t": "\"查了。\""}, {"s": 38.79, "e": 39.77, "t": "\"怎么样？\""}, {"s": 39.77, "e": 40.75, "t": "\"江城大学。"}, {"s": 40.75, "e": 41.4, "t": "计科。\""}, {"s": 41.4, "e": 43.04, "t": "电话那头安静了一秒。"}, {"s": 43.04, "e": 45.0, "t": "然后他说：\"我也查了。\""}, {"s": 45.0, "e": 45.99, "t": "\"怎么样？\""}, {"s": 45.99, "e": 46.97, "t": "\"江城大学。"}, {"s": 46.97, "e": 47.79, "t": "物理系。\""}, {"s": 47.79, "e": 49.91, "t": "我握着手机，站在客厅中央。"}, {"s": 49.91, "e": 56.79, "t": "窗外是七月的阳光，蝉声一阵一阵的，不知道哪一栋楼有人在装修，电钻的声音从远处传过来。"}, {"s": 56.79, "e": 57.28, "t": "很吵。"}, {"s": 57.28, "e": 59.24, "t": "但我什么声音都听不到了。"}, {"s": 59.24, "e": 60.88, "t": "\"我们……同一所？\""}, {"s": 60.88, "e": 61.86, "t": "\"同一所。\""}, {"s": 61.86, "e": 64.48, "t": "他顿了顿，又说：\"同一个校区。\""}, {"s": 64.48, "e": 65.63, "t": "EMS 到了。"}, {"s": 65.63, "e": 68.57, "t": "牛皮纸信封，盖着江城大学的红色印章。"}, {"s": 68.57, "e": 72.01, "t": "拿在手里不重，但我的手指把它捏出了一个角。"}, {"s": 72.01, "e": 75.44, "t": "我翻了翻手机——博文在微信上发了一条消息："}, {"s": 75.44, "e": 76.26, "t": "> 到了？"}, {"s": 76.26, "e": 77.08, "t": "> 到了。"}, {"s": 77.08, "e": 78.88, "t": "> 明天下午，老地方。"}, {"s": 78.88, "e": 81.66, "t": "\"老地方\"——我知道他指的是哪里。"}, {"s": 81.66, "e": 82.48, "t": "下午三点。"}, {"s": 82.48, "e": 85.92, "t": "我走到教学楼下的时候，博文已经站在那里了。"}, {"s": 85.92, "e": 91.97, "t": "他靠在楼门口旁边的墙上，手里拎着一个纸袋，穿着一件白 T 恤——不是校服。"}, {"s": 91.97, "e": 95.08, "t": "七月的阳光把他的影子缩成脚底下一个点。"}, {"s": 95.08, "e": 98.03, "t": "他看见我来了，没说话，转身往楼里走。"}, {"s": 98.03, "e": 98.85, "t": "我跟上去。"}, {"s": 98.85, "e": 99.99, "t": "楼道里很安静。"}, {"s": 99.99, "e": 106.38, "t": "放暑假已经快一个月了，教学楼里空荡荡的，只有走廊尽头的风扇还在不知疲倦地转着。"}, {"s": 106.38, "e": 113.74, "t": "墙上那些高考倒计时的贴纸还没撕——\"距高考还有 0 天\"，有人用马克笔在下面画了一个笑脸。"}, {"s": 113.74, "e": 114.72, "t": "他没停下来。"}, {"s": 114.72, "e": 116.52, "t": "一直往上走，走到四楼。"}, {"s": 116.52, "e": 117.67, "t": "然后他左转了。"}, {"s": 117.67, "e": 118.65, "t": "我停下脚步。"}, {"s": 118.65, "e": 120.78, "t": "四楼——我知道这里是哪里。"}, {"s": 120.78, "e": 121.76, "t": "611 班。"}, {"s": 121.76, "e": 123.89, "t": "他停在了 611 班门口。"}, {"s": 123.89, "e": 125.69, "t": "然后他转过身来看着我。"}, {"s": 125.69, "e": 127.49, "t": "\"你知道这是哪里吧？\""}, {"s": 127.49, "e": 128.47, "t": "我喉咙发紧。"}, {"s": 128.47, "e": 129.29, "t": "\"知道。\""}, {"s": 129.29, "e": 130.27, "t": "611 班。"}, {"s": 130.27, "e": 131.41, "t": "我的高一教室。"}, {"s": 131.41, "e": 134.36, "t": "那扇窗户——我靠窗坐了一年半的窗户。"}, {"s": 134.36, "e": 139.27, "t": "每天早自习我站在那里，透过玻璃看对面 610 班的最后一排。"}, {"s": 139.27, "e": 140.42, "t": "看他的那扇窗。"}, {"s": 140.42, "e": 143.2, "t": "博文站在 611 班门口，没进去。"}, {"s": 143.2, "e": 147.29, "t": "他伸手推了一下那扇窗户——咯吱一声，窗户往外开了。"}, {"s": 147.29, "e": 149.42, "t": "然后他转过头看向走廊外面。"}, {"s": 149.42, "e": 154.98, "t": "我顺着他的目光看过去——从这个角度，刚好看见对面的 610 班教室。"}, {"s": 154.98, "e": 156.78, "t": "最后一排，他的老位置。"}, {"s": 156.78, "e": 157.44, "t": "5 米。"}, {"s": 157.44, "e": 158.25, "t": "隔着天井。"}, {"s": 158.25, "e": 160.87, "t": "原来从这个角度看过去，是这样的。"}, {"s": 160.87, "e": 163.16, "t": "\"我以前一直想问你一个问题。"}, {"s": 163.16, "e": 163.82, "t": "\"他说。"}, {"s": 163.82, "e": 164.64, "t": "\"什么？\""}, {"s": 164.64, "e": 167.58, "t": "\"你站在这里的时候——你在看什么？\""}, {"s": 167.58, "e": 169.87, "t": "我看着对面那扇空荡荡的窗户。"}, {"s": 169.87, "e": 170.53, "t": "\"看你。"}, {"s": 170.53, "e": 172.66, "t": "你坐在最后一排，低头写字。"}, {"s": 172.66, "e": 174.46, "t": "偶尔抬头往这边看一眼。"}, {"s": 174.46, "e": 176.58, "t": "有时候用红笔在纸上划一道。"}, {"s": 176.58, "e": 178.71, "t": "你摸后脑勺的时候我会笑。\""}, {"s": 178.71, "e": 179.69, "t": "我停了一下。"}, {"s": 179.69, "e": 181.98, "t": "\"我站在这里看了你一年半。\""}, {"s": 181.98, "e": 183.78, "t": "他听完这句话，没回答。"}, {"s": 183.78, "e": 185.91, "t": "他从纸袋里拿出了一样东西。"}, {"s": 185.91, "e": 186.73, "t": "一个本子。"}, {"s": 186.73, "e": 191.15, "t": "封面是深蓝色的，上面有小小的树图案——我见过这个本子。"}, {"s": 191.15, "e": 192.46, "t": "去年 10 月。"}, {"s": 192.46, "e": 196.88, "t": "每天下午 4 点半，他都会拿出这个本子，写 1 分钟。"}, {"s": 196.88, "e": 199.49, "t": "我坐在他右边，从来没有看到内容。"}, {"s": 199.49, "e": 200.8, "t": "他把本子递给我。"}, {"s": 200.8, "e": 203.09, "t": "我接过来的时候，手指是凉的。"}, {"s": 203.09, "e": 204.24, "t": "翻开第一页——"}, {"s": 204.24, "e": 208.0, "t": "字迹很整齐，不像他平时写草稿那种飞起来的样子。"}, {"s": 208.0, "e": 211.93, "t": "蓝黑色的墨水，一行一行，日期写在每一条的左上角。"}, {"s": 211.93, "e": 212.91, "t": "第一行写着："}, {"s": 212.91, "e": 214.39, "t": "2024/12/7"}, {"s": 214.39, "e": 219.13, "t": "\"今天 611 班那个站在走廊上的人——他今天看了我很久。"}, {"s": 219.13, "e": 220.61, "t": "他的眼睛里有光。\""}, {"s": 220.61, "e": 222.73, "t": "我的手指停在了那一行字上。"}, {"s": 222.73, "e": 225.35, "t": "2024 年 12 月 7 日。"}, {"s": 225.35, "e": 226.01, "t": "高一上。"}, {"s": 226.01, "e": 227.81, "t": "那是开学大概三个月后。"}, {"s": 227.81, "e": 231.08, "t": "我每天站在走廊上，以为自己是一个人在看。"}, {"s": 231.08, "e": 235.66, "t": "我以为那扇 5 米外的窗户后面的人永远不会知道我的存在。"}, {"s": 235.66, "e": 236.48, "t": "但他知道。"}, {"s": 236.48, "e": 238.61, "t": "他不仅知道——他记下来了。"}, {"s": 238.61, "e": 239.43, "t": "我往下翻。"}, {"s": 239.43, "e": 240.08, "t": "第二页。"}, {"s": 240.08, "e": 241.72, "t": "2024/12/14"}, {"s": 241.72, "e": 243.35, "t": "\"今天他又在走廊上。"}, {"s": 243.35, "e": 245.48, "t": "我发现我抬头的时候会找他。"}, {"s": 245.48, "e": 246.95, "t": "这个习惯不太好。\""}, {"s": 246.95, "e": 247.61, "t": "第三页。"}, {"s": 247.61, "e": 249.25, "t": "2024/12/20"}, {"s": 249.25, "e": 250.72, "t": "\"他今天没来走廊。"}, {"s": 250.72, "e": 252.85, "t": "我抬头看了三次——他没在。"}, {"s": 252.85, "e": 254.15, "t": "是不是生病了？\""}, {"s": 254.15, "e": 254.81, "t": "第四页。"}, {"s": 254.81, "e": 256.12, "t": "2025/1/8"}, {"s": 256.12, "e": 256.94, "t": "\"期末了。"}, {"s": 256.94, "e": 260.05, "t": "不知道下学期还能不能在学校里看见他。\""}, {"s": 260.05, "e": 261.19, "t": "我的手有点抖。"}, {"s": 261.19, "e": 266.92, "t": "我看见了那个时间跨度——从高一上的 12 月，一直到高一下的 2 月。"}, {"s": 266.92, "e": 270.03, "t": "每次记录都只有一两行，有时候只有半行。"}, {"s": 270.03, "e": 271.5, "t": "2025/2/13"}, {"s": 271.5, "e": 273.3, "t": "\"他进 610 班了。"}, {"s": 273.3, "e": 274.61, "t": "原来他叫林深。\""}, {"s": 274.61, "e": 278.54, "t": "下面有一行，字迹比前面稍微潦草一点，像是补写的："}, {"s": 278.54, "e": 279.85, "t": "\"他坐在我后面。"}, {"s": 279.85, "e": 280.99, "t": "80 厘米。\""}, {"s": 280.99, "e": 283.45, "t": "我看到这里，眼泪突然就下来了。"}, {"s": 283.45, "e": 291.3, "t": "不是那种\"感动的眼泪\"——是那种你发现你一直以为是一个人的事情，其实是两个人一起经历的那种眼泪。"}, {"s": 291.3, "e": 293.76, "t": "我一直以为暗恋是我一个人的事。"}, {"s": 293.76, "e": 295.72, "t": "但这本子告诉我——不是。"}, {"s": 295.72, "e": 296.54, "t": "\"你——\""}, {"s": 296.54, "e": 297.85, "t": "我说不出话来了。"}, {"s": 297.85, "e": 299.81, "t": "博文站在我旁边，没看我。"}, {"s": 299.81, "e": 302.27, "t": "他看着对面的 610 班窗户。"}, {"s": 302.27, "e": 306.03, "t": "\"我高一上第一次抬头的时候——你在走廊上看我。"}, {"s": 306.03, "e": 308.49, "t": "我心里有了一种说不出来的满。\""}, {"s": 308.49, "e": 309.31, "t": "他顿了顿。"}, {"s": 309.31, "e": 311.6, "t": "\"那时候我就知道……完了。\""}, {"s": 311.6, "e": 312.91, "t": "\"什么叫完了？\""}, {"s": 312.91, "e": 315.85, "t": "\"就是——你再也不能不看他的意思。\""}, {"s": 315.85, "e": 318.96, "t": "我们站在 611 班的窗户前站了很久。"}, {"s": 318.96, "e": 323.54, "t": "七月的风从窗外吹进来，带着操场上被晒过的塑胶跑道的气味。"}, {"s": 323.54, "e": 328.29, "t": "对面 610 班的窗帘被风吹得鼓起来，飘了一下，又落回去。"}, {"s": 328.29, "e": 329.76, "t": "我低头看那个本子。"}, {"s": 329.76, "e": 332.22, "t": "翻到最后一页，有记录的那一页。"}, {"s": 332.22, "e": 333.53, "t": "2025/7/2"}, {"s": 333.53, "e": 334.67, "t": "\"我告诉他了。"}, {"s": 334.67, "e": 335.49, "t": "所有的事。"}, {"s": 335.49, "e": 336.15, "t": "他哭了。"}, {"s": 336.15, "e": 340.07, "t": "他的眼睛里有光——和那天第一次看到的时候一样。\""}, {"s": 340.07, "e": 344.16, "t": "\"我第一次看到你的时候——你知道我看到了什么吗？\""}, {"s": 344.16, "e": 345.96, "t": "博文的声音从旁边传来。"}, {"s": 345.96, "e": 346.46, "t": "很轻。"}, {"s": 346.46, "e": 354.15, "t": "\"你眼睛里的光——是像早上第一节课前、太阳刚升起来、照到对面教学楼的白墙再反射过来的那种光。\""}, {"s": 354.15, "e": 355.29, "t": "我转过头看他。"}, {"s": 355.29, "e": 357.26, "t": "他没在看我——但他笑了。"}, {"s": 357.26, "e": 360.53, "t": "眼睛底下那一块皱了一下——1 厘米的皱。"}, {"s": 360.53, "e": 361.68, "t": "\"我说完了。\""}, {"s": 361.68, "e": 362.17, "t": "他说。"}, {"s": 362.17, "e": 364.78, "t": "我低下头，把本子合上，封面朝上。"}, {"s": 364.78, "e": 369.2, "t": "深蓝色的封面上，那棵小树的轮廓在下午的阳光里特别清楚。"}, {"s": 369.2, "e": 370.51, "t": "\"这个本子——\""}, {"s": 370.51, "e": 371.49, "t": "\"送你了。\""}, {"s": 371.49, "e": 373.46, "t": "\"……你不是还在写吗？\""}, {"s": 373.46, "e": 374.77, "t": "\"以后换新的。\""}, {"s": 374.77, "e": 376.08, "t": "他转过头来看我。"}, {"s": 376.08, "e": 378.37, "t": "\"你要不要跟我去一个地方？\""}, {"s": 378.37, "e": 379.68, "t": "我们走在楼梯上。"}, {"s": 379.68, "e": 384.42, "t": "七月的阳光从天窗照下来，把楼梯间的灰尘照成一条一条的金线。"}, {"s": 384.42, "e": 387.37, "t": "我捏着那个本子的封面，手指还是凉的。"}, {"s": 387.37, "e": 390.48, "t": "\"最后一页那行字——你什么时候写的？\""}, {"s": 390.48, "e": 391.62, "t": "\"今天早上。\""}, {"s": 391.62, "e": 393.59, "t": "\"……你早知道我会哭？\""}, {"s": 393.59, "e": 394.57, "t": "\"不知道。\""}, {"s": 394.57, "e": 395.39, "t": "他顿了顿。"}, {"s": 395.39, "e": 396.7, "t": "\"但我带纸了。\""}, {"s": 396.7, "e": 399.64, "t": "他伸手从口袋里掏出一包纸巾，递给我。"}, {"s": 399.64, "e": 400.46, "t": "我接过来。"}, {"s": 400.46, "e": 405.37, "t": "撕开包装的时候，我看到他在笑——嘴角往上，眼睛底下皱了一下。"}, {"s": 405.37, "e": 407.17, "t": "七月的风从窗外吹进来。"}, {"s": 407.17, "e": 411.43, "t": "我把我高一上站在走廊上看了他一年半这件事，告诉了他。"}, {"s": 411.43, "e": 414.7, "t": "他把高一上就开始记录我的本子，交给了我。"}, {"s": 414.7, "e": 416.99, "t": "我们站在楼梯口，谁都没说话。"}, {"s": 416.99, "e": 418.46, "t": "但不是因为没话说。"}, {"s": 418.46, "e": 421.9, "t": "是因为话说完了之后，好像什么都不用再说了。"}, {"s": 421.9, "e": 422.88, "t": "\"带路吧。\""}, {"s": 422.88, "e": 423.37, "t": "我说。"}, {"s": 423.37, "e": 424.36, "t": "他点了点头。"}, {"s": 424.36, "e": 426.65, "t": "然后往六楼的方向走——天台。"}, {"s": 426.65, "e": 430.25, "t": "<!-- summary:start -->"}, {"s": 430.25, "e": 431.39, "t": "本章推进线索："}, {"s": 431.39, "e": 439.74, "t": "- F-本子（深蓝+小树）完整揭晓：2024/12/7 第一页 \"今天 611 班那个站在走廊上的人\""}, {"s": 439.74, "e": 449.72, "t": "- F-眼睛里的光 双向揭晓：博文说出与林深 Ch 1 完全相同的描述——\"像早上第一节课前、太阳照到白墙再反射过来的光\""}, {"s": 449.72, "e": 457.09, "t": "- POV-双向暗恋起点：2024/12/7 确认——两人从高一上 12/7 开始互相暗恋"}, {"s": 457.09, "e": 461.67, "t": "- 录取确认：两人都录到江城大学（林深计科、博文物理系）"}, {"s": 461.67, "e": 463.3, "t": "本章关键事件时间戳："}, {"s": 463.3, "e": 467.07, "t": "- 6/30 查录取：江城大学计科 + 物理系"}, {"s": 467.07, "e": 468.87, "t": "- 7/1 EMS 到"}, {"s": 468.87, "e": 474.11, "t": "- 7/2 611 班走廊 → 本子揭晓 → 眼睛对称 → 天台"}, {"s": 474.11, "e": 474.92, "t": "下章钩子："}, {"s": 474.92, "e": 477.38, "t": "- \"你要不要跟我去一个地方？"}, {"s": 477.38, "e": 478.36, "t": "\"——天台。"}, {"s": 478.36, "e": 480.98, "t": "Ch 40 终章：\"你没会错意\""}, {"s": 480.98, "e": 484.25, "t": "<!-- summary:end -->"}, {"s": 484.25, "e": 486.54, "t": "2026-07-19 修复："}, {"s": 486.54, "e": 490.8, "t": "1. 北京大学 → 江城大学（虚构大学，省重点一本）"}, {"s": 490.8, "e": 496.36, "t": "2. 校训\"思想自由 兼容并包\" → 删除，改为江城大学红色印章描述"}, {"s": 496.36, "e": 500.29, "t": "3. 录取专业：计科/物理系（配合普通一本设定）"}, {"s": 500.29, "e": 503.4, "t": "4. 博文的记录时间不变，情感核心不变"}]}, {"num": 40, "title": "第40章 你没会错意", "file": "chapters/ch040.mp3", "dur": 502.2, "size_mb": 4.0, "segs": [{"s": 0.0, "e": 3.89, "t": "时间：7 月 16 日（周三）· 高考后的夏天"}, {"s": 3.89, "e": 6.08, "t": "我跟在博文后面，走上六楼。"}, {"s": 6.08, "e": 10.98, "t": "楼梯间的阳光从天窗斜斜地照下来，把我的影子叠在他的影子上。"}, {"s": 10.98, "e": 16.39, "t": "我手里还捏着那个深蓝色的本子——封面上小树的轮廓在光里特别清楚。"}, {"s": 16.39, "e": 21.46, "t": "从 7 月 2 号那天他把它交给我开始，我走到哪里都带着它。"}, {"s": 21.46, "e": 23.32, "t": "他在天台门口停了一下。"}, {"s": 23.32, "e": 26.19, "t": "那扇铁门——两年前他带我来过一次。"}, {"s": 26.19, "e": 33.96, "t": "那天下午的阳光把整片天台染成橘色的，他站在门前面，回过头来看我，说了一句我到现在都记得的话。"}, {"s": 33.96, "e": 36.33, "t": "\"我高一上就想离你近一点。\""}, {"s": 36.33, "e": 37.85, "t": "那是两年前的事了。"}, {"s": 37.85, "e": 40.72, "t": "他伸手推开门——铁门发出吱的一声。"}, {"s": 40.72, "e": 42.24, "t": "和两年前一模一样。"}, {"s": 42.24, "e": 43.6, "t": "然后他走了出去。"}, {"s": 43.6, "e": 44.44, "t": "我跟上去。"}, {"s": 44.44, "e": 45.96, "t": "天台还是那个天台。"}, {"s": 45.96, "e": 51.54, "t": "水泥地面，边上生锈的围栏，远处的城市天际线在七月的热气里微微扭曲。"}, {"s": 51.54, "e": 57.79, "t": "围栏上还留着不知道谁刻的字——\"2025 高考加油\"，笔画已经被晒褪色了。"}, {"s": 57.79, "e": 62.18, "t": "不一样的是这一次我不再是\"跟他上来看看\"的那个人了。"}, {"s": 62.18, "e": 64.55, "t": "博文走到围栏边上，没转过来。"}, {"s": 64.55, "e": 74.69, "t": "七月的风从城市那边吹过来，带着柏油路面晒过的气味和他衣服上那股熟悉的洗衣液味道——不是柚子味的，换了，但我也闻了两年了。"}, {"s": 74.69, "e": 77.73, "t": "\"你知道这个天台对我来说是什么吗？\""}, {"s": 77.73, "e": 79.42, "t": "他开口了，声音不大。"}, {"s": 79.42, "e": 81.95, "t": "我走过去，靠在他旁边的围栏上。"}, {"s": 81.95, "e": 82.8, "t": "\"什么？\""}, {"s": 82.8, "e": 84.15, "t": "他沉默了一会儿。"}, {"s": 84.15, "e": 87.19, "t": "\"高二那天——我在这里说了一句话。\""}, {"s": 87.19, "e": 88.04, "t": "\"哪句？\""}, {"s": 88.04, "e": 90.06, "t": "\"'我想和你在一起'。\""}, {"s": 90.06, "e": 94.46, "t": "他说这句话的时候语气很平，像在读一条早就确定的定理。"}, {"s": 94.46, "e": 98.85, "t": "\"我说完那句话之后，这个天台就不再是普通的天台了。\""}, {"s": 98.85, "e": 100.2, "t": "他转过头来看我。"}, {"s": 100.2, "e": 108.82, "t": "阳光落在他侧脸上，把他眼底的光照得发亮——那种像早上第一节课前、太阳照到对面教学楼白墙再反射过来的光。"}, {"s": 108.82, "e": 112.2, "t": "\"从那之后——我来天台就不用一个人了。\""}, {"s": 112.2, "e": 115.41, "t": "风忽然大了一些，把他的头发吹乱了一点。"}, {"s": 115.41, "e": 116.59, "t": "他没伸手去理。"}, {"s": 116.59, "e": 117.61, "t": "我也没说话。"}, {"s": 117.61, "e": 118.96, "t": "不是因为没话说。"}, {"s": 118.96, "e": 120.82, "t": "是因为有些话不需要说。"}, {"s": 120.82, "e": 125.04, "t": "过了好一会儿，他从口袋里掏出一个东西——一个本子。"}, {"s": 125.04, "e": 130.28, "t": "新的，封面是纯黑色的，连价格标签都没撕干净，露出一截白色的边。"}, {"s": 130.28, "e": 131.97, "t": "\"我昨天晚上写的。\""}, {"s": 131.97, "e": 132.82, "t": "他递过来。"}, {"s": 132.82, "e": 136.2, "t": "我接住的时候，手指碰到他的手指——暖的。"}, {"s": 136.2, "e": 138.39, "t": "和两年前借笔记那次一样暖。"}, {"s": 138.39, "e": 139.58, "t": "我翻开第一页。"}, {"s": 139.58, "e": 143.12, "t": "字迹很整齐，和他那个深蓝色本子里的字一样。"}, {"s": 143.12, "e": 145.83, "t": "蓝黑色的墨水，在纸面上微微反光。"}, {"s": 145.83, "e": 147.35, "t": "2026/7/15"}, {"s": 147.35, "e": 149.88, "t": "\"明天我要跟他说：你没会错意。"}, {"s": 149.88, "e": 151.4, "t": "从高一开始就没有。"}, {"s": 151.4, "e": 152.59, "t": "以后也不会。\""}, {"s": 152.59, "e": 155.8, "t": "我看着那行字，喉咙动了一下，没说出来。"}, {"s": 155.8, "e": 162.56, "t": "他伸手把我的手指按在那一页上——他的拇指按在我的手背上，用力了一下，然后松开了。"}, {"s": 162.56, "e": 164.25, "t": "\"那个本子送你了。\""}, {"s": 164.25, "e": 164.75, "t": "他说。"}, {"s": 164.75, "e": 165.77, "t": "\"这是新的。"}, {"s": 165.77, "e": 167.12, "t": "第一页给你看。\""}, {"s": 167.12, "e": 168.64, "t": "我低头看着那行字。"}, {"s": 168.64, "e": 175.4, "t": "他把\"你没会错意\"单独写在一行——字比其他行稍微用力一点，笔画比旁边的字深一些。"}, {"s": 175.4, "e": 176.24, "t": "\"你——\""}, {"s": 176.24, "e": 177.43, "t": "话卡在喉咙里。"}, {"s": 177.43, "e": 178.27, "t": "他没催我。"}, {"s": 178.27, "e": 181.65, "t": "他只是转过去，重新看向远处的城市天际线。"}, {"s": 181.65, "e": 184.35, "t": "夏天的风从我们两个人之间穿过去。"}, {"s": 184.35, "e": 193.65, "t": "我忽然想起高一上那个站在走廊上的自己——趴在窗台上，透过 5 米宽的空气，看着对面那个永远不知道我在看他的人。"}, {"s": 193.65, "e": 197.03, "t": "那时候我想：我这辈子大概只能这样看他了。"}, {"s": 197.03, "e": 200.74, "t": "但现在我站在天台边上，手里握着他昨天写的字。"}, {"s": 200.74, "e": 202.6, "t": "上面写着：你没会错意。"}, {"s": 202.6, "e": 204.12, "t": "从高一开始就没有。"}, {"s": 204.12, "e": 205.14, "t": "以后也不会。"}, {"s": 205.14, "e": 206.32, "t": "——\"以后\"。"}, {"s": 206.32, "e": 209.7, "t": "这个词从高一到现在，我从来没敢认真想过。"}, {"s": 209.7, "e": 210.55, "t": "\"博文。\""}, {"s": 210.55, "e": 211.22, "t": "\"嗯？\""}, {"s": 211.22, "e": 213.25, "t": "\"你为什么选江城大学？\""}, {"s": 213.25, "e": 215.11, "t": "他转过头来看了我一眼。"}, {"s": 215.11, "e": 218.15, "t": "\"物理系只有江大在省内收分最合适。\""}, {"s": 218.15, "e": 219.5, "t": "\"……就这样？\""}, {"s": 219.5, "e": 220.85, "t": "他沉默了一会儿。"}, {"s": 220.85, "e": 224.57, "t": "\"也有一部分——\"他顿了一下，\"是因为你。\""}, {"s": 224.57, "e": 227.11, "t": "\"……什么叫'也有一部分'？\""}, {"s": 227.11, "e": 230.15, "t": "他的目光落在远处的天际线上，不看我。"}, {"s": 230.15, "e": 234.2, "t": "\"就是——\"他的声音比刚才小了一点，\"你在那里。"}, {"s": 234.2, "e": 236.91, "t": "所以我填志愿的时候没有犹豫过。\""}, {"s": 236.91, "e": 239.95, "t": "夏天午后的风从远处吹过来，带着热浪。"}, {"s": 239.95, "e": 244.17, "t": "不知道哪栋楼的空调外机在嗡嗡地转，声音很远很模糊。"}, {"s": 244.17, "e": 252.45, "t": "我把那个纯黑色的本子合上，两只手各握着一个本子——深蓝的，从高一开始写的；纯黑的，从昨天开始写的。"}, {"s": 252.45, "e": 254.65, "t": "\"那你——接下来写什么？\""}, {"s": 254.65, "e": 255.49, "t": "他想了想。"}, {"s": 255.49, "e": 258.03, "t": "\"写江城大学秋天有没有银杏。\""}, {"s": 258.03, "e": 259.04, "t": "\"还有呢？\""}, {"s": 259.04, "e": 261.75, "t": "\"写大一第一节课你会坐第几排。\""}, {"s": 261.75, "e": 262.76, "t": "\"还有呢？\""}, {"s": 262.76, "e": 264.11, "t": "他转过头来看我。"}, {"s": 264.11, "e": 266.14, "t": "那个眼神——我说不上来。"}, {"s": 266.14, "e": 269.86, "t": "不是回答，是那种\"你真的要我说完吗\"的眼神。"}, {"s": 269.86, "e": 271.38, "t": "我看着他，没躲开。"}, {"s": 271.38, "e": 275.26, "t": "他嘴角动了一下——然后眼睛底下那一块皱了一下。"}, {"s": 275.26, "e": 276.45, "t": "1 厘米的皱。"}, {"s": 276.45, "e": 279.32, "t": "\"写你不用再问'还有呢'的那天。\""}, {"s": 279.32, "e": 279.83, "t": "他说。"}, {"s": 279.83, "e": 281.35, "t": "心脏猛地跳了一下。"}, {"s": 281.35, "e": 282.7, "t": "\"哪天是那天？\""}, {"s": 282.7, "e": 283.88, "t": "他没马上回答。"}, {"s": 283.88, "e": 291.65, "t": "过了一会儿，他伸手拿走我手里的纯黑色本子，翻到刚才那一页，在\"以后也不会\"下面又写了一行字。"}, {"s": 291.65, "e": 294.19, "t": "他写的时候没挡着——我看见了。"}, {"s": 294.19, "e": 297.91, "t": "他的字写得比上一行轻一些，像是写给自己看的："}, {"s": 297.91, "e": 299.77, "t": "\"写到不用写的那天。\""}, {"s": 299.77, "e": 301.79, "t": "他把本子合上，递回给我。"}, {"s": 301.79, "e": 304.33, "t": "\"哪一天是'不用写的那天'？\""}, {"s": 304.33, "e": 307.54, "t": "他把目光从我脸上移开，看向远处的城市。"}, {"s": 307.54, "e": 310.58, "t": "\"等我不用靠写来确认你还在的那天。\""}, {"s": 310.58, "e": 312.1, "t": "风忽然安静了一瞬。"}, {"s": 312.1, "e": 316.33, "t": "远处工地打桩的声音停了几秒，不知道是午休还是换料。"}, {"s": 316.33, "e": 319.7, "t": "操场上空荡荡的，暑假的学校像另一个星球。"}, {"s": 319.7, "e": 323.25, "t": "我站在他旁边，肩膀之间隔了一个拳头的距离。"}, {"s": 323.25, "e": 324.77, "t": "比 80 厘米近。"}, {"s": 324.77, "e": 328.32, "t": "比 5 米——比那扇反光玻璃——近太多了。"}, {"s": 328.32, "e": 329.51, "t": "\"那要很久。\""}, {"s": 329.51, "e": 330.01, "t": "我说。"}, {"s": 330.01, "e": 331.03, "t": "\"我知道。\""}, {"s": 331.03, "e": 332.55, "t": "\"你会写很多本。\""}, {"s": 332.55, "e": 333.22, "t": "\"嗯。\""}, {"s": 333.22, "e": 334.91, "t": "\"你书房装得下吗？\""}, {"s": 334.91, "e": 336.1, "t": "他转过来看我。"}, {"s": 336.1, "e": 340.49, "t": "那个表情——不是笑，是那种\"你终于不紧张了\"的表情。"}, {"s": 340.49, "e": 342.52, "t": "嘴角往上翘了大概半厘米。"}, {"s": 342.52, "e": 344.38, "t": "\"装不下就放你那边。\""}, {"s": 344.38, "e": 344.88, "t": "他说。"}, {"s": 344.88, "e": 346.57, "t": "我低下头，笑了一下。"}, {"s": 346.57, "e": 349.28, "t": "远处的天际线上，云在慢慢地移动。"}, {"s": 349.28, "e": 357.39, "t": "七月的天空从蓝色开始往橘色过渡——不是两年前那种鲜艳的橘色，是更淡的、被夏天的热气稀释过的橘色。"}, {"s": 357.39, "e": 360.09, "t": "不是同一个下午，但颜色是一样的。"}, {"s": 360.09, "e": 365.5, "t": "我忽然觉得，两年前站在这里的我和现在站在这里的我，不是同一个人。"}, {"s": 365.5, "e": 370.9, "t": "两年前我站在这里，听到他说\"我喜欢你\"，心里想的是：这是真的吗？"}, {"s": 370.9, "e": 372.09, "t": "他会不会后悔？"}, {"s": 372.09, "e": 375.3, "t": "现在我还是站在这里，手里多了两个本子。"}, {"s": 375.3, "e": 381.21, "t": "一个高二上他被我发现的本子——记录了他从高一上就开始的、三年半的注视。"}, {"s": 381.21, "e": 387.97, "t": "一个昨天晚上才买的、第一页就写着\"你没会错意\"——从高一开始就没有，以后也不会。"}, {"s": 387.97, "e": 390.84, "t": "我低下头，把两个本子并排拿在手里。"}, {"s": 390.84, "e": 391.69, "t": "\"博文。\""}, {"s": 391.69, "e": 392.36, "t": "\"嗯？\""}, {"s": 392.36, "e": 397.43, "t": "\"我高一上站在走廊上的时候——从来没想过能走到今天这一步。\""}, {"s": 397.43, "e": 398.28, "t": "他没回答。"}, {"s": 398.28, "e": 404.19, "t": "但他把手从围栏上拿下来——搭在围栏上的那只手——然后往我这边挪了一点。"}, {"s": 404.19, "e": 405.55, "t": "不到 5 厘米。"}, {"s": 405.55, "e": 406.22, "t": "但够了。"}, {"s": 406.22, "e": 408.76, "t": "他的手臂外侧贴着我的手臂外侧。"}, {"s": 408.76, "e": 411.8, "t": "皮肤碰到皮肤的那一下，两个人都没动。"}, {"s": 411.8, "e": 413.99, "t": "夏天的风从城市那边吹过来。"}, {"s": 413.99, "e": 416.53, "t": "远处的天际线在热气里微微起伏。"}, {"s": 416.53, "e": 418.39, "t": "我没看他，他也没看我。"}, {"s": 418.39, "e": 419.74, "t": "我们就那么站着。"}, {"s": 419.74, "e": 424.47, "t": "两个本子叠在一起，一个从过去写到今天，一个从今天开始写。"}, {"s": 424.47, "e": 428.02, "t": "他的手搭在围栏上，离我的手大概 2 厘米。"}, {"s": 428.02, "e": 429.37, "t": "我没再往那边挪。"}, {"s": 429.37, "e": 430.55, "t": "不是因为不敢。"}, {"s": 430.55, "e": 436.97, "t": "是因为我知道——明天、后天、大学四年、以后——还有很长很长的时间可以慢慢挪。"}, {"s": 436.97, "e": 440.69, "t": "<!-- summary:start -->"}, {"s": 440.69, "e": 441.88, "t": "本章推进线索："}, {"s": 441.88, "e": 452.69, "t": "- ✅ 天台意象第三次出场（橘色光：Ch 30 的橙 → Ch 34 的白 → Ch 40 的淡橘+暮色）——完成天台三阶意象弧"}, {"s": 452.69, "e": 460.97, "t": "- ✅ 距离意象最终收束：5米→80厘米→30厘米→1拳→2厘米→\"还有很长很长的时间可以慢慢挪\""}, {"s": 460.97, "e": 469.08, "t": "- ✅ \"你没会错意\"——博文以\"写在新本子第一页\"的方式完成表达，符合\"行动多于语言\"核心人设"}, {"s": 469.08, "e": 477.87, "t": "- ✅ 本子意象升级：深蓝（暗恋记录）→ 纯黑（未来记录），\"写到不用写的那天\"完成\"一辈子\"的含蓄表达"}, {"s": 477.87, "e": 483.61, "t": "- ✅ \"我不用靠写来确认你还在\"——以博文式短句完成承诺，不崩人设"}, {"s": 483.61, "e": 485.3, "t": "本章关键事件时间戳："}, {"s": 485.3, "e": 491.72, "t": "- 7/16 天台：博文新本子第一页 → \"你没会错意\"确认 → 手臂贴着站"}, {"s": 491.72, "e": 493.75, "t": "未解悬念：无（全书完成）"}, {"s": 493.75, "e": 497.13, "t": "<!-- summary:end -->"}, {"s": 497.13, "e": 502.2, "t": "初始版本：2026-07-19 Ch 40 终章·你没会错意"}]}];